window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q06"]=window.__LIBQ["tien-nghich"]["q06"]||{};window.__LIBQ["tien-nghich"]["q06"]["characters"]={"updatedAt":"2026-06-23","count":132,"chars":[{"id":"vuong-lam","name":"Vương Lâm","gioiTinh":"nam","tabs":{"diem":[],"kinhLich":[{"chuong":"@c0458","importance":"normal","tieuDe":"Lấy toàn bộ tiên ngọc Phẩm Linh Các","text":"Với thân phận Đệ thất tử Tử hệ đã 103 năm chưa lĩnh tiên ngọc, Vương Lâm vào tiên cảnh tầng bảy Phẩm Linh Các, chọn lấy toàn bộ và thu trọn 123.600 khối tiên ngọc cao như núi vào túi trữ vật, định bế quan trong ba tháng để đột phá Anh Biến trung kỳ, tranh đoạt danh hiệu thiên vận thất tử."},{"chuong":"@c0458","importance":"normal","tieuDe":"Năm người vây kích tại Tử Lâm Các","text":"Vừa về Tử Lâm Các, hắn bị năm người hợp vây gồm tứ sư tỷ Tử hệ, Triệu Tinh Sát, đệ tử thứ hai Lam tông, Tư Mã Như Phong và một người y phục xanh nửa bước vấn đỉnh; tứ sư tỷ bắt quyết thi triển Tử thuật - Na di bao trùm mười dặm để khởi chiến."},{"chuong":"@c0459","importance":"normal","tieuDe":"Bị vây khốn thạch lâm khốn địa","text":"Vương Lâm bị tứ sư tỷ cùng Triệu Tinh Sát, nhị sư huynh và hai người Thanh-Lam hai hệ liên thủ khóa không gian, phát bốn đạo sát khí chấn nhiếp rồi na di tới thạch lâm khốn địa ngoài Thiên Vận Tông hơn mười ngàn dặm. Tứ sư tỷ hẹn ba năm sau tới thả ra, để hắn yên tĩnh bế quan."},{"bridge":true,"khoang":"@c0459–@c0459","text":"Hắn thử phá vây nhiều cách — chém kiếm quang bằng tiên kiếm, bay thẳng lên trên chịu lực cản tương đương Anh Biến hậu kỳ, rồi cho Hứa Lập Quốc và loan đao lao thử — đều bị trận pháp triệt tiêu."},{"chuong":"@c0459","importance":"normal","tieuDe":"Quyết tu luyện đột phá Anh Biến trung kỳ","text":"Nhận ra kẻ địch định vây tới khi tranh đoạt danh hiệu Thiên Vận Thất Tử kết thúc, Vương Lâm quyết không chờ ba năm mà tự phá nơi này. Hắn tìm được biên giới thạch lâm, ngồi khoanh chân hấp thu lượng lớn tiên ngọc luyện công, sau lưng hiện quầng sáng vàng báo hiệu tiên lực đạt bão hòa."},{"chuong":"@c0460","importance":"normal","tieuDe":"Hoàn tất hấp thu tiên lực","text":"Toàn bộ tiên lực điên cuồng nhập thể, Vương Lâm dồn toàn lực hấp thu suốt ba tháng tại thạch lâm cách Thiên Vận Tông hơn mười ngàn dặm."},{"chuong":"@c0460","importance":"normal","tieuDe":"Đột phá chấn thiên địa","text":"Mở mắt phát hai luồng quang như trăng rằm, một cái nhấn tay làm thạch lâm mười dặm tan thành bụi; há miệng hút thu khí tức như phễu rồi thét dài chấn động thiên địa, vụt đứng dậy dáng như đội trời đạp đất."},{"chuong":"@c0461","importance":"normal","tieuDe":"Phá trận thoát thạch lâm","text":"Sau ba tháng bị tấm màn sáng hình vòm vây khốn trong thạch lâm rộng mười dặm, Vương Lâm bay lên sát đỉnh màn, dùng Tịch Diệt Chỉ điểm tạo vô số vết nứt nhưng trận tự khôi phục; hắn chuyển sang Hóa Ma Chỉ nghịch hóa toàn bộ tiên lực thành ma hỏa tím, thiêu rụi cả tấm màn chỉ trong ba nhịp thở."},{"chuong":"@c0461","importance":"normal","tieuDe":"Trở về Thiên Vận Tông báo thù","text":"Không thuộc địa hình, Vương Lâm thả nguyên thần Tào Nhất Đấu dẫn đường, thuấn di ba mươi vạn dặm về hướng tây; hồi tưởng bị Tử hệ nhất mạch chèn ép na di vây khốn, hắn lập thề ai phạm ta giết không tha, xuất hiện thành cầu vồng tím từ đằng đông ngay giữa thọ yến ngàn năm của Thiên Vận Tử đúng lúc Triệu Tinh Sát chúc rượu."},{"chuong":"@c0462","importance":"normal","tieuDe":"Xông vào thọ yến truy sát kẻ thù","text":"Cưỡi đám mây tím phá không tới Tử Tông Sơn trên Thiên Vận Tinh, kinh động cả buổi thọ yến của sư tôn Tử hệ. Hắn dùng Cấm Phiên xé tan Thượng chi lực của nhị sư huynh, cảnh cáo các tu sĩ tông phái khác không được can dự, rồi khơi ma hỏa quyết tâm đòi mạng."},{"chuong":"@c0462","importance":"normal","tieuDe":"Ma hỏa tự bạo phá quyết Triệu Tinh Sát","text":"Khi Triệu Tinh Sát bước ra dùng Đại tự tại thiên địa quyết bọc ma hỏa hòng cản, Vương Lâm hô “Bạo”, ma hỏa tự nổ phát tiết ma khí và lửa tím, thiêu vỡ quầng sáng trắng, quét nghìn trượng tạo hố lớn khiến mọi tu sĩ tản chạy."},{"chuong":"@c0462","importance":"normal","tieuDe":"Đả thương nguyên thần Hứa Lập Quốc","text":"Vương Lâm vung tiên kiếm và loan đao chém tan màn sương đen Tiên Ma thể của Hứa Lập Quốc, rồi dùng Côn Cực Tiên kéo dài đánh trúng nguyên thần đang thuấn di trốn cách nghìn trượng, khiến nguyên thần run rẩy sắp tan, lưng hiện vết thương sâu, phát tiết lượng lớn tiên lực tinh hoa."},{"chuong":"@c0463","importance":"normal","tieuDe":"Uy hiếp Triệu Tinh Sát giữa Tử Tông","text":"Vương Lâm thu nốt nguyên thần đối phương vào Tôn Hồn Phiên rồi chỉ thẳng Triệu Tinh Sát, tuyên bố ai cản trở sẽ thành kẻ thù. Các chấp pháp trưởng lão Tử Tông do dự không ai dám tiến lên."},{"chuong":"@c0463","importance":"normal","tieuDe":"Đối đầu Cổ Yêu, triệu Hồn Thú","text":"Khi Triệu Tinh Sát triệu hư ảnh cổ yêu trăm trượng, Vương Lâm dùng Tôn Hồn Phiên thu hồi chủ hồn bị lốc xoáy đỏ hút, rồi vỗ Xạ Thần Xa triệu Hồn Thú đâm xuyên thân yêu vật. Ánh mắt lạnh thấu xương của cổ yêu khiến hắn liên tưởng tới hóa thân của cổ thần thiên đạo sứ giả."},{"bridge":true,"khoang":"@c0463–@c0463","text":"Sau khi Xích Liệt quát đuổi cổ yêu kết thúc trận, Vương Lâm điềm tĩnh thu Khu Thú Quyển, ung dung đi tới ngồi vào bàn trống thứ ba dưới chỗ tứ sư tỷ — vị trí thuộc về hắn."},{"chuong":"@c0464","importance":"normal","tieuDe":"Thay chủ yến hội Tử hệ","text":"Sau khi Xích Liệt bắt Triệu Sát Tinh đi, Vương Lâm trở thành tâm điểm yến hội ngày cuối, được các tu sĩ tông phái kéo đến chúc rượu vì nhận định hắn chắc chắn trở thành Thiên Vận Thất Tử."},{"chuong":"@c0464","importance":"normal","tieuDe":"Nhận ngọc giản hai cấm pháp","text":"Đêm khuya yến tàn, tứ sư tỷ trao ngọc giản chứa cấm pháp đại na di và một cấm pháp do sư tôn phỏng tiên thuật sáng tạo, coi như xin lỗi việc tháng trước; Vương Lâm nhận, không muốn trở mặt hoàn toàn."},{"chuong":"@c0464","importance":"normal","tieuDe":"Tu thành thuật đại na di","text":"Trong mật thất tầng ba Tử Lâm Các, Vương Lâm thử cấm pháp dịch chuyển mười vạn dặm, bước bảy bước trong hào quang bạc rồi xuất hiện trên đỉnh núi cách đó mười vạn dặm, xác nhận đã tới đúng Thiên Vận Tinh."},{"chuong":"@c0464","importance":"major","tieuDe":"Khai mở tu luyện tiên thuật","text":"Vương Lâm đặt tên Cửu Chuyển Luyện Tiên Quyết cho cấm pháp thứ hai, tu liên tiếp nhất chuyển, nhị chuyển, tam chuyển, ngưng tụ luồng kim tiên lực sắc bén ở tay trái — đánh dấu lần đầu tu thành tiên thuật chân chính nhờ đã có tiên thể bậc trung."},{"chuong":"@c0464","importance":"normal","tieuDe":"Dự lễ giảng đạo Thiên Vận Tử","text":"Trời sáng, Vương Lâm tới dự lễ giảng đạo vạn năm một lần của sư tôn; quét mắt nhận ra ba cao thủ trong sáu tông: Tư Mã Như Phong, nam tử họ Vương của Thanh Tông (nửa bước Vấn Đỉnh) và người trung niên Cam Tông từng đánh Sất Hổ."},{"chuong":"@c0465","importance":"normal","tieuDe":"Dự thọ yến vạn năm Thiên Vận Tử","text":"Với thân phận đệ tử Tử Hệ, Vương Lâm dự đại thọ vạn năm của Thiên Vận Tử, đánh giá thực lực thất hệ và nhận thấy nhiều đệ tử ẩn giấu bản lãnh, trừ ba người Tử Hệ thì các Hệ khác đều có thể hoành hành ở Chu Tước Tinh. Hắn chứng kiến Tôn trưởng lão từ tu chân liên minh giáng lâm bằng kim quang trận pháp khổng lồ."},{"bridge":true,"khoang":"@c0465","text":"Khi Thiên Vận Tử bắt đầu giảng Thiên Vận Chi Đạo, con tiểu điêu ba mắt của Tôn trưởng lão bất ngờ bay tới đậu lên vai Vương Lâm, ba mắt phát tia sáng âm u dò xét hắn; Vương Lâm thấy con chim quen quen liền chăm chú quan sát."},{"chuong":"@c0466","importance":"normal","tieuDe":"Tinh Ngân điêu tìm tới","text":"Một con tử điêu ba mắt đậu trên vai Vương Lâm; qua truyền thừa ký ức cổ thần Đồ Ti hắn nhận ra đó là Tinh Ngân điêu còn nhỏ. Con chim không màng thượng phẩm tinh thạch, chỉ chăm chú nhìn hắn vì bị khí tức cổ thần cực yếu trên người hắn thu hút, song lượng khí tức quá ít khiến hắn thất vọng."},{"chuong":"@c0466","importance":"normal","tieuDe":"Vấn đạo trước sư tôn","text":"Được Thiên Vận Tử gọi đích danh chỉ điểm trước tu sĩ bốn phía và đệ tử lục hệ, Vương Lâm cung kính hỏi cách phân biệt tu tiên, tu chân và tu đạo. Nghe sư tôn giảng ba bước tu đạo, hắn vẫn hoài nghi có thực sự tồn tại bước thứ ba hay không, dẫn tới việc Thiên Vận Tử tiết lộ về ‘hắn’."},{"bridge":true,"khoang":"@c0466–@c0466","text":"Vương Lâm thử dụ tử điêu bằng tiên ngọc; con chim đoạt nuốt liền hai khối với tốc độ khó tưởng tượng rồi đậu sang vai Tôn trưởng lão, mắt vẫn dán vào túi trữ vật của hắn."},{"chuong":"@c0467","importance":"normal","tieuDe":"Gặp lại Lăng Thiên Hầu","text":"Tại lễ đại thọ vạn năm, Vương Lâm lặng nghe trọn ba ngày giảng đạo của Thiên Vận Tử và dần có lĩnh ngộ. Hắn chứng kiến Tiên thuật lần đầu trong đời khi Thiên Vận Tử thi triển trung phẩm Dẫn Tiên thuật, đồng thời nhận ra xà hình bảo kiếm dưới chân Lăng Thiên Hầu chính là Vũ chi đệ nhị kiếm từng thấy ở Tiên giới."},{"bridge":true,"khoang":"@c0467","text":"Khi thiên uy vô thanh của Dẫn Tiên thuật giáng xuống khiến tiên lực trong người hỗn loạn, Vương Lâm vận tam chuyển kim tiên lực từ cánh tay trái lưu chuyển toàn thân, khống chế không để nó hòa lẫn tiên lực vốn có, nhờ đó dần đứng vững lại."},{"chuong":"@c0468","importance":"normal","tieuDe":"Trụ vững khảo nghiệm áp lực Tử hệ","text":"Trong khảo nghiệm áp lực phân loại đệ tử tại đại thọ Thiên Vận Tử, Vương Lâm cùng Tứ sư tỷ là hai người duy nhất của Tử hệ trụ vững; hắn vận kim tiên lực ba vòng khôi phục sắc mặt, được Tứ sư tỷ liếc nhìn đầy thâm ý."},{"chuong":"@c0468","importance":"normal","tieuDe":"Giấu Tôn Hồn Phiên trước Kỳ Lân thú","text":"Khi Lăng Thiên Hầu triệu Kỳ Lân thú từ mi tâm, Tôn Hồn Phiên trong nguyên thần Vương Lâm phát tiếng gầm rít cộng hưởng khiến Kỳ Lân thú dừng lại quét mắt tìm kiếm; hắn lập tức vận Tôn Hồn Phiên che giấu toàn bộ tàn hồn, tránh bị phát hiện."},{"bridge":true,"khoang":"@c0468","text":"Quan sát Dẫn Tiên thuật của Thiên Vận Tử, Vương Lâm lĩnh hội sâu thêm rằng Tiên thuật do hư ảo tạo thành nhưng tồn tại vĩnh hằng, chỉ cần có khẩu quyết, phương pháp và tư cách là thi triển được ở bất kỳ đâu."},{"chuong":"@c0469","importance":"normal","tieuDe":"Tranh phong hiệu, đấu Triệu Hân Mộng","text":"Vương Lâm (Lão Thất) ban đầu định bỏ cuộc tranh phong hiệu Thiên Vận Thất tử vì linh cảm điều bất thường nơi Vận Đường, nhưng bị Thiên Vận Tử đích thân khuyên giải — người thứ hai sau Tôn Vân được sư phụ khuyên — nên đổi ý quyết tranh đoạt. Hắn khai chiến với Tứ sư tỷ Triệu Hân Mộng: nàng dùng Tử Ma thủ mô phỏng từ Hoá Ma chỉ của hắn, Vương Lâm đáp trả bằng Hoá Ma chỉ khiến ma khí ngập trời gào rít bao phủ bốn phía."},{"chuong":"@c0470","importance":"normal","tieuDe":"Phá bẫy hấp thu ma lực","text":"Vương Lâm thi triển Hoá Ma chỉ đối đầu Tử Ma thủ của Triệu Hân Mộng; nàng dùng hạt châu hô ‘Thu’ hút ma lực để cướp đoạt, nhưng Vương Lâm vạch trần đây chỉ là tia hư ảo do tiên lực chuyển hoá, tâm niệm khẽ động liền khiến nó tự sụp. Hắn từ chối nhường, viện lời hứa với Tư Đồ Nam không truyền ba thức sát chiêu ra ngoài."},{"chuong":"@c0470","importance":"normal","tieuDe":"Ngũ chuyển luyện tiên trong vài ngày","text":"Đối đáp Cửu chuyển luyện tiên quyết của Triệu Hân Mộng, Vương Lâm dù mới nhận công pháp vài ngày đã lập tức tu ra tam chuyển, tứ chuyển rồi ngũ chuyển kim tiên lực, chịu đau đớn cực lớn mà thần sắc thong dong, lại rút chiến phủ Cự Ma Tộc và Xạ Thần xa uy hiếp. Triệu Hân Mộng thừa nhận đã xem thường hắn rồi bỏ cuộc."},{"chuong":"@c0470","importance":"normal","tieuDe":"Giao chiến Trần Đào","text":"Trần Đào (Vấn Đỉnh) đánh ấn quyết chấn nhiếp nhưng chỉ đẩy lùi Vương Lâm hơn mười trượng thay vì trăm trượng như dự tính. Vương Lâm phóng ngũ chuyển kim tiên lực, bị Trần Đào đẩy lên cửu chuyển phản công; hắn dùng chiến phủ chém rồi thi Đại Na Di khiến cơn lốc cửu chuyển biến mất ngay trước mặt, sau đó triệu Hồn thú từ Xạ Thần xa khiến cả trường chấn động."},{"chuong":"@c0471","importance":"normal","tieuDe":"Lần đầu mở phong ấn Xạ Thần xa","text":"Trong trận đấu với Trần Đào tại lễ chúc thọ, Vương Lâm lần đầu kết ấn mở đạo phong ấn thứ nhất của Xạ Thần xa, khiến Hồn thú bạo tăng từ mười trượng lên hơn trăm trượng và đoạt được thiên uy thần thông mới."},{"chuong":"@c0471","importance":"normal","tieuDe":"Thi triển Hoàng tuyền chỉ","text":"Biết mình không phải đối thủ Vấn Đỉnh kỳ nhưng không từ bỏ, Vương Lâm cưỡng dùng sát chiêu cuối Hoàng tuyền chỉ của Tư Đồ Nam: tiêu tan sinh mạng, hiện Sinh tử luân hồi ý cảnh, khiến toàn trường sững sờ và các đại nhân vật như Thiên Vận Tử, Lăng Thiên Hầu chú ý."},{"chuong":"@c0472","importance":"normal","tieuDe":"Bại trận trước Trần Đào","text":"Phóng hai đạo Hoàng tuyền chỉ (một từ ngón út, một từ Luân hồi ý cảnh hóa thành) công kích Trần Đào gây nổ kinh thiên động địa, nhưng Trần Đào nhờ kỳ ngộ đạt Vấn Đỉnh trung kỳ nên đỡ được. Vương Lâm bị đẩy lùi hơn trăm trượng, phun một ngụm tiên huyết, tiên lực hỗn loạn nên tuyên bố bỏ cuộc; Trần Đào do đó đoạt phong hiệu Thiên Vận Thất tử của Tử hệ."},{"chuong":"@c0472","importance":"major","tieuDe":"Thành đệ tử chân chính Thiên Vận Tử","text":"Được Thiên Vận Tử gọi theo về Tổng tông tế bái Tổ linh, hứa truyền Cấm pháp thần thông và ban pháp bảo bản mạng, chính thức trở thành đệ tử chân chính. Giải đúng câu đố ba ngọn núi (nhìn ra hai sườn núi hai bên là giả do Chân huyễn pháp) nên được đặc ân tự chọn Cấm pháp thần thông thay vì bị chỉ định."},{"chuong":"@c0472","importance":"normal","tieuDe":"Vượt kỷ lục Toái Tiên chi địa","text":"Leo ngọn núi trắng phủ Cửu U chi hàn không dùng thuấn di, đạp băng đối mặt khảo nghiệm Toái Tiên chi địa. Đi được hai mươi mốt bước (vượt xa cực hạn Anh Biến trung kỳ mà Thiên Vận Tử dự đoán), rồi bước thứ hai mươi hai và thêm năm bước nữa, tiến gần kỷ lục hai mươi sáu bước của Tôn Vân."},{"chuong":"@c0473","importance":"major","tieuDe":"Bái sư nhập Thiên Vận Tông","text":"Vương Lâm chính thức quỳ bái Thiên Vận Tử, được thu làm đệ tử thứ bảy của Tử hệ dưới ánh sáng chín màu. Hắn thề chỉ cần sư phụ và Thiên Vận Tông không phụ hắn thì hắn sẽ không phụ lại; một tòa Tế đàn bảy màu hạ xuống, lệnh bài khắc danh tự cháy hóa lửa tím bay về tế đàn. Sau đó được Thiên Vận Tử hỏi muốn chọn loại Cấm pháp thần thông nào."},{"chuong":"@c0474","importance":"normal","tieuDe":"Chọn Cấm pháp thần thông phòng thân","text":"Vương Lâm điểm lại sở học (Cấm pháp Đại Na Di, Ngân Long la bàn) và nhận ra chúng chỉ hữu dụng với tu sĩ Vấn Đỉnh, không đủ đối phó kẻ vượt Vấn Đỉnh hay đạt cảnh giới Toái Niết. Hắn xin Thiên Vận Tử truyền ‘Sinh tồn pháp thuật’ nhưng bị từ chối, nên được sư phụ điểm ánh sáng bảy màu đưa vào thế giới bảy màu để tự chọn theo cơ duyên."},{"chuong":"@c0474","importance":"normal","tieuDe":"Từ chối Sát Lục Tiên quyết","text":"Trong thế giới bảy màu, Vương Lâm phát hiện một Thiên Vận Tử áo xám dị thường (người ‘hơn một người’ — thứ 3601), mọi công kích đều xuyên qua như ảo ảnh. Qua sáu lần chạm mặt, người áo xám tiết lộ Thiên Vận Tử đưa hắn tới chính vì Sát Lục Tiên quyết, ra điều kiện ‘xuất thủ không lưu người sống’. Vương Lâm thi triển Sinh tử Luân hồi ý cảnh rồi trầm mặc từ chối: ‘Ta không học!’, sau đó nhận lấy ngọc giản người áo xám để lại."},{"chuong":"@c0476","importance":"normal","tieuDe":"Rời Thiên Vận Tinh tới Địa Tinh","text":"Vương Lâm dùng Truyền tống trận khổng lồ của Huyền Uyên Phái do Triệu Tứ kích hoạt, vượt liên tinh cầu rời Thiên Vận Tinh để tới Địa Tinh, mang theo lệnh bài khắc chữ “Thất” biểu thị thân phận Tử hệ Lão Thất."},{"chuong":"@c0476","importance":"normal","tieuDe":"Nhậm chức sứ giả Linh Nhạc quốc","text":"Tới Huyền Uyên Phái được Thiếu Tông Hứa Vân Sơn nghênh đón và kết giao; sau hai ngày, hắn được đưa tới Ngũ cấp tu chân quốc Linh Nhạc quốc để nhận chức sứ giả, ngầm tìm chỗ tĩnh tu tránh cạnh tranh ở Thiên Vận Tông."},{"bridge":true,"khoang":"@c0476–@c0476","text":"Trong hoa viên, Vương Lâm ngẫm về việc đề cao tu vi để đối phó mối uy hiếp Thác Lâm, nghiền ngẫm Sát lục tiên quyết, Sinh chi lạc ấn hộ thể và việc Thiên nghịch châu còn thiếu kim thuộc tính, nhớ tới Chu Tước Tinh xa xôi."},{"chuong":"@c0477","importance":"normal","tieuDe":"Nhậm Sứ giả Huyền Uyên Phái","text":"Vương Lâm chính thức nhậm chức Sứ giả của Huyền Uyên Phái tại Linh Nhạc quốc, được hơn trăm tu sĩ cung kính đón tiếp. Hứa Vân Sơn cáo từ rời đi, để mình hắn ở lại tọa trấn Thông Thiên tháp."},{"bridge":true,"khoang":"@c0477","text":"Hắn tuyên bố bế quan, cấm mọi người bước vào phạm vi ngàn dặm, dùng Cấm Phiên phóng hắc khí tạo màn sương đen và thả Chủ hồn từ Tôn Hồn Phiên ra phòng bị, rồi nghiên cứu Sát Lục Tiên quyết suốt hơn một tháng nhưng không tìm được điểm khởi đầu."},{"chuong":"@c0477","importance":"normal","tieuDe":"Áp chế Xạ Thần xa cắn trả","text":"Xạ Thần xa lần đầu cắn trả kể từ khi giải khai đạo phong ấn đầu tiên. Vương Lâm đã chuẩn bị trước, đại chiến với Khuất thú bên trong mấy ngày, dùng bí pháp áp chế khiến lần cắn trả thất bại."},{"chuong":"@c0477","importance":"normal","tieuDe":"Thu cấm chế, quyết đi Đông Hải","text":"Vương Lâm ngộ ra Sát Lục Tiên quyết phải cảm ngộ từ giết chóc thật, bèn thu hết màn sương đen ngàn dặm ngưng tụ thành khối cầu điện quang đen hóa Cấm Phiên tím đen, thu Chủ hồn vào Tôn Hồn Phiên tế luyện. Nhớ lời sư phụ dặn đến Đông Hải trong ba tháng (còn hơn một tháng), hắn lên đường, trước hết tới Ngũ Linh Sơn gặp Thiên Thai lão nhân."},{"chuong":"@c0478","importance":"normal","tieuDe":"Chọn Địa Ma Bắc Giới tu Sát Lục Tiên quyết","text":"Vương Lâm hỏi Thiên Thai lão nhân về nơi yêu thú tụ tập, nhận ngọc giản ghi ba chỗ rồi thuấn di tới Cực Bắc Địa Tinh, bước thẳng qua tấm bia Địa Ma Bắc Giới vào làn sương mù để tu luyện Sát Lục Tiên quyết — công pháp phải ở trong giết chóc mới lĩnh ngộ huyền diệu."},{"bridge":true,"khoang":"@c0478","text":"Hắn để tâm tới Đại La Kiếm Tông nhằm tìm tung tích Chu Dật tiền bối, đồng thời tò mò về Diệu Kim quả mà nhóm kiếm tu tranh chấp."},{"chuong":"@c0479","importance":"normal","tieuDe":"Nuôi Văn thú bằng yêu thú Hóa Thần","text":"Phi hành trong Tùng Mãng Sơn mạch tu luyện Sát Lục Tiên quyết, Vương Lâm giết tiểu thú sương đen và Bôn Ngưu thú (tương đương Hóa Thần kỳ), thu bụi khí nghi là sinh lực và thả Văn thú hấp thu nội đan, huyết nhục con mồi để thúc nó lớn lên."},{"chuong":"@c0479","importance":"normal","tieuDe":"Lần theo Đại La Kiếm Tông tìm Diệu Kim quả","text":"Vương Lâm dùng thần thức theo dõi đoàn Đại La Kiếm Tông, dự định dùng hai lão Anh Biến sơ kỳ làm thí luyện giả cho Sát Lục Tiên quyết, rồi cưỡi Văn thú bay nhanh về phía Nam nơi có Diệu Kim quả."},{"chuong":"@c0480","importance":"normal","tieuDe":"Bám theo đoàn Đại La Kiếm Tông","text":"Ngồi trên Văn thú vô thanh vô tức, Vương Lâm âm thầm đi theo đoàn Đại La Kiếm Tông tiến vào Địa Ma Bắc Giới tìm Diệu Kim quả. Dựa vào ký ức Cổ Thần Đồ Ti, hắn nhận ra Diệu Kim quả thực chất là kim linh căn mà các tu sĩ kiếm tông không biết cách dùng đúng — nuốt vào khiến thân thể cứng rắn, là thuốc bổ hi���m có với Cổ Thần thuở nhỏ. Hắn nhắm đoạt vật này cho Văn thú đang loé bạch mang khát vọng, vỗ đầu nó gật đầu cho phép."},{"chuong":"@c0483","importance":"normal","tieuDe":"Giết Thạch Phương đoạt xá","text":"Tại sơn cốc, Vương Lâm phá Huyết Thủ ấn, diệt Thiên Quỷ đầu rồi dùng kính tản tia sáng phát Tứ chuyển hàm tiên lực vỗ tan kiếm quang của Thạch Phương. Tiên ảnh đánh trọng thương nguyên thần ly thể, Văn thú nuốt sạch thân xác chỉ còn hài cốt; dù Thạch Phương đoạt xá Quách Tà Dật siêu tốc rồi cầu xin hiến ngọc giản, Vương Lâm vẫn phóng khí xám khiến hắn nổ tung."},{"chuong":"@c0483","importance":"minor","tieuDe":"Hái Diệu Kim quả","text":"Vương Lâm tới mảng hoa vàng phía Tây sơn cốc hái một Diệu Kim quả, định dùng tăng kim thuộc tính cho Nghịch Thiên châu (sau trận Chu Tước mộ vẫn thiếu gần một nửa), nếu không thì cho Văn thú ăn; chưa l��p tức tra hỏi Trưởng lão Đại La Kiếm Tông đang bị giam."},{"chuong":"@c0484","importance":"normal","tieuDe":"Luyện thành bốn kim linh căn","text":"Hiểu ra Diệu Kim quả không trực tiếp làm viên mãn kim thuộc tính của Nghịch Thiên châu, Vương Lâm dùng phương pháp điều hoà thừa kế trong ký ức Đồ Ti: bố trí ngọc giản khắc văn, kết thủ ấn cổ quái và thốt Chú ngôn ép hoa, quả, cành cây héo rũ. Quá trình khoảng nửa nén hương, hắn bới đất thu được bốn kim linh căn cỡ ngón tay cái, kỳ dị giống nhân sâm."},{"chuong":"@c0484","importance":"normal","tieuDe":"Phân chia kim linh căn","text":"Hắn ném một kim linh căn cho Văn thú khiến nó bắt đầu biến hoá, kim quang bọc thành lồng vàng; một rễ cho Lôi Oa; một rễ cuối tặng Thiên Cầm coi như đền cơ duyên đã chiếm. Thân cây hắn thu lại lưu cho bổn tôn."},{"bridge":true,"khoang":"@c0484","text":"Hoá khói rời sơn cốc, nhoáng qua dãy núi phóng vào chỗ sâu Địa Ma Bắc giới."},{"chuong":"@c0485","importance":"normal","tieuDe":"Tra Hỏi Bí Mật Đông Hải","text":"Vương Lâm khống chế lão già thấp người của Đại La Kiếm Tông bằng phi kiếm cực cứng và thanh loan đao quỷ dị, ép lão khai bí mật về Kiếm Tôn từ tiên giới trở về cùng Đông Hải Yêu Linh chi môn — ba đại cấm địa, huyết tinh thí luyện, phần thưởng Yêu Linh quán đính. Khai xong, hắn để loan đao xuyên đầu giết lão rồi rời đi; khi lão dùng Tam phân thần thức thuật tái sinh, khí xám truy sát của hắn quay lại hút sạch sức sống lão."},{"chuong":"@c0485","importance":"normal","tieuDe":"Sát Lục Tiên Quyết Ba Phân","text":"Ẩn trong Địa Ma Bắc giới hai mươi ngày tu Sát lục tiên quyết, Vương Lâm chuyển hoá sinh lực thành Sinh ấn, lần này ngưng kết được ba phân — ba phù văn xám bao phủ toàn thân khiến thân thể cứng hoá, kiếm chỉ miết qua không xuyên thấu. Còn sáu ngày là hết hạn ba tháng, hắn ra khỏi Địa Ma Bắc giới, ánh mắt quyết đoán hướng về Đông Hải, định đi cứu Chu Dật và tìm kim thuộc tính giúp Nghịch Thiên châu viên mãn để Lý Mộ Uyển thức tỉnh."},{"bridge":true,"khoang":"@c0487","text":"Được Thiên Vận Tử cử đi Đông Hải Yêu Linh, hóa đạo cầu vồng tử quang tới hội hợp với Tôn Vân Sơn rồi cùng vào trận pháp tinh không của Huyền Uyên phái để di chuyển tới cửa Đông Hải."},{"chuong":"@c0488","importance":"normal","tieuDe":"Bái kiến sư tôn trước cửa Đông Hải","text":"Vương Lâm hóa thân ảnh tử sắc phóng tới cửa Đông Hải Yêu Linh, tách khỏi Tôn Vân Sơn rồi cung kính tham kiến sư tôn Thiên Vận Tử. Hắn được tu sĩ nhận ra qua áo tử sắc và tử sắc lệnh bài là Tử Hệ Lão Thất Thiên Vận Tông, đứng vào hàng cùng chín đồng môn, được Thiên Vận Tử nhìn đầy thâm ý và nhắc có thể lấy được bảo vật."},{"bridge":true,"khoang":"@c0488–@c0488","text":"Sự xuất hiện của hắn thu hút chú ý của Lăng Thiên Hậu, Tham Lang, Diêu Tích Tuyết cùng nhiều lão quái; thủy triều Đông Hải năm nghìn năm một lần bắt đầu khởi động."},{"chuong":"@c0489","importance":"normal","tieuDe":"Chứng kiến thủy triều Đông Hải Yêu Linh","text":"Lần đầu đặt chân tới cửa Đông Hải Yêu Linh, Vương Lâm chứng kiến hiện tượng thủy triều năm nghìn năm một lần: vật trôi nổi xoay tròn ngưng tụ thành cột thanh khí cao ngàn trượng rồi nổ tan phát hồng quang. Đạo tâm hắn kiên định, không bị thần thông xoay tròn lôi cuốn. Khi cổ uy áp nồng hơn thiên uy gấp bội đè xuống như Thập Vạn Đại Sơn khiến thân thể rắc rắc sắp vỡ, hắn dùng đạo khí xám lóe trên mi tâm hóa thành ký hiệu bao trùm toàn thân, gắng chống đỡ tới cực hạn."},{"chuong":"@c0490","importance":"normal","tieuDe":"Phá hồng quang nhìn thấy lệnh bài","text":"Khi cửa Đông Hải Yêu Linh bên ngoài Thiên Vận Tinh mở ra, hồng quang nghìn năm điên cuồng rút về như thủy triều, cuốn theo vô số pháp bảo, linh thạch, yêu thú vô chủ. Nhờ ký ức Cổ Thần Đồ Ti, Vương Lâm nhận ra nhiều vật luyện khí quý cùng một thanh đại kiếm rỉ sét hình cánh cửa trong hồng quang. Trước con sóng cuối ngăn cản thần thức, hắn vận ba đạo ấn ký khí xám trên mi tâm thành thần thông ánh mắt, chịu đau đớn chảy máu mắt để xuyên thủng tầng tầng hồng quang, nhìn rõ một khối lệnh bài kim quang khắc ký hiệu khiến mọi cao thủ đại biến sắc."},{"chuong":"@c0491","importance":"normal","tieuDe":"Tiến nhập thế giới Đông Hải yêu linh","text":"Cố ý chậm chân vào cánh cửa Đông Hải yêu linh sau cùng, bị một lực kỳ dị đẩy tản khỏi chín đồng môn, một mình rơi xuống hoang nguyên giữa thế giới hỗn độn tự hình thành bên trong."},{"chuong":"@c0491","importance":"normal","tieuDe":"Lập kế hoạch năm trăm năm","text":"Định ở lại năm trăm năm để tu Sát lục tiên quyết tới đại thành (ngưng kết lạc ấn sinh mệnh chống Thác Sâm), tìm cứu Chu Dật nơi phong ấn của Lăng Thiên Hậu, và truy tìm thanh đại kiếm Cự Phú để học kiếm kỹ kiếm hồn, tất cả nhằm đề phòng Thác Sâm thoát khốn truy sát."},{"chuong":"@c0492","importance":"normal","tieuDe":"Phát hiện sơn cốc trận pháp thượng cổ","text":"Sau khi bay mười ngày qua bình nguyên hoang vu, Vương Lâm phát hiện vùng núi non trùng điệp, chứng kiến một người nửa xích lõa không có linh lực nhưng linh tính kinh người săn giết dã thú. Theo người này tới một sơn cốc, hắn nhận ra bên ngoài cốc có trận pháp ẩn giấu khí tức sinh mạng do tu sĩ thượng cổ bố trí, thủ pháp khác hẳn liên minh tu chân, trong thời gian ngắn không thể phá giải."},{"bridge":true,"khoang":"@c0492","text":"Hắn trầm tư về khối lệnh bài bí ẩn từng khiến Thiên Vận Tử và Lăng Thiên Hậu biến sắc, định mượn năm trăm năm ẩn náu ở tinh cầu để tăng nhanh tu vi và tránh Thác Sâm. Khi thử trận pháp thì bị luồng khí xanh thôn phệ linh quang phản kích; cuối cùng hắn làm tan trường côn, dùng lực vô hình giam bốn người trong cốc để tra hỏi, rồi hai người nữa từ trong cốc đi ra."},{"chuong":"@c0493","importance":"normal","tieuDe":"Phá trận sơn cốc bộ tộc xích lõa","text":"Vương Lâm quan sát thượng cổ trận pháp ngoài sơn cốc bộ tộc thân trâu mình người, bắt giữ rồi thả tộc nhân, đối thoại với trưởng lão Âu Dương Hoa và được chỉ điểm về Cổ yêu thành. Sau đó hắn nhận ra Âu Dương Hoa trước mặt chỉ là thế thân hư ảo, dùng Cấm Phiên phóng chín trăm chín mươi chín đạo cấm khí công phá trận, rồi triển khai Cấm pháp chi mâu nghênh chiến thanh ảnh xanh do trận tạo."},{"chuong":"@c0494","importance":"normal","tieuDe":"Phá trận thượng cổ sơn cốc","text":"Bị vây trong trận pháp thượng cổ của Âu Dương Hoa, Vương Lâm dùng trường mâu cấm khí câu giờ, vận thượng cổ cấm chế của cổ thần để tính toán rồi phóng ra tám mươi ba tổ hợp cấm chế đánh tan lồng thanh quang thôn phệ vạn vật, áp sát sơn cốc khiến Âu Dương Hoa hoảng sợ cầu tha."},{"chuong":"@c0495","importance":"normal","tieuDe":"Bức tranh Hoàng Long chấn động","text":"Vào sơn cốc tộc Âu Dương Hoa, khôi phục trận pháp cổ bảo vệ tộc nhân rồi tặng ba bình ngọc đan dược cố bổn bồi nguyên làm lời tạ lỗi. Tại nhà Âu Dương Hoa, hắn thấy bức tranh ố vàng vẽ Hoàng Long thượng tiên; nguyên thần chấn động, hồi tưởng quê nhà Chu Tước tinh và thời thiếu niên từ sơn thôn ra ngoài gia nhập Hằng Nhạc phái."},{"chuong":"@c0496","importance":"normal","tieuDe":"Hấp thu yêu lực ngọc yêu linh","text":"Tại sơn cốc bộ tộc Âu Dương Hoa, Vương Lâm dùng hơn mười bình ngọc đan dược đổi lấy ngọc yêu linh (kết tinh tiên lực) khảm trong vách đá xanh thẫm. Hắn chụp lấy tinh thạch trắng, hấp thu khí tức cực lạnh yêu dị: khí tức chạy theo các khớp xương chứ không qua kinh mạch, tụ tại đan điền hóa thành tinh thể cỡ hạt gạo xoay như tinh vân, toàn thân biến hóa rõ ràng."},{"bridge":true,"khoang":"@c0496–@c0496","text":"Trầm ngâm về bức tranh người giống Hoàng Long chân nhân của Hằng Nhạc phái, nghe Âu Dương Hoa giải thích về Thiên Yêu quận, đêm yêu linh và quy luật người bên ngoài; khi đi qua khu cư dân, xoa đầu một hài đồng và nhớ tới Đại Ngưu lúc nhỏ."},{"chuong":"@c0497","importance":"normal","tieuDe":"Đổi yêu lực kết tinh ở Hồ Lô Cốc","text":"Tại thung lũng Hồ Lô Cốc trên Thiên Vận Tinh, Vương Lâm hấp thu yêu lực hống khiến yêu khí trong người biến hóa thành đoàn yêu hỏa; hắn nhận định yêu lực kết tinh giống tiên lực nhưng quỷ dị, có thể dung hợp đẩy tu vi. Hắn phất tay áo cho Âu Dương Hoa hơn mười bình ngọc để đổi lấy yêu lực kết tinh duy nhất của thung lũng, rồi ngồi thiền nghiên cứu trong đan điền."},{"bridge":true,"khoang":"@c0497","text":"Vương Lâm tách một tia nguyên thần hóa thần thức phóng đi xa, thấy yêu linh Đông Hải tạo đạo khí tím khuếch tán hình tròn hủy diệt sinh khí, rồi phát hiện Hắc y nam tử đang hấp thu yêu lực và tuyên bố coi hắn là con mồi; hắn nhận ra đối thủ là tu sĩ Ứng Biến hậu kỳ đại viên mãn."},{"chuong":"@c0497","importance":"normal","tieuDe":"Hiện thân cứu Hồ Lô Cốc","text":"Khi trận pháp thung lũng bị sóng yêu khí công phá sắp vỡ và Hắc y nam tử hóa điện quang phi kiếm lao tới, Vương Lâm bước một bước hóa khói nhẹ xuất hiện ở cửa cốc bên cạnh Âu Dương Hoa; lúc này hắn vẫn để đối thủ lầm tưởng mình chỉ Ứng Biến trung kỳ."},{"chuong":"@c0498","importance":"normal","tieuDe":"Giao chiến La mỗ ngoài thung lũng yêu linh","text":"Tại Thiên Yêu quận, Vương Lâm gia cố trận pháp thung lũng giam yêu linh bằng Cấm Phiên rồi bước ra ngoài đối đầu hắc y nam tử La mỗ. Hắn diệt một đầu yêu linh thú, xuất kiếm tiên cùng loan đao làm rạn phi kiếm địch và đả thương ngực y. Khi La mỗ tung Kiếm toái cùng Địa diệt chi hỏa hóa sáu rồng lửa, Vương Lâm thi triển Sinh Chi Lạc Ấn chống đỡ, gây vụ nổ long trời rồi bước ra từ bóng tối suýt điểm trúng đối phương."},{"bridge":true,"khoang":"@c0499","text":"Giao chiến với Hắc y nam tử (La mỗ) trong vùng Yêu linh khí lãng: bị phối hợp kiếm vỡ hàn quang và hắc hỏa phá mất một tầng Sinh chi lạc ấn, đáp trả bằng Côn Cực Tiên đả thương nguyên thần đối phương; khi đối thủ phun độc khí rút lui, hắn niệm thần chú Phong gọi gió phá độc thoát ra rồi truy kích, quyết không tha."},{"chuong":"@c0500","importance":"normal","tieuDe":"Mở Xạ Thần Xa ép lui Hắc y nam tử","text":"Trong trận sinh tử với Hắc y nam tử (Anh Biến hậu kỳ đại viên mãn), Vương Lâm dùng chủ hồn — gồm tàn hồn kỳ lân — làm mồi nhử Quỷ ảnh, thừa cơ ném Khu Thú Quyển. Hắn thi triển Hóa ma chỉ và Sinh chi lạc ấn xuyên qua khói độc, rồi mở Xạ Thần Xa, dùng Cửu Tự Chân Ngôn khống chế Hồn thú nhằm thẳng đối thủ, buộc Hắc y nam tử bỏ thân xác cho nguyên thần chạy trốn."},{"chuong":"@c0501","importance":"normal","tieuDe":"Bắt sống nguyên thần La Vân","text":"Sau khi hồn thú thiêu hủy thân thể Hắc y nam tử, Vương Lâm lần đầu phối hợp ăn ý với hồn thú qua Xạ Thần Xa, dùng Côn Cực Tiên quấn bắt nguyên thần đối phương (Anh Biến hậu kỳ đại viên mãn) trước khi hắn kịp tự nổ, giam vào hồn phiên. Khi hồn thú phẫn nộ vì bị cướp mồi, Xạ Thần Xa hóa Khu Thú Quyển hút mạnh tiên lực, Vương Lâm phải dùng tiên ngọc chống đỡ."},{"chuong":"@c0501","importance":"normal","tieuDe":"Thi triển Sưu Hồn Thuật đoạt ký ức","text":"Vương Lâm lập cấm chế ngăn La Vân tự bạo, ép hắn lộ thân phận người Thiên Quỷ Đạo, rồi niệm Sưu Hồn rút kết tinh trong đan điền cùng toàn bộ ký ức của La Vân. Hắn dự định luyện nguyên thần đã suy yếu của La Vân thành một chủ hồn trong Tôn hồn phiên, và thấy trong ký ức có vài thuật ma cấm Thiên Quỷ Đạo đáng tu luyện."},{"chuong":"@c0502","importance":"normal","tieuDe":"Thấu hiểu cơ chế vùng đất yêu linh","text":"Qua ký ức La Vân, Vương Lâm nắm rõ vùng đất yêu linh chia mười quận, mỗi quận phong ấn một Cổ yêu chi linh; dung hợp được thì tu vi tăng vọt và có cơ hội vào cảnh thần chi thủy. Hắn định kế hoạch nhập Thiên Yêu quận để đạt chiến công, và phát hiện yêu tinh La Vân cộng yêu lực đã hấp thu vừa đủ ba giáp — hiểu vì sao La Vân muốn giết mình."},{"bridge":true,"khoang":"@c0502","text":"Hắn liên tưởng thần chi thủy với Thủy cảnh, nhớ lại tài liệu Cực Cảnh - Đạo cảnh - Thủy cảnh từng chiếm ở động tiên ngầm trong Tu Ma Hải, mơ tưởng kết hợp Cực cảnh và Thủy cảnh thành đại đạo luân hồi rồi tự kiềm chế."},{"bridge":true,"khoang":"@c0502","text":"Dịch chuyển tới bình nguyên có khe rãnh, hắn há mồm hút các chủ hồn âm hồn (gồm một đầu lân) dung nhập Tôn Hồn Phiên, rồi dùng thuật đám bụi khí hóa hàn quang truy diệt Thiên quỷ phản chủ của La Vân đang suy yếu trốn trong khe, phủ đầy tro bụi lên thân nó."},{"chuong":"@c0503","importance":"normal","tieuDe":"Thu Phục Thiên Quỷ","text":"Vương Lâm dụ Thiên quỷ ra khỏi khe rãnh, dùng Côn Cực Tiên chuyên đánh nguyên thần quất cho suy yếu. Theo trí nhớ La Vân, hắn biết Thiên quỷ sau phản bội cần bốn chín ngày tu dưỡng nên quyết bắt sống lúc nó yếu nhất. Khi Thiên quỷ phun Bản mạng chi hỏa định hủy roi, Côn Cực Tiên lóe một đạo kim quang chụp tắt lửa khiến Thiên quỷ suýt tiêu tan; hắn vội thu roi, dùng hồn phiên cuộn Thiên quỷ vào giữ lại."},{"bridge":true,"khoang":"@c0503","text":"Ba ngày sau hắn về sơn cốc tộc Âu Dương Hoa qua trận pháp đã dung hợp cấm phiên, vào cấm địa tọa định. Hắn tính ở lại giáo hóa cư dân, truyền thuật hồn phiên để gây dựng lực lượng riêng trước khi tới thành Cổ Yêu, nhắm khôi phục Tôn hồn phiên và đoạt Cổ yêu chi linh. Hắn lưu khẩu quyết Luyện Hồn, Trừu Phách cùng cách chế tác hồn phiên vào hai ngọc giản, cố ý cài một sơ hở trí mạng chỉ mình biết để có thể trực tiếp khống chế hồn phiên của đệ tử."},{"chuong":"@c0504","importance":"normal","tieuDe":"Truyền Luyện Hồn thuật cho cốc yêu linh","text":"Vương Lâm chế tác yêu giản chứa khẩu quyết luyện hồn, cưỡng ép song chỉ đả thông một kinh mạch giúp trưởng lão Âu Dương Hoa đột phá nhị tinh, rồi tuyên bố truyền thụ thuật luyện hồn cho toàn bộ cư dân sơn cốc — thứ cực hiếm nơi vùng đất yêu linh."},{"bridge":true,"khoang":"@c0504","text":"Suốt ba tháng hắn nghiên cứu yêu tinh, dung hợp hai khối thành ‘Ba giáp yêu tinh’ ẩn yêu lực vô biên; nuốt thử khiến thân hóa yêu dị (đồng tử dựng đứng) nhưng vận chuyển toàn bộ chỉ đạt Trúc Cơ kỳ vì lượng yêu lực chưa đủ, sau đó rút yêu lực về và trở lại trạng thái siêu phàm."},{"chuong":"@c0505","importance":"normal","tieuDe":"Cài sơ hở khống chế hồn thú","text":"Tại sơn cốc ở Thiên Vận Tinh, Vương Lâm chế hồn phiên thay thế từ cươn thụ chi mộc, da dã thú và thủ ấn để bù tài liệu thiếu khuyết, rồi cải biến Luyện Hồn Thuật cài backdoor khiến mọi hồn thú do người học thuật phong ấn đều bị hắn hoàn toàn điều khiển và chấn nhiếp."},{"chuong":"@c0505","importance":"normal","tieuDe":"Chấn nhiếp sư tử cánh dài phản phệ","text":"Khi hồn phách sư tử cánh dài quay đầu phản phệ Thập Tam, Vương Lâm chỉ một tiếng hừ “Nghiệt súc, ngươi dám!” đã khiến nó tan nát rồi nằm bẹp thuần phục; hắn lướt mấy trăm trượng hiện thân, khiến cả sơn cốc kinh hãi sùng kính."},{"bridge":true,"khoang":"@c0505–@c0505","text":"Vương Lâm coi trọng ngộ tính của Thập Tam, trao ngọc giản phương pháp chế hồn phiên mới, mặc Âu Dương Hoa định kế tấn công bộ tộc cách ngàn dặm v��i một câu “Tùy ngươi!”."},{"chuong":"@c0506","importance":"normal","tieuDe":"Lập kế Tán Hồn Dưỡng Phách","text":"Đóng vai ‘thượng tiên’ ẩn ở sơn cốc, Vương Lâm thao túng bộ lạc tu Luyện Hồn Thuật để gom hồn phách và yêu tinh. Hắn để tộc nhân phong ấn hồn phách vào Hồn Phiên, chỉ cần khởi ý là thu về — kế sách ‘tán hồn dưỡng phách’ nhằm hồi phục thập ức tôn Hồn Phiên."},{"bridge":true,"khoang":"@c0506–@c0506","text":"Thu phục con sư tử yêu thú làm chủ hồn cho Hồn Phiên của Thập Tam, cảnh cáo về rủi ro chủ hồn cắn trả; ban khẩu quyết Luyện Hồn Thuật theo công lao; nuốt nhị giáp yêu tinh Âu Dương Hoa dâng, dung hợp thành ngũ giáp yêu tinh trong đan điền."},{"chuong":"@c0507","importance":"normal","tieuDe":"Cứu Thập Tam, nhận Chiến thư","text":"Cứu Thập Tam khỏi yêu vật tơ hồng ký sinh, thu chủ hồn sư tử thành dấu ấn ngón tay; nhận ra việc lão áo trắng cướp hồn phiên và để lời nhắn là Chiến thư khiêu khích."},{"chuong":"@c0507","importance":"normal","tieuDe":"Nhổ đất phá trận Thiên Thủy","text":"Không phá nổi trận pháp viễn cổ mười dặm, dùng Khai Thiên phủ đào vòng quanh ven trận rồi nhổ cả mảnh đất mười dặm bay lên, mang về thung lũng luyện hóa bằng lửa sáu chủ hồn."},{"chuong":"@c0507","importance":"normal","tieuDe":"Giết lão áo trắng, lập bộ lạc Luyện Hồn","text":"Bóp cổ giết lão áo trắng, giam nguyên thần vào cờ Tôn Hồn; thu nạp toàn bộ dân Thiên Thủy, dung hợp ba trận thành trận hai mươi dặm, lập bộ lạc Luyện Hồn với hơn năm trăm nam đinh."},{"bridge":true,"khoang":"@c0507","text":"Hai năm ở Yêu Linh chi địa, hấp thu yêu lực từ vạn vật; bộ lạc Luyện Hồn mỗi tháng đánh chiếm bộ lạc nhỏ thu tù binh và yêu tinh."},{"chuong":"@c0508","importance":"normal","tieuDe":"Dựng bộ lạc Luyện Hồn hùng mạnh","text":"Mở rộng trận pháp lên bốn mươi dặm rồi dùng Tôn Hồn phiên tạo màn sương đen tế dưỡng hồn phách cho toàn tộc. Qua bốn năm, bộ lạc bành trướng tới gần ba trăm dặm với hơn năm nghìn nam đinh, thôn tính hầu hết bộ lạc trong mười vạn dặm; hắn ba lần ra tay diệt cao thủ tọa trấn rồi dừng tấn công, để mười vạn dặm thành thế chân vạc."},{"chuong":"@c0508","importance":"normal","tieuDe":"Cứu và thu phục Thập Tam","text":"Phát hiện Thập Tam tự nhiên luyện thể nhờ tích yêu lực trong xương cốt máu thịt; dùng Nguyên thần đọc trí nhớ, cảm động trước sự kiên trì hơn một năm của hắn nên ra tay cứu chữa và truyền Luyện Thể thuật của Cự Ma Tộc, hứa truyền khẩu quyết tầng một Cổ Thần nếu thành tựu."},{"chuong":"@c0508","importance":"normal","tieuDe":"Lên đường tới Cổ Yêu thành","text":"Luyện hai ngọc giản truyền âm làm đường lui (một mang theo, một để lại bộ lạc), dẫn Thập Tam và Hổ Bào rời bộ lạc, triệu Văn Thú làm tọa kỵ tiến về Cổ Yêu thành."},{"chuong":"@c0509","importance":"normal","tieuDe":"Tới Cổ Yêu thành giành chức vị","text":"Vương Lâm cưỡi Văn Thú vượt ba ngàn vạn dặm tới Cổ Yêu thành trong Thiên Yêu quận, mang theo Thập Tam và Hổ Bào. Hắn không thu liễm tiên lực, phá quy củ ở cửa Bắc, thị uy đám yêu binh bằng một quyền vào không trung khiến cả đám đông cứng rồi bị đẩy bay thổ huyết."},{"chuong":"@c0509","importance":"normal","tieuDe":"Đối đầu Tả dực Yêu tương","text":"Được Diêu Nghiêu lĩnh dẫn qua Truyền tống trận tới cung điện Yêu tương, Vương Lâm hóa giải đòn quyền thử của Tả dực Yêu tương bằng Tịch Diệt chỉ, từ chối chức Trưởng lão (chức trong không binh quyền) vì chỉ muốn chức ngoài có binh quyền. Khi bị ra đòn Thập Băng Chiến Ý, hắn đứng vững vận Sát lục tiên quyết kết hợp Hóa Ma chỉ nghịch hóa tiên lực thành ma khí mà tiếp."},{"chuong":"@c0510","importance":"normal","tieuDe":"Đối đầu Thập Băng Quyền Ý","text":"Tại Cổ Yêu thành, Vương Lâm giao chiến với Tả dực Yêu tương dưới thần công Thập Băng Quyền Ý gồm tám lần sụp đổ ngày càng mạnh. Hắn lần lượt dùng Hóa Ma chỉ chống lần thứ nhất, Sát lục tiên quyết tạo hai con rồng khí xám và lốc xoáy giết chóc cho lần thứ hai, rồi ngưng thành trường kiếm bảy thước khí xám chém vỡ lần thứ ba. Đến lần thứ tư mạnh gấp ngàn lần khiến trường kiếm vỡ nát, hắn không muốn lộ Hoàng Tuyền chỉ ở Yêu linh nguy cơ nên thu khí xám về, hiện hai đạo Sanh ấn phòng hộ trên mi tâm."},{"chuong":"@c0510","importance":"normal","tieuDe":"Cảm ngộ “niềm tin”","text":"Giữa lần sụp đổ thứ tư, Vương Lâm cảm nhận trong quyền ý ẩn chứa một niềm tin vô bờ bến, ánh mắt sáng ngời — loại cảm ngộ mấy trăm năm hiếm thấy, được ví như Chu Dật năm xưa lúc linh lực thiêu đốt ngộ ra, hé mở một bước lĩnh ngộ sắp tới."},{"chuong":"@c0511","importance":"major","tieuDe":"Ngộ Thần Thông Niềm Tin","text":"Dưới sức ép Thập Băng Quyền Ý của Tả dực Yêu tướng, Vương Lâm cảm nhận được ‘niềm tin tất thắng’ tích lũy từ tâm niệm vô số kẻ bại trận, ngộ ra bản chất quyền ý là Thần thông Niềm tin — đạo tâm thăng hoa, nguyên thần dung nhập đạo tâm, một niềm tin vững có thể đổi cả trời đất. Hắn nhận ra mấu chốt phá quyền ý không nằm ở tu vi mà ở niềm tin, từ đó dung niềm tin vào pháp thuật và lần đầu khơi dậy uy lực chân chính của Hóa Ma chỉ."},{"chuong":"@c0511","importance":"normal","tieuDe":"Một Chỉ Hóa Ma Chân Chính","text":"Vương Lâm chỉ thẳng lên trời, tiên lực vô thanh vô tức hóa thành ma khí khác hẳn lối nghịch chuyển; tóc dài quá gối, ma văn xanh bạc hiện ở mi tâm, ma khí lan trăm trượng hóa lửa xanh. Nửa Sanh ấn còn sót dung hợp tâm tính, sinh trưởng lại thành đầy đủ và bao trùm toàn thân. Hắn lĩnh ngộ thêm ‘Ma niệm’ — nghịch thiên tùy ý, phá hư đạo pháp, tự đi con đường riêng."},{"chuong":"@c0511","importance":"normal","tieuDe":"Phá Bảy Lần Sụp Đổ Quyền Ý","text":"Dùng Hóa Ma chỉ tạo biển lửa ma rồi hóa thân đen như bóng ma, Vương Lâm phá liên tiếp lần sụp đổ thứ năm và thứ sáu của Thập Băng Quyền Ý. Đến lần thứ bảy, hắn dồn niềm tin vô bờ vào hai chữ ‘Nhường đường’ khiến đợt sụp đổ tan biến, trở thành người đầu tiên cảm ngộ được dưới quyền ý này khiến Tả dực Yêu tướng lần đầu chấn động sau mấy ngàn năm."},{"chuong":"@c0512","importance":"normal","tieuDe":"Thống lĩnh Cổ Yêu thành","text":"Trong khảo nghiệm của Tả Dực Yêu tương, Vương Lâm nhập ma vượt qua bảy lần ‘sụp đổ’ của Thập Băng Quyền, đối kháng được lần thứ tám hóa dạng nước lũ; khi lần thứ chín im lìm xuất hiện, hắn quyết đoán lùi ra nghìn trượng để bảo toàn đạo tâm thay vì liều đánh. Được khen biết tiến biết lùi, hắn được phong Thống lĩnh Cổ Yêu thành nắm một vạn yêu binh, nhận một lệnh bài đồng."},{"chuong":"@c0512","importance":"normal","tieuDe":"Nén ma niệm thành phong ấn","text":"Vào trung tâm Cổ Yêu thành, hắn khoanh chân thổ nạp bốn ngày bốn đêm để khôi phục đạo tâm. Nhận ra đạo của mình không phải ma đạo, nếu để ma niệm tràn lan sẽ thành ma đầu mất thần trí, hắn không loại trừ mà nén ma niệm thành một điểm phong ấn trong cơ thể để giữ làm uy lực về sau. Hắn cũng làm rõ động cơ nhập ma là lĩnh ngộ Niềm tin và đoạt lấy chức vị bên ngoài."},{"bridge":true,"khoang":"@c0512","text":"Ngày thứ năm, Thập Tam và Hổ Bào hội hợp; ba người dạo Cổ Yêu thành. Vương Lâm ngờ cả vùng Yêu linh Đông Hải là động phủ một vị tiên đế, cư dân như gia súc trong ‘hàng rào tre’. Ở Trúc Thanh lâu, hắn uống rượu Trúc Thanh và hoài niệm loại rượu duy nhất từng uống thời phàm nhân ở Chu Tước Tinh do Đại Ngưu để lại."},{"chuong":"@c0513","importance":"normal","tieuDe":"Tâm ma trỗi dậy, ngộ ma niệm","text":"Uống rượu cùng Thập Tam và Hổ Bào, Vương Lâm chìm trong hồi ức hơn mười năm sống đời phàm nhân, nhớ Đại Ngưu và Chu Tước tinh — nơi hắn sinh ra. Niềm xúc động muốn trở về cố hương kéo dài bất thường khiến tâm ma bị áp chế lớn mạnh, chén rư��u vỡ cắm vào tay mà hắn không hay. Cuối cùng sáu đạo yêu lực mất khống chế chui vào mi tâm, ma niệm hút trọn khiến hắn bừng tỉnh khỏi hồi ức, ánh mắt trở lại trong sáng và kinh hãi nhận ra ma niệm lợi hại."},{"chuong":"@c0514","importance":"normal","tieuDe":"Thoát nhập ma nhờ nuốt yêu lực","text":"Bị ma niệm còn sót lôi ký ức Chu Tước tinh khiến đắm chìm tựa kiếp nạn; nhờ yêu lực sáu yêu binh tung hoành trong tửu lâu mà tìm được đường đột phá, dung hợp yêu lực vào tiên lực rồi cắn nuốt toàn bộ sáu luồng yêu lực, thần trí khôi phục."},{"chuong":"@c0514","importance":"normal","tieuDe":"Khu trừ sạch ma niệm","text":"Về khách sạn vận tiên lực dò khắp cơ thể suốt hai ngày, trục xuất hết ma niệm kết thành ba quả cầu đen, thu vào túi trữ vật để dùng làm thủ đoạn ảnh hưởng đạo pháp đối phương về sau."},{"bridge":true,"khoang":"@c0514–@c0514","text":"Rời tửu lâu, vung tay tạo gió hóa giải đòn trường kiếm yêu khí của nam tử âm trầm, để lại lời sẽ còn gặp lại."},{"chuong":"@c0514","importance":"normal","tieuDe":"Tới quân doanh, đối diện vạn yêu binh","text":"Theo quản sự tham quân qua Truyền Tống trận tới quân doanh; khi qua trận, truyền lực ôn hòa cứu Hổ Bào loạn yêu lực và chữa thương Thập Tam; đứng giữa hơn vạn yêu binh giáp đen dồn sát khí mà vẫn hết sức bình thản, đáp lại bằng ánh mắt lạnh lẽo."},{"chuong":"@c0515","importance":"normal","tieuDe":"Nhậm chức Thống lĩnh Hắc Giáp quân","text":"Vương Lâm từ pháp trận bước ra, chính thức nhậm chức tân thống lĩnh đạo quân yêu binh một vạn người Hắc Giáp quân ở Yêu Linh chi địa, với Tư Mã Viêm làm phó thống lĩnh. Khi hắn lệnh toàn quân lui ra, không một yêu binh nào động đậy cho tới khi Tư Mã Viêm lên tiếng, chúng cười khinh miệt sau lưng hắn. Vương Lâm không tranh chấp, cùng Thập Tam và Hổ Bào ngồi thổ nạp ngoài bãi đất trống suốt ba ngày, dùng thần thức quan sát toàn bộ vạn yêu binh và nắm rõ cơ cấu mười Thống đội."},{"bridge":true,"khoang":"@c0515","text":"Dựa vào ghi chép tổ tiên do La Vân đưa, Vương Lâm hiểu rõ quy tắc Cửu quận yêu binh cùng quy định mười người không nghe hiệu lệnh, quyết không vội ra tay mà ẩn nhẫn chờ thời cơ chỉnh đốn toàn quân như một thợ săn rình mồi."},{"chuong":"@c0516","importance":"normal","tieuDe":"Ép Phục Quân Doanh Thiên Yêu","text":"Sau nửa tháng ẩn nhẫn thổ nạp trong quân doanh Thiên Yêu quận, Vương Lâm ra tay bóp chết Tôn thống đội kẻ sỉ nhục mình là phế vật, phá tu vi và hút yêu khí từ thất khiếu xác chết. Hắn trảm nửa ngàn yêu binh phản kháng bằng kiếm tiên và loan đao, hấp thu yêu lực mấy trăm xác yêu binh tạo thành lốc yêu lực quanh thân. Khi chín ngàn yêu binh sắp trận vây khốn và Tư Mã Viêm phóng tới chất vấn, hắn vẫn ngồi khoanh chân, sai Thập Tam viện dẫn quân quy điều mười ba và điều hai để ép cả đám phải lùi, rồi nhắm mắt cho Thập Tam đếm ngược nhịp hô hấp."},{"chuong":"@c0517","importance":"normal","tieuDe":"Trình ngọc giản thoát truy cứu","text":"Khi quản sự tham quân và lão già áo vải bố tới thị uy, Vương Lâm chỉ một cái liếc mắt khiến phong ấn trong thân lão già suýt vỡ, rồi ném ngọc giản lưu hình ảnh chứng minh thống lĩnh giết người vô cớ. Quản sự bỏ ý truy cứu, sinh lòng kết giao và hứa bẩm báo Yêu Tương đại nhân theo hướng có lợi cho hắn."},{"chuong":"@c0517","importance":"normal","tieuDe":"Dựng lầu bùn đất lập uy","text":"Vương Lâm nhấn tay xuống đất, mặt đất rung chuyển phun lên một ngôi lầu hai tầng bằng bùn đất uy nghiêm, chấn nhiếp Tư Mã Viêm cùng chín ngàn yêu binh; uy danh trong Hắc Giáp quân ngày càng vượt Tư Mã Viêm."},{"chuong":"@c0518","importance":"normal","tieuDe":"Diêu Tích Tuyết cầu phá trận","text":"Trong lầu tối doanh trại Hắc Giáp quân, Vương Lâm bị Diêu Tích Tuyết xông vào nhờ trợ giúp bài trừ một trận pháp cấm chế mười tám phong ấn. Hắn ban đầu từ chối vì đang luyện hóa yêu lực và nghi nàng giấu giếm, nhưng dao động mạnh khi nàng hứa cung cấp đủ tiên ngọc để hắn đạt Vấn Đỉnh sơ kỳ. Hắn hoãn quyết định, hẹn sau bốn tháng cho câu trả lời."},{"bridge":true,"khoang":"@c0518","text":"Vương Lâm khổ tu trong Hắc Giáp quân, sau khi hấp thu yêu lực của năm trăm yêu binh và Tôn thống đội, yêu tinh trong cơ thể dung hợp đạt gần ngàn giáp nên tốc độ hút yêu khí tăng vọt; hắn dùng cơn gió giải trừ khống chế của Diêu Tích Tuyết trên Thập Tam và ra hiệu cho Thập Tam ngừng can dự."},{"chuong":"@c0519","importance":"normal","tieuDe":"Nhận Huyết Hồn đan, ước hẹn cổ sơn","text":"Trước lời nhờ bài trừ phong ấn của Diêu Tích Tuyết, Vương Lâm liên tục trì hoãn để nâng giá, cuối cùng nhận cây đèn Huyết Hồn đan cùng túi tiên ngọc đủ tu tới Anh Biến hậu kỳ, hẹn ba ngày sau canh ba lên cổ sơn cùng đi. Triệu hồn phách Tào Nhất Đấu giám định, hắn dần sinh nghi sự hào hiệp bất thường của đối phương cùng việc phương pháp phân biệt đan quá phổ biến, đoán ra đèn chỉ là phế đan độc do Huyết Tổ tung ra để giữ bảo vật thật."},{"chuong":"@c0520","importance":"normal","tieuDe":"Luận phá Huyết Hồn đan giả","text":"Từ thân phận thấp kém của Tào Nhất Đấu cùng thái độ hào hiệp của Diêu Tích Tuyết, Vương Lâm suy ra Huyết Hồn đan có thật-giả mà chỉ cha con Huyết Tổ mới phân biệt được, xác định viên đan nàng đưa là giả khiến người dùng tử vong. Hắn không vạch trần, lặng lẽ cất cây đèn vào túi trữ vật, giữ thế chủ động."},{"chuong":"@c0520","importance":"normal","tieuDe":"Luyện thành Tiên tinh","text":"Thu túi trữ vật Diêu Tích Tuyết với lượng tiên ngọc đủ tu tới Anh Biến hậu kỳ, hắn chìm xuống lòng đất ba ngày hấp thu điên cuồng. Dựa kết cấu yêu tinh học được ở bộ lạc Luyện Hồn, hắn cô đọng tiên lực thành ‘Tiên tinh’ — vật giống yêu tinh nhưng tỏa tiên lực, chứa lượng bằng một phần mười số tiên ngọc."},{"chuong":"@c0520","importance":"normal","tieuDe":"Truyền tống tới không gian Tôn Long","text":"Theo Diêu Tích Tuyết tới cổ sơn ngoài quân doanh ngàn dặm, hắn cùng nàng vượt truyền tống trận lúc trăng tím cực điểm, tới một không gian giống tinh không chỉ toàn ánh sáng. Hắn nhận ra con đường uốn lượn là thân giao long Tôn Long do thần thông bố trí, định moi bí mật từ Diêu Tích Tuyết thì trong đầu chợt nảy một ý nghĩ."},{"chuong":"@c0521","importance":"normal","tieuDe":"Đắc kim phù ấn sáu nét","text":"Tại Yêu Linh chi địa, Vương Lâm tĩnh tâm cảm ngộ ý cảnh Sinh Tử luân hồi (tay trái sinh, tay phải tử, ở giữa là thời gian bất biến) mà vẫn phân một niệm cảnh giác Diêu Tích Tuyết. Khi lực lượng thần bí từ trời giáng xuống, hắn dùng ấn ký Sát Lục chi đạo trên mi tâm cùng Sinh ấn, chọn nghe thanh âm thay vì nhìn ảnh, nắm bắt được tiếng tự xưng “Ta là Thanh Sương” và đắc kim phù ấn sáu nét — phức tạp, lấn át hẳn kim phù ba nét của Diêu Tích Tuyết."},{"bridge":true,"khoang":"@c0521","text":"Hai người bước lên con đường Tôn Long lắc lư trong hư không, đi cực nhanh ba ngày mới được một phần ba đường; tới bình đài phong ấn đầu tiên, Vương Lâm quan sát Diêu Tích Tuyết kích hoạt rồi phong ấn tượng đá, hiểu thêm thực lực của nàng."},{"chuong":"@c0522","importance":"normal","tieuDe":"Phá tượng đá ba mắt, thu ký tự vàng","text":"Trên con đường Tôn Long, Vương Lâm một mình ác chiến với pho tượng đá ba mắt ở bình đài thứ ba. Hắn nhận ra tượng vốn không tồn tại mà chỉ là một đống cấm chế chồng lớp, liền dùng Cấm phiên hấp thu nguồn lực lẫn rừng cột đá nhọn, rồi phun máu triệt tiêu ánh sáng vàng từ con mắt thứ ba và hét bốn tiếng phá vỡ tượng. Cuối cùng hắn vẽ ký tự hai nét bằng tiên lực, hút lấy ký tự vàng dung hợp vào nét vẽ của mình."},{"chuong":"@c0523","importance":"normal","tieuDe":"Ngộ kim phù ba nét phù văn","text":"Trên đài phong ấn đường Tôn Long, Vương Lâm vẽ thành công ba nét phù văn trong mắt; khi tiên lực dung nhập, ký hiệu phát kim quang xua tan hắc khí, ẩn chứa ấn ký thiên đạo. Hắn không vẽ ra nổi nét thứ tư vì thiếu căn cứ, nhưng kim phù đủ uy thế buộc Diêu Tích Tuyết phải dùng huyết ngọc trăm năm hóa giải."},{"chuong":"@c0523","importance":"normal","tieuDe":"Dùng kế tiên tinh phong ấn Diêu Tích Tuyết","text":"Tự xưng chỉ Anh Biến trung kỳ, Vương Lâm cố ý trúng đạo kiếm khí thứ nhất rồi chấn nát tiên tinh giấu trong người để bùng tiên lực chống đỡ, diễn cảnh trọng thương văng vào hư vô đánh lừa Diêu Tích Tuyết. Khi nàng kiệt lực vì hai đạo kiếm khí sau, hắn đội mũ rơm Vân Tước Tử che thần thức bay lên, điểm mi tâm phong ấn nàng giữa sự sống và cái chết, đoạt sạch bốn túi trữ vật rồi đề nghị giao dịch."},{"chuong":"@c0524","importance":"normal","tieuDe":"Phong Ấn Diêu Tích Tuyết","text":"Vương Lâm mặc cả giảm năm mươi năm trong tổng năm trăm năm phong ấn để đổi một câu trả lời, kèm lời cảnh báo nếu nàng nói dối thì về sau y sẽ không tới mở phong ấn. Diêu Tích Tuyết chỉ đáp muốn vào không có nguyên nhân, không chịu khai thật, nên y bấm pháp quyết bủa hàng loạt cấm chế thành vòng tròn tản hắc quang, ôm nàng ném vào rồi hô Phong, thu thành quả cầu nhốt nàng cất vào túi trữ vật."},{"chuong":"@c0524","importance":"normal","tieuDe":"Phá Bình Cảnh Thuật Cấm Chế","text":"Trong khu vườn trung tâm động phủ tiên cấm, Vương Lâm thôi diễn cấm chế suốt hai tháng, liên tục bắn tiên lực dẫn phát thử từ ba nghìn biến hóa lên hơn một vạn, mắt đỏ ngầu quên cả thân ở động phủ người khác. Nhờ sở học cấm chế thượng cổ thời Cổ Thần cộng sách cổ ở Chu Tước Tinh và mấy trăm năm dung hợp, khi chín trăm chín mươi chín tổ cấm chế trên cấm phiên hoàn thành, y vô tình phá vỡ bình cảnh, độ nắm chắc phá giải tăng từ bốn phần lên năm phần."},{"bridge":true,"khoang":"@c0524","text":"Qua vấn đáp với Động Phủ Chi Linh, Vương Lâm xác nhận tư cách tiến vào, đọc dấu vết ba tiền nhân (một người dùng Mai Hoa Thập Bát Cấm, hai kẻ cưỡng ép phá lấy đồ) rồi men theo đường sinh tiến vào khu vườn; đi nhiều vòng tới cách bàn đá ba bốn trượng thì trận pháp đột nhiên xoay ngược đổi phương hướng vận chuyển, nổ cơn lốc đen sấm chớp như Du Long."},{"chuong":"@c0525","importance":"major","tieuDe":"Đại tiến tu vi, sát ngưỡng Vấn Đỉnh","text":"Phá cấm chế tiến vào bàn đá, kích hoạt chùm sáng vạn trượng mở ra động phủ và nhận tư cách sở hữu cùng Động Phủ Lệnh. Vương Lâm đoạt được bầu rượu chứa mười giọt mỹ tửu, uống một giọt liền chìm vào giấc ngủ say suốt một năm. Trong giấc ngủ tiên lực điên cuồng tăng trưởng, Yêu Tinh trong đan điền vỡ tan hòa vào tiên lực; tỉnh dậy hắn kinh hoàng nhận ra tiên lực đã vượt xa Anh Biến hậu kỳ đại viên mãn, chỉ cần cảm ngộ thành công ý cảnh là đủ sức trùng kích Vấn Đỉnh."},{"bridge":true,"khoang":"@c0525–@c0525","text":"Hắn phong ấn cất kỹ bầu rượu cùng chín giọt còn lại, dự định khi ý cảnh đủ sẽ quay lại nơi thần bí này trùng kích Vấn Đỉnh, rồi dùng lệnh bài thủy tinh rời khỏi động phủ, xem đó là kho báu lớn sẽ trở lại khai thác."},{"chuong":"@c0526","importance":"normal","tieuDe":"Áp chế quân doanh Hắc Giáp quân","text":"Sau hơn một năm mất tích, Vương Lâm truyền tống về ngoài Cổ Yêu Thành rồi lao tới quân doanh Hắc Giáp quân. Hắn phá tan màn sương đen phòng hộ, chỉ một tiếng quát “Lui ra!” đã chấn nhiếp bốn thống lĩnh, rồi từng bước áp khí thế tới Đô Thống và thi triển Tịch Diệt Chỉ khiến thiên địa biến sắc."},{"bridge":true,"khoang":"@c0526","text":"Hắn mở ba trong bốn túi trữ vật cướp của Diêu Tích Tuyết, né cạm bẫy tử tuyến trên túi thứ tư, thu được tiên ngọc, Ngọc phù huyết sắc, Huyết Hồn Đan và la bàn huyết sắc; sau đó dùng ba ngày hiệu chỉnh la bàn cùng trận truyền tống, ba mươi ngày bố trí cấm chế biến trận thành cạm bẫy nuốt người ngoài vào khe không gian."},{"chuong":"@c0527","importance":"normal","tieuDe":"Báo thù tùy tùng, quyết xông cung","text":"Tại vùng đất Yêu Linh, Vương Lâm hạ gục Đô thống Tần Lâm bằng Tịch Diệt Chỉ, phá tan Huyền Vũ hóa thân của hắn. Hắn thi triển Sưu hồn thuật lên Tư Mã Viêm, đọc ra việc Hổ Bào bị phế tu vi ném vào hắc lao rồi mất tích, còn Thập Tam bị phế rồi bị Tần Lâm mang dâng cho Yêu Tướng. Phẫn nộ, hắn vận Sát Lục Tiên quyết giết Tư Mã Viêm, luyện hóa toàn thân công phu đối phương thành tia khí xám tụ ở tay phải. Hắn tha Tần Lâm vì có công có tội, rồi quyết tâm xông thẳng sáu cửa vào cung Yêu Tướng để cứu Thập Tam, dù điều đó tương đương chống lại cả Thiên Yêu Quận."},{"bridge":true,"khoang":"@c0527","text":"Tu vi Vương Lâm lúc này ở Anh Biến đại viên mãn, chênh lệch như hào sâu so với Anh Biến hậu kỳ, đã gần tiếp cận Vấn Đỉnh; tự nhận mình không hợp làm người tu đạo, chỉ cầu cả đời không thẹn lương tâm. Hắn hiện thân trước cửa thứ sáu, thả tiên kiếm chứa Hứa Lập Quốc bay ra chuẩn bị phá cửa."},{"chuong":"@c0528","importance":"normal","tieuDe":"Đơn thân phá cung Yêu Tướng","text":"Để cầu kiến Yêu Tướng, Vương Lâm một mình xông phá liên tiếp năm cánh cửa cung điện, lần lượt thi triển Tịch Diệt Chỉ, Sát Lục Tiên quyết, Hóa Ma Chỉ rồi Hoàng Tuyền Chỉ, giết vô số yêu binh và các cường giả trấn cửa. Cuối cùng hắn chạm trán người cao lớn dùng Thập Băng Quyền ý ở cửa thứ nhất, bị sóng chấn đẩy lùi hơn ba trượng mới đứng vững, còn Yêu Tướng thì suốt trận không hề ra mặt."},{"chuong":"@c0529","importance":"normal","tieuDe":"Tâm lý chiến hạ Yêu Tướng","text":"Đối đầu chiêu Yêu Hải Bách Lãng của Mạc Lệ Hải, Vương Lâm dùng Sát Lục chi khí cùng phù văn thần thông từ tượng đá thứ hai phản kích, rồi tạo một chưởng ấn hư ảo mang khí thế hủy thiên diệt địa. Chưởng ấn thực ra vô lực, nhưng buộc Mạc Lệ Hải không dám đánh cuộc mạng sống, phải nhận thua và thả người."},{"chuong":"@c0529","importance":"normal","tieuDe":"Nhận chức Tả dực đệ nhất phó tướng","text":"Mạc Lệ Hải mời Vương Lâm làm Tả dực đệ nhất phó tướng, hứa nếu trợ giúp tại so đấu Thiên Yêu thành ba tháng sau sẽ tiến cử lên Yêu Đế. Vương Lâm nhận lời, cứu được Thập Tam đang bị giam."},{"bridge":true,"khoang":"@c0529","text":"Tìm khắp Cổ Yêu thành và hắc lao nhưng không thấy dấu vết linh hồn Hổ Bào, Vương Lâm về bộ lạc Luyện Hồn được toàn tộc quỳ nghênh lão tổ; ba ngày sau đánh thức Thập Tam, nắm rõ mọi chuyện một năm qua."},{"bridge":true,"khoang":"@c0530–@c0530","text":"Trong Luyện Hồn cốc, Vương Lâm ghi nhớ trọn chín tầng Cự Linh Cửu Tu rồi xóa ba tầng sau, chỉ chép sáu tầng đầu vào ngọc giản xanh ném cho Thập Tam, dặn bảo vệ bộ tộc Luyện Hồn; sau đó ngồi một mình dưỡng hồn bằng hắc vụ do Tôn Hồn Phiên hóa thành, tính toán ba tháng sau phải lên đường tới kinh thành Thiên Yêu quận nên không thể mang theo Tôn Hồn Phiên."},{"chuong":"@c0531","importance":"normal","tieuDe":"Phong ấn Diêu Tích Tuyết","text":"Trong sơn cốc bộ lạc Luyện Hồn, cho Diêu Tích Tuyết cơ hội đổi câu trả lời lấy 50 năm giảm phong ấn; nàng từ chối, hắn phá nỗ lực tự sát bằng châm tinh khí giấu trong miệng và phá tâm cảnh hận nhập đạo, thu nàng thành quả cầu cấm chế cất vào túi trữ vật, tiếc rằng tu vi chưa tới Vấn Đỉnh nên chưa dùng được Sưu Hồn Thuật."},{"chuong":"@c0531","importance":"normal","tieuDe":"Bàn giao bộ lạc Luyện Hồn","text":"Hai tháng sau, trước hẹn ước với Yêu tướng, dặn Âu Dương Hoa phái mấy trăm tộc nhân tiềm nhập các bộ lạc lớn nhỏ dùng Hồn Phách Thủ Thần chống Linh Thang Loạn Thần rồi truyền Luyện Hồn Thuật, trao ngọc giản phần hai (thần thông rút phách) chỉ cho chi chính; thu Tôn Hồn Phiên vào nguyên thần, ném nhiều Hồn Phiên thường thay thế phủ bầu trời rồi rời đi, Âu Dương Hoa quỳ xưng lão tổ."},{"chuong":"@c0531","importance":"normal","tieuDe":"Lên đường tới kinh đô Thiên Yêu","text":"Bay tới Cổ Yêu thành gặp Yêu tướng Mạc Lực Hải, cùng qua ba truyền tống trận hướng kinh thành Thiên Yêu quận, ấp ủ ý định bắt một người Đại La Kiếm Tông trong mười kẻ tới đây để hỏi nơi Chu Dật bị phong ấn."},{"chuong":"@c0532","importance":"normal","tieuDe":"Nhập Đế Đô làm Vương tướng","text":"Theo Mạc Lệ Hải qua truyền tống trận thứ mười bốn vào Đế Đô của Thiên Yêu quận, được giới thiệu công khai là “Vương tướng” bạn tốt của Mạc Lệ Hải để nhập cuộc chiến Yêu tướng với thân phận trợ thủ. Mười chín kỵ binh giáp đen dưới trướng Mạc Lệ Hải đồng loạt tham kiến hắn."},{"chuong":"@c0532","importance":"minor","text":"Cùng Mạc Lệ Hải phóng ngựa về phủ ở Hồng thành; cuối đường nghe tiếng vó ngựa phía trước, hắn lóe mắt nhận ra một người quen."},{"chuong":"@c0533","importance":"normal","tieuDe":"Gặp lại Trần Đào sư huynh","text":"Trên quân đạo, Vương Lâm trợ thủ Mạc Lệ Hải một điểm xảo diệu hóa giải lực của Thạch Tiễn, rồi nhận ra tên gầy gò chính là Trần Đào — sư huynh đồng hệ bị Đại La Kiếm Tông đánh trọng thương tụt từ Vấn Đỉnh trung kỳ xuống Anh Biến viên mãn. Hắn ném tặng một túi Tuy Bình đan để biểu thị thiện chí, ngầm tính liên kết đồng môn đối phó Đại La Kiếm Tông."},{"bridge":true,"khoang":"@c0533","text":"Vào Mạc phủ ở phía nam sau hòn giả sơn, Vương Lâm tu luyện bốn ngày, thổ nạp Yêu lực chuyển hóa thành tiên lực bồi đắp Nguyên Thần, nhắm tới chức Yêu tướng tại kinh đô Thiên Yêu quận."},{"chuong":"@c0533","importance":"normal","tieuDe":"Sát Lục Chi Khí bộc phát","text":"Một lần ngồi luyện Sát Lục Tiên Quyết kéo dài bảy ngày, Sát Lục Chi Khí lan ra khiến hai quân sĩ hầu cận phát điên sát khí, mắt đỏ hồng, Yêu lực tiêu tán hơn nửa. Vương Lâm tỉnh lại sinh nghi: vì sao giết nhiều sinh linh mà Sát Lục Chi Khí lại sinh ra ít, hồi tưởng từng lần luyện hóa để tìm nguyên nhân."},{"bridge":true,"khoang":"@c0534","text":"Truy xét quy luật sinh ra Sát Lục Chi Khí mà không tìm ra điểm chung, hắn xác định Sát Lục Tiên Quyết là trọng điểm chuyến vào lãnh thổ Yêu linh và định thí nghiệm, thôi diễn hàng loạt để lĩnh ngộ phần huyền bí còn ẩn."},{"chuong":"@c0534","importance":"normal","tieuDe":"Lời hứa bên dòng Thiên Yêu","text":"Giấu tiên lực giả làm thư sinh dạo Hồng thành, giữa phố xá náo nhiệt vẫn thấy cô độc; nghe tiếng đàn bi thương từ một thuyền hoa gợi nhớ Uyển Nhi, hắn vuốt mi tâm như chạm vào nàng trong Hạt Châu Thiên Nghịch và thề sẽ gặp lại nàng."},{"chuong":"@c0535","importance":"normal","tieuDe":"Thương lượng vào Hồng lao","text":"Phát hiện trong Hồng lao của Hồng thành ẩn một cỗ yêu khí cường đại không kém Mạc Lệ Hải, Vương Lâm về Mạc phủ đề nghị được đưa vào lao ngục để giết chóc tu luyện. Hắn vung tay tạo năm đạo sát lục khí hóa thành năm con thương long, bị Mạc Lệ Hải đánh tan thì dung hợp lại len qua quyền phong chấn động yêu giáp đối phương, khiến hắn kinh ngạc và chốt cho vào bảy ngày."},{"chuong":"@c0535","importance":"normal","tieuDe":"Tẩy lễ tâm linh ba ngày","text":"Ba ngày liền Vương Lâm không tu luyện, không thổ nạp, chỉ ngồi bên sông uống rượu nghe tiếng đàn bi thương từ hoa thuyền để tẩy rửa tâm linh. Hắn độc thoại về đạo nghịch thiên cô độc, về việc trong lòng phải giữ một tia cảm động kẻo chỉ là thuận thiên, và về chí cầu thoát khỏi thân phận con kiến hôi; rồi đập vỡ vò rượu, phong ấn lại mọi cảm xúc, ánh mắt trở nên thâm thúy."},{"chuong":"@c0536","importance":"normal","tieuDe":"Nhập Hồng lao luyện sát lục","text":"Nửa đêm theo Mạc Lệ Hải phóng tới Hồng lao ở Hồng thành, được nam tử họ Hứa tiếp nhận và cho một tháng trong lồng giam dưới lòng đất để nghiên cứu sát lục khí. Sau năm ngày giết hơn nửa ngàn phạm nhân, hắn vẫn cách một tầng giấy mỏng, nhận ra mình còn thiếu sát tâm."},{"bridge":true,"khoang":"@c0536","text":"Hứa chỉ điểm về sát tâm, ra điều kiện sau này nhờ Vương Lâm dùng thần thông sát lục giết yêu tướng Thạch Tiễn, rồi tiết lộ bí mật tầng đáy Hồng lao."},{"chuong":"@c0536","importance":"normal","tieuDe":"Ngộ sát lục chi tâm trong biển máu","text":"Vương Lâm hòa vào chu kỳ chém giết của thế giới máu tầng đáy, mất ý thức thi triển Tịch Diệt Chỉ và Hóa Ma Chỉ, trở thành một trong hơn trăm người sống sót. Tỉnh lại hắn ngộ ra phải có sát lục chi tâm mới luyện hóa được sát lục khí, dần nối nó với ý cảnh sinh tử luân hồi của mình; huyết sát vụ trên thân dày tới hơn trăm trượng, cuối cùng chỉ còn hắn và một thanh niên tóc đen khi ngân long hiện ra hút mạnh."},{"chuong":"@c0537","importance":"major","tieuDe":"Đại ngộ Sát Lục tiên quyết","text":"Trong thế giới huyết sắc của Hồng Lao, Vương Lâm minh ngộ bản chất Sát Lục tiên quyết — lấy sát niệm đoạt tính mệnh người khác, luyện sinh cơ thành lạc ấn sinh mệnh, “từ tử tới sinh” hợp luân hồi chi đạo. Khí Sát Lục bạo phát khiến 792 rồi cuối cùng 3792 đạo sát lục khí xám vờn quanh hắn."},{"chuong":"@c0537","importance":"normal","tieuDe":"Đánh bại một trảo Đế Kiếm","text":"Vương Lâm dùng 3792 đạo sát lục khí như kiếm phá vỡ một trảo của ngân long Đế Kiếm — lần đầu con mồi đánh bại nó, khiến nó phẫn nộ phun kiếm quang. Hắn hóa điện quang dùng hơn ba nghìn lạc ấn làm phòng hộ, lao khỏi thế giới huyết sắc."},{"bridge":true,"khoang":"@c0537","text":"Nam tử họ Hứa dẫn Vương Lâm theo đường bí mật trốn khỏi Hồng Lao; hắn thu khí tức chạy bộ về Mạc phủ, được Mạc Lệ Hải đưa xuống động bế quan và ẩn trong Thiên Nghịch Châu suốt một tháng tránh Đế Kiếm lùng sục."},{"bridge":true,"khoang":"@c0537","text":"Mạc Lệ Hải định kế cho Vương Lâm ra trận thay tại đại hội Yêu Tướng đêm yêu linh; hắn ngồi bên sông nghe đàn nữ tử mắt đen, đối ẩm chào thanh niên áo xanh mang yêu lực, rồi cùng Mạc Lệ Hải viếng phủ phó soái Huyền Thành."},{"chuong":"@c0538","importance":"normal","tieuDe":"Trấn áp phó soái Huyền Thành","text":"Đóng vai tùy tùng của Mạc Lệ Hải bái kiến phó soái Huyền Thành. Khi bị thách thi triển thần thông mạnh nhất, Vương Lâm phóng hai nghìn đạo sát lục chi khí như rồng giận, xuyên thủng mãnh hổ yêu khí và màn yêu giáp bảy tấc, ép phó soái Vấn Đỉnh Sơ Kỳ liên tục lui và phải công nhận tư cách. Sau đó đồng ý trợ giúp Mạc Lệ Hải trong đại hội Yêu Tướng, cùng uống rượu chôn hơn năm trăm năm."},{"chuong":"@c0539","importance":"normal","tieuDe":"Giết sát thủ thám thính","text":"Giữa thời loạn trước cuộc đấu Yêu Tướng, Vương Lâm — phó tướng Mạc Lệ Hải — vẫn bình thản mỗi sáng ra bờ sông nghe đàn uống rượu, thu liễm tiên lực tránh Đế Kiếm dò tìm. Khi một sát thủ áo đen của Yêu Linh (Hóa Thần hậu kỳ) tới thử, hắn chỉ điểm ngón cái phải dùng Tịch Diệt Chỉ giết gọn một đòn, thu đám khí xám từ thất khiếu đối phương vào tay phải."},{"chuong":"@c0540","importance":"normal","tieuDe":"Áp chế sát thủ bằng Sát Lục Đạo","text":"Đang ngồi nghe đàn bên bờ sông thì bị nhóm sát thủ của “lão tổ” truy bắt. Vương Lâm dùng Tịch Diệt Nhất Chỉ giết chết sát thủ số bốn, rồi lần đầu quay đầu phóng Sát Lục Đạo từ ánh mắt màu hồng áp chế sát thủ số hai khiến hắn tâm thần suýt sụp đổ, cả nhóm áo đen khiếp sợ."},{"chuong":"@c0541","importance":"normal","tieuDe":"Đè bẹp Mạt Dương Kiếm Tiếu Thập Nhị Tử","text":"Tại Mạc phủ, Vương Lâm chạm trán Mạt Dương của Đại La Kiếm Tông tới đưa chiến thư. Hắn đi xuyên qua khí thế Mạt Dương, hóa giải sạch sáu mươi tư đạo kiếm khí bằng dấu ấn hộ thể, bắt sống cự kiếm tím bằng tay phải ngàn dấu ấn rồi dùng sát lục chi khí từ mắt đánh tan Tà Dương Chi Hồn, khiến Mạt Dương hộc máu vì mất kiếm bản mệnh."},{"chuong":"@c0541","importance":"normal","tieuDe":"Giả tha rồi âm thầm hạ sát Mạt Dương","text":"Vương Lâm ném trả cự kiếm, nói không muốn đối địch Đại La Kiếm Tông tại vùng đất Yêu Linh, nhờ chuyển lời tới Kiếm Tiếu Thập Nhị Tử. Khi Mạt Dương rời đi nghìn trượng thầm thề báo thù, đám khí xám ẩn trong cự kiếm chui vào đầu hắn, hóa ấn chú cắt đứt nguyên thần với thân thể, hấp thu tinh hoa huyết nhục và tiên lực khiến Mạt Dương hóa thây khô; Vương Lâm hiện thân đoạt thi thể rồi biến mất."},{"bridge":true,"khoang":"@c0541","text":"Trước đó Vương Lâm áp chế một yêu tu lớn tuổi đến tự bộc tiên yêu lực hòng thoát thân; hắn gài một tia khí xám âm thầm đuổi theo, rồi ngồi uống rượu bên bờ sông, nhận định đại hội Yêu Tướng là “trò chơi” Yêu Đế dựng để người ngoài thừa cơ chém giết."},{"chuong":"@c0542","importance":"normal","tieuDe":"Đoạt kiếm khí Lăng Thiên Hậu","text":"Luyện hóa thi thể và nguyên thần Mạt Dương trong Mạc phủ. Phát hiện ở mi tâm nguyên thần Mạt Dương có một đường chỉ lam — đạo kiếm khí bảo mệnh Lăng Thiên Hậu ban cho mười hai đệ tử Đại La Kiếm Tông năm xưa ở cửa Yêu Linh Đông Hải. Vương Lâm cắn răng nuốt thẳng sợi chỉ lam, nguyên thần suýt đứt liên hệ với thân thể, tĩnh tọa ba ngày rồi mở mắt lóe kiếm ảnh."},{"chuong":"@c0542","importance":"normal","tieuDe":"Xuất quan trước đại hội Yêu Tướng","text":"Bước ra khỏi phòng với khí thế như nhất đại tông sư rồi thu liễm như phàm nhân, khiến Mạc Lệ Hải khiếp sợ. Nghe tin Mạc Lệ Hải đã bại trận trước Mặc Phi; ngày mai là đại hội Yêu Tướng tranh đoạt."},{"chuong":"@c0543","importance":"normal","tieuDe":"Trợ giúp Mạc Lệ Hải tranh Phó Soái","text":"Tại trận chiến Yêu Tướng ở Đế Đô, Vương Lâm đóng vai người trợ giúp cho Mạc Lệ Hải. Bị Hoàng Phó Soái coi thường vì chỉ là Anh Biến hậu kỳ viên mãn, nhưng Huyền Phó Soái quả quyết hắn sẽ vào tam giáp, thậm chí đứng đầu. Bị Thạch Tiêu khiêu chiến rồi hăm dọa giết; Vương Lâm cự tuyệt vì “đánh nhau mà không giết người thì không có hứng”."},{"chuong":"@c0543","importance":"normal","tieuDe":"Đối mặt Ngao Địch khiêu chiến","text":"Yêu Tướng Ngao Địch chớp cơ hội ra khiêu chiến vì thắng Vương Lâm tương đương thắng Mạc Lệ Hải. Vương Lâm bình thản đáp lại rằng đối phương không phải là đối thủ của hắn."},{"chuong":"@c0544","importance":"normal","tieuDe":"Phế Yêu Tướng Ngao Địch chớp mắt","text":"Tại đại hội Yêu Tướng của Thiên Yêu Môn, Vương Lâm bước một bước phá đất bức Ngao Địch lộ thân, túm tay phải truyền tiên lực phá hủy toàn bộ kinh mạch, dùng Sinh Chi Lạc Ấn hóa giải hư ảnh long quy tới tầng thứ tám rồi rung tay làm vỡ nát xương cốt đối phương thành phế nhân. Lần đầu một người ngoài đánh phế một Yêu Tướng chỉ trong chớp mắt, chấn động cả khán đài Yêu Tướng – Yêu Soái."},{"chuong":"@c0544","importance":"normal","tieuDe":"Đẩy lui trường thương Kim tổng quản","text":"Khi Kim tổng quản ngưng ánh sáng mặt trời thành trường thương vàng phóng tới cứu Ngao Địch, Vương Lâm dùng Sinh Chi Lạc Ấn vỗ hai cái vào hai vị trí khác nhau khiến trường thương đổi hướng lướt qua, lạnh lùng chất vấn đối phương có muốn phá vỡ quy tắc. Kim tổng quản đành thu thương, liếc Vương Lâm thật sâu — gieo mối ân oán."},{"bridge":true,"khoang":"@c0544","text":"Sau đó Vương Lâm cảm nhận được Hứa Lập Quốc xin ra ngoài, mở khe túi trữ vật thả ma đầu Kiếm Linh bay đi đuổi theo thiếu nữ Kiếm Linh của Đế Kiếm; hết ngày đầu đại hội, sáu trận đã phân thắng bại."},{"chuong":"@c0545","importance":"normal","tieuDe":"Trấn áp kế làm phản Hứa Lập Quốc","text":"Trong lúc nghỉ giữa vòng tỷ thí tranh đoạt Yêu Tướng, Vương Lâm nhận ra Hứa Lập Quốc che giấu nhiều thủ đoạn và lòng trung thành chỉ duy trì khi chủ nhân mạnh. Hắn thu hồi sát khí, cắt liên hệ tiên kiếm, dùng cấm chế bắt lại kẻ định trốn rồi cảnh báo nguy cơ bị luyện hóa."},{"chuong":"@c0545","importance":"normal","tieuDe":"Thu phục Tiểu Hắc Đao","text":"Khi loan đao đen Tiểu Hắc tự xông ra tập kích hai lần nhắm giữa lông mày, Vương Lâm dựa Sinh Chi Lạc Ấn bật ra, phóng hơn ba nghìn đạo Sát lục chi khí ép loan đao thành quả cầu rồi in dấu ấn nguyên thần thu phục."},{"chuong":"@c0545","importance":"normal","tieuDe":"Ngộ chữ “nghịch” hướng Vấn Đỉnh","text":"Từ ánh đèn lồng Mạc phủ leo lét mà ngoan cường và bình minh quét tan bóng đêm, Vương Lâm phân biệt “tránh” với “nghịch”, lóe lên cảm ngộ về chữ nghịch — mấu chốt đưa hắn tiến tới Vấn Đỉnh, một biến đổi âm thầm bén rễ."},{"chuong":"@c0545","importance":"normal","tieuDe":"Đối thoại thanh niên trên thuyền tranh","text":"Vương Lâm lên thuyền tranh nghe đàn của Minh Phí cô nương, đáp tiếng đàn khiến hắn “nhớ tới cố nhân”, hai người nhận nhau là tục nhân và hẹn uống rượu tới bình minh."},{"chuong":"@c0546","importance":"normal","tieuDe":"Vào vòng hai gõ Chiến Yêu Cổ","text":"Sau khi chia tay thanh niên ôm đàn trên thuyền, Vương Lâm cùng 48 Yêu Tướng vào vòng hai cuộc tranh đoạt Yêu Tướng tại Đế Đô. Vòng hai đổi luật thành gõ thánh vật Chiến Yêu Cổ. Hắn được Huyền Phó Soái âm thầm đánh giá là “đáng sợ” hơn cả Mặc Phi. Cuối cùng bị nam tử mặc kim giáp gọi tên, đáp lạnh và bị thách đánh cược."},{"chuong":"@c0546","importance":"normal","tieuDe":"Nhận ra Mặc Phi giống nam tử Hồng Lao","text":"Khi mặt nạ Mặc Phi vỡ lộ khuôn mặt anh tuấn, Vương Lâm sững lại nhận ra hắn giống hệt nam tử tóc đen ở chỗ sâu nhất Hồng Lao."},{"chuong":"@c0547","importance":"normal","tieuDe":"Chín tiếng Yêu Cổ vượt kỷ lục","text":"Vương Lâm cá cược với Kim tổng quản, đòi một cánh tay của hắn nếu đánh vượt năm tiếng trống trên Yêu Cổ. Hắn vận hơn ba ngàn Lạc Ấn Sinh Mệnh làm lá chắn, đánh liền năm tiếng hợp nhất mà thân thể không di động, rồi tiếp tục tới tiếng thứ chín — vượt qua kỷ lục tám tiếng của đệ nhất yêu tướng Mặc Phi, vang danh Thiên Yêu quận."},{"chuong":"@c0547","importance":"normal","tieuDe":"Ngộ đạo Thuận - Nghịch","text":"Vương Lâm ngộ ra phản lực Yêu Cổ là khí tức bất khuất, cuồng ngạo nghịch thiên trong ý niệm; lực đánh là thuận, tiếng trống vang là nghịch, một thuận một nghịch ẩn tàng biến hóa thiên địa. Hắn tiến chín bước vuốt mặt trống, cả người như dung hợp vào Yêu Cổ."},{"chuong":"@c0548","importance":"normal","tieuDe":"Yêu Cổ tẩy tủy đạt riêng đạo","text":"Đánh Yêu Cổ tới tiếng thứ mười, Vương Lâm thu hồi Sinh Chi Lạc Ấn cho lực phản chấn tiến thẳng vào người để tẩy tủy — mồ hôi đen tiết ra nhưng lực vận chuyển loạn khiến sắc mặt trắng xanh. Hắn ngộ ra mình bị thương không phải do tu vi yếu mà do dung hợp theo đạo của Yêu Cổ chứ không phải đạo của riêng mình, một chữ “nghịch” chia thành nhiều con đường tùy cảm ngộ."},{"chuong":"@c0548","importance":"major","tieuDe":"Trống truyền niệm chấn động toàn trường","text":"Vương Lâm đem ý niệm bi thương cùng cảm ngộ tiếng đàn hoa thuyền hòa vào tiếng trống thứ mười một, đạt cảnh giới “trống truyền niệm” — lấy bi nhập thần, dùng thần nhập niệm, lấy niệm đánh trống, dùng trống truyền đạo. Bi niệm lan khắp Thiên Yêu thành, gây cộng hưởng tâm linh khiến cả khán đài Yêu soái, Yêu tướng cùng văn thần rơi lệ; Huyền Hôn soái ngờ hắn chính là người Yêu Đế chờ đợi nhiều năm, Thiên soái lần đầu đứng thẳng kinh ngạc nhận ra danh tính Vương Lâm."},{"chuong":"@c0549","importance":"major","tieuDe":"Cảm nhận kêu gọi Vấn Đỉnh","text":"Khi gõ Yêu Cổ tới tiếng trống thứ mười một truyền niệm, Vương Lâm lần đầu cảm nhận sự kêu gọi của Vấn Đỉnh, đứng cạnh biên giới Vấn Đỉnh. Hắn nhận ra tu đạo bảy trăm năm, Ý Cảnh nhập thể đã viên mãn, Ý Cảnh Vấn Đỉnh đã có tám phần, song đạo tâm chưa viên mãn vì còn một tia bi thương — chấp niệm về Lý Mộ Uyển. Hắn tuyên bố trong lòng “Ta phải Vấn Đỉnh”."},{"chuong":"@c0549","importance":"normal","tieuDe":"Gõ trống tẩy tủy","text":"Vương Lâm gõ thêm các tiếng trống thứ mười hai, mười ba, mười bốn, đem bi ai dung nhập tiếng trống tạo lực trùng kích đi vào cơ thể, mồ hôi đen tiết ra khắp lỗ chân lông, đạt tẩy tủy thật. Thiên soái tán thưởng đây mới là tẩy tủy thật, trước chỉ là tẩy da lông."},{"chuong":"@c0549","importance":"normal","tieuDe":"Do dự cái giá phải quên","text":"Để đạo tâm viên mãn đạt Vấn Đỉnh, Vương Lâm phải xóa sạch ký ức và tình cảm với Lý Mộ Uyển. Hắn nâng tay định hạ xuống Yêu Cổ thì bàn tay run lên, do dự chưa hạ — nếu quên, dù Lý Mộ Uyển trong Nghịch Thiên châu có ngày thức tỉnh, hắn cũng chỉ vô tình mỉm cười tiễn nàng về Chu Tước Tinh."}],"tuViMoc":[{"chuong":"@c0459","canhGioi":"Anh Biến kỳ","text":"Đặt mục tiêu tu luyện đột phá tới Anh Biến trung kỳ để có đủ lực phá vỡ trận pháp khốn địa; chuyên tâm hấp thu tiên ngọc, tiên lực trong cơ thể đạt bão hòa dung nhập thân thể làm lực lượng dự phòng.","importance":"minor"},{"chuong":"@c0461","canhGioi":"Anh Biến trung kỳ","text":"Nhờ lượng lớn tiên ngọc trợ giúp đột phá khi còn bị vây trong thạch lâm, Vương Lâm tiến lên Anh Biến trung kỳ, uy lực Hóa Ma Chỉ nhờ đó tăng mấy lần.","importance":"minor"},{"chuong":"@c0462","canhGioi":"Anh Biến Trung Kỳ","text":"Khi tái xuất phá vây, Vương Lâm đã đột phá lên Anh Biến Trung Kỳ, khiến Triệu Tinh Sát kinh hãi vì hắn vừa thoát vây vừa tăng cảnh giới.","importance":"minor"},{"chuong":"@c0472","canhGioi":"Anh Biến trung kỳ","text":"Lĩnh ngộ Vấn Tâm chỉ cảnh tại Toái Tiên chi địa: khi tâm lạnh lẽo hơn cả vạn vật băng hàn, ý chí bất khuất vờn quanh thân, thần thức từ nguyên thần quét lui hàn khí xâm nhập kinh mạch. Đồng thời lĩnh ngộ Luân hồi đạo chính là đại Vô tình đạo, sau lưng hiện ra Luân hồi Hoạ trục chỉ hai màu đen trắng. Thuộc hệ tu tâm — không phải tu vi chính.","importance":"major"},{"chuong":"@c0473","canhGioi":"Anh Biến kỳ","importance":"major","text":"Ý cảnh nhập thể: trên nền hai mươi bước, Vương Lâm dung một tia cảm ngộ vào tâm cảnh, bước thêm năm bước đạt cực hạn hai mươi bảy bước, mở ra con đường lên Vấn Đỉnh. Sinh Tử Luân Hồi đạo của hắn là loại lĩnh ngộ cực hiếm khó thực chất hóa nhất; nhờ kết hợp Vấn Tâm chi đạo tại Toái Tiên chi địa mới khai thông. Bước thứ hai mươi tám nếu bước ra sẽ khiến tu vi sụp đổ, nguyên thần tiêu tan."},{"chuong":"@c0483","canhGioi":"Anh Biến","text":"Tu vi xác nhận đã đạt Anh Biến trung kỳ; nhờ vậy không còn ngại đối kháng trực tiếp nguyên thần ly thể dung trong bản mạng pháp khí như thuở chưa có Côn Cực tiên.","importance":"minor"},{"chuong":"@c0498","canhGioi":"Anh Biến trung kỳ","text":"Được La mỗ xác nhận tu vi mới Anh Biến trung kỳ; dù vậy hắn từng đấu mười một trận với tu sĩ Vấn Đỉnh, lực công hùng mạnh khiến nhiều thế lực chú ý.","importance":"minor"},{"chuong":"@c0500","canhGioi":"Anh Biến trung kỳ","text":"Đang ở Anh Biến trung kỳ, kém đối thủ Anh Biến hậu kỳ đại viên mãn một bậc, nhưng nhờ Thiên Quỷ hấp thu tiên lực của địch và thủ đoạn áp chế mà giành thế thượng phong.","importance":"minor"},{"chuong":"@c0507","canhGioi":"Anh Biến hậu kỳ (yêu tinh ba mươi bốn giáp)","text":"Sau hai năm hấp thu yêu lực ở Yêu Linh chi địa, nâng yêu tinh từ năm giáp lên ba mươi bốn giáp; tiên ngọc gần đủ Anh Biến hậu kỳ, mở ra con đường dùng yêu lực thay tiên ngọc để hướng tới Vấn Đỉnh.","importance":"major"},{"chuong":"@c0517","canhGioi":"Anh Biến kỳ","importance":"minor","text":"Sau mấy tháng thổ nạp luyện hóa yêu lực dung nhập tiên lực, tiến tới Anh Biến hậu kỳ."},{"chuong":"@c0518","canhGioi":"Anh Biến trung kỳ","text":"Tu vi đang ở Anh Biến trung kỳ; hấp thu yêu lực gần ngàn giáp yêu tinh để dồn sức đột phá Anh Biến hậu kỳ, dự tính lên đại viên mãn rồi dẫn yêu binh ra ngoài huyết tẩy tu sĩ thu tiên ngọc, tiến tới Vấn Đỉnh.","importance":"minor"},{"chuong":"@c0525","canhGioi":"Anh Biến hậu kỳ","text":"Sau khi uống một giọt mỹ tửu và ngủ say một năm, tiên lực tăng vọt vượt xa mức Anh Biến hậu kỳ đại viên mãn; Yêu Tinh trong đan điền vỡ vụn, yêu lực bị thôn phệ hòa làm một bộ phận của tiên lực. Tu vi đã không còn đối thủ trong Anh Biến kỳ, chỉ chờ cảm ngộ ý cảnh là đủ sức tiến lên Vấn Đỉnh.","importance":"major"},{"chuong":"@c0526","canhGioi":"Anh Biến","text":"Tu vi nâng lên Anh Biến hậu kỳ đại viên mãn, đã thuộc hàng đỉnh trong Anh Biến kỳ; tốc độ nhảy vọt nhanh hơn sấm chớp.","importance":"minor"},{"chuong":"@c0536","canhGioi":"Anh Biến kỳ","text":"Tu luyện Sát lục tiên quyết trong Hồng lao, ngộ được sát lục chi tâm và liên hệ với ý cảnh sinh tử luân hồi — thuộc hệ thần thông sát đạo, không phải bước đột phá tu vi chính.","importance":"normal"}],"tuVi":"","nhanMach":[{"ten":"Trương Hướng Phàm","tag":"dong-minh","quanHe":"Đệ tử mở khóa trận pháp Phẩm Linh Các, cung kính dẫn Vương Lâm vào lấy tiên ngọc","ghiChu":"@c0458"},{"ten":"Tư Mã Như Phong","tag":"doi-thu","quanHe":"Đệ tử hàng thứ hai Lam tông, tham gia vây kích Vương Lâm","ghiChu":"@c0458"},{"ten":"Tứ sư tỷ (Tử hệ)","tag":"doi-thu","quanHe":"Đồng hệ Tử nhưng được người nhờ vả nên ra tay vây kích","ghiChu":"@c0458"},{"ten":"Người y phục xanh (như tượng băng)","tag":"doi-thu","quanHe":"Sư huynh ẩn mình nửa bước vấn đỉnh, coi Vương Lâm không xứng ra tay","ghiChu":"@c0458"},{"ten":"Thủy tổ đại nhân (Thiên Vận Tông)","tag":"su-mon","quanHe":"Thủy tổ tông môn, từng dặn chỉ cần không phạm môn quy thì khỏi quản Vương Lâm","ghiChu":"@c0458"},{"ten":"Tứ sư tỷ (Tử hệ)","tag":"su-mon","quanHe":"Sư tỷ đồng môn","ghiChu":"Trực tiếp na di Vương Lâm tới khốn địa, hẹn ba năm thả ra; từng hứa truyền thần thông na di cho hắn sau khi mọi chuyện giải quyết."},{"ten":"Đại sư huynh (Thiên Vận Tông)","tag":"doi-thu","quanHe":"Sư huynh đồng môn","ghiChu":"Người bố trí trận pháp thạch lâm vây khốn Vương Lâm."},{"ten":"Tào Nhất Đấu","tag":"dong-minh","quanHe":"Nguyên thần bị Vương Lâm thu nhận làm người dẫn đường","ghiChu":"Vương Lâm hứa cho một thân thể anh biến để đổi lấy việc dẫn đường về Thiên Vận Tông."},{"ten":"Triệu Tinh Sát","tag":"doi-thu","quanHe":"Đại sư huynh Tử hệ nhất mạch đứng sau việc na di vây khốn Vương Lâm","ghiChu":"Vương Lâm trở về quyết báo thù sự chèn ép của Triệu Tinh Sát và Tử hệ nhất mạch."},{"ten":"Hứa Lập Quốc","tag":"doi-thu","quanHe":"Kẻ thù bị Vương Lâm truy sát giữa thọ yến, đánh trọng thương nguyên thần","ghiChu":"Nhị sư huynh Tử hệ Thiên Vận Tông"},{"ten":"Triệu Tinh Sát","tag":"doi-thu","quanHe":"Cản Vương Lâm bằng Đại tự tại thiên địa quyết nhưng bị ma hỏa tự bạo phá vỡ","ghiChu":""},{"ten":"Bạch Vi","tag":"khac","quanHe":"Đệ tử Tử hệ, mỉm cười kỳ dị khi thấy Vương Lâm trở lại nhưng không ra tay","ghiChu":""},{"ten":"Triệu Tinh Sát","tag":"doi-thu","quanHe":"Đối thủ tranh danh hiệu Thiên Vận Thất Tử","ghiChu":"Bị Vương Lâm uy hiếp, đáp trả bằng thuật triệu Cổ Yêu nhưng bị phản phệ."},{"ten":"Xích Liệt","tag":"su-mon","quanHe":"Sư thúc trong Thiên Vận Tông","ghiChu":"Xuất hiện quát đuổi cổ yêu, vô tình cứu Hồn Thú của Vương Lâm."},{"ten":"Xích Liệt","tag":"su-mon","quanHe":"Tiền bối Thiên Vận Tông cùng tông, sư đệ của sư tôn","ghiChu":"Tiết lộ sư phụ kỳ vọng cao ở Vương Lâm và đại sư huynh sẽ không tranh danh hiệu Thiên Vận Thất Tử."},{"ten":"Tư Mã Như Phong","tag":"doi-thu","quanHe":"Đệ tử hàng thứ ba Lam Tông cùng Thiên Vận Tông","ghiChu":"Anh Biến đại viên mãn, gần Vấn Đỉnh; được Vương Lâm nhận ra trong lễ giảng đạo."},{"ten":"Tôn trưởng lão","tag":"khac","quanHe":"Cao thủ tu chân liên minh giáng lâm thọ yến","ghiChu":"Tiểu điêu ba mắt của Tôn trưởng lão đậu vai dò xét riêng Vương Lâm; hắn thấy quen quen."},{"ten":"Côn Bằng Tử","tag":"khac","quanHe":"Đầu lĩnh Hoàng Hệ cùng dự thọ yến","ghiChu":"Được Thiên Vận Tử tặng lại phi kiếm trung phẩm tiên khí."},{"ten":"Lăng Thiên Hầu","tag":"doi-thu","quanHe":"Kiếm Tôn Đại La Kiếm Tông","ghiChu":"Vương Lâm nhận ra thanh xà hình bảo kiếm của Lăng Thiên Hầu là Vũ chi đệ nhị kiếm bị hắn cướp ở Tiên giới năm xưa, gợi mở ân oán liên quan các thanh Vũ chi kiếm."},{"ten":"Triệu Hân Mộng","tag":"doi-thu","quanHe":"Tứ sư tỷ đồng môn","ghiChu":"Khiêu chiến Vương Lâm trong cuộc tranh phong hiệu; mô phỏng Hoá Ma chỉ của hắn để sáng chế Tử Ma thủ."},{"ten":"Vận Đường","tag":"khac","quanHe":"Đại sư huynh Hoàng hệ đồng môn","ghiChu":"Vương Lâm phát hiện biểu hiện quỷ dị: mắt Vận Đường co rút khi tinh thể vàng xuất hiện, ánh mắt thoáng sợ hãi rồi mỉm cười với hắn."},{"ten":"Trần Đào","tag":"doi-thu","quanHe":"Tử hệ Lão Lục giành phong hiệu","ghiChu":"Trần Đào khinh thường Vương Lâm, hai bên giao chiến tranh phong hiệu Thiên Vận Thất tử."},{"ten":"Triệu Hân Mộng","tag":"doi-thu","quanHe":"Tứ sư tỷ Tử hệ","ghiChu":"Gài bẫy hấp thu ma lực thất bại, thừa nhận xem thường Vương Lâm rồi bỏ cuộc."},{"ten":"Trần Đào","tag":"doi-thu","quanHe":"Đối thủ tại lễ chúc thọ","ghiChu":"Trần Đào tự xưng sư huynh, Vương Lâm phủ nhận tư cách đó của hắn; hai người giao chiến."},{"ten":"Lão già mặt đỏ","tag":"khac","quanHe":"Khách chúc thọ nhận ra sát chiêu","ghiChu":"Lão già mặt đỏ thấy Hoàng tuyền chỉ của Vương Lâm giống hệt sát chiêu của một “người điên” lão từng gặp."},{"ten":"Trần Đào","tag":"doi-thu","quanHe":"Sư huynh đệ Tử hệ kiêm đối thủ","ghiChu":"Thắng Vương Lâm đoạt phong hiệu Thiên Vận Thất tử, hẹn tái chiến sau khi Vương Lâm đạt Vấn Đỉnh."},{"ten":"Thiên Vận Tử","tag":"su-mon","quanHe":"Sư phụ","ghiChu":"Nhận Vương Lâm làm đệ tử chân chính, hứa truyền Cấm pháp thần thông và pháp bảo bản mạng, sắp đặt khảo nghiệm Toái Tiên chi địa."},{"ten":"Lăng Thiên Hầu","tag":"khac","quanHe":"Kiếm Tôn quen biết qua đại thọ","ghiChu":"Có ước hẹn với Thiên Vận Tử về Đông Hải Yêu Linh chi môn ba tháng sau."},{"ten":"Thiên Vận Tử áo xám","tag":"khac","quanHe":"Nhân vật bí ẩn ‘hơn một người’ trong thế giới bảy màu, nắm Sát Lục Tiên quyết, mời truyền nhưng Vương Lâm từ chối; vẫn để lại ngọc giản","ghiChu":"@c0474"},{"ten":"Hứa Vân Sơn","tag":"dong-minh","quanHe":"Thiếu Tông Huyền Uyên Phái chủ động ra đón và kết giao, đưa Vương Lâm tới Linh Nhạc quốc","ghiChu":"Cùng tu vi Anh Biến Trung kỳ"},{"ten":"Triệu Tứ","tag":"khac","quanHe":"Tu sĩ vận hành Truyền tống trận đưa Vương Lâm tới Địa Tinh, kính gọi hắn là Thất sư tổ"},{"ten":"Thiên Thai lão nhân","tag":"khac","quanHe":"Cao thủ đệ nhất Linh Nhạc quốc; từng đến Thông Thiên tháp thăm dò Vương Lâm rồi khiếp sợ, cuối chương Vương Lâm tìm đến tại Ngũ Linh Sơn","ghiChu":"@c0477"},{"ten":"Hứa Vân Sơn","tag":"dong-minh","quanHe":"Đưa Vương Lâm đến nhậm chức Sứ giả, gọi là Vương huynh, hẹn ngày sau cùng uống rượu","ghiChu":"@c0477"},{"ten":"Thiên Thai lão nhân","tag":"dong-minh","quanHe":"Tu sĩ Anh Biến kỳ phục vụ, trao ngọc giản ba chỗ yêu thú","ghiChu":"Gọi Vương Lâm là Sứ giả đại nhân"},{"ten":"Văn thú","tag":"khac","quanHe":"Vật nuôi","ghiChu":"Yêu thú đến từ tinh không, Vương Lâm nuôi lớn bằng cách thả hấp thu yêu thú Hóa Thần trở lên; đang ở thời khắc sắp tiến hóa."},{"ten":"Thiên Cầm cô nương","tag":"khac","quanHe":"Cùng hướng tới Diệu Kim quả","ghiChu":"Vương Lâm âm thầm theo dõi đoàn của nàng (bị Đại La Kiếm Tông ép dẫn đường)."},{"ten":"Thạch Phương","tag":"doi-thu","quanHe":"Đối thủ bị Vương Lâm đánh tan nguyên thần, nuốt thân xác và cuối cùng giết chết dù đã đoạt xá Quách Tà Dật.","ghiChu":"@c0483"},{"ten":"Thiên Cầm cô nương","tag":"khac","quanHe":"Nữ tử tiểu bối quỳ cầu Vương Lâm giết Thạch Phương cùng Trưởng lão Đại La Kiếm Tông, nguyện làm trâu ngựa hầu hạ.","ghiChu":"@c0483"},{"ten":"Thiên Cầm cô nương","tag":"an-nhan","quanHe":"Tặng Thiên Cầm sợi kim linh căn cuối cùng coi như đền bù cơ duyên đã chiếm.","ghiChu":"@c0484"},{"ten":"Lão già thấp người (Trưởng lão Đại La Kiếm Tông)","tag":"doi-thu","quanHe":"Tù nhân khai bí mật rồi bị giết","ghiChu":"Bắt giam tra hỏi về Kiếm Tôn và Đông Hải Yêu Linh chi môn, sau đó xử tử bằng loan đao và khí xám Sát lục tiên quyết."},{"ten":"Kiếm Tôn","tag":"khac","quanHe":"Mục tiêu liên quan chuyến đi","ghiChu":"Kẻ phong ấn Chu Dật và 1/3 kiếm hồn trong Đông Hải Yêu Linh chi môn — nơi Vương Lâm sắp tới."},{"ten":"Tôn Vân Sơn","tag":"dong-minh","quanHe":"Bạn đồng hành cùng đi Đông Hải Yêu Linh","ghiChu":"Tôn Vân Sơn cố đợi để cùng đi cho có bạn"},{"ten":"Tôn Nhược Nam","tag":"khac","quanHe":"Muội của Tôn Vân Sơn, lén bám theo hắn","ghiChu":"Nhìn Vương Lâm thoáng lóe kinh ngạc"},{"ten":"Tham Lang","tag":"doi-thu","quanHe":"Kẻ truy tìm sợi tơ Thiên Kiếp và tìm Vương Lâm","ghiChu":"Xuất hiện ngay tại nơi Vương Lâm đang đến"},{"ten":"Trần Đào","tag":"doi-thu","quanHe":"Đồng môn Tử hệ Thiên Vận Tông","ghiChu":"Lão lục từng tranh phong hào Thiên Vận Thất Tử; nhìn Vương Lâm với ánh mắt kỳ dị khi hắn tới cửa Đông Hải."},{"ten":"Tôn Vân Sơn","tag":"dong-hanh","quanHe":"Đồng hành tới Đông Hải","ghiChu":"Tách ra trước cửa, nhờ Vương Lâm chiếu cố, hẹn gặp lại trong Đông Hải Yêu Linh."},{"ten":"Diêu Tích Tuyết","tag":"khac","quanHe":"Người được phụ thân dặn theo dõi Vương Lâm","ghiChu":"Thấy ánh mắt yêu dị mang khí xám của hắn sau khi dùng thần thông liền chấn động, hiểu vì sao phụ thân bảo nàng phải chú ý đến hắn (@c0490)."},{"ten":"Tôn Vân Sơn","tag":"dong-minh","quanHe":"Người báo cho Vương Lâm rằng hành trình Đông Hải kéo dài năm trăm năm","ghiChu":"@c0491"},{"ten":"Người xích lõa vẽ nhựa cây (thợ săn)","tag":"khac","quanHe":"Người chủng tộc lạ Vương Lâm gặp đầu tiên trong sơn cốc","ghiChu":"Vương Lâm nhường con thú, sau đó giam giữ để tra hỏi nguồn gốc nơi này."},{"ten":"Âu Dương Hoa","tag":"doi-thu","quanHe":"Trưởng lão bộ tộc sơn cốc, đối đầu qua trận pháp","ghiChu":"Khuyên Vương Lâm rời đi tới Cổ yêu thành rồi điều khiển trận pháp phản kích."},{"ten":"Âu Dương Hoa","tag":"doi-thu","quanHe":"Đối thủ","ghiChu":"Âu Dương Hoa vây Vương Lâm bằng trận pháp thượng cổ, chiêu hàng tàn nhẫn rồi cầu tha khi bị phá trận."},{"ten":"Âu Dương Hoa","tag":"khac","quanHe":"Trưởng lão tộc nhân sơn cốc thần phục, mời vào cốc và kể về Hoàng Long cùng đêm yêu linh","ghiChu":""},{"ten":"Hoàng Long","tag":"khac","quanHe":"Người trong bức tranh cổ khiến Vương Lâm chấn động nguyên thần","ghiChu":""},{"ten":"Hắc y nam tử","tag":"doi-thu","quanHe":"Tu sĩ Thiên Vận Tinh săn yêu linh, tuyên bố coi Vương Lâm là con mồi để lấy yêu tinh tiến vào Thiên Yêu Thành","ghiChu":"Gặp @c0497; đối thủ lầm tưởng Vương Lâm chỉ Ứng Biến trung kỳ."},{"ten":"Âu Dương Hoa","tag":"khac","quanHe":"Tu sĩ trông coi Hồ Lô Cốc, đổi yêu lực kết tinh và cầu Vương Lâm cứu mạng khi yêu linh tấn công","ghiChu":"@c0497"},{"ten":"La mỗ","tag":"doi-thu","quanHe":"Đối thủ chạm trán ngoài thung lũng yêu linh","ghiChu":"Ban đầu tưởng Vương Lâm là người Đại La Kiếm Tông, sau nhận ra hắn là đệ tử Thiên Vận Tử; lo khó giết vì Vương Lâm có pháp bảo bảo mệnh."},{"ten":"Tử hệ lão Lục","tag":"doi-thu","quanHe":"Sư huynh đồng môn Tử hệ","ghiChu":"Từng dùng tu vi Vấn Đỉnh đè ép, khiến Vương Lâm mất danh hiệu Thiên Vận Thất Tử."},{"ten":"La mỗ (Hắc y nhân)","tag":"doi-thu","quanHe":"Đối thủ giao chiến trong Yêu linh khí lãng","ghiChu":"Tu sĩ Anh Biến hậu kỳ đại viên mãn, tự xưng hành sự thay Tôn sư; bị Vương Lâm đả thương nguyên thần, đáp trả bằng Ma cấm triệu Quỷ ảnh."},{"ten":"Hắc y nam tử (mặt sẹo)","tag":"doi-thu","quanHe":"Đối thủ sinh tử","ghiChu":"Áp chế bằng Hóa ma chỉ và Xạ Thần Xa, buộc hắn bỏ thân xác chạy nguyên thần; trước đó từng dùng cùng sát chiêu đấu Tử hệ lão Tứ."},{"ten":"La Vân","tag":"doi-thu","quanHe":"Đối thủ bị Vương Lâm diệt thân, bắt sống nguyên thần và Sưu Hồn đoạt ký ức","ghiChu":"Tu sĩ Thiên Quỷ Đạo, bị giam vào hồn phiên để luyện chủ hồn (@c0501)"},{"ten":"Quỷ Chân Nhân","tag":"doi-thu","quanHe":"Sư tôn của La Vân, bị La Vân dọa sẽ báo thù Vương Lâm","ghiChu":"Mầm xung đột tương lai với Thiên Quỷ Đạo (@c0501)"},{"ten":"La Vân","tag":"doi-thu","quanHe":"Tu sĩ Thiên Quỷ Đạo bị Vương Lâm hấp thu ký ức","ghiChu":"Vương Lâm nắm trọn ký ức về vùng đất yêu linh từ La Vân; hiểu La Vân muốn giết mình để đoạt giáp yêu lực còn thiếu."},{"ten":"Âu Dương Hoa","tag":"su-mon","quanHe":"Đệ tử quy phục","ghiChu":"Được Vương Lâm đả thông kinh mạch đột phá nhị tinh và truyền thụ thuật luyện hồn; đ���i xưng hô thành vãn bối, hành lễ như đệ tử."},{"ten":"Thập Tam","tag":"khac","quanHe":"Thuộc hạ được coi trọng","ghiChu":"Thanh niên Vương Lâm âm thầm theo dõi, có ngộ tính trời sinh với Luyện Hồn Thuật; Vương Lâm trao phương pháp mới và cứu hắn khi bị sư tử phản phệ."},{"ten":"Thập Tam","tag":"dong-minh","quanHe":"Tộc nhân chủ lực được Vương Lâm dạy Luyện Hồn Thuật và ban chủ hồn","ghiChu":""},{"ten":"Âu Dương Hoa","tag":"dong-minh","quanHe":"Người dẫn dắt bộ lạc, cung kính gọi Vương Lâm ‘thượng tiên’, dâng yêu tinh đổi khẩu quyết","ghiChu":""},{"ten":"Thập Tam","tag":"su-mon","quanHe":"đệ tử (gọi Sư phụ)","ghiChu":"Cứu khỏi yêu vật, cân nhắc truyền thuật Cổ Thần rồi từ bỏ, tiếc tư chất khi Thập Tam bị phế."},{"ten":"Âu Dương Hoa","tag":"dong-minh","quanHe":"tộc nhân thân tín","ghiChu":"Giao Âu Dương Hoa thu nạp dân Thiên Thủy và quản bộ lạc Luyện Hồn."},{"ten":"Lão già áo trắng","tag":"doi-thu","quanHe":"kẻ thù bị giết","ghiChu":"Đánh phế Thập Tam, cướp hồn phiên — Vương Lâm bóp cổ giết, giam nguyên thần vào cờ Tôn Hồn."},{"ten":"Lão già áo xám (Thiên Thủy)","tag":"khac","quanHe":"hàng phục, thu làm tộc nhân Luyện Hồn","ghiChu":"Sau khi lão áo trắng chết, mở trận pháp và quy thuận, sinh hứng thú với thuật Luyện hồn."},{"ten":"Hổ Bào","tag":"su-mon","quanHe":"Đệ tử thiên tài được giữ bên người","ghiChu":"Đánh giá là thiên tài, giữ bên người vừa bồi dưỡng vừa khống chế."},{"ten":"Diêu Nghiêu lĩnh","tag":"dong-minh","quanHe":"Người quen cũ","ghiChu":"Từng gặp ở ngoài cửa Đông Hải Yêu linh; tại Cổ Yêu thành nàng hóa giải cầu máu, từ chối giao chiến và dẫn Vương Lâm đi gặp Tả dực Yêu tương."},{"ten":"Tả dực Yêu tương","tag":"doi-thu","quanHe":"Chủ Cổ Yêu thành thử thách","ghiChu":"Ra đòn thử Vương Lâm để xét ban chức; bị Vương Lâm hóa giải Tịch Diệt chỉ rồi tiếp Thập Băng Chiến Ý."},{"ten":"Tả dực Yêu tương","tag":"doi-thu","quanHe":"Đối thủ giao chiến tại Cổ Yêu thành","ghiChu":"Tả dực Yêu tương thi triển Thập Băng Quyền Ý, thách Vương Lâm phá tám lần sụp đổ để áp sát."},{"ten":"Tả dực Yêu tướng","tag":"doi-thu","quanHe":"Đối thủ thử thách","ghiChu":"Chủ nhân Thập Băng Quyền Ý; ban đầu xem thường rồi chấn động khi Vương Lâm phá được tới lần thứ bảy bằng niềm tin."},{"ten":"Vân Lệ Hải","tag":"cap-tren","quanHe":"Tả Dực Yêu tương phong Vương Lâm làm Thống lĩnh Cổ Yêu thành","ghiChu":"Khen hắn biết tiến lùi, trao lệnh bài đồng, hẹn bảy ngày sau tới quân doanh."},{"ten":"Thống lĩnh (Nghiêu Lĩnh, Cổ Yêu thành)","tag":"doi-thu","quanHe":"Yêu binh khiêu khích","ghiChu":"Cảm nhận trong cơ thể Vương Lâm có hai luồng lực lượng quỷ dị đang chém giết nhau, ném vò rượu tấn công."},{"ten":"Quản sự tham quân","tag":"khac","quanHe":"Quản sự dưới trướng Yêu Tương, tới đưa Vương Lâm tới quân doanh","ghiChu":"Kiểm tra lệnh bài đồng rồi vẽ Truyền Tống trận đưa đi (@c0514)"},{"ten":"Nam tử âm trầm","tag":"doi-thu","quanHe":"Đầu lĩnh sáu yêu binh trong tửu lâu, đối đầu thoáng qua","ghiChu":"Tấn công bằng trường kiếm yêu khí nhưng bị hóa giải; Vương Lâm hẹn sẽ gặp lại (@c0514)"},{"ten":"Tư Mã Viêm","tag":"doi-thu","quanHe":"Phó thống lĩnh Hắc Giáp quân dưới quyền Vương Lâm","ghiChu":"Bề ngoài quy phục nhưng nắm thực quyền mười Thống đội, ngày càng khiếp sợ vì nhìn không thấu Vương Lâm."},{"ten":"Tôn thống đội","tag":"doi-thu","quanHe":"Thống đội yêu binh dưới quyền Tư Mã Viêm","ghiChu":"Sỉ nhục Vương Lâm là phế vật, bị hắn bóp nát cổ, phá tu vi và hút yêu khí."},{"ten":"Tư Mã Viêm","tag":"doi-thu","quanHe":"Thống lĩnh quân doanh Thiên Yêu quận","ghiChu":"Bày kế chờ Vương Lâm lộ diện, sau bị hắn dùng quân quy phản chế khi ra mặt chất vấn."},{"ten":"Lão già áo vải bố","tag":"khac","quanHe":"Người đi cùng quản sự tham quân tới thị uy","ghiChu":"Bị một cái liếc mắt của Vương Lâm làm phong ấn suýt vỡ, sau đó ôm quyền bội phục tu vi của hắn."},{"ten":"Diêu Tích Tuyết","tag":"khac","quanHe":"Nữ tu quân doanh thứ ba","ghiChu":"Sau khi xông “nơi đó” thất bại lần thứ tư, nàng nghĩ tới việc nhờ Vương Lâm giúp đỡ."},{"ten":"Diêu Tích Tuyết","tag":"dong-minh","quanHe":"Thống lĩnh yêu binh tìm tới nhờ Vương Lâm phá trận cấm chế, lấy tiên ngọc làm điều kiện","ghiChu":"Mới gặp ba lần, Vương Lâm nghi nàng che giấu nhiều chuyện"},{"ten":"Thập Tam","tag":"dong-minh","quanHe":"Canh gác ngoài lầu cho Vương Lâm; được Vương Lâm dùng gió giải trừ khống chế"},{"ten":"Diêu Tích Tuyết","tag":"dong-minh","quanHe":"Con gái Huyết Tổ, nhờ Vương Lâm giúp bài trừ phong ấn","ghiChu":"Trao Huyết Hồn đan, lệnh bài Huyết Phù và tiên ngọc làm thù lao; hẹn ba ngày sau ở cổ sơn"},{"ten":"Diêu Tích Tuyết","tag":"doi-thu","quanHe":"Con gái Huyết Tổ, dẫn dắt Vương Lâm qua truyền tống trận tới không gian Tôn Long","ghiChu":"Đưa hắn tiên ngọc và Huyết Hồn đan (b�� hắn luận ra là giả), hứa trao lệnh bài Huyết Phủ khi trở về; Vương Lâm đề phòng và toan moi bí mật."},{"ten":"Diêu Tích Tuyết","tag":"dong-minh","quanHe":"Người đồng hành trên con đường Tôn Long; Vương Lâm ngầm đề phòng vì nàng có Huyết Hồn đan rất khó giết, tự nhủ chưa phải lúc trở mặt.","ghiChu":"@c0522"},{"ten":"Diêu Tích Tuyết","tag":"doi-thu","quanHe":"Đối thủ bị Vương Lâm dùng kế phản đòn, phong ấn giữa sinh tử và đoạt hết trữ vật.","ghiChu":"Con gái Huyết Tổ; trước đó cùng tiến vào đường Tôn Long."},{"ten":"Động Phủ Chi Linh","tag":"khac","quanHe":"Tia linh hồn động phủ ra ba đạo kiếm khí khảo nghiệm; Vương Lâm lợi dụng để giăng kế.","ghiChu":""},{"ten":"Diêu Tích Tuyết","tag":"doi-thu","quanHe":"Đối tượng bị Vương Lâm phong ấn","ghiChu":"Mặc cả giảm năm mươi năm đổi một câu trả lời nhưng nàng không hợp tác, nên bị nhốt vào quả cầu cấm chế cất trong túi trữ vật."},{"ten":"Động Phủ Chi Linh (động phủ tiên cấm)","tag":"khac","quanHe":"Linh thể canh giữ động phủ giải đáp cho y","ghiChu":"Cho biết điều kiện tư cách tiến vào, Hộ Phủ Thần Thông, cách mở phong ấn và rời đi."},{"ten":"Đô Thống Hắc Giáp quân","tag":"doi-thu","quanHe":"Chỉ huy quân doanh Hắc Giáp quân, ra lệnh giết Vương Lâm rồi bị hắn áp chế.","ghiChu":"Đối đầu @c0526"},{"ten":"Tần Lâm","tag":"doi-thu","quanHe":"Đô thống yêu dân bị Vương Lâm đánh bại rồi tha","ghiChu":"Kẻ đã mang Thập Tam đi dâng cho Yêu Tướng"},{"ten":"Yêu Tương đại nhân","tag":"doi-thu","quanHe":"Đối tượng Vương Lâm quyết xông cung đòi người","ghiChu":"Kẻ thu nhận Thập Tam"},{"ten":"Lão già quản lý quân doanh Hắc Giáp","tag":"doi-thu","quanHe":"Đối thủ","ghiChu":"Lão già từng để ý tới hắn hơn một năm trước, lần này hóa mãng xà đánh lén và bị hắn giết bằng Hóa Ma Chỉ tại cửa thứ ba."},{"ten":"Đệ nhất Đô Thống","tag":"doi-thu","quanHe":"Đối thủ","ghiChu":"Đô Thống thấp bé chặn Hoàng Tuyền Chỉ của hắn cách ba tấc rồi bị đẩy lùi xô sập cửa, phun huyết bắn ra xa."},{"ten":"Người cao lớn (Thập Băng Quyền ý)","tag":"doi-thu","quanHe":"Đối thủ","ghiChu":"Cao thủ trấn cửa thứ nhất, tung Thập Băng Quyền ý nghênh chiến ngang ngửa Hoàng Tuyền Chỉ."},{"ten":"Mạc Lệ Hải","tag":"doi-thu","quanHe":"Đối thủ rồi tạm thời quy phục dưới danh nghĩa","ghiChu":"Bị Vương Lâm dùng chưởng ấn hư ảo uy hiếp, phong Vương Lâm làm Tả dực đệ nhất phó tướng."},{"ten":"Thập Tam","tag":"dong-minh","quanHe":"Thuộc hạ trung thành","ghiChu":"Nhận sáu tầng Cự Linh Cửu Tu, quỳ thề cả đời chỉ tuân mệnh Vương Lâm và tôn hắn làm Lão tổ."},{"ten":"Hổ Bào","tag":"doi-thu","quanHe":"Thuộc hạ cũ trở mặt","ghiChu":"Từng được Vương Lâm truyền Luyện Hồn Thuật; nay nuôi hận vì chờ Vương Lâm cứu khỏi hắc lao vô vọng, thề báo thù."},{"ten":"Mạc Lực Hải","tag":"dong-minh","quanHe":"Đồng hành tới kinh đô Thiên Yêu quận","ghiChu":"Gặp ở tường thành cửa đông Cổ Yêu thành, cùng qua ba truyền tống trận."},{"ten":"Huyết Tổ Diêu Tinh Hải","tag":"doi-thu","quanHe":"Mục tiêu treo đầu — giam con gái làm con tin tìm đường sống","ghiChu":"Thừa nhận tu vi Huyết Tổ vượt xa mình."},{"ten":"Mạc Lệ Hải","tag":"dong-minh","quanHe":"Yêu tướng kết giao, bảo chứng thân phận “Vương tướng” và mời về phủ","ghiChu":"Mạc Lệ Hải dặn thuộc hạ gặp Vương Lâm như gặp chính mình"},{"ten":"Trần Đào","tag":"su-mon","quanHe":"Sư huynh đồng hệ","ghiChu":"Gặp lại trên quân đạo Thiên Yêu quận; Vương Lâm tặng đan dược thiện chí và tính liên kết đối phó Đại La Kiếm Tông."},{"ten":"Thạch Tiễn","tag":"khac","quanHe":"Người thanh niên tà dị đi cùng Trần Đào","ghiChu":"Kình địch của Mạc Lệ Hải trong cuộc chiến Yêu tướng."},{"ten":"Lý Mộ Uyển","tag":"the-thiep","quanHe":"Người thân đã mất, hiện ở trong Hạt Châu Thiên Nghịch","ghiChu":"Tiếng đàn trên thuyền hoa gợi hắn nhớ tiếng đàn của nàng ở sơn cốc Chu Tước Tinh; hắn thề sẽ gặp lại nàng."},{"ten":"Cô gái mù trên thuyền hoa","tag":"khac","quanHe":"Người dưng gặp thoáng qua","ghiChu":"Đi ngang thuyền hoa nghe nàng gảy đàn; nàng cảm nhận được bóng hắn tan vào đêm."},{"ten":"Mạc Lệ Hải","tag":"dong-minh","quanHe":"Đối tác giao dịch — yêu tu chủ Mạc phủ, sắp xếp cho Vương Lâm vào Hồng lao đổi lấy sự trợ giúp","ghiChu":"@c0535"},{"ten":"Minh Huyên","tag":"khac","quanHe":"Nữ tử đánh đàn trên hoa thuyền; tiếng đàn bi thương của nàng khiến Vương Lâm cảm ngộ về đạo","ghiChu":"@c0535"},{"ten":"Nam tử họ Hứa","tag":"dong-minh","quanHe":"Người phụ trách Hồng lao tiếp nhận và chỉ điểm sát tâm cho Vương Lâm; ra điều kiện đổi việc giết yêu tướng Thạch Tiễn.","ghiChu":"Gặp @c0536."},{"ten":"Mạc Lệ Hải","tag":"dong-minh","quanHe":"Đưa Vương Lâm tới Hồng lao, trả giá ba tầng đầu Thập Băng Quyền Ý để hắn được vào tu luyện.","ghiChu":"@c0536."},{"ten":"Thanh Sương","tag":"khac","quanHe":"Danh tính trong thanh âm thần bí Vương Lâm nghe được khi đắc kim phù ấn","ghiChu":"Tự xưng “Ta là Thanh Sương”, thân phận chưa rõ"},{"ten":"Nam tử họ Hứa","tag":"an-nhan","quanHe":"Người canh giữ bậc thang cao nhất Hồng Lao, dẫn Vương Lâm trốn thoát; có giao hẹn chưa tiết lộ giữa hai người","ghiChu":"@c0537"},{"ten":"Thanh niên áo xanh (trên họa thuyền)","tag":"khac","quanHe":"Đối ẩm từ xa bên sông, nâng rượu chào nhau; gọi Vương Lâm là “tiểu tử rất thú vị”","ghiChu":"@c0537"},{"ten":"Phó soái Huyền Thành","tag":"doi-thu","quanHe":"Bị Vương Lâm trấn áp","ghiChu":"Phó soái Thiên Yêu Thành kiêu ngạo coi thường Vương Lâm, bị một chiêu sát lục chi khí ép lui và gây nội thương."},{"ten":"Mạc Lệ Hải","tag":"cap-tren","quanHe":"Chủ tướng (Vương Lâm làm phó tướng)","ghiChu":"Vương Lâm đánh giá Mạc Lệ Hải tâm cơ sâu, thủ đoạn nhiều, không bất lực như đang thể hiện."},{"ten":"Nam tử lớn tuổi áo đen (đầu lĩnh sát thủ)","tag":"doi-thu","quanHe":"Đầu lĩnh nhóm sát thủ truy bắt Vương Lâm","ghiChu":"Kinh hãi gọi tên Sát Lục Đạo khi thấy ánh mắt của Vương Lâm.","gap":"@c0540"},{"ten":"Sát thủ số hai (thanh niên áo đen)","tag":"doi-thu","quanHe":"Đối thủ trực tiếp, bị Sát Lục Đạo áp chế suýt sụp đổ tâm thần","gap":"@c0540"},{"ten":"Sát thủ số bốn (trung niên mắt sáng)","tag":"doi-thu","quanHe":"Bị Vương Lâm giết bằng Tịch Diệt Nhất Chỉ","gap":"@c0540"},{"ten":"Mạc Lệ Hải","tag":"dong-minh","quanHe":"Đồng minh người Mạc phủ, chờ Vương Lâm xuất quan ba ngày rồi báo tin bại trận trước Mặc Phi","ghiChu":"@c0542"},{"ten":"Mặc Phi","tag":"doi-thu","quanHe":"Đệ nhất nhân trong đám Yêu Tướng, đối thủ tiềm tàng trong cuộc tranh đoạt sắp tới","ghiChu":"@c0542"},{"ten":"Thạch Tiêu","tag":"doi-thu","quanHe":"Yêu Tướng khiêu chiến rồi hăm dọa giết Vương Lâm cho hả giận","ghiChu":"Gặp tại trận chiến Yêu Tướng @c0543"},{"ten":"Ngao Địch","tag":"doi-thu","quanHe":"Yêu Tướng ra khiêu chiến, bị Vương Lâm coi thường","ghiChu":"@c0543"},{"ten":"Huyền Phó Soái","tag":"doi-thu","quanHe":"Phó Soái có thù cũ, căm ghét nhưng tin Vương Lâm sẽ dẫn đầu","ghiChu":"@c0543"},{"ten":"Hoàng Phó Soái","tag":"khac","quanHe":"Phó Soái nghi ngờ thực lực Vương Lâm, đánh cược về hắn với Huyền Phó Soái","ghiChu":"@c0543"},{"ten":"Ngao Địch","tag":"doi-thu","quanHe":"Yêu Tướng bị Vương Lâm đánh phế kinh mạch và xương cốt thành phế nhân tại đại hội","ghiChu":"@c0544"},{"ten":"Nam tử mặc giáp vàng","tag":"doi-thu","quanHe":"Kim tổng quản can thiệp cứu Ngao Địch, bị Vương Lâm đẩy lui trường thương rồi đe dọa tội trảm — kết mối ân oán","ghiChu":"@c0544"},{"ten":"Mạc Lệ Hải","tag":"dong-minh","quanHe":"Người chiêu mộ Vương Lâm, mừng thầm vì quyết định sáng suốt khi thấy uy thế của hắn","ghiChu":"@c0544"},{"ten":"Thanh niên trên thuyền tranh","tag":"khac","quanHe":"Người lạ mời lên thuyền tranh nghe đàn uống rượu, cùng nhận nhau là tục nhân","ghiChu":"Đối thoại tại Hồng Thành @c0545"},{"ten":"Minh Phí (cô nương)","tag":"khac","quanHe":"Nữ tử đánh đàn trên thuyền tranh, tiếng đàn khơi cảm ngộ của Vương Lâm","ghiChu":"@c0545"},{"ten":"Thiếu môn chủ Ngọc Kiếm Môn (nam tử áo trắng)","tag":"khac","quanHe":"Cảm phục Vương Lâm, cáo từ trước khi dẫn đoàn rời Thiên Yêu Thành","ghiChu":"@c0545"},{"ten":"Mạt Dương","tag":"doi-thu","quanHe":"Kẻ địch bị giết","ghiChu":"Kiếm Tiếu Thập Nhị Tử của Đại La Kiếm Tông; khiêu chiến Vương Lâm tại Mạc phủ, bị hóa giải kiếm khí, đoạt kiếm bản mệnh rồi âm thầm hạ sát hóa thây khô."},{"ten":"Nam tử mặc kim giáp","tag":"doi-thu","quanHe":"Chủ trì vòng hai phụng mệnh Đế Quân, tỏa sát khí với Vương Lâm và thách đánh cược","ghiChu":"Gặp tại Thiên Yêu Môn @c0546"},{"ten":"Mặc Phi","tag":"doi-thu","quanHe":"Yêu Tướng đệ nhất gõ 8 tiếng Chiến Yêu Cổ; Vương Lâm nhận ra giống nam tử tóc đen Hồng Lao","ghiChu":"@c0546"},{"ten":"Huyền Phó Soái","tag":"khac","quanHe":"Phó Soái chọn Vương Lâm để đánh cược, âm thầm cho rằng hắn đáng sợ","ghiChu":"@c0546"},{"ten":"Tà Liên","tag":"khac","quanHe":"Nữ yêu tướng duy nhất chú ý tới Vương Lâm khi hắn gõ trống","ghiChu":"Mắt đẹp lóe tinh quang nhìn Vương Lâm trên khán đài"},{"ten":"Tà Liên","tag":"doi-thu","quanHe":"Nữ Yêu tướng châm biếm Vương Lâm","ghiChu":"Lộ vẻ châm biếm, ngầm hỏi Vương Lâm có vứt bỏ được cảm động lưu luyến không (@c0549)."},{"ten":"Trần Đào","tag":"doi-thu","quanHe":"Người chọn đưa Vương Lâm đến giúp Yêu tướng","ghiChu":"Lần đầu thấy chán ghét Vương Lâm (@c0549)."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[{"ten":"Tiên ngọc","loai":"tài nguyên tu luyện","trangThai":"dang-co","moTa":"123.600 khối tiên ngọc lấy từ Phẩm Linh Các, dùng để hấp thu đột phá Anh Biến trung kỳ","nguon":"@c0458"}],"linhThao":[],"khac":[{"ten":"Lệnh bài Phẩm Linh Các","loai":"vật phẩm","trangThai":"da-dung","moTa":"Lệnh bài lấy tiên ngọc, ấn vào trận pháp ba đạo bạch ngân để mở cửa truyền tống lên tầng bảy và xác nhận thân phận lĩnh tiên ngọc","nguon":"@c0458"}]}},"nguon":["@c0458","@c0459","@c0460","@c0461","@c0462","@c0463","@c0464","@c0465","@c0466","@c0467","@c0468","@c0469","@c0470","@c0471","@c0472","@c0473","@c0474","@c0476","@c0477","@c0478","@c0479","@c0480","@c0483","@c0484","@c0485","@c0487","@c0488","@c0489","@c0490","@c0491","@c0492","@c0493","@c0494","@c0495","@c0496","@c0497","@c0498","@c0499","@c0500","@c0501","@c0502","@c0503","@c0504","@c0505","@c0506","@c0507","@c0508","@c0509","@c0510","@c0511","@c0512","@c0513","@c0514","@c0515","@c0516","@c0517","@c0518","@c0519","@c0520","@c0522","@c0523","@c0524","@c0525","@c0526","@c0527","@c0528","@c0529","@c0530","@c0531","@c0532","@c0533","@c0534","@c0535","@c0536","@c0521","@c0537","@c0538","@c0539","@c0540","@c0542","@c0543","@c0545","@c0541","@c0546","@c0547","@c0548","@c0549"]},{"id":"truong-huong-pham","name":"Trương Hướng Phàm","gioiTinh":"nam","tabs":{"diem":[],"kinhLich":[{"text":"Trương Hướng Phàm ấn lệnh bài vào chỗ ba đạo bạch ngân giao nhau, kích hoạt trận pháp tạo cánh cửa truyền tống tại tầng thứ bảy Phẩm Linh Các, rồi cung kính mời Thất sư tổ Vương Lâm cầm lệnh bài tiến vào.","bridge":true,"khoang":"@c0458"}],"tuViMoc":[],"tuVi":"","nhanMach":[{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Cung kính dẫn Thất sư tổ Vương Lâm vào Phẩm Linh Các lấy tiên ngọc","ghiChu":"@c0458"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0458"]},{"id":"trieu-tinh-sat","name":"Triệu Tinh Sát","gioiTinh":"nam","tabs":{"diem":[],"kinhLich":[{"text":"Sắc mặt ôn hòa tiêu sái, Triệu Tinh Sát hiện ra từ gợn sóng bên cạnh Vương Lâm, là một trong năm người hợp vây tại Tử Lâm Các.","bridge":true,"khoang":"@c0458"},{"text":"Trong khi canh giữ tử vụ đại trận trước thọ yến, độc thoại điểm danh sáu vị tử còn lại (lão nhị bỏ cuộc, lão tam không để vào mắt, lão tứ nữ có cách giữ, lão ngũ bị phạt thiên ngục, lão lục xuất ngoại sinh tử chưa rõ), cảnh cáo lão thất chớ tranh đoạt với mình.","bridge":true,"khoang":"@c0460"},{"text":"Nhận ra Kim Ma tử trên chiến xa vàng, toát mồ hôi lạnh cung kính ra mắt rồi dẫn đường đưa chiến xa về Thiên Vận Tinh dự thọ yến.","bridge":true,"khoang":"@c0460"},{"chuong":"@c0461","importance":"normal","tieuDe":"Chủ tọa thọ yến Thiên Vận Tử","text":"Đại sư huynh Tử hệ nhất mạch ngồi chủ tọa tiệc thọ yến ngàn năm của sư tôn Thiên Vận Tử; vừa đứng dậy chúc rượu thì Vương Lâm — kẻ hắn từng mượn sức người ngoài na di vây khốn trong thạch lâm — xuất hiện thành cầu vồng tím từ chân trời đằng đông lao thẳng tới."},{"text":"Sắc mặt cực xấu khi thấy Vương Lâm phá vây đạt Anh Biến Trung Kỳ, bóp nát chén rượu. Lão bước ra chắn trước nhị sư huynh, thi triển Đại tự tại thiên địa quyết tạo quầng sáng trắng bọc ma hỏa, nhưng bị ma hỏa tự bạo thiêu vỡ nên phải lui lại.","bridge":true,"khoang":"@c0462"},{"text":"Sau khi cản thất bại, Triệu Tinh Sát đứng nhìn Hứa Lập Quốc bị Vương Lâm truy sát mà cười lạnh, không hề ra tay cứu, hé lộ rạn nứt và toan tính trong nội bộ Tử hệ.","bridge":true,"khoang":"@c0462"},{"text":"Bị Vương Lâm dồn ép và bị lão tứ từ chối trợ giúp, Triệu Tinh Sát dùng trước thuật triệu Cổ Yêu vốn định để dành cho dịp tranh danh hiệu Thiên Vận Thất Tử. Ký hiệu cổ quái lóe giữa lông mày gọi ra hư ảnh yêu vật trăm trượng, nhưng càng dùng thân thể hắn càng suy yếu.","bridge":true,"khoang":"@c0463"},{"chuong":"@c0463","importance":"normal","tieuDe":"Phản phệ và tham kiến Xích Liệt","text":"Cổ yêu bị tiếng hét của Xích Liệt buộc rút lui, Triệu Tinh Sát phun máu, cười u ám nhìn Vương Lâm. Hắn cung kính tham kiến Xích Liệt sư thúc, xác nhận mấy ngàn năm trước khi mới bái nhập Thiên Vận Tông từng gặp mặt một lần."},{"chuong":"@c0464","importance":"normal","tieuDe":"Bị Xích Liệt áp giải","text":"Sau khi gượng dùng yêu linh chưa kịp luyện hóa, Triệu Sát Tinh bị Xích Liệt túm mang đi để sư phụ trừng phạt, mất chức chủ yến hội về tay Vương Lâm."}],"tuViMoc":[],"tuVi":"","nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Tham gia nhóm năm người vây kích Vương Lâm","ghiChu":"@c0458"},{"ten":"Thiên Vận Tử","tag":"su-mon","quanHe":"sư tôn","ghiChu":"Triệu Tinh Sát là đại sư huynh Tử hệ thuộc Thiên Vận Thất tử của Thiên Vận Tử."},{"ten":"Kim Ma tử","tag":"khac","quanHe":"khách chúc thọ","ghiChu":"Cung kính nghênh đón, dẫn đường về Thiên Vận Tinh."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"đối thủ ngầm (nghi là lão thất)","ghiChu":"Triệu Tinh Sát cảnh cáo lão thất, đối tượng có thể chính là Vương Lâm."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Sư đệ bị hắn chèn ép, na di vây khốn","ghiChu":"Vương Lâm trở về quyết báo thù giữa thọ yến."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối đầu, cản bất thành rồi bị ma hỏa đánh lui","ghiChu":""},{"ten":"Hứa Lập Quốc","tag":"khac","quanHe":"Đồng môn Tử hệ mà Triệu Tinh Sát bỏ mặc không cứu","ghiChu":""},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối thủ, bị hắn tố giết lão nhị","ghiChu":"Định dùng Cổ Yêu trừ Vương Lâm nhưng thất bại."},{"ten":"Tứ sư tỷ (Tử hệ)","tag":"khac","quanHe":"Cầu viện trợ nhưng bị từ chối","ghiChu":"Lão tứ viện cớ đã đền ân ba tháng trước và không tranh danh hiệu."},{"ten":"Xích Liệt","tag":"su-mon","quanHe":"Sư thúc Thiên Vận Tông","ghiChu":"Tham kiến cung kính, từng gặp mấy ngàn năm trước."},{"ten":"Xích Liệt","tag":"su-mon","quanHe":"Tiền bối tông môn áp giải","ghiChu":"Bị Xích Liệt túm đi sau khi gượng dùng yêu linh."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0458","@c0460","@c0461","@c0462","@c0463","@c0464"],"aliases":["Triệu Sát Tinh"]},{"id":"tu-ma-nhu-phong","name":"Tư Mã Như Phong","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Lam tông (Thiên Vận Tông)","trangThai":"gan-bo"},{"ten":"Thiên Vận Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Anh Biến kỳ","trangThai":"song","blurb":"Đệ tử đứng hàng thứ hai thuộc Lam tông của Thiên Vận Tông, y phục lam thêu ba con lam long, tươi cười ôn hòa nhưng tham gia vây kích Vương Lâm.","vaiTro":"Đệ tử Lam tông Thiên Vận Tông, một trong năm người vây kích Vương Lâm","tinhCach":[{"text":"Tươi cười ôn hòa nhưng ngầm hiểm, khéo quan sát đối thủ","chuong":"@c0458"}],"tabs":{"diem":[{"text":"Y phục lam thêu ba con lam long, đứng hàng thứ hai trong đệ tử Lam tông","chuong":"@c0458"}],"kinhLich":[{"text":"Tư Mã Như Phong tươi cười hiện thân trong nhóm vây kích Vương Lâm tại Tử Lâm Các, đoán Vương Lâm đã Anh Biến hậu kỳ đại viên mãn, rồi giới thiệu một vị sư huynh ẩn mình mạnh hơn hẳn.","bridge":true,"khoang":"@c0458"}],"tuViMoc":[],"tuVi":"Đệ tử Anh Biến kỳ đứng hàng thứ hai thuộc Lam tông Thiên Vận Tông.","nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Tham gia vây kích, đoán định tu vi Vương Lâm","ghiChu":"@c0458"},{"ten":"Người y phục xanh (như tượng băng)","tag":"dong-minh","quanHe":"Giới thiệu vị sư huynh ẩn mình nửa bước vấn đỉnh","ghiChu":"@c0458"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0458"]},{"id":"tu-su-ty-tu-he","name":"Tứ sư tỷ (Tử hệ)","cn":"","aliases":["Tứ sư tỷ","Tứ sư tỷ (Tử hệ)"],"gioiTinh":"nu","theLuc":[{"ten":"Tử hệ (Thiên Vận Tông)","trangThai":"gan-bo"},{"ten":"Thiên Vận Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Anh Biến hậu kỳ","trangThai":"song","blurb":"Nữ tử Anh Biến hậu kỳ thuộc Tử hệ Thiên Vận Tông; được người nhờ vả nên ra tay, thi triển Tử thuật - Na di trong cuộc vây kích Vương Lâm.","vaiTro":"Sư tỷ đồng hệ Tử của Vương Lâm, một trong năm người vây kích","tinhCach":[{"text":"Bất đắc dĩ ra tay vì chịu lời nhờ vả của người khác","chuong":"@c0458"}],"tabs":{"diem":[{"text":"Anh Biến hậu kỳ, thuộc Tử hệ và sử dụng Tử thuật","chuong":"@c0458"}],"kinhLich":[{"text":"Bất đắc dĩ thừa nhận được người nhờ vả, tứ sư tỷ bắt quyết điểm vào hư không, một tia sáng bạc lan ra bao trùm mười dặm, mở màn cuộc vây kích Vương Lâm tại Tử Lâm Các.","bridge":true,"khoang":"@c0458"},{"text":"Tứ sư tỷ — nữ tử xinh đẹp như tiên tử đội mũ tơ tằm — dùng thần thông na di đưa Vương Lâm tới thạch lâm khốn địa, hứa sau ba năm sẽ tới thả ra và truyền thần thông na di cho hắn khi mọi chuyện giải quyết xong. Trước khi rời đi, nàng nói với đại sư huynh rằng nhân tình năm đó nay đã hồi báo, từ nay hai người không còn liên quan, rồi hóa ngân quang bay về Thiên Vận Tông.","bridge":true,"khoang":"@c0459"},{"text":"Khi Triệu Tinh Sát lớn tiếng cầu viện, lão tứ bình thản đáp ân tình ba tháng trước đã đền đáp và đã đồng ý không tranh đoạt danh hiệu Thiên Vận Thất Tử với hắn, đòi một lý do mới chịu ra tay. Triệu Tinh Sát cắn răng tức giận mất chỗ dựa.","bridge":true,"khoang":"@c0463"},{"chuong":"@c0464","importance":"normal","tieuDe":"Trao ngọc giản hai cấm pháp","text":"Đêm khuya yến tàn, tứ sư tỷ đưa Vương Lâm một ngọc giản chứa cấm pháp đại na di cùng một cấm pháp do sư tôn phỏng theo hạ phẩm tiên thuật sáng tạo, coi như xin lỗi việc tháng trước — lúc đó nàng dùng cấm pháp phong ấn nhưng chưa thực sự ra tay."},{"bridge":true,"khoang":"@c0465","text":"Trong thọ yến, Tứ sư tỷ truyền âm than thở với Vương Lâm rằng Tử Tông đang sa sút vì tranh đoạt nội bộ quá nhiều, danh hiệu Thiên Vận Thất Tử thay đổi thường xuyên, không còn uy phong như thời Tôn Vân sư đệ năm xưa."},{"bridge":true,"khoang":"@c0468","text":"Tứ sư tỷ thần thái như thường, bình tĩnh trụ vững khảo nghiệm áp lực cùng Vương Lâm; khi thấy hắn vượt trội nàng liếc một cái đầy thâm ý nhưng không nói gì."},{"text":"Sau khi Bạch Vi bỏ cuộc, Triệu Hân Mộng nhíu mắt nhìn Vương Lâm, đòi giao chiến một trận để hắn không đạt phong hiệu quá đơn giản. Khi khai chiến nàng giật lui hơn mười trượng, vận Tử Ma thủ — thần thông tự sáng chế bằng cách mô phỏng Hoá Ma chỉ của Vương Lâm — đẩy tử quang gào rít lao tới.","bridge":true,"khoang":"@c0469"},{"text":"Triệu Hân Mộng bắt chước Tử Ma thủ dụ Vương Lâm dùng Hoá Ma chỉ để cướp ma lực, định không tranh phong hiệu Thiên Vận Thất tử với hắn. Nàng dùng hạt châu trắng hút ma lực khiến nó hoá đen, nhưng Vương Lâm khiến ma lực hư ảo tự sụp, hạt châu vỡ vụn; nàng đe doạ nhưng bị từ chối.","bridge":true,"khoang":"@c0470"},{"text":"Nàng thi Cửu chuyển luyện tiên quyết tu ra kim sắc lốc xoáy năm vòng, nhưng kinh ngạc khi Vương Lâm chỉ vài ngày đã đạt ngũ chuyển lại rút chiến phủ và Xạ Thần xa. Triệu Hân Mộng thừa nhận đã xem thường hắn rồi rời đi, sau đó truyền âm cho Trần Đào về việc Tôn Vân.","bridge":true,"khoang":"@c0470"}],"tuViMoc":[],"tuVi":"Nữ tử Anh Biến hậu kỳ thuộc Tử hệ Thiên Vận Tông.","nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đồng hệ Tử nhưng ra tay vây kích theo lời nhờ vả","ghiChu":"@c0458"},{"ten":"Vương Lâm","tag":"su-mon","quanHe":"Sư đệ đồng môn (lão thất)","ghiChu":"Đích thân na di đưa hắn tới khốn địa, hẹn ba năm thả; hứa truyền thần thông na di."},{"ten":"Đại sư huynh (Thiên Vận Tông)","tag":"doi-thu","quanHe":"Sư huynh đồng môn, từng có nhân tình","ghiChu":"Tuyên bố nhân tình năm xưa đã hồi báo, cắt đứt quan hệ với đại sư huynh."},{"ten":"Triệu Tinh Sát","tag":"khac","quanHe":"Người từng chịu ân, nay cầu viện","ghiChu":"Lão tứ từ chối trợ giúp."},{"ten":"Vương Lâm","tag":"su-mon","quanHe":"Sư đệ cùng Tử hệ","ghiChu":"Trao ngọc giản hai cấm pháp xin lỗi việc tháng trước."},{"ten":"Tôn Vân","tag":"su-mon","quanHe":"Sư đệ Tử Hệ thời còn uy phong, được nhắc lại khi than về sự sa sút","ghiChu":""},{"ten":"Vương Lâm","tag":"su-mon","quanHe":"Đồng môn Tử hệ","ghiChu":"Hai người duy nhất của Tử hệ trụ vững khảo nghiệm; Tứ sư tỷ liếc Vương Lâm đầy thâm ý trước biểu hiện vượt trội của hắn."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Lão Thất đồng môn","ghiChu":"Khiêu chiến và giao chiến với Vương Lâm; mô phỏng Hoá Ma chỉ của hắn thành Tử Ma thủ."},{"ten":"Thiên Vận Tử","tag":"su-mon","quanHe":"Sư phụ"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Thất sư đệ Tử hệ (giả danh)","ghiChu":"Gài bẫy hấp thu ma lực bất thành, đánh giá thấp rồi bỏ cuộc."},{"ten":"Trần Đào","tag":"su-mon","quanHe":"Đồng môn Tử hệ","ghiChu":"Truyền âm cho Trần Đào về việc Tôn Vân khiến hắn biến sắc."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[{"ten":"Tử thuật - Na di","moTa":"Pháp thuật Tử hệ, bắt quyết điểm vào hư không phát tia sáng bạc bao trùm mười dặm","nguon":"@c0458"}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0458","@c0459","@c0463","@c0464","@c0465","@c0468","@c0469","@c0470"]},{"id":"nguoi-y-phuc-xanh-tuong-bang","name":"Người y phục xanh (như tượng băng)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thiên Vận Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Nửa bước vấn đỉnh kỳ","trangThai":"song","blurb":"Vị sư huynh ẩn mình do Tư Mã Như Phong giới thiệu; lạnh lùng như chúa tể thiên hạ, tu vi đã bước nửa bước vào vấn đỉnh kỳ.","vaiTro":"Cường giả ẩn mình trong nhóm vây kích Vương Lâm","tinhCach":[{"text":"Lạnh lùng kiêu ngạo, đứng như tượng băng ngàn năm, coi đối thủ không xứng để ra tay","chuong":"@c0458"}],"tabs":{"diem":[{"text":"Tu vi nửa bước vấn đỉnh kỳ, ánh mắt đầy vẻ chúa tể thiên hạ","chuong":"@c0458"}],"kinhLich":[{"text":"Một tiếng nói lạnh như băng vang lên, người y phục xanh xuất hiện sau lưng Vương Lâm vài chục trượng, đứng như tượng băng ngàn năm, liếc một cái rồi nhắm mắt dưỡng thần vì coi Vương Lâm không xứng để ra tay.","bridge":true,"khoang":"@c0458"}],"tuViMoc":[],"tuVi":"Tu vi đã bước nửa bước vào vấn đỉnh kỳ.","nhanMach":[{"ten":"Tư Mã Như Phong","tag":"dong-minh","quanHe":"Được Tư Mã Như Phong giới thiệu là sư huynh ẩn mình","ghiChu":"@c0458"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Tham gia vây kích nhưng coi Vương Lâm không xứng để ra tay","ghiChu":"@c0458"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0458"]},{"id":"thuy-to-thien-van-tong","name":"Thủy tổ đại nhân (Thiên Vận Tông)","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[{"ten":"Thiên Vận Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"khong-ro","blurb":"Thủy tổ của Thiên Vận Tông; từng dặn chỉ cần Vương Lâm không phạm môn quy thì khỏi quản, và cạnh tranh nội bộ giữa đệ tử của ông cực kỳ khốc liệt.","vaiTro":"Thủy tổ tông môn Thiên Vận Tông, được nhắc tên","tinhCach":[],"tabs":{"diem":[],"kinhLich":[{"text":"Được ba chấp pháp trưởng lão nhắc tới: Thủy tổ từng dặn chỉ cần Vương Lâm không phạm môn quy thì khỏi quản; cạnh tranh nội bộ giữa các đệ tử của ông cực kỳ khốc liệt.","bridge":true,"khoang":"@c0458"}],"tuViMoc":[],"tuVi":"","nhanMach":[{"ten":"Vương Lâm","tag":"su-mon","quanHe":"Thủy tổ tông môn, ra lệnh không quản chừng nào Vương Lâm chưa phạm môn quy","ghiChu":"@c0458"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0458"]},{"id":"dai-su-huynh-thien-van-tong","name":"Đại sư huynh (Thiên Vận Tông)","gioiTinh":"nam","tabs":{"diem":[],"kinhLich":[{"text":"Đại sư huynh là người bố trí trận pháp tại thạch lâm khốn địa để vây Vương Lâm — màn sáng bạc bao phủ mười dặm, triệt tiêu mọi kiếm quang pháp bảo phóng ra. Bị tứ sư tỷ tuyên bố cắt đứt nhân tình năm xưa khi nàng đưa Vương Lâm tới đây.","bridge":true,"khoang":"@c0459"}],"tuViMoc":[],"nhanMach":[{"ten":"Tứ sư tỷ (Tử hệ)","tag":"doi-thu","quanHe":"Sư muội đồng môn, từng có nhân tình","ghiChu":"Bị tứ sư tỷ tuyên bố nhân tình đã hồi báo, từ nay không còn liên quan."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Sư đệ đồng môn","ghiChu":"Bố trí trận pháp vây khốn Vương Lâm tại thạch lâm."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0459"]},{"id":"hua-lap-quoc","name":"Hứa Lập Quốc","gioiTinh":"nam","tabs":{"diem":[],"kinhLich":[{"bridge":true,"khoang":"@c0459–@c0459","text":"Là khí linh trong tiên kiếm của Vương Lâm, được điều khiển cùng loan đao lao thử phá trận pháp khốn địa nhưng thất bại, kêu thảm rằng không phá nổi thứ này rồi bị thu về."},{"text":"Là nhị sư huynh Tử hệ Thiên Vận Tông, hóa tử quang nghênh chiến Vương Lâm, phóng Thượng chi lực hóa đám cát như bầy ong nhưng bị Cấm Phiên xé tan. Hắn dùng cấm thuật Tiên Ma thể hóa toàn thân thành sương mù đen để trốn, viện cớ hôm nay là đại thọ sư tôn, song bị tiên kiếm cùng loan đao chém tan, cuối cùng nguyên thần bị Côn Cực Tiên đánh trúng, trọng thương sắp tan.","bridge":true,"khoang":"@c0462"},{"text":"Bị nhốt trong kiếm tiên của Vương Lâm, Hứa Lập Quốc lên tiếng kiêu ngạo và cùng thanh loan đao đuổi theo, giam giữ lão già thấp người Trưởng lão Đại La Kiếm Tông đang bỏ chạy.","bridge":true,"khoang":"@c0483"},{"chuong":"@c0527","importance":"normal","tieuDe":"Gầm rú trong tiên kiếm","text":"Tồn tại như hồn/khí linh trong tiên kiếm của Vương Lâm. Khi Vương Lâm thả tiên kiếm bay ra trước cửa thứ sáu để chuẩn bị xông cung, bên trong kiếm truyền ra tiếng gầm rú liên tục của Hứa Lập Quốc."},{"chuong":"@c0545","importance":"normal","tieuDe":"Bại lộ kế làm phản, bị trấn áp","text":"Si mê thiếu nữ Kiếm Linh (Đế Kiếm), Hứa Lập Quốc phá phong tỏa lải nhải đòi Vương Lâm thả ra tìm tiểu mỹ nhân, mắng Vương Lâm ghen tị. Hắn lén cùng Tiểu Hắc làm yếu cấm chế, biến thành hình kiếm phá cấm chế bỏ chạy ra khỏi Thiên Yêu Thành nhưng bị Vương Lâm dùng cấm chế kéo về, quỳ cầu xin và khai toàn bộ thần thông học từ Kiếm Linh."}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"cap-tren","quanHe":"Chủ tử","ghiChu":"Gọi Vương Lâm là Chủ tử, được sai phá vây bất thành."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Bị Vương Lâm truy sát, đả thương nguyên thần giữa thọ yến","ghiChu":""},{"ten":"Triệu Tinh Sát","tag":"khac","quanHe":"Đồng môn Tử hệ đứng nhìn không cứu khi hắn bị giết","ghiChu":""},{"ten":"Tiểu Hắc (Tiểu Hắc Đao)","tag":"dong-minh","quanHe":"Cùng giao lưu, học thần thông Kiếm Linh; sau khi bị thu phục, loan đao đi theo bên cạnh hắn","ghiChu":"@c0545"},{"ten":"Đế Kiếm (thiếu nữ Kiếm Linh)","tag":"khac","quanHe":"Si mê gọi là “tiểu mỹ nhân”; bị Đế Kiếm thề chém nếu gặp lại","ghiChu":"@c0545"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0459","@c0462","@c0483","@c0527","@c0545"],"aliases":["Lão nhị","Nhị sư huynh"]},{"id":"kim-ma-tu","name":"Kim Ma tử","gioiTinh":"nam","tabs":{"diem":[{"text":"Tôn giả độc chiếm một tiểu tinh, hoành hành ngang ngược, tính nóng nảy, giết người vô số.","chuong":"@c0460"},{"text":"Thân to như quả cầu thịt, da trong suốt như thủy tinh.","chuong":"@c0460"}],"kinhLich":[{"text":"Đáp chiến xa vàng cao hơn ngàn trượng do bốn yêu thú khổng lồ nâng đỡ, kèm mười tùy tùng trường sam bạc, tới Thiên Vận Tinh dự thọ yến; được Triệu Tinh Sát cung kính dẫn đường, thân phận chỉ đủ ngồi ở thọ tiệc do Xích tông tổ chức.","bridge":true,"khoang":"@c0460"}],"tuViMoc":[{"chuong":"@c0460","canhGioi":"Thông thiên (đồn đạt Hư Thật nhị ý)","text":"Tu vi loại thông thiên, có lời đồn đã chạm tới cảnh giới truyền thuyết Hư Thật nhị ý.","importance":"major"}],"nhanMach":[{"ten":"Thiên Vận Tử","tag":"khac","quanHe":"khách chúc thọ","ghiChu":"Tự thân tới chúc đại thọ ngàn năm."},{"ten":"Triệu Tinh Sát","tag":"khac","quanHe":"người nghênh đón","ghiChu":"Được dẫn đường về Thiên Vận Tinh."}],"tuiDo":{"phapBao":[{"ten":"Chiến xa màu vàng của Kim Ma tử","trangThai":"dang-co","moTa":"Chiến xa khổng lồ cao hơn ngàn trượng đầy mũi nhọn, bốn yêu thú nâng đỡ; trên xe có ghế lớn và mười tùy tùng.","nguon":"@c0460"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"theLuc":[{"ten":"Thiên Vận Tông","trangThai":"danh-nghia"}],"canhGioiCaoNhat":"Thông thiên","trangThai":"song","vaiTro":"Tôn giả độc chiếm một tiểu tinh thuộc Thiên Vận Tông, khách chúc thọ Thiên Vận Tử.","blurb":"Tôn giả thân tròn như cầu thịt da trong như thủy tinh, hoành hành ngang ngược, tu vi thông thiên đồn đạt Hư Thật nhị ý.","nguon":["@c0460"]},{"id":"tao-nhat-dau","name":"Tào Nhất Đấu","gioiTinh":"nam","tabs":{"diem":[],"kinhLich":[{"text":"Được Vương Lâm phất hồn phiên thả nguyên thần ra, Tào Nhất Đấu nhận ra đây chính là Thiên Vận Tinh quê cũ, chỉ về hướng tây cách khoảng ba mươi vạn dặm là sơn môn Thiên Vận Tông; hắn tình nguyện dẫn đường vì được hứa cho một thân thể anh biến.","bridge":true,"khoang":"@c0461"},{"chuong":"@c0519","importance":"normal","tieuDe":"Giám định Huyết Hồn đan cho Vương Lâm","text":"Bị Vương Lâm rung hồn phiên triệu ra, hồn phách Tào Nhất Đấu biến sắc khi nghe tên Huyết Tổ và Huyết Hồn đan. Hắn xác nhận đèn đúng là Huyết Hồn đan với 3614 ký tự phù văn, nhỏ máu lóe sáng lam, là một trong ba bảo vật Thiên Vận tinh, đồng thời lộ vẻ thèm muốn; nhưng cũng phân tích đây là mưu k��� phế đan của Huyết Tổ vì phương pháp phân biệt quá phổ biến."}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Người thu nhận nguyên thần của hắn ở Thi Âm tông","ghiChu":"Làm người dẫn đường để đổi lấy lời hứa một thân thể anh biến."},{"ten":"Vương Lâm","tag":"cap-tren","quanHe":"Chủ nhân khống chế hồn phách, sai giám định Huyết Hồn đan","ghiChu":"Từng dẫn đường cho Vương Lâm ở Chu Tước tinh"}],"tuiDo":{}},"nguon":["@c0461","@c0519"]},{"id":"thien-van-tu-su-ton","name":"Thiên Vận Tử","cn":"","aliases":["Sư tôn Tử tông"],"gioiTinh":"nam","theLuc":[{"ten":"Thiên Vận Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Sư tôn của Tử tông trong Thiên Vận Tông, được tông môn mở thọ yến ngàn năm và sẽ giảng đạo sau bảy ngày.","vaiTro":"Sư tôn của Tử hệ nhất mạch, nhân vật cấp cao trên Thiên Vận Tinh.","tinhCach":[],"tabs":{"diem":[{"text":"Bậc sư tôn được cả Tử tông tổ chức thọ yến ngàn năm","chuong":"@c0461"}],"kinhLich":[{"text":"Thiên Vận Tông mở thọ yến ngàn năm mừng sư tôn Thiên Vận Tử, bày tiệc tiên quả sơn tửu náo nhiệt; bảy ngày thọ yến xong sẽ là ngày Thiên Vận Tử giảng đạo, một tháng sau là kỳ Tử Hoàng nhị tông tranh đoạt danh hiệu Thiên Vận Thất tử.","bridge":true,"khoang":"@c0461"},{"chuong":"@c0465","importance":"normal","tieuDe":"Chủ trì đại thọ vạn năm, giảng Thiên Vận Chi Đạo","text":"Thiên Vận Tử xuất hiện trên quầng sáng bảy màu, được đệ tử đích hệ bảy tông và vô số tu sĩ tham bái. Ông mời lão bằng hữu Tôn trưởng lão từ tu chân liên minh xuất hiện, nhận phi kiếm trung phẩm tiên khí rồi tặng lại Côn Bằng Tử, sau đó khoanh chân ngồi giảng Thiên Vận Chi Đạo với cốt lõi ‘nghe theo mệnh trời’."},{"text":"Ngồi khoanh chân trên tường vân, Thiên Vận Tử giảng đạo cho đệ tử lục hệ và tu sĩ bốn phía: liệt kê bảy cảnh Ngưng Khí tới Vấn Đỉnh thuộc chữ ‘tu’ (bước một), bước hai là hư thực nhị ý và toái niết tam cảnh nơi hầu hết tu sĩ phải dừng chân, bước ba là chữ ‘đạo’ cầu thiên vận. Hắn phân biệt tu tiên, tu chân, tu đạo và thừa nhận chính mình bước một còn chưa hoàn thành.","bridge":true,"khoang":"@c0466"},{"text":"Đáp lời hoài nghi của Vương Lâm, Thiên Vận Tử than nhẹ lộ vẻ bồi hồi hiếm thấy, kể rằng ba ngàn năm trước hắn cũng không tin có bước thứ ba cho tới khi gặp được ‘hắn’ — một nhân vật bí ẩn cực mạnh.","bridge":true,"khoang":"@c0466"},{"text":"Kết thúc ba ngày giảng đạo nhân đại thọ vạn năm, trước truy hỏi của tu sĩ, Thiên Vận Tử tiết lộ về “hắn” — kẻ duy nhất lão biết đã đạt tới bước thứ ba và từng khiến Tu Chân Liên Minh nếm khổ một lần. Sau đó lão tuyên bố thi triển một trung phẩm Tiên thuật tên Dẫn Tiên thuật, lấy Lăng Thiên Hầu làm đối tượng, phóng xích mang lên trời hiện mảnh màu đỏ mây cuộn như rồng kèm thiên uy giáng xuống.","bridge":true,"khoang":"@c0467"},{"text":"Trong đại thọ vạn năm tuổi, Thiên Vận Tử thi triển Dẫn Tiên thuật (Trung phẩm Tiên thuật), hô “Dẫn độ” cuốn hơn vạn đệ tử Đại La Kiếm Tông mê man bay lên hư không, triệu hư ảnh sứ giả Tiên giới ấn chưởng phong kín; làm nhục Kiếm Tôn Lăng Thiên Hầu và hứa ba ngày sau trả người.","bridge":true,"khoang":"@c0468"},{"text":"Lão công bố trong bảy hệ đệ tử chỉ Hoàng hệ và Tử hệ chưa ai nắm phong hiệu Thiên Vận Thất tử, hôm nay sẽ xuất hiện người mang phong hiệu từ hai hệ này; nh��c lại lão Tam Hoàng hệ từng đạt phong hiệu rồi mất tích ở tinh không ba mươi năm trước.","bridge":true,"khoang":"@c0468"},{"text":"Thiên Vận Tử chủ trì phân phong hiệu Thiên Vận Thất tử, trao tinh thể vàng cho Côn Bằng Tử của Hoàng hệ và nhấn mạnh phong hiệu là dấu hiệu thân phận của Thiên Vận Tông. Khi Vương Lâm định bỏ cuộc, lão ngẩn ra rồi đích thân khuyên giải, cho nửa nén hương suy xét, dặn đừng để người ngoài mê hoặc; lão liếc Vận Đường bằng ánh mắt âm trầm khiến lão này run sợ.","bridge":true,"khoang":"@c0469"},{"text":"Lão hé lộ ba vạn năm trước từng gặp ‘hắn’, người để lại lời rằng chỉ khi tìm được kẻ phù hợp số phận mới tiến được bước thứ ba của Thiên Vận đạo. Suốt ba vạn năm lão thất bại vô số lần, tổn thất hơn nửa đệ tử, nay chăm chú nhìn ngón trỏ Vương Lâm để xét hắn có phải người đó, ánh mắt cuối cùng lộ một tia chán nản.","bridge":true,"khoang":"@c0469"},{"text":"Sắp đại thọ vạn năm, Thiên Vận Tử nhận đoá Thất thải lưu ly quang từ Trần Đào, phán chỉ Trần Đào và Vương Lâm đủ tư cách tranh phong hiệu Thiên Vận Thất tử nhưng chỉ một người đạt; hắn tán thưởng cả hai trong trận giao đấu.","bridge":true,"khoang":"@c0470"},{"chuong":"@c0472","importance":"normal","tieuDe":"Kết thúc đại thọ, thu nhận Vương Lâm","text":"Tuyên Trần Đào thắng và trao phong hiệu Thiên Vận Thất tử của Tử hệ; kết thúc đại thọ vạn năm tuổi khiến tu sĩ tản đi. Nhận Vương Lâm làm đệ tử chân chính, đưa về Tổng tông ba ngọn núi tại Thiên Vận Tinh, khảo Vương Lâm câu đố Chân huyễn pháp rồi sắp đặt khảo nghiệm leo Toái Tiên chi địa."},{"chuong":"@c0473","importance":"normal","tieuDe":"Thu Vương Lâm làm đệ tử Tử hệ","text":"Thiên Vận Tử triệu Vương Lâm lên đỉnh, kể nguồn gốc Thiên Vận Tông: tổ tiên không phải tu sĩ mà là Thiên vận số, cả đời theo đuổi Thiên vận, tin hết thảy vận số là trời định. Lão vốn không định tới Chu Tước Tinh, vừa lúc gặp Vương Lâm đang cảm ngộ Hóa Thần tìm bản nguyên thiên đạo nên vì quý tài và vận số thầy trò mà thu làm đệ tử thứ bảy của Tử hệ. Lão xé không trung tỏa ánh sáng bảy màu Tối hỉ thất thải chiếu rọi gần nửa bầu trời Thiên Vận Tinh, rồi hỏi Vương Lâm chọn loại Cấm pháp thần thông nào."},{"chuong":"@c0474","importance":"normal","tieuDe":"Mở 3600 Cấm pháp thần thông cho đệ tử","text":"Thiên Vận Tử bình tĩnh để Vương Lâm tự chọn thần thông, từ chối yêu cầu ‘Sinh tồn pháp thuật’ (vi sư không có), rồi nâng tay phải điểm ánh sáng bảy màu, mở ra thế giới bảy màu chứa 3600 đạo Cấm pháp thần thông để đệ tử chọn theo cơ duyên. Lão sở hữu thần thông bảy màu (Tối hỷ khẩu thất thải) và từng có hứa hẹn với Thiên Vận Tử áo xám."},{"text":"Ngày thành đạo từng mời bạn tốt (gồm Kiếm Tôn Lăng Thiên Hậu) lập nhóm đến Đông Hải thăm dò ba lần: hai lần đầu về tay không, lần thứ ba vào được bên trong nhưng ra chỉ còn nửa quân số; sau đó tách với Lăng Thiên Hậu, không ai nói ra chuyện đã xảy ra.","bridge":true,"khoang":"@c0486"},{"chuong":"@c0486","importance":"normal","tieuDe":"Tuyên bố Đông Hải thành cấm địa","text":"Tuyên bố trong Đông Hải có Cổ Yêu tồn tại, lập nơi này thành một trong những cấm địa — cửa Đông Hải Yêu Linh; cùng Lăng Thiên Hậu và các lão quái thống nhất không cho người ngoài tiến vào, khiến Tu Chân Liên Minh đành để mặc."},{"text":"Thiên Vận Tử mặc áo trắng từ đám mây bảy màu bước ra, dẫn chín đệ tử Thiên Vận Tông tới cửa Đông Hải Yêu Linh và được nghênh đón long trọng nh��t. Lão cùng Trần Đào tìm kiếm Vương Lâm, khi hắn tới thì bảo đứng phía sau, nhắc xem trọng việc trọng đại và nhìn hắn đầy thâm ý.","bridge":true,"khoang":"@c0488"},{"bridge":true,"khoang":"@c0489","text":"Quan sát thủy triều Đông Hải Yêu Linh, ánh mắt bình tĩnh ngầm lấp lánh tia sáng bảy màu, băn khoăn không biết lần này vật gì sẽ bị hút đến."},{"bridge":true,"khoang":"@c0490","text":"Sắc mặt khẽ biến rồi vội xoay người khi con sóng hồng quang cuối ập tới; đại biến sắc khi khối lệnh bài kim quang lộ ra giữa thủy triều cửa Đông Hải Yêu Linh."},{"text":"Điều mười đệ tử Thiên Vận Tông (gồm Vương Lâm) vào cánh cửa; xác nhận có tất cả ba cái lệnh bài liên quan đại bí mật Thiên Vận Tinh, ước định năm trăm năm sau theo chu kỳ thí luyện sẽ tụ tập tiến vào lần nữa, dặn mọi người chuẩn bị cẩn thận vì chuyện năm đó.","bridge":true,"khoang":"@c0491"},{"chuong":"@c0491","importance":"normal","tieuDe":"Bói vận may Vương Lâm","text":"Về bảo tháp bảy màu trong dãy núi tam sắc ở Thiên Vận Tinh, rải vài mẩu xương thú đen kịt tỏa khí tà dị quanh mình để quan sát, nhận xét Vương Lâm là kẻ may mắn nhưng ngầm hỏi vận may còn lại bao nhiêu, khóe miệng lộ nụ cười."}],"tuViMoc":[],"nhanMach":[{"ten":"Tôn trưởng lão","tag":"ban-be","quanHe":"Lão bằng hữu từ tu chân liên minh, được mời dự đại thọ","ghiChu":"Xưng hô thân mật, gọi nhau là lão quái."},{"ten":"Côn Bằng Tử","tag":"su-mon","quanHe":"Đệ tử đầu lĩnh Hoàng Hệ, được tặng phi kiếm tiên khí","ghiChu":""},{"ten":"Hắc y nhân (mặt sẹo)","tag":"khac","quanHe":"Tu sĩ hắc y mặt sẹo trầm giọng hỏi hắn về bước thứ ba của tu đạo giữa buổi giảng.","ghiChu":""},{"ten":"Lăng Thiên Hầu","tag":"doi-thu","quanHe":"khách dự đại thọ kiêm đối tượng thi triển Tiên thuật","ghiChu":"Hai cao thủ đối thoại trêu chọc nhau; Lăng Thiên Hầu lạnh lùng đồng ý làm đối tượng để Thiên Vận Tử biểu diễn Dẫn Tiên thuật."},{"ten":"Lăng Thiên Hầu","tag":"doi-thu","quanHe":"Khách dự thọ bị làm nhục","ghiChu":"Thiên Vận Tử ra tay với đệ tử Đại La Kiếm Tông của Lăng Thiên Hầu, khiến lão âm trầm trách móc nhưng đành nhẫn nhịn chờ ba ngày."},{"ten":"Vận Đường","tag":"su-mon","quanHe":"Đệ tử lão đại Hoàng hệ","ghiChu":"Thiên Vận Tử nhìn Vận Đường bằng ánh mắt thâm thuý rồi âm trầm khi lão nhường phong hiệu và lộ biểu hiện quỷ dị."},{"ten":"Trần Đào","tag":"su-mon","quanHe":"Đệ tử lâu năm","ghiChu":"Nhận kỳ bảo Trần Đào dâng, cho hắn tranh phong hiệu."},{"ten":"Vương Lâm","tag":"su-mon","quanHe":"Đệ tử chân chính mới thu nhận","ghiChu":"Hứa truyền Cấm pháp thần thông và pháp bảo bản mạng, cho đặc ân tự chọn."},{"ten":"Trần Đào","tag":"su-mon","quanHe":"Đệ tử Tử hệ","ghiChu":"Trao phong hiệu Thiên Vận Thất tử."},{"ten":"Lăng Thiên Hầu","tag":"khac","quanHe":"Kiếm Tôn có ước hẹn","ghiChu":"Ba tháng sau phải tuyển người tiến vào Đông Hải Yêu Linh chi môn."},{"ten":"Vương Lâm","tag":"su-mon","quanHe":"Đệ tử thứ bảy của Tử hệ","ghiChu":"Thu nhận sau khi Vương Lâm đạt ý cảnh nhập thể hai mươi bảy bước."},{"ten":"Thiên Vận Tử áo xám","tag":"khac","quanHe":"Có hứa hẹn từ trước; nhờ đó người áo xám mới truyền Sát Lục Tiên quyết cho đệ tử của Thiên Vận Tử","ghiChu":"@c0474"},{"ten":"Lăng Thiên Hậu","tag":"ban-be","quanHe":"Bạn cũ cùng thăm dò Đông Hải","ghiChu":"Sau lần thứ ba thì tách ra, giữ kín bí mật."},{"ten":"Huyết Tổ Diêu Tinh Hải","tag":"doi-thu","quanHe":"Đối thủ","ghiChu":"Bị Huyết Tổ bảy lần khiêu chiến."}],"tuiDo":{}},"nguon":["@c0461","@c0465","@c0466","@c0467","@c0468","@c0469","@c0470","@c0472","@c0473","@c0474","@c0486","@c0488","@c0489","@c0490","@c0491"]},{"id":"bach-vi","name":"Bạch Vi","cn":"","gioiTinh":"nam","trangThai":"song","tabs":{"diem":[],"kinhLich":[{"text":"Khi Vương Lâm phá vây xông vào thọ yến, mắt Bạch Vi lộ tia kỳ dị, chỉ mỉm cười khó hiểu mà ung dung uống rượu, không hề ra tay, gợi ý còn ẩn tình giữa các đệ tử Tử hệ.","bridge":true,"khoang":"@c0462"},{"chuong":"@c0464","importance":"normal","tieuDe":"Lộ tâm tư báo thù đại sư huynh","text":"Trên đường về Tử Vi Các, Bạch Vi lộ vẻ ác độc, lẩm bẩm trách sư tôn bất công đã cấy yêu linh vào thân đại sư huynh — nếu yêu linh thức tỉnh, đại sư huynh khôi phục bản lãnh thì hắn vĩnh viễn không báo được thù; ngoài mặt vẫn chúc mừng Vương Lâm."},{"bridge":true,"khoang":"@c0468","text":"Trong khảo nghiệm áp lực phân loại đệ tử Tử hệ, Bạch Vi kiên trì thêm một lúc rồi than thầm, rơi xuống ngồi trên mặt đất."},{"bridge":true,"khoang":"@c0469","text":"Trong cuộc tranh phong hiệu, Bạch Vi cung kính tuyên bố bỏ cuộc."},{"text":"Đệ tử Tử hệ Bạch Vi nhận ra Trần Đào khi hắn trở về, sắc mặt không tự nhiên và im lặng.","bridge":true,"khoang":"@c0470"}],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Cùng phe Tử hệ; quan sát Vương Lâm trở lại với nụ cười kỳ dị","ghiChu":""},{"ten":"Đại sư huynh (Tử hệ)","tag":"doi-thu","quanHe":"Đối tượng báo thù","ghiChu":"Lo yêu linh thức tỉnh sẽ khôi phục bản lãnh đại sư huynh, hắn không báo được thù."},{"ten":"Thiên Vận Tử","tag":"su-mon","quanHe":"Sư tôn","ghiChu":"Trách sư tôn bất công đã cấy yêu linh vào thân đại sư huynh."},{"ten":"Trần Đào","tag":"su-mon","quanHe":"Đồng môn Tử hệ","ghiChu":"Nhận ra Trần Đào, sắc mặt không tự nhiên."}],"tuiDo":{},"tuViMoc":[]},"nguon":["@c0462","@c0464","@c0468","@c0469","@c0470"]},{"id":"xich-liet","name":"Xích Liệt","cn":"","aliases":["Xích Liệt sư thúc","Lão già mặt đỏ hồng bào"],"gioiTinh":"nam","theLuc":[{"ten":"Thiên Vận Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ (cao thâm)","trangThai":"song","blurb":"Sư thúc trong Thiên Vận Tông, lão già hồng bào mặt đỏ đeo hồ lô rượu; chỉ một tiếng hét đã buộc cổ yêu rút lui.","vaiTro":"Sư thúc bậc trên trong Thiên Vận Tông","tinhCach":[{"text":"Phóng khoáng, ham rượu, tiếc chén rượu dở dang hơn cả việc đệ tử đánh nhau","chuong":"@c0463"},{"text":"Nể sợ tổ sư Thiên Vận Tử","chuong":"@c0463"}],"tabs":{"diem":[{"text":"Hóa từ một đám mây đỏ, sặc mùi rượu, mắng đệ tử đánh nhau làm dở chén rượu","chuong":"@c0463"},{"text":"Uy nghiêm trấn yêu: chỉ một tiếng hét “Nghiệt súc! Cút đi cho ta!” đã khiến cổ yêu run rẩy buông mồi","chuong":"@c0463"}],"kinhLich":[{"text":"Khi cổ yêu định nuốt Hồn Thú của Vương Lâm, từ tổng tông Thiên Vận Tông vang tiếng hét của Xích Liệt buộc cổ yêu thu nhỏ rút về. Một đám mây đỏ hóa thành lão già hồng bào mặt đỏ đeo hồ lô, mắng các đệ tử đánh nhau và lo Thiên Vận Tử trách.","bridge":true,"khoang":"@c0463"},{"text":"Xích Liệt khẳng định yêu linh trong Triệu Sát Tinh vừa hình thành đã gượng dùng, túm hắn để sư phụ trừng phạt; tiết lộ sư phụ kỳ vọng cao ở Vương Lâm và đại sư huynh sẽ không xuất hiện tranh danh hiệu Thiên Vận Thất Tử, rồi hóa mây đỏ mang Triệu Sát Tinh bay đi.","bridge":true,"khoang":"@c0464"},{"chuong":"@c0464","importance":"minor","tieuDe":"Báo lịch giảng đạo","text":"Trước khi rời đi, Xích Liệt ôm quyền xin lỗi các tu sĩ tông phái và thông báo hôm sau là ngày sư huynh Thiên Vận Tử giảng đạo."}],"tuVi":"Cảnh giới chưa nêu rõ, song uy thế đủ trấn áp cổ yêu chỉ bằng một tiếng hét.","nhanMach":[{"ten":"Triệu Tinh Sát","tag":"su-mon","quanHe":"Đệ tử bậc dưới trong tông","ghiChu":"Triệu Tinh Sát tham kiến, từng gặp mấy ngàn năm trước."},{"ten":"Vương Lâm","tag":"su-mon","quanHe":"Đệ tử trong tông","ghiChu":"Tiếng hét của Xích Liệt vô tình cứu Hồn Thú của Vương Lâm."},{"ten":"Thiên Vận Tử","tag":"su-mon","quanHe":"Tổ sư mà Xích Liệt nể sợ","ghiChu":"Sợ bị Thiên Vận Tử trách phạt."},{"ten":"Thiên Vận Tử","tag":"su-mon","quanHe":"Sư huynh","ghiChu":"Báo lịch giảng đạo hôm sau của sư huynh."},{"ten":"Triệu Tinh Sát","tag":"khac","quanHe":"Đệ tử cháu (lão đại Tử hệ) bị áp giải","ghiChu":"Túm đi sau khi hắn gượng dùng yêu linh chưa luyện hóa."}],"tuiDo":{"phapBao":[{"ten":"Hồ lô lớn","loai":"vật đựng rượu","moTa":"Hồ lô lớn đeo sau lưng, đựng rượu; Xích Liệt sặc mùi rượu khi xuất hiện.","nguon":"@c0463"}]},"tuViMoc":[]},"nguon":["@c0463","@c0464"]},{"id":"khuong-thien-ton","name":"Khương Thiên Tôn","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thủy Vân Môn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Vấn Đỉnh Hậu Kỳ","trangThai":"song","blurb":"Trưởng lão Vấn Đỉnh Hậu Kỳ của Thủy Vân Môn; người nhận ra hư ảnh là cổ yêu trong truyền thuyết thượng cổ và gọi tên Yêu lực.","vaiTro":"Trưởng lão Thủy Vân Môn, kiến thức uyên bác về thượng cổ","tinhCach":[{"text":"Trầm tĩnh, ngồi im suốt bảy ngày quan sát","chuong":"@c0463"}],"tabs":{"diem":[{"text":"Suốt bảy ngày ngồi im, chỉ nhẹ giọng khi nhận ra cổ yêu truyền thuyết","chuong":"@c0463"}],"kinhLich":[{"text":"Khi hư ảnh yêu vật xuất hiện, Khương Thiên Tôn nghi đó là cổ yêu trong truyền thuyết thượng cổ và xác nhận “Rất giống”. Lúc khí tức cổ yêu vượt xa linh lực, sánh ngang tiên lực và ma hỏa của Vương Lâm, ông gọi đó là “Yêu lực”.","bridge":true,"khoang":"@c0463"}],"tuViMoc":[{"chuong":"@c0463","canhGioi":"Vấn Đỉnh Hậu Kỳ","text":"Ra mặt với cảnh giới Vấn Đỉnh Hậu Kỳ, một trong các Vấn Đỉnh trưởng lão hiện diện.","importance":"major"}],"nhanMach":[],"tuiDo":{}},"nguon":["@c0463"]},{"id":"nam-tu-ho-vuong-thanh-tong","name":"Nam tử họ Vương (Thanh Tông)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thanh Tông","trangThai":"gan-bo"},{"ten":"Thiên Vận Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Nửa bước Vấn Đỉnh","trangThai":"song","blurb":"Đệ tử Thanh Tông của Thiên Vận Tông, mặt lạnh như băng, đã bước nửa bước vào Vấn Đỉnh — vượt cả Tư Mã Như Phong.","vaiTro":"Đệ tử mạnh của Thanh Tông trong lễ giảng đạo Thiên Vận Tử","tinhCach":[{"text":"Mặt lạnh như băng, ít biểu lộ","chuong":"@c0464"}],"tabs":{"diem":[{"text":"Nửa bước Vấn Đỉnh, vượt Tư Mã Như Phong","chuong":"@c0464"}],"kinhLich":[{"text":"Theo đoàn Thanh Tông kính bái tổng tông trong lễ giảng đạo Thiên Vận Tử; Vương Lâm quét mắt nhận ra hắn đã bước nửa bước vào Vấn Đỉnh, vượt Tư Mã Như Phong.","bridge":true,"khoang":"@c0464"}],"tuViMoc":[{"chuong":"@c0464","canhGioi":"Nửa bước Vấn Đỉnh","text":"Tu vi đã bước nửa bước vào Vấn Đỉnh, vượt cả Tư Mã Như Phong Anh Biến đại viên mãn.","importance":"major"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Cùng dự lễ giảng đạo Thiên Vận Tử","ghiChu":"Bị Vương Lâm nhận ra tu vi nửa bước Vấn Đỉnh."},{"ten":"Tư Mã Như Phong","tag":"doi-thu","quanHe":"Cùng sáu tông Thiên Vận Tông","ghiChu":"Tu vi vượt Tư Mã Như Phong."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0464"]},{"id":"nguoi-trung-nien-cam-tong","name":"Người trung niên Cam Tông","cn":"","aliases":["Người đàn ông trung niên (Cam Tông)"],"gioiTinh":"nam","theLuc":[{"ten":"Cam Tông","trangThai":"gan-bo"},{"ten":"Thiên Vận Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Anh Biến Hậu Kỳ","trangThai":"song","blurb":"Đệ tử vị trí thứ tư Cam Tông (Chanh Tông) của Thiên Vận Tông; năm xưa ở tiên giới từng dùng Sát Khí Huyết Tinh đánh nhau với Sất Hổ.","vaiTro":"Cao thủ Cam Tông Vương Lâm nhận ra trong lễ giảng đạo","tinhCach":[],"tabs":{"diem":[{"text":"Năm xưa đánh Sất Hổ ở tiên giới bằng Sát Khí Huyết Tinh","chuong":"@c0464"}],"kinhLich":[{"text":"Đứng vị trí thứ tư đoàn Cam Tông trong lễ giảng đạo Thiên Vận Tử; Vương Lâm nhận ra hắn chính là người năm xưa đánh nhau với Sất Hổ ở tiên giới, khi đó chưa tới Anh Biến nay đã đạt Anh Biến Hậu Kỳ.","bridge":true,"khoang":"@c0464"}],"tuViMoc":[{"chuong":"@c0464","canhGioi":"Anh Biến Hậu Kỳ","text":"Năm xưa ở tiên giới chưa tới Anh Biến, nay đã Anh Biến Hậu Kỳ.","importance":"major"}],"nhanMach":[{"ten":"Sất Hổ","tag":"doi-thu","quanHe":"Đối thủ trận đánh năm xưa ở tiên giới","ghiChu":"Từng dùng Sát Khí Huyết Tinh đánh nhau với Sất Hổ."},{"ten":"Vương Lâm","tag":"khac","quanHe":"Cùng dự lễ giảng đạo, bị nhận ra","ghiChu":"Vương Lâm nhận ra qua ký ức tiên giới."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[{"ten":"Sát Khí Huyết Tinh","trangThai":"dang-co","moTa":"Thần thông/pháp thuật từng dùng đánh Sất Hổ ở tiên giới năm xưa.","nguon":"@c0464"}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0464"]},{"id":"ton-truong-lao","name":"Tôn trưởng lão","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Tu chân liên minh","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ (cao thủ tột bậc tiên giới)","trangThai":"song","blurb":"Cao thủ uy áp tột bậc từ tu chân liên minh, được Thiên Vận Tử mời tới dự đại thọ vạn năm với danh nghĩa lão bằng hữu.","vaiTro":"Lão bằng hữu khách quý của Thiên Vận Tử, cao thủ tu chân liên minh","tinhCach":[{"text":"Hào sảng, thân thiết suồng sã với Thiên Vận Tử, gọi đối phương là Thiên Vận lão quái và đùa cợt thoải mái.","chuong":"@c0465"},{"text":"Uy áp khủng khiếp, chỉ một ánh mắt khiến các cao thủ phải cúi đầu.","chuong":"@c0465"}],"tabs":{"diem":[{"text":"Giáng lâm bằng đạo kim quang vạn trượng ngưng tụ thành trận pháp khổng lồ, khiến mặt trời mất màu, trời đất ảm đạm.","chuong":"@c0465"},{"text":"Dáng vẻ khoảng bốn mươi tuổi, thân hình cường tráng như pho tượng chiến tiên, mặt cương nghị, mắt như có tia chớp, mặc trường bào màu tím.","chuong":"@c0465"},{"text":"Nuôi một con tiểu điêu ba mắt đậu trên vai, tốc độ nhanh hơn tia chớp vô số lần.","chuong":"@c0465"}],"kinhLich":[{"chuong":"@c0465","importance":"normal","tieuDe":"Giáng lâm thọ yến Thiên Vận Tử","text":"Được Thiên Vận Tử mời từ hư không, Tôn trưởng lão hiện thân giữa đại thọ vạn năm, uy áp khiến cao thủ phải cúi đầu. Hắn tặng một thanh phi kiếm trung phẩm tiên khí ngưng luyện vạn năm làm hậu lễ, rồi ngồi một bên nghe Thiên Vận Tử giảng đạo."},{"bridge":true,"khoang":"@c0466–@c0466","text":"Trưởng lão đến từ liên minh tu chân dự buổi giảng đạo; tử điêu đậu lên vai lão nhai nuốt tiên ngọc, lão mỉm cười gật đầu với Vương Lâm. Khi Thiên Vận Tử nhắc tới ‘hắn’, sắc mặt lão lập tức khó coi, hồi tưởng mang theo nhiều vẻ sợ hãi vì rõ ràng biết đó là ai."},{"bridge":true,"khoang":"@c0467","text":"Dự lễ đại thọ vạn năm, Tôn trưởng lão sắc mặt khó coi và muốn ngăn Thiên Vận Tử nhắc về “hắn” nhưng đành để lão nói; vốn quen biết Lăng Thiên Hầu nên có lời chào hỏi khi vị Kiếm Tôn xuất hiện."},{"text":"Tôn trưởng lão xác nhận đoá hoa Trần Đào dâng là Thất thải lưu ly quang, nhận xét hoả hậu còn kém cánh thứ bảy.","bridge":true,"khoang":"@c0470"}],"tuViMoc":[],"tuVi":"Cao thủ tột bậc của tu chân liên minh; thực lực không rõ cảnh giới nhưng uy áp khiến các cao thủ Thiên Vận Tông phải cúi đầu.","nhanMach":[{"ten":"Thiên Vận Tử","tag":"ban-be","quanHe":"Lão bằng hữu, được mời dự đại thọ vạn năm","ghiChu":"Xưng hô thân mật, gọi nhau là lão quái / Thiên Vận lão quái."},{"ten":"Côn Bằng Tử","tag":"khac","quanHe":"Người được Thiên Vận Tử chuyển tặng phi kiếm của ông","ghiChu":""},{"ten":"Vương Lâm","tag":"khac","quanHe":"Đệ tử Tử Hệ bị tiểu điêu ba mắt của ông dò xét riêng","ghiChu":""},{"ten":"Lăng Thiên Hầu","tag":"dong-minh","quanHe":"quen biết","ghiChu":"Lăng Thiên Hầu chào hỏi Tôn trưởng lão như người quen khi tới dự đại thọ."}],"tuiDo":{"phapBao":[{"ten":"Phi kiếm màu vàng (trung phẩm tiên khí)","loai":"phi-kiem","trangThai":"da-dung","moTa":"Trung phẩm tiên khí do Tôn trưởng lão tự ngưng luyện vạn năm, đem tặng Thiên Vận Tử làm hậu lễ thọ yến (sau đó được tặng lại Côn Bằng Tử).","nguon":"@c0465"}],"linhThu":[{"ten":"Tiểu điêu ba mắt","moTa":"Con chim toàn thân màu tím, ba mắt phát tia sáng âm u, đậu trên vai Tôn trưởng lão; tốc độ nhanh hơn tia chớp vô số lần. Trong thọ yến nó bay tới đậu vai Vương Lâm dò xét.","nguon":"@c0465"}]}},"nguon":["@c0465","@c0466","@c0467","@c0470"]},{"id":"con-bang-tu","name":"Côn Bằng Tử","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Hoàng Hệ (Thiên Vận Tông)","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Người đứng đầu Hoàng Hệ của Thiên Vận Tông, được Thiên Vận Tử tặng lại phi kiếm trung phẩm tiên khí trong thọ yến.","vaiTro":"Đầu lĩnh Hoàng Hệ Thiên Vận Tông","tinhCach":[{"text":"Trung thành, dễ xúc động trước ân điển của sư tôn; run rẩy tạ ơn khi nhận bảo vật.","chuong":"@c0465"}],"tabs":{"diem":[{"text":"Đứng đầu Hoàng Hệ, được Thiên Vận Tử ban tặng phi kiếm trung phẩm tiên khí ngay tại thọ yến.","chuong":"@c0465"}],"kinhLich":[{"chuong":"@c0465","importance":"normal","tieuDe":"Nhận phi kiếm trung phẩm tiên khí","text":"Tại đại thọ vạn năm, Thiên Vận Tử nhận thanh phi kiếm trung phẩm tiên khí của Tôn trưởng lão rồi ném tặng lại cho Côn Bằng Tử; hắn run lên xúc động, cung kính tạ ơn sư tôn."},{"chuong":"@c0469","importance":"normal","tieuDe":"Nhận phong hiệu Thiên Vận Thất tử Hoàng hệ","text":"Sau khi Vận Đường nhường ngôi và đề cử, Côn Bằng Tử (Nhị sư đệ Hoàng hệ) được Thiên Vận Tử trao tinh thể vàng — dấu hiệu phong hiệu Thiên Vận Thất tử của Hoàng hệ, hứa truyền một bản Hạ phẩm Tiên thuật đầy đủ nếu giữ phong hiệu ngàn năm và một bảo mệnh pháp bảo khi xuất quan. Hắn kích động quỳ bái nhận lời rồi vào bế quan cảm thụ tinh thể vàng."}],"tuViMoc":[],"tuVi":"Không rõ cảnh giới; là đầu lĩnh Hoàng Hệ Thiên Vận Tông.","nhanMach":[{"ten":"Thiên Vận Tử","tag":"su-mon","quanHe":"Sư tôn / thủy tổ Thiên Vận Tông, ban tặng phi kiếm tiên khí","ghiChu":""},{"ten":"Tôn trưởng lão","tag":"an-nhan","quanHe":"Người ngưng luyện thanh phi kiếm mà hắn được nhận","ghiChu":""},{"ten":"Vận Đường","tag":"su-mon","quanHe":"Đại sư huynh Hoàng hệ","ghiChu":"Vận Đường chủ động bỏ cuộc, đề cử Côn Bằng Tử là người thích hợp nhất với phong hiệu."}],"tuiDo":{"phapBao":[{"ten":"Phi kiếm màu vàng (trung phẩm tiên khí)","loai":"phi-kiem","trangThai":"dang-co","moTa":"Trung phẩm tiên khí do Tôn trưởng lão ngưng luyện vạn năm, được Thiên Vận Tử chuyển tặng tại thọ yến.","nguon":"@c0465"}]}},"nguon":["@c0465","@c0469"]},{"id":"hac-y-nhan-mat-seo","name":"Hắc y nhân (mặt sẹo)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"","trangThai":"khong-ro","blurb":"Tu sĩ mặc hắc y tỏa hung khí, mặt có vết sẹo hung ác chạy từ mặt xuống cổ, hỏi Thiên Vận Tử về bước thứ ba của tu đạo.","vaiTro":"Tu sĩ bí ẩn dự buổi giảng đạo của Thiên Vận Tử.","tinhCach":[{"text":"Trầm tĩnh nhưng ẩn chứa hung khí dày đặc, khiến trong vòng mười trượng quanh thân không tu sĩ nào dám lại gần.","chuong":"@c0466"}],"tabs":{"diem":[{"text":"Quanh thân mười trượng không ai dám lại gần, hung khí cuộn trào, mặt có vết sẹo hung ác từ mặt xuống cổ.","chuong":"@c0466"}],"kinhLich":[{"text":"Giữa buổi giảng đạo trên tường vân, hắc y nhân trầm giọng hỏi Thiên Vận Tử về bước thứ ba của tu đạo, dẫn tới phần giải thích chữ ‘đạo’ và thiên vận.","bridge":true,"khoang":"@c0466"}],"tuViMoc":[],"nhanMach":[{"ten":"Thiên Vận Tử","tag":"khac","quanHe":"Hỏi Thiên Vận Tử về bước thứ ba của tu đạo trong buổi giảng.","ghiChu":""}],"tuiDo":{}},"nguon":["@c0466"]},{"id":"han-bi-an","name":"Hắn (nhân vật bí ẩn)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"","trangThai":"khong-ro","blurb":"Nhân vật bí ẩn Thiên Vận Tử gặp ba ngàn năm trước, khiến hắn tin có bước thứ ba của tu đạo; Tôn trưởng lão biết và lộ vẻ sợ hãi khi nhớ lại.","vaiTro":"Nhân vật cực mạnh được nhắc tới, chưa lộ diện.","tinhCach":[],"tabs":{"diem":[{"text":"Sự tồn tại đủ khiến cả Thiên Vận Tử thay đổi nhận thức về bước thứ ba và khiến Tôn trưởng lão sợ hãi.","chuong":"@c0466"}],"kinhLich":[{"text":"Thiên Vận Tử kể rằng ba ngàn năm trước nhờ gặp ‘hắn’ mới tin có bước thứ ba của tu đạo; Tôn trưởng lão hiển nhiên biết ‘hắn’ là ai và lộ vẻ sợ hãi.","bridge":true,"khoang":"@c0466"},{"bridge":true,"khoang":"@c0467","text":"Được Thiên Vận Tử tiết lộ là kẻ duy nhất lão từng biết đã đạt tới bước thứ ba, từng khiến Tu Chân Liên Minh nếm đau khổ một lần duy nhất; như đoá phù dung sớm nở tối tàn, nay đã biệt tích không tung tích, danh tính bỏ ngỏ."}],"tuViMoc":[],"nhanMach":[{"ten":"Thiên Vận Tử","tag":"khac","quanHe":"Người Thiên Vận Tử gặp ba ngàn năm trước, làm hắn tin có bước thứ ba.","ghiChu":""}],"tuiDo":{}},"nguon":["@c0466","@c0467"]},{"id":"lang-thien-hau","name":"Lăng Thiên Hầu","aliases":["Kiếm Tôn Lăng Thiên Hầu","Lăng Thiên Hậu","Kiếm Tôn"],"gioiTinh":"nam","tabs":{"kinhLich":[{"chuong":"@c0467","importance":"normal","tieuDe":"Kiếm Tôn cưỡi biển phi kiếm dự đại thọ","text":"Kiếm Tôn Lăng Thiên Hầu, Tông chủ Đại La Kiếm Tông trên Thiên Vận Tinh, xuất hiện cùng sấm sét và vô số kiếm quang: một lão già áo xanh râu trắng gầy gò mang khí tức thiên uy, sau lưng có bốn bóng kiếm hư ảo, dưới chân là xà hình bảo kiếm đầy máu tanh. Hắn dẫn hơn vạn đệ tử áo đen đeo kiếm cổ tới chúc thọ, chào hỏi Tôn trưởng lão và lạnh lùng đồng ý làm đối tượng cho Thiên Vận Tử thi triển Tiên thuật."},{"text":"Kiếm Tôn Lăng Thiên Hầu dẫn hơn vạn đệ tử Đại La Kiếm Tông tới chúc thọ; khi Thiên Vận Tử thi triển Dẫn Tiên thuật cuốn đệ tử đi, lão thúc xà hình phi kiếm lao lên rồi triệu Kỳ Lân thú từ mi tâm phản kích, nhưng cuối cùng nhẫn nhịn gọi kiếm tiên về, chờ ba ngày đệ tử trở về.","bridge":true,"khoang":"@c0468"},{"bridge":true,"khoang":"@c0469","text":"Khi Thiên Vận Tử trao phong hiệu Thiên Vận Thất tử cho Côn Bằng Tử, Kiếm Tôn Lăng Thiên Hầu lộ một tia khinh thường."},{"text":"Là quan khách mừng thọ, Kiếm Tôn Lăng Thiên Hầu lộ vẻ kinh ngạc khi thấy Hồn thú khổng lồ Vương Lâm triệu ra từ Xạ Thần xa.","bridge":true,"khoang":"@c0470"},{"text":"Rời đại thọ sớm bằng kiếm quang; trước khi đi nhắc lại ước hẹn với Thiên Vận Tử rằng ba tháng sau lão phải tuyển người tiến vào Đông Hải Yêu Linh chi môn.","bridge":true,"khoang":"@c0472"},{"chuong":"@c0486","importance":"normal","tieuDe":"Cùng thăm dò Đông Hải lần ba","text":"Là người chưa bao giờ nể mặt Thiên Vận Tử nhưng vẫn cùng lập nhóm thăm dò Đông Hải; lần thứ ba vào được bên trong rồi ra chỉ còn nửa quân số, sau đó tách với Thiên Vận Tử và giữ kín chuyện đã xảy ra."},{"text":"Kiếm Tôn Lăng Thiên Hậu dò hỏi Tham Lang về hạt châu, hoãn việc đến sau Đông Hải Yêu Linh, đổi lại yêu cầu Tham Lang vào trong bảo vệ mười hai đệ tử của lão hoàn thành nhiệm vụ bí mật. Lão vạch trần tâm cơ Tham Lang đang bị người giữ hạt châu bức bách, hứa sẽ mở cửa Yêu Linh cho hắn vào.","bridge":true,"khoang":"@c0488"},{"bridge":true,"khoang":"@c0489","text":"Là tu sĩ kỳ cựu từng chứng kiến Đông Hải Yêu Linh, khi thủy triều khởi động hắn ánh mắt lộ tia sáng kỳ dị, lẩm bẩm “Bắt đầu rồi!”."},{"bridge":true,"khoang":"@c0490","text":"Hai mắt tuôn tinh quang khó tưởng tượng, nhìn chằm chằm vào con sóng hồng quang cuối; phải biến sắc trước sự quỷ dị của thủy triều bảo vật cửa Đông Hải Yêu Linh."},{"chuong":"@c0491","importance":"normal","tieuDe":"Mở cánh cửa Đông Hải yêu linh","text":"Chỉ tay về Đông Hải, bốn kiếm ảnh hư ảo sau lưng hóa bốn đạo cầu vồng đánh vào khối nước khổng lồ lơ lửng, mở ra lối vào hỗn độn xanh đỏ dẫn tới một thế giới khác, hô gọi chúng tu sĩ tiến vào rồi thu kiếm đóng cửa."},{"chuong":"@c0491","importance":"normal","tieuDe":"Về Đại La tinh bế quan luyện yêu kiếm","text":"Tiết lộ Đại La kiếm tông đặt ở Đại La tinh do hắn đưa từ tinh không tới; phá cương phong vào đông bộ bế quan, quyết trong hai trăm năm lấy chín chín yêu linh quy nhất luyện Tiên kiếm thành yêu kiếm để chắc tay thu lệnh bài Đông Hải."}],"nhanMach":[{"ten":"Thiên Vận Tử","tag":"doi-thu","quanHe":"đồng cấp/đối thủ thực lực","ghiChu":"Tu vi và thực lực môn phái của hai bên gần tương đương; Lăng Thiên Hầu đồng ý làm đối tượng cho Thiên Vận Tử thi triển Dẫn Tiên thuật."},{"ten":"Tôn trưởng lão","tag":"dong-minh","quanHe":"quen biết","ghiChu":"Chào hỏi Tôn trưởng lão khi tới dự đại thọ."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"ân oán tiềm ẩn","ghiChu":"Vương Lâm nhận ra thanh xà hình bảo kiếm của Lăng Thiên Hầu là Vũ chi đệ nhị kiếm bị cướp ở Tiên giới năm xưa."},{"ten":"Thiên Vận Tử","tag":"doi-thu","quanHe":"Chủ nhân đại thọ làm nhục mình","ghiChu":"Thiên Vận Tử cuốn đi đệ tử Đại La Kiếm Tông của lão; Lăng Thiên Hầu trách móc nhưng biết thân phận đối phương nên đành chờ ba ngày."},{"ten":"Vương Lâm","tag":"khac","quanHe":"Đệ tử Tử hệ trong đám đông","ghiChu":"Kỳ Lân thú của Lăng Thiên Hầu cộng hưởng tiếng gầm với Tôn Hồn Phiên trong người Vương Lâm."},{"ten":"Thiên Vận Tử","tag":"khac","quanHe":"Đại lão có ước hẹn","ghiChu":"Ước hẹn Đông Hải Yêu Linh chi môn."},{"ten":"Thiên Vận Tử","tag":"ban-be","quanHe":"Bạn cũ cùng thăm dò Đông Hải","ghiChu":"Sau lần thứ ba thì tách ra."},{"ten":"Tham Lang","tag":"dong-minh","quanHe":"Cố nhân tới cầu nhờ","ghiChu":"Tham Lang chạy đường xa đến Thiên Vận Tinh tìm lão; Lăng Thiên Hậu ra điều kiện đổi lấy việc giúp hắn."}],"tuiDo":{"phapBao":[{"ten":"Vũ chi đệ nhị kiếm","tenCu":"Xà hình bảo kiếm","trangThai":"dang-co","moTa":"Bảo kiếm hình con rắn đầy máu tanh dưới chân Lăng Thiên Hầu, tế luyện bằng phương pháp khiến người nhìn tâm thần đại chấn; chính là Vũ chi đệ nhị kiếm hắn cướp ở Tiên giới năm đó.","nguon":"@c0467"}]},"tuViMoc":[]},"nguon":["@c0467","@c0468","@c0469","@c0470","@c0472","@c0486","@c0488","@c0489","@c0490","@c0491"]},{"id":"lao-tam-hoang-he-thien-van","name":"Lão Tam (Hoàng hệ)","gioiTinh":"nam","theLuc":[{"ten":"Thiên Vận Tông","trangThai":"gan-bo"}],"trangThai":"mat-tich","blurb":"Đệ tử Hoàng hệ của Thiên Vận Tử, ba mươi năm trước từng đạt phong hiệu Thiên Vận Thất tử rồi mất tích thần bí khi ra tinh không.","vaiTro":"Nhân vật được nhắc tên","tabs":{"diem":[{"text":"Từng mang phong hiệu Thiên Vận Thất tử nhưng một lần ra tinh không thì bặt vô âm tín cho tới nay","chuong":"@c0468"}],"kinhLich":[{"chuong":"@c0468","importance":"normal","tieuDe":"Mất tích ở tinh không","text":"Ba mươi năm trước, lão Tam Hoàng hệ đạt phong hiệu Thiên Vận Thất tử, nhưng trong một lần ra tinh không thì mất tích thần bí, đến nay vẫn bặt tin."}],"tuViMoc":[],"nhanMach":[{"ten":"Thiên Vận Tử","tag":"su-mon","quanHe":"Sư phụ","ghiChu":"Thiên Vận Tử nhắc tới lão Tam khi tuyên bố tranh đoạt phong hiệu Thiên Vận Thất tử cho Hoàng hệ và Tử hệ."}],"tuiDo":{}},"nguon":["@c0468"]},{"id":"van-duong","name":"Vận Đường","aliases":["Đại sư huynh Hoàng hệ","Lão đại Hoàng hệ"],"gioiTinh":"nam","theLuc":[{"ten":"Thiên Vận Tông","trangThai":"gan-bo"},{"ten":"Hoàng hệ","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ","trangThai":"song","blurb":"Lão đại Hoàng hệ, dung mạo xấu xí nhiều nếp nhăn; từng làm Thiên Vận Thất tử hơn 800 năm rồi bị lão Tam đoạt, tính nhàn nhã không tranh đoạt nhưng ẩn giấu điều quỷ dị.","vaiTro":"Đại sư huynh Hoàng hệ, người chủ động nhường phong hiệu nhưng để lộ biểu hiện bí ẩn khiến Vương Lâm và Thiên Vận Tử để ý.","tinhCach":[{"text":"Nhàn nhã, không có tâm tranh đoạt, chỉ thích tu luyện thong dong","chuong":"@c0469"},{"text":"Ẩn giấu điều quỷ dị — mắt co rút và lộ vẻ sợ hãi khi tinh thể vàng xuất hiện","chuong":"@c0469"}],"tabs":{"diem":[{"text":"Từng làm Thiên Vận Thất tử hơn 800 năm rồi bị lão Tam đoạt mất","chuong":"@c0469"},{"text":"Theo Thiên Vận Tử trước cả Côn Bằng Tử (hơn 2000 năm), tính tình quái gỡ không tiếp xúc người khác","chuong":"@c0469"}],"kinhLich":[{"text":"Trong cuộc tranh phong hiệu Hoàng hệ, Vận Đường — chỉ còn lại cùng Côn Bằng Tử — cung kính xin bỏ cuộc, tự nhận không có tâm tranh đoạt và đề cử Nhị sư đệ Côn Bằng Tử là người thích hợp nhất với phong hiệu. Khi tinh thể vàng từ mi tâm Thiên Vận Tử bay ra, hai mắt lão co rút rồi lập tức bình tĩnh; bị Vương Lâm nhìn lâu, lão ngẩng đầu quét mắt rồi khoé miệng mỉm cười, sau lại run sợ trước ánh mắt âm trầm của Thiên Vận Tử.","bridge":true,"khoang":"@c0469"}],"tuViMoc":[],"tuVi":"Tu vi chưa rõ; che giấu rất giỏi, từng đủ sức làm Thiên Vận Thất tử Hoàng hệ hơn 800 năm.","nhanMach":[{"ten":"Côn Bằng Tử","tag":"su-mon","quanHe":"Nhị sư đệ Hoàng hệ","ghiChu":"Vận Đường nhường phong hiệu, đề cử Côn Bằng Tử."},{"ten":"Thiên Vận Tử","tag":"su-mon","quanHe":"Sư phụ","ghiChu":"Bị Thiên Vận Tử nhìn bằng ánh mắt âm trầm khiến run lòng cúi đầu."},{"ten":"Vương Lâm","tag":"khac","quanHe":"Sư đệ đồng môn (Lão Thất)","ghiChu":"Vương Lâm phát hiện biểu hiện quỷ dị của lão; ánh mắt sợ hãi của lão khiến Vương Lâm do dự bỏ cuộc."}],"tuiDo":{}},"nguon":["@c0469"]},{"id":"tran-dao","name":"Trần Đào","aliases":["Tử hệ Lão Lục","Lão Lục"],"gioiTinh":"nam","theLuc":[{"ten":"Thiên Vận Tông","trangThai":"gan-bo"},{"ten":"Tử hệ","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Vấn Đỉnh kỳ","trangThai":"song","blurb":"Tử hệ Lão Lục, đệ tử lâu năm của Thiên Vận Tử, từng đạt phong hiệu Thiên Vận Thất tử trước thời Tôn Vân; trở về đòi tranh lại phong hiệu.","vaiTro":"Đệ tử kỳ cựu Tử hệ trở về tranh phong hiệu, đối thủ mới của Vương Lâm trong tiệc đại thọ.","tinhCach":[{"text":"Kiêu ngạo, khinh thường Vương Lâm, chỉ thừa nhận Tôn Vân mới là Thất sư đệ thật.","chuong":"@c0470"},{"text":"Hiếu chiến, hứng thú trước cường địch — xé áo lộ nửa thân, rút trường thằng nghênh chiến.","chuong":"@c0470"}],"tabs":{"diem":[{"text":"Từng đạt phong hiệu Thiên Vận Thất tử trước Tôn Vân, năm xưa thua Tôn Vân rồi rời tông ra tinh ngoại rèn luyện.","chuong":"@c0470"}],"kinhLich":[{"text":"Một đạo tử khí xông tới hiện ra Trần Đào, dâng cho Thiên Vận Tử đoá Thất thải lưu ly quang cướp được ở Hắc Mặc Tinh — thiên địa kỳ bảo xếp thứ 93 Tu Chân Liên Minh. Hắn đòi lại phong hiệu Thiên Vận Thất tử; khi Triệu Hân Mộng truyền âm về Tôn Vân, hắn biến sắc.","bridge":true,"khoang":"@c0470"},{"chuong":"@c0470","importance":"normal","tieuDe":"Giao chiến Vương Lâm","text":"Trần Đào (Vấn Đỉnh) đánh ấn quyết chấn nhiếp nhưng chỉ đẩy lùi Vương Lâm mười trượng nên kinh ngạc; hắn đẩy ngũ chuyển kim tiên lực của Vương Lâm lên cửu chuyển phản công, rồi nổ tan đòn nuốt của Hồn thú khiến quần áo rách bươm. Hứng thú trước cường địch, hắn xé áo lộ nửa thân, rút ra trường thằng đen như sợi gân sinh vật toả khí tức hoang dã (trận chưa dứt)."},{"text":"Trần Đào khoe Long cân rút từ xác một con yêu long ở Yêu Tinh, vung từ góc độ khó tin buộc lấy cổ Hồn thú của Vương Lâm rồi đứng trên đầu nó siết chặt khống chế.","bridge":true,"khoang":"@c0471"},{"text":"Sau khi Vương Lâm mở phong ấn Xạ Thần xa khiến Hồn thú phản công, Trần Đào dựng tử sắc quang cầu phòng ngự nhưng vẫn bị tổn thương; hắn mỉa mai Vương Lâm “có tư cách làm sư đệ”, bị phản bác, rồi hóa tàn ảnh lao tới tấn công.","bridge":true,"khoang":"@c0471"},{"chuong":"@c0472","importance":"normal","tieuDe":"Thắng Vương Lâm đoạt phong hiệu","text":"Đỡ được hai đạo Hoàng tuyền chỉ của Vương Lâm nhờ trước khi trở về có kỳ ngộ đạt Vấn Đỉnh trung kỳ, thừa nhận một chỉ này vượt ngoài dự liệu. Thắng trận nên được Thiên Vận Tử trao phong hiệu Thiên Vận Thất tử của Tử hệ; lão điểm mi tâm đưa cảm ngộ phong hiệu vào người hắn."},{"bridge":true,"khoang":"@c0488–@c0488","text":"Lão lục Trần Đào, đệ tử Tử hệ mặc áo tím uy áp như kiếm sắc, sốt ruột chờ Vương Lâm tới cửa Đông Hải; khi thấy thân ảnh tử sắc thì mừng thầm gọi “Lão Thất”, rồi nhìn Vương Lâm bằng ánh mắt kỳ dị."},{"chuong":"@c0533","importance":"normal","tieuDe":"Trọng thương vì Đại La Kiếm Tông","text":"Bị mười người Đại La Kiếm Tông tiến vào Yêu Linh Chi Địa liên thủ đánh trọng thương cả Nguyên Thần, tu vi tụt từ Vấn Đỉnh trung kỳ xuống Anh Biến viên mãn. Gặp lại sư đệ Vương Lâm trên quân đạo, nhận túi Tuy Bình đan thiện chí; hắn tính nếu đủ tài liệu sẽ luyện một lò Thiên Nguyên đan để ngắn hạn khôi phục về Vấn Đỉnh sơ kỳ, và hết lời nể phục sức mạnh Vương Lâm."},{"chuong":"@c0546","importance":"normal","tieuDe":"Tự ước lượng gõ bảy tiếng","text":"Tu sĩ Vấn Đỉnh kỳ; ước lượng thời đỉnh cao có thể gõ hơn mười tiếng, nay đã uống đan dược chỉ gõ bảy tiếng (không hơn Mặc Phi). Khen Mặc Phi là đệ nhất dưới Vấn Đỉnh kỳ, tiếc bản thân chưa đạt Vấn Đỉnh trung kỳ."}],"tuViMoc":[{"chuong":"@c0470","canhGioi":"Vấn Đỉnh kỳ","text":"Trần Đào tu vi Vấn Đỉnh, đủ sức đẩy kim tiên lực lên cửu chuyển.","importance":"minor"},{"chuong":"@c0472","canhGioi":"Vấn Đỉnh trung kỳ","text":"Trước khi trở về tham dự đại thọ, nhờ một kỳ ngộ mà đạt tới Vấn Đỉnh trung kỳ, đủ sức đỡ Hoàng tuyền chỉ của Vương Lâm.","importance":"major"},{"chuong":"@c0533","canhGioi":"Anh Biến viên mãn","text":"Vốn ở Vấn Đỉnh trung kỳ, bị Đại La Kiếm Tông đánh trọng thương ảnh hưởng Nguyên Thần nên tụt xuống Anh Biến viên mãn; có thể tạm khôi phục Vấn Đỉnh sơ kỳ nếu luyện được Thiên Nguyên đan.","importance":"major"}],"nhanMach":[{"ten":"Thiên Vận Tử","tag":"su-mon","quanHe":"Sư phụ","ghiChu":"Đệ tử lâu năm, dâng kỳ bảo mừng đại thọ vạn năm của sư phụ."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Tranh phong hiệu Thiên Vận Thất tử","ghiChu":"Khinh thường rồi giao chiến với Vương Lâm."},{"ten":"Tôn Vân","tag":"doi-thu","quanHe":"Người từng đoạt phong hiệu của hắn","ghiChu":"Năm xưa thua Tôn Vân; thừa nhận Tôn Vân mới là Thất sư đệ thật."},{"ten":"Triệu Hân Mộng","tag":"su-mon","quanHe":"Đồng môn Tử hệ","ghiChu":"Triệu Hân Mộng truyền âm về Tôn Vân khiến hắn biến sắc."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối thủ tại lễ chúc thọ","ghiChu":"Trần Đào (Vấn Đỉnh kỳ) tự xưng sư huynh, giao chiến với Vương Lâm."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Sư huynh đệ Tử hệ kiêm đối thủ","ghiChu":"Hẹn tái chiến với Vương Lâm sau khi đối phương đạt Vấn Đỉnh."},{"ten":"Thiên Vận Tử","tag":"su-mon","quanHe":"Trưởng bối Thiên Vận Tông","ghiChu":"Trao phong hiệu Thiên Vận Thất tử."},{"ten":"Vương Lâm","tag":"su-mon","quanHe":"Sư đệ đồng hệ","ghiChu":"Tự nhận Vương Lâm là sư đệ; nhận đan dược thiện chí của Vương Lâm."},{"ten":"Thạch Tiễn","tag":"dong-minh","quanHe":"Đồng hành nâng đỡ","ghiChu":"Thạch Tiễn thu thập tài liệu giúp Trần Đào luyện Thiên Nguyên đan."},{"ten":"Mạc Lệ Hải","tag":"doi-thu","quanHe":"Đối thủ cuộc chiến Yêu tướng","ghiChu":"Trần Đào tự nhận nếu chưa bị thương có thể giết được Mạc Lệ Hải."},{"ten":"Thạch Tiêu","tag":"dong-minh","quanHe":"Đáp Thạch Tiêu hỏi về số tiếng có thể gõ được","ghiChu":"@c0546"}],"tuiDo":{"phapBao":[{"ten":"Trường thằng đen","trangThai":"dang-co","moTa":"Sợi dây như gân sinh vật rút ra từ thân, toả khí tức hoang dã, dùng đối phó Hồn thú.","nguon":"@c0470"}],"khac":[{"ten":"Thất thải lưu ly quang","moTa":"Đoá hoa kỳ bảo cướp ở Hắc Mặc Tinh, dâng cho Thiên Vận Tử.","trangThai":"da-dung","nguon":"@c0470"}]}},"nguon":["@c0470","@c0471","@c0472","@c0488","@c0533","@c0546"]},{"id":"lao-gia-mat-do-ho-lo-do","name":"Lão già mặt đỏ (mang hồ lô đỏ)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"khong-ro","trangThai":"song","blurb":"Vị khách lạ mặt đỏ mang hồ lô đỏ lớn đến lễ chúc thọ, vừa uống rượu vừa nhận ra Hoàng tuyền chỉ của Vương Lâm giống hệt sát chiêu của một “người điên” lão từng gặp.","vaiTro":"Nhân vật bí ẩn quan khán tại lễ chúc thọ","tinhCach":[{"text":"Phóng khoáng, mê rượu","chuong":"@c0471"}],"tabs":{"diem":[{"text":"Nhận ra mối liên hệ giữa sát chiêu Hoàng tuyền chỉ và một “lão quái / người điên” lão từng gặp thuở mới đến nơi này","chuong":"@c0471"}],"kinhLich":[{"text":"Lão già mặt đỏ mang hồ lô đỏ đến chúc thọ, vừa uống rượu vừa ngạc nhiên khi thấy Hoàng tuyền chỉ của Vương Lâm giống hệt sát chiêu của “người điên kia” mà lão từng gặp khi mới tới nơi này; danh tính lão chưa lộ.","bridge":true,"khoang":"@c0471"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Quan khán nhận ra sát chiêu","ghiChu":"Thấy Hoàng tuyền chỉ của Vương Lâm giống sát chiêu một nhân vật bí ẩn lão từng gặp."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0471"]},{"id":"thien-van-tu-ao-xam","name":"Thiên Vận Tử áo xám","aliases":["Người áo xám","Hơn một người"],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Không rõ (siêu việt Vấn Đỉnh)","trangThai":"khong-ro","blurb":"Một Thiên Vận Tử mặc áo bào màu tro, mắt xám, trẻ tuổi hơn các Thiên Vận Tử khác — là người ‘hơn một người’ (thứ 3601) trong thế giới bảy màu, nắm giữ Sát Lục Tiên quyết.","vaiTro":"Nhân vật bí ẩn xuất hiện trong tâm thần Thiên Vận Tử, mời truyền Sát Lục Tiên quyết cho Vương Lâm.","tinhCach":[{"text":"Lạnh lùng, sát khí cực mạnh — chỉ một chữ làm sụp phong ấn của 3600 Thiên Vận Tử","chuong":"@c0474"},{"text":"Kỳ dị, kiêng kỵ con số bảy","chuong":"@c0474"}],"tabs":{"diem":[{"text":"Là ‘hơn một người’ — thực thể thứ 3601 trong thế giới bảy màu, không có tiên lực dao động, mọi công kích xuyên qua như ảo ảnh","chuong":"@c0474"},{"text":"Sát khí mạnh nhất Vương Lâm từng gặp; một chữ ‘Cút!’ đẩy lui 3600 Thiên Vận Tử mấy vạn dặm","chuong":"@c0474"},{"text":"Nắm giữ Sát Lục Tiên quyết, thân được hàng tỷ Sinh chi lạc ấn thủ hộ","chuong":"@c0474"}],"kinhLich":[{"text":"Khi Vương Lâm vào thế giới bảy màu chọn thần thông, người áo xám ngồi thổ nạp bất động giữa 3600 Thiên Vận Tử. Sát khí của lão khiến cả 3600 Thiên Vận Tử hô ‘Phong!’ phong ấn, nhưng một chữ ‘Cút!’ làm phong ấn sụp đổ, để lộ tổng số 3601 — hơn một người.","bridge":true,"khoang":"@c0474"},{"chuong":"@c0474","importance":"normal","tieuDe":"Mời truyền Sát Lục Tiên quyết","text":"Sau sáu lần chạm mặt, người áo xám hỏi Vương Lâm có phải đệ tử Thiên Vận Tử, tiết lộ lão được đưa tới vì Sát Lục Tiên quyết, ra điều kiện ‘không lưu người sống’. Khi Vương Lâm từ chối, lão không đáp câu hỏi về quan hệ với sư phụ, hoá một ngọc giản từ bụi khí để lại rồi biến mất."}],"tuVi":"Cảnh giới chưa nói rõ nhưng siêu việt Vấn Đỉnh; thân được hàng tỷ Sinh chi lạc ấn thủ hộ, dù Thiên Vận Tinh sụp đổ cũng bình yên vô sự.","nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Người thứ sáu được đưa tới; được mời truyền Sát Lục Tiên quyết nhưng từ chối, vẫn được để lại ngọc giản","ghiChu":"@c0474"},{"ten":"Thiên Vận Tử","tag":"khac","quanHe":"Có hứa hẹn từ trước nên mới chịu truyền cho đệ tử của Thiên Vận Tử; quan hệ cụ thể chưa tiết lộ","ghiChu":"@c0474"}],"tuiDo":{"congPhap":[{"ten":"Sát Lục Tiên quyết","trangThai":"dang-co","moTa":"Tiên quyết bắt chước từ một loại Tiên thuật vô danh, dựa vào giết chóc đoạt sinh lực ngưng kết Sinh chi lạc ấn phòng thủ.","nguon":"@c0474"}]}},"nguon":["@c0474"]},{"id":"hua-van-son","name":"Hứa Vân Sơn","cn":"","aliases":["Thiếu Tông Huyền Uyên Phái"],"gioiTinh":"nam","theLuc":[{"ten":"Huyền Uyên Phái","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Anh Biến Trung kỳ","trangThai":"song","blurb":"Thiếu Tông của Huyền Uyên Phái trên Địa Tinh, chủ động ra đón và kết giao với Vương Lâm.","vaiTro":"Thiếu Tông Huyền Uyên Phái, người dẫn dắt Vương Lâm khi tới Địa Tinh và đưa hắn nhậm chức sứ giả Linh Nhạc quốc.","tinhCach":[{"text":"Tinh ý, biết nhìn xa, chủ động kết giao với người có tiềm lực lớn","chuong":"@c0476"}],"tabs":{"diem":[{"text":"Cầm bảo phiến ngọc bích, phong thái ung dung của một Thiếu Tông","chuong":"@c0476"},{"text":"Khi biết sứ giả mới là Tử hệ Lão Thất Vương Lâm thì rung động muốn kết giao sớm","chuong":"@c0476"}],"kinhLich":[{"chuong":"@c0476","importance":"normal","tieuDe":"Nghênh đón sứ giả Tử hệ","text":"Ba ngày trước biết tin từ một bằng hữu Thiên Vận Tông rằng có người Tử hệ sẽ tới Địa Tinh làm sứ giả Linh Nhạc quốc; khi biết đó là Vương Lâm — đệ tử mới của Thiên Vận Tử — hắn cầm bảo phiến ngọc bích cùng mấy Trưởng lão tóc bạc ra Truyền tống trận chờ đón, ôm quyền xưng Thiếu tông và mời với tư cách chủ nhà."},{"bridge":true,"khoang":"@c0476–@c0476","text":"Sau hai ngày quan hệ đã hoà hợp, Hứa Vân Sơn đưa Vương Lâm tới Linh Nhạc quốc nhận chức sứ giả."},{"bridge":true,"khoang":"@c0477","text":"Cùng Vương Lâm bay tới Linh Nhạc quốc đưa hắn nhậm chức Sứ giả, cười cáo từ gọi Vương Lâm là Vương huynh, hẹn ngày sau uống rượu rồi hóa sét bay đi."}],"tuViMoc":[{"chuong":"@c0476","canhGioi":"Anh Biến Trung kỳ","text":"Tu vi ngang hàng Vương Lâm khi gặp mặt.","importance":"minor"}],"nhanMach":[{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Chủ động ra đón và kết giao, làm chủ nhà dẫn Vương Lâm tới Linh Nhạc quốc"},{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Đưa Vương Lâm đến nhậm chức Sứ giả Huyền Uyên Phái, xưng hô thân thiết","ghiChu":"@c0477"}],"tuiDo":{"phapBao":[{"ten":"Bảo phiến ngọc bích","moTa":"Cây quạt gấp màu ngọc bích Hứa Vân Sơn cầm khi ra đón Vương Lâm.","nguon":"@c0476"}]}},"nguon":["@c0476","@c0477"]},{"id":"trieu-tu","name":"Triệu Tứ","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Huyền Uyên Phái","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Hoá Thần (hướng tới hậu kỳ)","trangThai":"song","blurb":"Tu sĩ Huyền Uyên Phái vận hành Truyền tống trận, người tiễn Vương Lâm tới Địa Tinh.","vaiTro":"Tu sĩ trông coi và kích hoạt Truyền tống trận của Huyền Uyên Phái.","tinhCach":[{"text":"Hâm mộ kẻ mạnh, chuyên tâm tu luyện","chuong":"@c0476"}],"tabs":{"diem":[{"text":"Kính gọi Vương Lâm là “Tử hệ Thất sư tổ”, hâm mộ nhìn theo sau khi tiễn","chuong":"@c0476"}],"kinhLich":[{"text":"Triệu Tứ kết quyết đánh một đạo thanh quang vào Truyền tống trận mười dặm, khiến toàn trận chấn động và truyền Vương Lâm rời đi; sau đó hắn lẩm bẩm không biết Thất sư tổ tới Địa Tinh làm gì rồi khoanh chân thổ nạp, quyết sớm đạt Hoá Thần hậu kỳ.","bridge":true,"khoang":"@c0476"}],"tuViMoc":[{"chuong":"@c0476","canhGioi":"Hoá Thần","text":"Đang tu luyện hướng tới Hoá Thần hậu kỳ.","importance":"minor"}],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Vận hành Truyền tống trận tiễn Vương Lâm tới Địa Tinh, kính gọi là Thất sư tổ"}]},"nguon":["@c0476"]},{"id":"lao-to-huyen-minh","name":"Lão Tổ Huyền Minh","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Huyền Uyên Phái","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Vượt Vấn Đỉnh","trangThai":"song","blurb":"Lão Tổ đứng đầu Huyền Uyên Phái trên Địa Tinh, tu vi vượt quá Vấn Đỉnh.","vaiTro":"Người đứng đầu Huyền Uyên Phái, thế lực tu chân mạnh nhất Địa Tinh.","tinhCach":[],"tabs":{"diem":[{"text":"Tu vi vượt quá Vấn Đỉnh, là chỗ dựa của Huyền Uyên Phái","chuong":"@c0476"}],"kinhLich":[{"bridge":true,"khoang":"@c0476–@c0476","text":"Được nhắc tới là Lão Tổ đứng đầu Huyền Uyên Phái — Lục cấp tu chân quốc duy nhất trên Địa Tinh, tu vi vượt quá Vấn Đỉnh."}],"nhanMach":[]},"nguon":["@c0476"]},{"id":"thien-thai-lao-nhan","name":"Thiên Thai lão nhân","cn":"","aliases":["Lão nhân tóc bạc trắng","Cao thủ đệ nhất Linh Nhạc quốc"],"gioiTinh":"nam","theLuc":[{"ten":"Linh Nhạc quốc","trangThai":"gan-bo"},{"ten":"Ngũ Linh Sơn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Anh Biến hậu kỳ đại viên mãn (một chân vào Vấn Đỉnh)","trangThai":"song","blurb":"Cao thủ đệ nhất Linh Nhạc quốc, lão nhân tóc bạc ở Ngũ Linh Sơn, tu vi gần chạm cảnh giới Vấn Đỉnh.","vaiTro":"Tu sĩ mạnh nhất Linh Nhạc quốc; sau khi thăm dò Vương Lâm và thấy Khuất thú thì khiếp sợ, hạ lệnh lập cấm địa quanh Thông Thiên tháp.","tinhCach":[{"text":"Điềm tĩnh, thận trọng, biết tiến thoái","chuong":"@c0477"}],"tabs":{"diem":[{"text":"Tu vi cao nhất Linh Nhạc quốc, đã đặt một chân vào cảnh giới Vấn Đỉnh","chuong":"@c0477"},{"text":"Hấp thu thái âm lực thổ nạp trên đỉnh Ngũ Linh Sơn","chuong":"@c0477"}],"kinhLich":[{"text":"Là cao thủ đệ nhất Linh Nhạc quốc, lão nhân đến Thông Thiên tháp thăm dò vị tân Sứ giả. Ba ngày sau trở về với sắc mặt cực kỳ khó coi, mắt hiện vẻ khiếp sợ vì tận mắt thấy Khuất thú; các tông phái liền truyền lệnh cấm đệ tử bước vào phạm vi ngàn dặm quanh tháp.","bridge":true,"khoang":"@c0477"},{"text":"Lão đang ngồi khoanh chân trên đỉnh Ngũ Linh Sơn hấp thu thái âm lực thì Vương Lâm tìm đến. Lão mở mắt bình tĩnh nói ra mắt Sứ giả đại nhân, Vương Lâm ôm quyền đáp lời.","bridge":true,"khoang":"@c0477"},{"bridge":true,"khoang":"@c0478","text":"Tự trách vì để lão đạo phá quy củ tiến vào phạm vi ngàn dặm quanh Thông Thiên Tháp, kinh động Khuất thú khiến Vương Lâm không thu phục được; cung kính trao Vương Lâm ngọc giản ghi ba chỗ yêu thú tụ tập, nhận ra giữa mi tâm hắn ẩn sát khí và đoán hắn đi vì giết chóc."}],"tuViMoc":[{"chuong":"@c0477","canhGioi":"Anh Biến hậu kỳ đại viên mãn","text":"Tu vi cao nhất Linh Nhạc quốc, gần như đặt một chân vào cảnh giới Vấn Đỉnh.","importance":"major"}],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Tân Sứ giả Huyền Uyên Phái mà lão thăm dò rồi khiếp sợ; cuối chương Vương Lâm tìm đến lão tại Ngũ Linh Sơn","ghiChu":"@c0477"},{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Tôn xưng Sứ giả đại nhân, phục vụ và trao ngọc giản","ghiChu":""}],"tuiDo":{}},"nguon":["@c0477","@c0478"]},{"id":"quach-ta-dat","name":"Quách Tà Dật","aliases":["Quách đại sư huynh"],"gioiTinh":"nam","theLuc":[{"ten":"Đại La Kiếm Tông","trangThai":"gan-bo"}],"trangThai":"song","blurb":"Lục đại đệ tử Đại La Kiếm Tông, đại sư huynh của nhóm năm người tới Địa Ma Bắc Giới.","vaiTro":"Đệ tử kiếm tu Đại La Kiếm Tông","tinhCach":[{"text":"Khéo léo, dùng thủ đoạn mượn danh sư môn để chiếm lợi","chuong":"@c0478"}],"tabs":{"diem":[{"text":"Mượn danh Đại La Kiếm Tông và lời mời trợ trận để chiếm Diệu Kim quả","chuong":"@c0478"}],"kinhLich":[{"text":"Trung tuần mặc trường sam trắng xanh đeo trường kiếm cổ, làm đại sư huynh nhóm năm người, bảo chờ Sư bá rồi mới tiến vào; mâu thuẫn với Thiên Cầm cô nương về Diệu Kim quả, rồi cung kính tham kiến lão sư thúc Hoá Thần hậu kỳ và quỳ một gối ra mắt hai Kiếm Các Trưởng lão.","bridge":true,"khoang":"@c0478"},{"text":"Là tu sĩ Đại La Kiếm Tông, Quách Tà Dật khai với hai Trưởng lão về việc sư môn Thiên Cầm phát hiện Diệu Kim quả, chỉ về phía nàng và cầu xin cho nàng một quả sau khi thu được. Sau đó hắn ân cần bắt chuyện muốn hàn gắn với Thiên Cầm.","bridge":true,"khoang":"@c0479"},{"chuong":"@c0481","importance":"normal","tieuDe":"Dựng cục hại sư huynh Thiên Cầm","text":"Là kẻ dựng nên việc đẩy sư huynh Thiên Cầm vào sơn cốc Cửu Lê trùng; nắm chặt bảo kiếm trong tay áo, lóe sát khí về phía Thiên Cầm và thừa nhận hai bên đã kết thù."},{"chuong":"@c0483","importance":"major","tieuDe":"Bị Thạch Phương đoạt xá","text":"Nguyên thần ly thể Thạch Phương lao tới, xuyên liễu diệp phi kiếm qua mi tâm Quách Tà Dật mà đoạt xá siêu tốc, chiếm lấy thân thể hắn; sau đó thân xác cùng chung số phận nổ tung khi Vương Lâm giết Thạch Phương."}],"tuViMoc":[{"chuong":"@c0478","canhGioi":"Kết Đan trở lên","text":"Đại đệ tử dẫn đầu nhóm, tu vi cao hơn các sư đệ sư muội Kết Đan","importance":"minor"}],"nhanMach":[{"ten":"Thiên Cầm cô nương","tag":"doi-thu","quanHe":"Được nàng mời trợ trận nhưng chiếm Diệu Kim quả, bị nàng căm hận","ghiChu":""},{"ten":"Lão già Hoá Thần hậu kỳ (sư thúc Quách Tà Dật)","tag":"su-mon","quanHe":"Sư thúc, dẫn ra mắt hai Trưởng lão","ghiChu":""},{"ten":"Thiên Cầm cô nương","tag":"khac","quanHe":"Người hắn khai ra rồi muốn hàn gắn","ghiChu":"Hắn khiến nàng bị ép dẫn đường rồi xin cho nàng một quả, sau ân cần bắt chuyện."},{"ten":"Lão già cao người (Trưởng lão Đại La Kiếm Tông)","tag":"su-mon","quanHe":"Trưởng lão tông môn","ghiChu":"Tra hỏi hắn và đồng ý cho Thiên Cầm một quả."},{"ten":"Lão già thấp người (Trưởng lão Đại La Kiếm Tông)","tag":"su-mon","quanHe":"Trưởng lão tông môn","ghiChu":"Hỏi hắn số lượng Diệu Kim quả."},{"ten":"Thiên Cầm","tag":"doi-thu","quanHe":"Kết thù sau khi hại chết sư huynh nàng","ghiChu":"@c0481"},{"ten":"Lữ Tùng Nghĩa","tag":"su-mon","quanHe":"Sư thúc, lão già Hóa Thần kỳ đi cùng","ghiChu":"@c0481"},{"ten":"Nữ tử (sư muội Quách Tà Dật)","tag":"su-mon","quanHe":"Sư muội đi cùng, gọi hắn là sư huynh","ghiChu":"@c0481"},{"ten":"Thạch Phương","tag":"doi-thu","quanHe":"Bị trưởng lão Thạch Phương đoạt xá, mất thân xác.","ghiChu":"@c0483"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0478","@c0479","@c0481","@c0483"]},{"id":"thien-cam-co-nuong","name":"Thiên Cầm cô nương","gioiTinh":"nu","theLuc":[],"trangThai":"song","blurb":"Nữ tử xinh đẹp mời Quách Tà Dật trợ trận nhưng bị hắn mượn danh sư môn chiếm Diệu Kim quả.","vaiTro":"Nữ tu tranh chấp Diệu Kim quả","tinhCach":[{"text":"Đầy thù hận, thẳng thắn mắng kẻ dùng thủ đoạn đê tiện","chuong":"@c0478"}],"tabs":{"diem":[{"text":"Căm hận Quách Tà Dật vì bị chiếm đoạt Diệu Kim quả","chuong":"@c0478"}],"kinhLich":[{"text":"Mặc quần lụa trắng thắt nơ bướm tơ tằm, mắng Quách Tà Dật mượn danh Đại La Kiếm Tông dùng thủ đoạn đê tiện; được hắn hứa để lại một quả Diệu Kim quả mang về sư môn.","bridge":true,"khoang":"@c0478"},{"text":"Bị Quách Tà Dật khai ra việc sư môn nàng phát hiện Diệu Kim quả, Thiên Cầm bị hai Trưởng lão Anh Biến sơ kỳ của Đại La Kiếm Tông ép dẫn đường vào Địa Ma Bắc Giới. Nội tâm chua xót hận Quách Tà Dật phản bội, nhưng vì khí tức hai Trưởng lão vượt xa sư môn nhỏ bé của nàng, nàng đành cắn răng cam chịu, chỉ mong đạt được một Diệu Kim quả.","bridge":true,"khoang":"@c0479"},{"bridge":true,"khoang":"@c0480","text":"Dẫn đường cho đoàn Đại La Kiếm Tông tới sơn cốc nơi sư môn vãn bối phát hiện Diệu Kim quả hai tháng trước, rồi lui về sau; bị lão già Hoá Thần kỳ liếc nhìn thân thể với quang mang kỳ lạ."},{"chuong":"@c0481","importance":"normal","tieuDe":"Mất sư huynh trong sơn cốc","text":"Chứng kiến sư huynh áo trắng bị Cửu Lê trùng chui vào cơ thể ăn thịt đến chết, nàng chấn động gặng hỏi tiền bối vì sao, nở nụ cười thê thảm rồi chuyển sang bình tĩnh đáng sợ."},{"chuong":"@c0483","importance":"normal","tieuDe":"Quỳ cầu Vương Lâm","text":"Thiên Cầm run rẩy quỳ xin Vương Lâm giết Thạch Phương và Trưởng lão Đại La Kiếm Tông đang bỏ chạy, nguyện làm trâu ngựa hầu hạ. Vẫn là xử nữ nên từng bị Thạch Phương định mượn thân để chữa thương; than rằng sư môn tốn công biết sơn cốc có Diệu Kim quả nhưng cục diện đã đổi khác khi Vương Lâm xuất hiện."},{"text":"Quan khán Vương Lâm hành sự, ban đầu ngỡ hắn bố trí trận pháp, sau đau lòng như rỉ máu khi thấy Diệu Kim quả héo rũ. Cuối cùng nàng vỡ lẽ giá trị thật của Diệu Kim quả nằm ở gốc rễ, theo bản năng tiếp lấy sợi kim linh căn Vương Lâm tặng rồi về bên đồng môn, hoá cầu vồng rời đi.","bridge":true,"khoang":"@c0484"}],"tuViMoc":[],"nhanMach":[{"ten":"Quách Tà Dật","tag":"doi-thu","quanHe":"Mời trợ trận nhưng bị chiếm Diệu Kim quả, sinh thù hận","ghiChu":""},{"ten":"Quách Tà Dật","tag":"doi-thu","quanHe":"Từng tin tưởng, nay hận vì bị phản bội","ghiChu":"Quách Tà Dật khai ra việc sư môn nàng phát hiện Diệu Kim quả khiến nàng bị ép dẫn đường; sau đó hắn ân cần muốn hàn gắn nhưng nàng càng chua xót."},{"ten":"Lão già cao người (Trưởng lão Đại La Kiếm Tông)","tag":"doi-thu","quanHe":"Kẻ ép nàng dẫn đường","ghiChu":"Đồng ý cho nàng một quả sau khi thu được, ra lệnh dẫn đường."},{"ten":"Nam tử áo trắng (đồng môn Thiên Cầm)","tag":"su-mon","quanHe":"Cùng sư môn","ghiChu":"Đồng môn tức giận thay nàng nhưng bị nàng quát im."},{"ten":"Nam tử áo trắng (đồng môn Thiên Cầm)","tag":"su-mon","quanHe":"Sư huynh, bị hại chết trong sơn cốc","ghiChu":"@c0481"},{"ten":"Quách Tà Dật","tag":"doi-thu","quanHe":"Kẻ dựng cục đẩy sư huynh nàng vào cốc, kết thù","ghiChu":"@c0481"},{"ten":"Vương Lâm","tag":"khac","quanHe":"Quỳ cầu Vương Lâm cứu mạng, nguyện làm trâu ngựa hầu hạ.","ghiChu":"@c0483"},{"ten":"Thạch Phương","tag":"su-mon","quanHe":"Trưởng lão sư môn định mượn thân xử nữ của nàng để chữa thương.","ghiChu":"@c0483"},{"ten":"Vương Lâm","tag":"an-nhan","quanHe":"Được Vương Lâm tặng một sợi kim linh căn coi như đền lại cơ duyên Diệu Kim quả đã bị chiếm.","ghiChu":"@c0484"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0478","@c0479","@c0480","@c0481","@c0483","@c0484"]},{"id":"lao-gia-hoa-than-su-thuc-quach-ta-dat","name":"Lão già Hoá Thần hậu kỳ (sư thúc Quách Tà Dật)","gioiTinh":"nam","theLuc":[{"ten":"Đại La Kiếm Tông","trangThai":"gan-bo"}],"trangThai":"song","blurb":"Một trong ba lão tóc bạc hắc y đeo bảo kiếm cổ, tu vi Hoá Thần hậu kỳ, sư thúc của Quách Tà Dật.","vaiTro":"Trưởng bối Đại La Kiếm Tông","tinhCach":[],"tabs":{"diem":[],"kinhLich":[{"text":"Cùng hai Kiếm Các Trưởng lão lao tới bằng trường hồng, khí lãng thổi bay những người khác lui hơn mười trượng; dẫn Quách Tà Dật ra mắt hai Trưởng lão.","bridge":true,"khoang":"@c0478"},{"bridge":true,"khoang":"@c0480","text":"Trong đoàn tiến vào Địa Ma Bắc Giới, thỉnh thoảng liếc nhìn thân thể yêu kiều của Thiên Cầm với quang mang kỳ lạ, lộ ý đồ; không nhận ra sự kinh hoàng của hai Trưởng lão trước áp lực quỷ dị."}],"tuViMoc":[{"chuong":"@c0478","canhGioi":"Hoá Thần hậu kỳ","text":"Tu vi Hoá Thần hậu kỳ","importance":"minor"}],"nhanMach":[{"ten":"Quách Tà Dật","tag":"su-mon","quanHe":"Là sư thúc, dẫn ra mắt hai Trưởng lão","ghiChu":""}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0478","@c0480"],"aliases":["Lão già Hoá Thần hậu kỳ (sư thúc Quách Tà Dật)"]},{"id":"hai-kiem-cac-truong-lao","name":"Hai Kiếm Các Trưởng lão","gioiTinh":"nam","theLuc":[{"ten":"Đại La Kiếm Tông","trangThai":"gan-bo"}],"trangThai":"song","blurb":"Hai lão già hắc y tu vi Anh Biến sơ kỳ đeo bảo kiếm cổ, Trưởng lão Kiếm Các của Đại La Kiếm Tông.","vaiTro":"Trưởng lão Kiếm Các Đại La Kiếm Tông","tinhCach":[],"tabs":{"diem":[],"kinhLich":[{"text":"Lao tới cùng lão Hoá Thần hậu kỳ, được Quách Tà Dật quỳ một gối tham kiến.","bridge":true,"khoang":"@c0478"}],"tuViMoc":[{"chuong":"@c0478","canhGioi":"Anh Biến sơ kỳ","text":"Cả hai tu vi Anh Biến sơ kỳ","importance":"minor"}],"nhanMach":[{"ten":"Quách Tà Dật","tag":"su-mon","quanHe":"Được Quách Tà Dật quỳ tham kiến","ghiChu":""}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0478"]},{"id":"thieu-nu-ket-dan-dai-la-kiem-tong","name":"Thiếu nữ Kết Đan hậu kỳ (Đại La Kiếm Tông)","gioiTinh":"nu","theLuc":[{"ten":"Đại La Kiếm Tông","trangThai":"gan-bo"}],"trangThai":"song","blurb":"Một trong hai nữ tử nhóm Quách Tà Dật, tu vi Kết Đan hậu kỳ, báo có người tiến vào Địa Ma Bắc Giới.","vaiTro":"Đệ tử Đại La Kiếm Tông","tinhCach":[],"tabs":{"diem":[],"kinhLich":[{"bridge":true,"khoang":"@c0478","text":"Mặc quần lụa miệng xinh, báo với nhóm thấy có người vừa tiến vào Địa Ma Bắc Giới."}],"tuViMoc":[{"chuong":"@c0478","canhGioi":"Kết Đan hậu kỳ","text":"Tu vi Kết Đan hậu kỳ","importance":"minor"}],"nhanMach":[{"ten":"Quách Tà Dật","tag":"su-mon","quanHe":"Đại sư huynh dẫn đầu nhóm","ghiChu":""}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0478"]},{"id":"nam-tu-ao-lam-dai-la-kiem-tong","name":"Nam tử áo lam (Đại La Kiếm Tông)","gioiTinh":"nam","theLuc":[{"ten":"Đại La Kiếm Tông","trangThai":"gan-bo"}],"trangThai":"song","blurb":"Đệ tử trẻ chừng hai mươi bảy tám tuổi nịnh hót, đề cao Đại La Kiếm Tông và Quách Tà Dật.","vaiTro":"Đệ tử Đại La Kiếm Tông","tinhCach":[{"text":"Nịnh hót, tâng bốc đại sư huynh và sư môn","chuong":"@c0478"}],"tabs":{"diem":[],"kinhLich":[{"bridge":true,"khoang":"@c0478","text":"Khen Đại La Kiếm Tông là môn phái số một số hai Thiên Vận Tinh và đề cao Quách Tà Dật."},{"text":"Kẻ được Quách Tà Dật nịnh hót; trong khi mọi người kinh sợ, hắn lại thầm say mê cảnh tượng nam tử áo trắng bị Cửu Lê trùng ăn thịt.","bridge":true,"khoang":"@c0481"}],"tuViMoc":[],"nhanMach":[{"ten":"Quách Tà Dật","tag":"su-mon","quanHe":"Đại sư huynh được hắn tâng bốc","ghiChu":""},{"ten":"Quách Tà Dật","tag":"khac","quanHe":"Được Quách Tà Dật nịnh hót","ghiChu":"@c0481"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0478","@c0481"]},{"id":"lao-gia-cao-nguoi-dai-la-kiem-tong","name":"Lão già cao người (Trưởng lão Đại La Kiếm Tông)","cn":"","aliases":["Trưởng lão cao người Đại La Kiếm Tông","Lão già cao người (Trưởng lão Đại La Kiếm Tông)","Lão già cao họ Thạch","Thạch Phương Trưởng lão"],"gioiTinh":"nam","theLuc":[{"ten":"Đại La Kiếm Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Anh Biến sơ kỳ","trangThai":"song","blurb":"Một trong hai Trưởng lão Anh Biến sơ kỳ của Đại La Kiếm Tông tham gia chuyến tìm Diệu Kim quả.","vaiTro":"Trưởng lão tra hỏi và ép dẫn đường","tinhCach":[{"text":"Hống hách nhưng còn giữ lời, đồng ý cho Thiên Cầm một quả.","chuong":"@c0479"}],"tabs":{"diem":[],"kinhLich":[{"text":"Cùng lão già thấp người tra hỏi Quách Tà Dật về Diệu Kim quả, đồng ý cho Thiên Cầm một quả sau khi thu được rồi ra lệnh cho nàng dẫn đoàn vào Địa Ma Bắc Giới.","bridge":true,"khoang":"@c0479"},{"text":"Trưởng lão Anh Biến sơ kỳ Thạch Phương cảm nhận áp lực quỷ dị như vạn sơn áp đỉnh trong Địa Ma Bắc Giới — cảm giác chưa từng gặp từ khi Hoá Thần — song vẫn quyết đi nhanh hơn. Tới sơn cốc, lão bấm quyết ngưng tụ một chiếc côn nồng đậm tiên lực hoá tiên phong thổi tan cây cối, mở thông đạo lộ ra phiến Diệu Kim quả, rồi nhận ra ổ Cửu Lê trùng ẩn dưới lá khô gần đó.","bridge":true,"khoang":"@c0480"},{"text":"Xưng danh Trưởng lão Đại La Kiếm Tông, dùng cấm thuật Kiếm phong chi cấm qua ngọc giản đỏ phong ấn nam tử áo trắng cùng đàn Cửu Lê trùng. Khi kẻ mạnh trong bụi khí xuất hiện, bấm quyết hóa bóng kiếm hư ảo hơn mười trượng chém xuống, nhưng kiếm bị đợt bụi khí phá tan.","bridge":true,"khoang":"@c0481"}],"tuViMoc":[],"nhanMach":[{"ten":"Lão già thấp người (Trưởng lão Đại La Kiếm Tông)","tag":"dong-minh","quanHe":"Đồng liêu cùng tông","ghiChu":"Hai Trưởng lão cùng tham gia chuyến tìm Diệu Kim quả."},{"ten":"Quách Tà Dật","tag":"su-mon","quanHe":"Tu sĩ cùng tông bị tra hỏi","ghiChu":"Tra hỏi hắn về Diệu Kim quả."},{"ten":"Thiên Cầm cô nương","tag":"doi-thu","quanHe":"Người bị ép dẫn đường","ghiChu":"Ra lệnh nàng dẫn đường, hứa cho một quả."},{"ten":"Lão già thấp người (Trưởng lão Đại La Kiếm Tông)","tag":"dong-minh","quanHe":"Cùng là Trưởng lão Đại La Kiếm Tông, phối hợp ăn ý","ghiChu":"@c0481"},{"ten":"Người trong bụi khí (giọng lạnh lẽo)","tag":"doi-thu","quanHe":"Kẻ mạnh phá tan kiếm của hắn","ghiChu":"@c0481"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0479","@c0480","@c0481"]},{"id":"lao-gia-thap-nguoi-dai-la-kiem-tong","name":"Lão già thấp người (Trưởng lão Đại La Kiếm Tông)","cn":"","aliases":["Trưởng lão thấp người Đại La Kiếm Tông","Lão già thấp người (Trưởng lão Đại La Kiếm Tông)"],"gioiTinh":"nam","theLuc":[{"ten":"Đại La Kiếm Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Anh Biến sơ kỳ","trangThai":"song","blurb":"Một trong hai Trưởng lão Anh Biến sơ kỳ của Đại La Kiếm Tông, mắt bừng tinh quang khi nghe Diệu Kim quả có khoảng trăm quả.","vaiTro":"Trưởng lão tham lam Diệu Kim quả","tinhCach":[{"text":"Tham lam, mắt bừng tinh quang khi nghe số lượng Diệu Kim quả.","chuong":"@c0479"}],"tabs":{"diem":[],"kinhLich":[{"text":"Hỏi Thiên Cầm số lượng Diệu Kim quả; nghe đáp ước chừng trăm quả thì mắt bừng tinh quang, lộ rõ tham vọng.","bridge":true,"khoang":"@c0479"},{"text":"Trưởng lão Anh Biến sơ kỳ cảm giác kích động muốn giết người khi gặp Khổ Ảnh thú, từng đề nghị rời đi. Tới sơn cốc, lão chỉ ra cần dược dẫn đối phó Cửu Lê trùng rồi bất ngờ dùng lực vô hình chụp lấy gã đồng môn áo trắng bên người Thiên Cầm, ném thẳng vào sơn cốc làm mồi, lộ nụ cười tàn nhẫn.","bridge":true,"khoang":"@c0480"},{"text":"Tiến vào sơn cốc trước, bắn kiếm khí diệt sạch Cửu Lê trùng còn sót, ra lệnh cho Lữ Tùng Nghĩa đi hái Diệu Kim quả. Khi bụi khí áp tới, ném ra gương đồng một mặt tỏa thanh quang chống đỡ, nhưng gương bị giọng lạnh lẽo phá vỡ răng rắc.","bridge":true,"khoang":"@c0481"},{"text":"Sau khi Vương Lâm phá Huyết Thủ ấn và diệt Thiên Quỷ đầu, lão già thấp người liều mạng bỏ chạy nhưng bị thanh loan đao cùng kiếm tiên (nhốt Hứa Lập Quốc) đuổi theo giam giữ, chờ Vương Lâm tra hỏi.","bridge":true,"khoang":"@c0483"},{"text":"Ở chỗ sâu Địa Ma Bắc giới, lão mặt tái nhợt khoanh chân ngồi trên đại thụ không dám cử động: cách mi tâm một tấc có thanh loan đao lơ lửng bất động, cách thiên linh cái một tấc là một kiếm tiên với kiếm quang nồng đậm không tiêu tán đang đe doạ.","bridge":true,"khoang":"@c0484"},{"chuong":"@c0485","importance":"normal","tieuDe":"Khai Bí Mật Rồi Bị Diệt","text":"Tu sĩ Đại La Kiếm Tông, từng đến Địa Tinh cùng Thạch Phương và trêu chọc phải Vương Lâm. Bị phi kiếm cực cứng và loan đao quỷ dị của Vương Lâm khống chế đến không dám chạy, lão đành đứng chờ và cam đoan khai thật: chuyện Kiếm Tôn trở về bị kiếm hồn truy kích, phong ấn 1/3 kiếm hồn trong Đông Hải Yêu Linh chi môn, cùng bí mật ba đại cấm địa và phần thưởng Yêu Linh quán đính. Khai xong bị loan đao xuyên đầu, lão tu Tam phân thần thức thuật tái sinh lần cuối, thề về Đại La Kiếm Tông báo thù, nhưng vừa bay đi liền bị hai làn khí xám của Vương Lâm xuyên thân hút sạch sức sống mà chết thật."}],"tuViMoc":[],"nhanMach":[{"ten":"Lão già cao người (Trưởng lão Đại La Kiếm Tông)","tag":"dong-minh","quanHe":"Đồng liêu cùng tông","ghiChu":"Hai Trưởng lão cùng tham gia chuyến tìm Diệu Kim quả."},{"ten":"Thiên Cầm cô nương","tag":"doi-thu","quanHe":"Người bị tra hỏi số lượng quả","ghiChu":"Hỏi nàng số lượng Diệu Kim quả."},{"ten":"Lữ Tùng Nghĩa","tag":"dong-minh","quanHe":"Sai đi hái Diệu Kim quả","ghiChu":"@c0481"},{"ten":"Người trong bụi khí (giọng lạnh lẽo)","tag":"doi-thu","quanHe":"Kẻ mạnh phá vỡ gương đồng của lão","ghiChu":"@c0481"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Bị Vương Lâm truy sát, giam giữ chờ thẩm vấn.","ghiChu":"@c0483"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Kẻ bắt giam và xử tử","ghiChu":"Ép khai bí mật Đông Hải Yêu Linh chi môn rồi giết cả hai lần."},{"ten":"Thạch Phương","tag":"dong-hanh","quanHe":"Bạn đồng hành đến Địa Tinh","ghiChu":"Cùng đến Địa Tinh; lời khai của lão bị Vương Lâm lấy lời Thạch Phương làm chuẩn đối chiếu."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0479","@c0480","@c0481","@c0483","@c0484","@c0485"]},{"id":"nam-tu-ao-trang-dong-mon-thien-cam","name":"Nam tử áo trắng (đồng môn Thiên Cầm)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Sư môn của Thiên Cầm","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không-ro","trangThai":"song","blurb":"Tu sĩ cùng sư môn với Thiên Cầm, tức giận trách Đại La Kiếm Tông nhưng bị Thiên Cầm quát im.","vaiTro":"Đồng môn bất bình của Thiên Cầm","tinhCach":[{"text":"Nóng nảy, bất bình thay sư môn nhưng phải nhẫn nhịn.","chuong":"@c0479"}],"tabs":{"diem":[],"kinhLich":[{"text":"Tức giận trách Đại La Kiếm Tông về việc sư môn phải hy sinh nhiều trưởng bối mới tìm được Diệu Kim quả, nhưng bị Thiên Cầm quát ‘Câm mồm!’ buộc phải im lặng nhẫn nhịn.","bridge":true,"khoang":"@c0479"},{"bridge":true,"khoang":"@c0480","text":"Bị lão già thấp người dùng lực vô hình chụp lấy và ném thẳng vào sơn cốc làm dược dẫn thử Cửu Lê trùng; vừa tiến vào liền bị vô số điểm đỏ Cửu Lê trùng lao tới."},{"chuong":"@c0481","importance":"normal","tieuDe":"Bị Cửu Lê trùng ăn thịt đến chết","text":"Bị ném vào giữa sơn cốc, vô số Cửu Lê trùng phá quần áo chui vào da thịt; chưa đến ba tức toàn thân lộ huyết sắc, hắn tự cào cấu da thịt lộ cả xương cốt, dãy dụa thảm thiết rồi tắt tiếng, hai mắt ảm đạm tuyệt vọng oán hận."}],"tuViMoc":[],"nhanMach":[{"ten":"Thiên Cầm cô nương","tag":"su-mon","quanHe":"Cùng sư môn","ghiChu":"Bị nàng quát im khi tức giận trách Đại La Kiếm Tông."},{"ten":"Thiên Cầm","tag":"su-mon","quanHe":"Sư muội chứng kiến hắn chết","ghiChu":"@c0481"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0479","@c0480","@c0481"]},{"id":"lu-tung-nghia","name":"Lữ Tùng Nghĩa","gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Hóa Thần kỳ","trangThai":"song","blurb":"Lão già Hóa Thần kỳ, sư thúc của Quách Tà Dật, được sai vào sơn cốc Địa Ma Bắc giới hái Diệu Kim quả.","vaiTro":"Trợ thủ trong nhóm Quách Tà Dật và hai Trưởng lão Đại La Kiếm Tông, đảm nhận việc hái Diệu Kim quả.","tinhCach":[{"text":"Tuân lệnh, hành động dứt khoát, lao như điện về phía Diệu Kim quả khi được sai.","chuong":"@c0481"}],"tabs":{"diem":[{"text":"Lão già Hóa Thần kỳ, vai vế sư thúc của Quách Tà Dật.","chuong":"@c0481"}],"kinhLich":[{"text":"Vào sơn cốc thứ ba sau hai Trưởng lão, được lão già lùn ra lệnh đi hái Diệu Kim quả. Khi biến cố bụi khí nổ ra, lão lao như điện tới được bên cạnh đóa hoa trên tảng đá vàng.","bridge":true,"khoang":"@c0481"}],"tuViMoc":[{"chuong":"@c0481","canhGioi":"Hóa Thần kỳ","text":"Xuất hiện với cảnh giới Hóa Thần kỳ.","importance":"minor"}],"nhanMach":[{"ten":"Quách Tà Dật","tag":"su-mon","quanHe":"Cháu (sư điệt)","ghiChu":"@c0481"},{"ten":"Lão già lùn (Trưởng lão Đại La Kiếm Tông)","tag":"dong-minh","quanHe":"Nhận lệnh hái Diệu Kim quả","ghiChu":"@c0481"}],"tuiDo":{}},"nguon":["@c0481"]},{"id":"nu-tu-su-muoi-quach-ta-dat","name":"Nữ tử (sư muội Quách Tà Dật)","gioiTinh":"nu","trangThai":"song","blurb":"Nữ tử gọi Quách Tà Dật là sư huynh; tái nhợt run rẩy trước cảnh tàn khốc trong sơn cốc.","tabs":{"diem":[],"kinhLich":[{"text":"Đi cùng nhóm Quách Tà Dật, sắc mặt tái nhợt và run rẩy vì kinh sợ khi chứng kiến nam tử áo trắng bị Cửu Lê trùng ăn thịt.","bridge":true,"khoang":"@c0481"}],"tuViMoc":[],"nhanMach":[{"ten":"Quách Tà Dật","tag":"su-mon","quanHe":"Sư huynh","ghiChu":"@c0481"}],"tuiDo":{}},"nguon":["@c0481"]},{"id":"nguoi-trong-bui-khi-giong-lanh-leo","name":"Người trong bụi khí (giọng lạnh lẽo)","gioiTinh":"khong-ro","trangThai":"khong-ro","blurb":"Kẻ mạnh ẩn trong đoàn bụi khí nồng đậm, thực lực áp đảo hai Trưởng lão Đại La Kiếm Tông; danh tính chưa rõ.","tabs":{"diem":[{"text":"Ẩn trong bụi khí, chỉ một câu nói và một đợt bụi khí đã phá vỡ gương đồng và kiếm của hai Trưởng lão.","chuong":"@c0481"}],"kinhLich":[{"text":"Xuất hiện sau cơn gió mát khiến hai Trưởng lão đại biến sắc mặt. Đoàn bụi khí nồng đậm bùng lên như vạn mã, phá tan thanh quang gương đồng và kiếm khí Thạch Phương; từ trong bụi khí truyền ra giọng lạnh lẽo: “Ánh sáng của đom đóm há có thể so sánh với ánh trăng!”","bridge":true,"khoang":"@c0481"}],"tuViMoc":[],"nhanMach":[{"ten":"Thạch Phương","tag":"doi-thu","quanHe":"Phá tan kiếm của Thạch Phương","ghiChu":"@c0481"},{"ten":"Lão già lùn (Trưởng lão Đại La Kiếm Tông)","tag":"doi-thu","quanHe":"Phá vỡ gương đồng của lão","ghiChu":"@c0481"}],"tuiDo":{}},"nguon":["@c0481"]},{"id":"thach-phuong","name":"Thạch Phương","gioiTinh":"nam","aliases":[],"theLuc":[{"ten":"Sư môn của Thiên Cầm","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"tu-vong","blurb":"Trưởng lão của nhóm tiểu bối (đồng môn Thiên Cầm, Quách Tà Dật), tinh thông đoạt xá siêu tốc; bị Vương Lâm tiêu diệt tại sơn cốc.","vaiTro":"Phản diện một chương — trưởng lão kiếm tu nguyên thần ly thể đối đầu Vương Lâm.","tinhCach":[{"text":"Gian xảo, tham sống sợ chết: đoạt xá vật chủ, cầu xin và sẵn sàng giết môn hạ để mua mạng.","chuong":"@c0483"}],"tabs":{"diem":[{"text":"Nắm phương pháp đoạt xá siêu tốc, gần như khôi phục thần trí tức thì sau khi chiếm thân.","chuong":"@c0483"}],"kinhLich":[{"text":"Kiếm quang cùng nguyên thần ly thể của Thạch Phương xông tới mi tâm Vương Lâm nhưng bị Tứ chuyển hàm tiên lực vỗ tan, tiên ảnh đánh trọng thương nguyên thần, Văn thú nuốt sạch thân xác. Hắn vội đoạt xá tiểu bối Quách Tà Dật theo lối siêu tốc, cầu xin tha mạng, giết hai tiểu bối để chứng minh thành ý và hiến ngọc giản đoạt xá.","bridge":true,"khoang":"@c0483"},{"chuong":"@c0483","importance":"normal","tieuDe":"Bị khí xám nổ tung","text":"Sau khi ghi ngọc giản, Thạch Phương tranh thủ bỏ chạy khỏi sơn cốc nhưng thân vừa đoạt xá quá suy yếu; hai đạo khí xám của Vương Lâm chui vào kinh mạch khiến thân hắn nổ tung, để lại một khối cầu xám."}],"tuViMoc":[],"tuVi":"Tu sĩ có nguyên thần ly thể dung trong bản mạng phi kiếm; cảnh giới cụ thể không nêu rõ.","nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Bị Vương Lâm đánh tan nguyên thần, nuốt thân xác và cuối cùng giết chết.","ghiChu":"@c0483"},{"ten":"Quách Tà Dật","tag":"doi-thu","quanHe":"Tiểu bối bị Thạch Phương đoạt xá làm vật chủ.","ghiChu":"@c0483"},{"ten":"Thiên Cầm cô nương","tag":"su-mon","quanHe":"Trưởng lão của nhóm tiểu bối có Thiên Cầm; định mượn thân xử nữ Thiên Cầm để chữa thương.","ghiChu":"@c0483"}],"tuiDo":{"phapBao":[{"ten":"Liễu diệp phi kiếm","loai":"bản mạng pháp khí","trangThai":"mat","moTa":"Phi kiếm hình lá liễu dung nguyên thần ly thể, bị tiên ảnh đánh chấn động hào quang ảm đạm.","nguon":"@c0483"}]}},"nguon":["@c0483"]},{"id":"kiem-ton","name":"Kiếm Tôn","gioiTinh":"nam","theLuc":[],"trangThai":"khong-ro","blurb":"Cường giả từ tiên giới trở về, bị một đạo kiếm hồn đáng sợ truy kích; sau mấy ngày giao chiến đã phong ấn hơn 1/3 kiếm hồn cùng Chu Dật tại chỗ sâu trong Đông Hải Yêu Linh chi môn.","vaiTro":"Nhân vật được nhắc tới, liên quan trực tiếp đến mục tiêu chuyến đi của Vương Lâm.","tabs":{"diem":[{"text":"Từ tiên giới trở về, đủ sức phong ấn một đạo kiếm hồn cường đại trong cấm địa.","chuong":"@c0485"}],"kinhLich":[{"text":"Theo lời khai của lão già Đại La Kiếm Tông: lúc Kiếm Tôn từ tiên giới trở về có một đạo kiếm hồn đáng sợ từ chân trời truy kích, đánh nhau mấy ngày, cuối cùng kiếm hồn tan vỡ; hơn 1/3 bị Kiếm Tôn phong ấn tại chỗ sâu trong Đông Hải Yêu Linh chi môn, cùng nơi đó phong ấn Chu Dật.","bridge":true,"khoang":"@c0485"},{"text":"Hóa thanh kiếm cổ mang thiên uy phóng tới cửa Đông Hải Yêu Linh, ngồi khoanh chân trên Hùng Lân thú với bốn đạo kiếm quang hư ảnh sau lưng, dẫn theo Kiếm Tiếu Thập Nhị Tử của Đại La Kiếm Tông; tạo khoảng trống trăm dặm khiến tu sĩ vội tránh né.","bridge":true,"khoang":"@c0487"},{"chuong":"@c0487","importance":"normal","tieuDe":"Mục đích nhốt kiếm hồn","text":"Tiết lộ ý đồ mượn hiện tượng thủy triều năm nghìn năm một lần để hút đạo kiếm hồn của một nữ quân tiên giới chìm sâu vĩnh viễn vào Đông Hải, quyết không để vật ấy rơi vào tay Thiên Vận lão tặc; ngay sau đó lão hữu cũ Tham Lang phá hư không xông tới tìm hắn."}],"tuViMoc":[],"tuVi":"Chưa rõ cảnh giới cụ thể; đủ sức phong ấn kiếm hồn cường đại.","nhanMach":[{"ten":"Chu Dật","tag":"doi-thu","quanHe":"Người bị phong ấn","ghiChu":"Bị Kiếm Tôn phong ấn trong Đông Hải Yêu Linh chi môn."},{"ten":"Thiên Vận Tử","tag":"doi-thu","quanHe":"Kình địch cả đời, hai người đối lập kéo dài nhiều năm"},{"ten":"Tham Lang","tag":"dong-minh","quanHe":"Lão hữu cũ tới nhờ vả, muốn tặng hắn một cơ duyên cực lớn"},{"ten":"Diêu Tích Tuyết","tag":"khac","quanHe":"Lão quái phải kiêng nể hắn ở cửa Đông Hải"}],"tuiDo":{}},"nguon":["@c0485","@c0487"],"aliases":["Kiếm Tôn","Lăng Thiên Hậu","Lăng Thiên lão hữu"]},{"id":"dieu-tich-tuyet","name":"Diêu Tích Tuyết","cn":"","aliases":["Con gái Huyết Tổ"],"gioiTinh":"nu","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Con gái duy nhất của Huyết Tổ Diêu Tinh Hải, được cha truyền toàn bộ công pháp huyết hệ; xuất hiện ngồi trên huyết ngọc khổng lồ bay tới ngoài Đông Hải Yêu Linh.","vaiTro":"Cường giả huyết hệ trẻ tuổi đến chờ cửa Đông Hải Yêu Linh mở.","tinhCach":[{"text":"Lạnh lùng, kín tiếng — đến nơi không nói lời nào, nhắm mắt khoanh chân ngồi chờ.","chuong":"@c0486"}],"tabs":{"diem":[{"text":"Mắt phượng mi cong, da trắng bóng như thủy tinh, ánh mắt ẩn thâm thúy u hàn khiến người nhìn vào như vạn kiếp bất phục.","chuong":"@c0486"}],"kinhLich":[{"text":"Giữa hồng quang che trời và mùi máu tanh nồng đậm, nàng ngồi trên bức tượng huyết ngọc khổng lồ bay tới ngoài cửa Đông Hải Yêu Linh, dừng ở chỗ trống rồi nhắm chặt mắt khoanh chân ngồi, không nói lời nào.","bridge":true,"khoang":"@c0486"},{"bridge":true,"khoang":"@c0487","text":"Là con gái Huyết Tổ, có uy thế lớn nên trong phạm vi trăm trượng quanh nàng không ai dám tới; khi Kiếm Tôn Lăng Thiên Hậu xuất hiện ở cửa Đông Hải Yêu Linh nàng cũng phải kinh hãi than “Kiếm Tôn!”."},{"bridge":true,"khoang":"@c0488–@c0488","text":"Diêu Tích Tuyết ngồi trên khối huyết sắc ngọc thạch, theo lời dặn của phụ thân quan sát Vương Lâm; kinh ngạc vì một đệ tử tu vi tầm thường vừa gia nhập Thiên Vận Tử đã được chỉ đích danh vào Đông Hải."},{"text":"Đang ngồi trên khối huyết ngọc ở phương xa quan sát thủy triều hồng quang, nàng vô ý đảo mắt nhìn qua chỗ Vương Lâm. Vừa thấy ánh mắt hắn dày đặc tơ máu lẫn khí xám yêu dị sau khi vận thần thông, nàng chấn động không tự chủ, mặt tái nhợt vội cúi đầu, trong lòng dậy sóng và hiểu ra vì sao phụ thân dặn nàng phải chú ý đến người này.","bridge":true,"khoang":"@c0490"},{"text":"Đứng trên huyết ngọc lộ vẻ suy tư, cắn răng hóa thành đạo huyết quang bay vào lối vào cánh cửa Đông Hải yêu linh.","bridge":true,"khoang":"@c0491"},{"chuong":"@c0510","importance":"normal","tieuDe":"Hồi tưởng bại trận, nhận chức Thống lĩnh","text":"Đứng xa quan sát trận đấu của Vương Lâm, Diêu Tích Tuyết nhớ lại ba năm trước nàng cũng bại dưới Thập Băng Quyền Ý: đến lần thứ tư đã quá sức, nhờ Huyết thuật gia truyền của dòng Huyết tổ mới sống quá lần thứ năm, cuối cùng bại ở lần thứ tám và được ban chức Thống lĩnh."},{"chuong":"@c0511","importance":"normal","tieuDe":"Kinh Ngạc Trước Vương Lâm","text":"Đứng quan sát ở xa, Diêu Tích Tuyết biến sắc nhìn Vương Lâm phá liên tiếp các lần sụp đổ của Thập Băng Quyền Ý. Nàng nhớ lại lời phụ thân Huyết Tổ rằng người có chú ý đến Vương Lâm, càng thêm để tâm tới hắn."},{"bridge":true,"khoang":"@c0512","text":"Chứng kiến Vương Lâm được phong Thống lĩnh, nàng định mở miệng nói gì đó nhưng bị Vương Lâm phớt lờ không nhìn; nàng nhíu mày hừ nhẹ rồi bỏ đi."},{"chuong":"@c0517","importance":"normal","tieuDe":"Xông “nơi đó” lần thứ tư thất bại","text":"Tại quân doanh thứ ba, đêm trăng tím nửa-năm-một-lần, nàng dùng la bàn đỏ, cây đèn trắng và giọt máu lam thi triển pháp thuật xông vào vực sâu nơi thủy triều theo kế hoạch của phụ thân. Lần thứ tư vẫn thất bại, nhờ Huyết Hồn đan mới tái sinh trở về; nàng phá được hơn một nửa và nghĩ nếu có người giúp nhất định thành công — rồi gọi tên Vương Lâm."},{"chuong":"@c0518","importance":"normal","tieuDe":"Xông doanh cầu Vương Lâm phá trận","text":"Bị Vương Lâm lỡ hẹn ở cổ sơn, Diêu Tích Tuyết nổi giận hóa tia sáng trắng xông thẳng vào quân doanh Hắc Giáp quân — trận pháp doanh trại vô hiệu với nàng vì nàng là thống lĩnh. Nàng dùng tia sáng đỏ khống chế Thập Tam, phong tỏa chín ngàn yêu binh, rồi vào lầu cầu Vương Lâm cùng phá trận pháp mười tám phong ấn, hứa cung cấp toàn bộ tiên ngọc làm trọng tạ."},{"bridge":true,"khoang":"@c0518","text":"Nàng hé lộ trận có mười tám phong ấn mà một mình chỉ phá được tới cái thứ mười một; nội tâm nàng giấu việc phá trận liên quan sinh tử — đã thất bại bốn lần, chết bốn lần, hao bốn viên Huyết Hồn đan trong số mười ba viên do phụ thân luyện."},{"chuong":"@c0519","importance":"normal","tieuDe":"Trao Huyết Hồn đan nhờ bài trừ phong ấn","text":"Sau khi chứng kiến Vương Lâm đánh trận với Yêu Tương, nàng tin chỉ hắn đủ sức giúp bài trừ phong ấn cấm chế bí mật trên người mình. Bị hắn liên tục trì hoãn, nàng nổi giận rồi rốt cuộc giao cây đèn Huyết Hồn đan, ném thêm túi tiên ngọc cùng lời hứa lệnh bài Huyết Phù, hẹn ba ngày sau canh ba ở cổ sơn cùng đi; sự hào phóng khác thường này khiến Vương Lâm sinh nghi."},{"chuong":"@c0520","importance":"normal","tieuDe":"Mở trận ẩn thân dẫn Vương Lâm đi","text":"Trên cổ sơn dưới trăng tím, nàng xuất bảy pho tượng đỏ như máu, cắn lưỡi vẽ ký tự máu trăm trượng dựng trận ẩn thân khiến thần thức không soi thấy chính mình, nói cả Yêu Tương cũng không phát hiện được. Sau đó nàng dùng la bàn đỏ canh thời điểm yêu khí cực điểm, dẫn Vương Lâm vượt truyền tống trận tới không gian Tôn Long, hứa trao lệnh bài Huyết Phủ và tiên ngọc khi trở về."},{"chuong":"@c0521","importance":"normal","tieuDe":"Dẫn đường con đường Tôn Long","text":"Diêu Tích Tuyết đắc kim phù ấn ba nét — ký hiệu màu vàng ngưng tụ trong mi tâm tỏa uy nghiêm như vô thượng tiên tôn. Khi Vương Lâm đắc kim phù sáu nét, kim phù trong mắt nàng nhạt hẳn đi như đốm lửa so với trăng rằm; nàng khó chịu, vô thức tránh ánh mắt hắn rồi dẫn hắn lên con đường Tôn Long. Tới bình đài đầu tiên, nàng kích hoạt pho tượng đá (uy lực ngang Anh Biến sơ kỳ) rồi ném ngọc phù màu máu hô “Phong!” phong ấn tượng dễ dàng, hẹn Vương Lâm phá giải tầng thứ hai."},{"chuong":"@c0522","importance":"normal","tieuDe":"Đồng hành con đường Tôn Long","text":"Nữ tử áo đỏ cùng Vương Lâm men theo con đường Tôn Long qua các bình đài. Tới bình đài thứ ba có tượng đá ba mắt, nàng nhường Vương Lâm thử trước. Vương Lâm ngầm đoán cái ngọc phù đỏ như máu của nàng do phụ thân — Huyết Tổ — luyện chế, và nhận định nàng sở hữu Huyết Hồn đan nên dù bị đánh lén cũng sống lại được, rất khó giết."},{"chuong":"@c0523","importance":"normal","tieuDe":"Dẫn dụ phá phong ấn đường Tôn Long","text":"Đưa Vương Lâm vượt các tầng phong ấn để tới động phủ tiên nhân, nói dối rằng có mười tám tầng. Nàng hé lộ cha mình là Huyết Tổ nghe tin động phủ từ miệng một Yêu Đế, và mình đã uống Huyết Hồn Đan nên không sợ chết khi tiếp ba đạo kiếm khí."},{"chuong":"@c0523","importance":"normal","tieuDe":"Bị phong ấn giữa sinh tử","text":"Sau khi gắng tiếp đạo kiếm khí thứ hai và thứ ba đến cạn tiên lực, nàng bị Vương Lâm từ hư vô bay lên điểm mi tâm, đứt kinh mạch, phong ấn toàn thân giữa sự sống và cái chết — vô hiệu hóa Huyết Hồn Đan vốn phải chết mới dùng được — rồi mất sạch trữ vật."},{"chuong":"@c0524","importance":"normal","tieuDe":"Bị Phong Ấn Trong Túi Trữ Vật","text":"Bị Vương Lâm chất vấn vì sao vội vàng vào động phủ, Diêu Tích Tuyết chỉ đáp muốn vào không có nguyên nhân, từ chối khai thật. Vương Lâm lạnh mặt bủa cấm chế nhốt nàng vào một quả cầu hắc quang, áp phong ấn cực hạn năm trăm năm trong Yêu Linh rồi cất vào túi trữ vật."},{"chuong":"@c0531","importance":"normal","tieuDe":"Vỡ kế tự sát & bị thu vào túi trữ","text":"Trong sơn cốc Luyện Hồn, từ chối đề nghị giảm phong ấn 50 năm của Vương Lâm, mắng chửi thề báo thù qua phụ thân Huyết Tổ; giấu tia tinh khí nguyên thần cuối cùng hóa cây châm đỏ trong miệng định chặn sinh cơ của Sinh Chi Lạc Ấn để tự sát nhưng bị Vương Lâm lôi ra bóp vỡ, kế chuyển hận nhập đạo cầu thoát phong ấn cũng bị phá bằng kích thích tuần hoàn cấm chế, cuối cùng bị thu thành quả cầu cấm chế cất vào túi trữ vật."}],"tuViMoc":[],"tuVi":"Được Huyết Tổ truyền toàn bộ công pháp huyết hệ; tu vi cụ thể chưa rõ.","nhanMach":[{"ten":"Huyết Tổ Diêu Tinh Hải","tag":"cha-me","quanHe":"Cha ruột","ghiChu":"Được cha coi như ngọc quý, truyền toàn bộ công pháp."},{"ten":"Huyết Tổ Diêu Tinh Hải","tag":"cha-me","quanHe":"Phụ thân"},{"ten":"Kiếm Tôn","tag":"khac","quanHe":"Đại lão khiến nàng phải kiêng nể"},{"ten":"Vương Lâm","tag":"khac","quanHe":"Người nàng được phụ thân dặn chú ý","ghiChu":"Bị ánh mắt mang khí xám của Vương Lâm làm chấn động (@c0490)."},{"ten":"Tả dực Yêu tương","tag":"doi-thu","quanHe":"Người thi triển Thập Băng Quyền Ý khiến nàng bại trận","ghiChu":"Diêu Tích Tuyết bại ở lần thứ tám của quyền ý, sau nhận chức Thống lĩnh ở Cổ Yêu thành."},{"ten":"Vương Lâm","tag":"khac","quanHe":"Đối tượng để tâm","ghiChu":"Quan sát Vương Lâm phá Thập Băng Quyền Ý, nhớ lời phụ thân về hắn."},{"ten":"Vương Lâm","tag":"khac","quanHe":"Người nàng nghĩ tới để nhờ giúp xông “nơi đó”","ghiChu":""},{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Tìm tới nhờ Vương Lâm cùng phá trận cấm chế, dùng tiên ngọc làm mồi"},{"ten":"Huyết Tổ Diêu Tinh Hải","tag":"cha-me","quanHe":"Phụ thân, người dày công luyện mười ba viên Huyết Hồn đan cho nàng"},{"ten":"Thập Tam","tag":"doi-thu","quanHe":"Khống chế Thập Tam bằng tia sáng đỏ khi xông vào lầu Vương Lâm"},{"ten":"Huyết Tổ Diêu Tinh Hải","tag":"cha-me","quanHe":"Phụ thân, tu sĩ đứng thứ ba Thiên Vận tinh","ghiChu":"Sở hữu độc môn Huyết Hồn đan; động phủ cất nhiều tiên ngọc"},{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Người nàng nhờ giúp bài trừ phong ấn","ghiChu":"Trao Huyết Hồn đan và tiên ngọc làm thù lao"},{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Đối tượng nàng tìm cách lôi kéo, đưa tiên ngọc và Huyết Hồn đan rồi dẫn vào không gian Tôn Long","ghiChu":"Hành xử hào hiệp nhưng theo mưu kế của Huyết Tổ; Vương Lâm đã đề phòng."},{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Người đồng hành trên con đường Tôn Long.","ghiChu":"@c0522"},{"ten":"Huyết Tổ Diêu Tinh Hải","tag":"cha-me","quanHe":"Phụ thân; được cho là người luyện chế ngọc phù đỏ như máu có thần thông.","ghiChu":"@c0522"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Định mượn tay phá phong ấn rồi diệt, nhưng bị phản đòn và phong ấn giữa sinh tử.","ghiChu":""},{"ten":"Động Phủ Chi Linh","tag":"khac","quanHe":"Quen biết công pháp Huyết Quân của tổ tiên nàng nên đã ba lần tha mạng nàng.","ghiChu":""},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Người phong ấn nàng","ghiChu":"Đề nghị giảm năm mươi năm đổi câu trả lời, nàng không hợp tác nên bị nhốt và mang theo."},{"ten":"Thanh Sương","tag":"khac","quanHe":"Danh tính liên quan tới lực lượng thần bí ban kim phù ấn tại Yêu Linh chi địa","ghiChu":""}],"tuiDo":{"phapBao":[{"ten":"Huyết ngọc (tượng huyết sắc)","trangThai":"dang-co","moTa":"Bức tượng huyết sắc khổng lồ bằng ngọc thạch, tỏa hồng quang và mùi máu tanh, dùng làm phương tiện bay trong tinh không.","nguon":"@c0486"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0486","@c0487","@c0488","@c0490","@c0491","@c0510","@c0511","@c0512","@c0517","@c0518","@c0519","@c0520","@c0522","@c0523","@c0524","@c0531","@c0521"]},{"id":"huyet-to-dieu-tinh-hai","name":"Huyết Tổ Diêu Tinh Hải","cn":"","aliases":["Huyết Tổ"],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Thông Thiên","trangThai":"song","blurb":"Lão quái tu vi thông thiên của Thiên Vận Tinh, từng bảy lần khiêu chiến Thiên Vận Tử; độc chiếm Huyết Tinh khai hoang nạp huyết tu luyện ma công, cha của Diêu Tích Tuyết.","vaiTro":"Cường giả huyết hệ ẩn cư, được nhắc tới trong chương (chưa ra mặt).","tinhCach":[{"text":"Cô độc, cường ngạnh — cả đời không thu đồ đệ, chỉ dồn tâm huyết cho con gái.","chuong":"@c0486"}],"tabs":{"diem":[{"text":"Bảy lần khiêu chiến Thiên Vận Tử đều thất bại nhưng tu vi càng lúc càng cao, lần thứ bảy thi triển Huyết Công kinh người.","chuong":"@c0486"}],"kinhLich":[{"text":"Bảy lần khiêu chiến chủ nhân Thiên Vận Tinh là Thiên Vận Tử, tuy đều thất bại nhưng tu vi mỗi lần một mạnh; lần thứ bảy thi triển Huyết Công khiến người kinh sợ.","bridge":true,"khoang":"@c0486"},{"chuong":"@c0486","importance":"normal","tieuDe":"Độc chiếm Huyết Tinh tu ma công","text":"Độc chiếm một tinh cầu bên ngoài Thiên Vận Tinh (Huyết Tinh), khai hoang nạp huyết tu luyện ma công; cả đời không thu đồ đệ, đem toàn bộ công pháp truyền cho con gái rồi nghịch thiên cải mệnh."}],"tuViMoc":[],"tuVi":"Tu vi thông thiên, sở trường công pháp huyết hệ.","nhanMach":[{"ten":"Diêu Tích Tuyết","tag":"cha-me","quanHe":"Con gái ruột","ghiChu":"Coi như ngọc quý, truyền toàn bộ công pháp."},{"ten":"Thiên Vận Tử","tag":"doi-thu","quanHe":"Đối thủ","ghiChu":"Bảy lần khiêu chiến."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[{"ten":"Huyết Công","moTa":"Ma công huyết hệ sở trường, thi triển trong lần thứ bảy khiêu chiến Thiên Vận Tử.","nguon":"@c0486"}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0486"]},{"id":"ton-van-son","name":"Tôn Vân Sơn","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Huyền Uyên Phái","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Thiếu tông chủ Huyền Uyên phái, hay cầm quạt thúy ngọc; ngăn em gái lên Đông Hải Yêu Linh và long trọng chờ đón Vương huynh đến qua truyền tống trận.","vaiTro":"Người chủ trì truyền tống trận của Huyền Uyên phái, đón Vương Lâm.","tinhCach":[{"text":"Điềm tĩnh, có uy — quát mắng em gái nhưng vẫn giữ phong thái thong dong.","chuong":"@c0486"}],"tabs":{"diem":[{"text":"Thường cầm quạt thúy ngọc đập nhẹ vào lòng bàn tay, chốc chốc nhìn về phương xa chờ khách.","chuong":"@c0486"}],"kinhLich":[{"text":"Trước truyền tống trận khổng lồ của Huyền Uyên phái, ngăn em gái áo hồng đòi lên Đông Hải Yêu Linh, viện cớ tu vi nàng không đủ và phụ thân đã bế quan ra lệnh cấm, sai lão Huyền Nhất bắt nàng mang về tông phái.","bridge":true,"khoang":"@c0486"},{"text":"Phát hiện có người đến qua truyền tống trận liền mỉm cười nhìn về chân trời, nói “Vương huynh! Tôn mỗ chờ huynh đã lâu!”.","bridge":true,"khoang":"@c0486"},{"bridge":true,"khoang":"@c0487","text":"Cố đợi Vương Lâm để cùng đi Đông Hải Yêu Linh; than do gia phụ bắt buộc phải đi dù nguy hiểm; dẫn theo ba trưởng lão Huyền Uyên phái hộ vệ và ra lệnh mở trận pháp tinh không, nhưng từ chối cho muội Tôn Nhược Nam đi theo."},{"bridge":true,"khoang":"@c0488–@c0488","text":"Tôn Vân Sơn đồng hành cùng Vương Lâm tới cửa Đông Hải, âm trầm vì phải vội lên đường mới kịp ngày cuối; tách khỏi Vương Lâm, nhờ chiếu cố và hẹn gặp lại trong Đông Hải Yêu Linh."}],"tuViMoc":[],"tuVi":"Thiếu tông chủ Huyền Uyên phái; tu vi cụ thể chưa rõ.","nhanMach":[{"ten":"Em gái Tôn Vân Sơn","tag":"ho-hang","quanHe":"Em gái","ghiChu":"Ngăn nàng lên Đông Hải."},{"ten":"Huyền Nhất","tag":"cap-tren","quanHe":"Lão già cao thủ dưới trướng","ghiChu":"Sai bắt em gái mang về."},{"ten":"Vương Lâm","tag":"ban-be","quanHe":"Vương huynh","ghiChu":"Long trọng chờ đón qua truyền tống trận."},{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Bạn đồng hành cùng đi Đông Hải Yêu Linh"},{"ten":"Tôn Nhược Nam","tag":"ho-hang","quanHe":"Xá muội, bị hắn từ chối cho đi theo"},{"ten":"Huyền Nhất","tag":"su-mon","quanHe":"Trưởng lão Huyền Uyên phái phụ trách an toàn cho hắn"}],"tuiDo":{"phapBao":[{"ten":"Quạt thúy ngọc","trangThai":"dang-co","moTa":"Chiếc quạt ngọc thường cầm, hay đập thân quạt vào lòng bàn tay.","nguon":"@c0486"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0486","@c0487","@c0488"]},{"id":"huyen-nhat","name":"Huyền Nhất","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Huyền Uyên Phái","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Một trong ba lão già đầu tóc trắng khí tức kinh người theo Tôn Vân Sơn, cao thủ Huyền Uyên phái; được lệnh bắt tiểu thư mang về tông phái.","vaiTro":"Cao thủ hộ vệ của Huyền Uyên phái.","tinhCach":[],"tabs":{"diem":[{"text":"Đầu tóc trắng xóa, khí tức kinh người, đứng sau lưng thiếu tông chủ.","chuong":"@c0486"}],"kinhLich":[{"text":"Được Tôn Vân Sơn sai đi bắt em gái áo hồng đang đòi lên Đông Hải Yêu Linh mang về tông phái.","bridge":true,"khoang":"@c0486"},{"bridge":true,"khoang":"@c0487","text":"Là một trong ba lão già trưởng lão Huyền Uyên phái phụ trách an toàn cho Tôn Vân Sơn; được lệnh cùng hai lão già quay vào trận pháp tinh không để hộ tống chuyến đi Đông Hải Yêu Linh."}],"tuViMoc":[],"tuVi":"Cao thủ Huyền Uyên phái; tu vi cụ thể chưa rõ.","nhanMach":[{"ten":"Tôn Vân Sơn","tag":"su-mon","quanHe":"Thiếu tông chủ chủ quản","ghiChu":"Nhận lệnh hành sự."},{"ten":"Tôn Vân Sơn","tag":"su-mon","quanHe":"Người được hắn hộ vệ"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0486","@c0487"]},{"id":"em-gai-ton-van-son","name":"Em gái Tôn Vân Sơn","cn":"","aliases":["Em gái Tôn Vân Sơn","Xá muội Tôn Vân Sơn"],"gioiTinh":"nu","theLuc":[{"ten":"Huyền Uyên Phái","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Cô gái trẻ khoảng hai mươi tuổi mặc áo hồng nhạt, da trong suốt như thủy tinh, tỏa hương như cây Bách Linh; đòi anh trai cho lên Đông Hải Yêu Linh.","vaiTro":"Tiểu thư Huyền Uyên phái muốn vào Đông Hải Yêu Linh.","tinhCach":[{"text":"Bướng bỉnh, ngang ngạnh — đòi đi cho bằng được, viện cớ mẹ đã đồng ý.","chuong":"@c0486"}],"tabs":{"diem":[{"text":"Hóa từ một đám mây hồng, da trong suốt như thủy tinh, tỏa mùi thơm như cây Bách Linh.","chuong":"@c0486"}],"kinhLich":[{"text":"Đòi anh trai Tôn Vân Sơn cho lên Đông Hải Yêu Linh, ra điều kiện nếu vượt qua được thì phải để nàng đi; khi bị từ chối liền viện cớ “Mẹ đã đồng ý rồi!”.","bridge":true,"khoang":"@c0486"},{"text":"Bị huynh Tôn Vân Sơn từ chối cho đi Đông Hải Yêu Linh, nàng đắc ý lấy ra miếng truyền tống ngọc giản lén trộm của cha, hóa thành sợi tơ trắng phóng vào cầu vồng truyền tống để lén đi theo, hy vọng tìm được bảo vật ở Đông Hải.","bridge":true,"khoang":"@c0487"}],"tuViMoc":[],"tuVi":"Tu vi chưa đủ để vào Đông Hải theo lời Tôn Vân Sơn.","nhanMach":[{"ten":"Tôn Vân Sơn","tag":"ho-hang","quanHe":"Anh trai","ghiChu":"Bị anh ngăn không cho lên Đông Hải."},{"ten":"Tôn Vân Sơn","tag":"ho-hang","quanHe":"Huynh trưởng, người từ chối cho nàng đi theo"},{"ten":"Vương Lâm","tag":"khac","quanHe":"Người nàng lén bám theo, gọi “Vương đại ca”"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0486","@c0487"]},{"id":"tham-lang","name":"Tham Lang","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Tán tu","trangThai":"gan-bo"}],"canhGioiCaoNhat":"","trangThai":"song","blurb":"Người đàn ông trung niên bao phủ tử khí, cưỡi đống xương khô khổng lồ; chủ hung từng muốn cướp Hạt Châu Thiên Nghịch của Tư Đồ Nam, nay thân mang thương nặng tìm tới lão hữu Kiếm Tôn.","vaiTro":"Cường địch tiềm tàng truy tìm Vương Lâm","tinhCach":[{"text":"Tham lam, thủ đoạn — muốn thôn phệ thượng cổ tu sĩ để khôi phục tu vi","chuong":"@c0487"},{"text":"Khôn khéo, biết tránh kẻ mạnh hơn (Tư Đồ Nam) và mượn lực lão hữu","chuong":"@c0487"}],"tabs":{"diem":[{"text":"Bao phủ tử khí, cưỡi mấy nghìn bộ xương khô khổng lồ trong đó có một bộ cực lớn của mãnh thú thượng cổ","chuong":"@c0487"}],"kinhLich":[{"text":"Vì thân mang thương nặng và muốn tránh Tư Đồ Nam, hắn rời Chu Tước Tinh đến Đại La Kiếm Tông tìm Kiếm Tôn không gặp nên đuổi theo tới cửa Đông Hải; phá toái hư không xông vào phạm vi trăm dặm, chào “Lăng Thiên lão hữu” và đề nghị tặng Kiếm Tôn một cơ duyên cực lớn để đè đầu Thiên Vận Tử dễ như trở bàn tay.","bridge":true,"khoang":"@c0487"},{"chuong":"@c0488","importance":"normal","tieuDe":"Tiết lộ cơ duyên hạt châu","text":"Tham Lang kể với Lăng Thiên Hậu chuyện mấy vạn năm trước Tu Chân Liên Minh treo thưởng một bộ thượng phẩm tiên thuật hoàn chỉnh để tìm một hạt châu; thừa nhận vết thương của hắn liên quan đến hạt châu đó và đang bị người giữ nó bức bách. Hắn nhận lời giúp Lăng Thiên Hậu, hóa thành bóng ma ẩn sau lưng lão, cảm thấy Vương Lâm quen thuộc như cố nhân năm xưa."},{"text":"Đã sớm biến mất sau lưng Lăng Thiên Hậu, hóa thành đạo kiếm khí bảo mệnh được ban cho đệ tử cuối cùng của Kiếm Tiếu Thập Nhị Tử, theo Đại La kiếm tông tiến vào cánh cửa yêu linh.","bridge":true,"khoang":"@c0491"}],"tuViMoc":[],"nhanMach":[{"ten":"Kiếm Tôn","tag":"dong-minh","quanHe":"Lão hữu cũ mà hắn tới nhờ vả"},{"ten":"Tư Đồ Nam","tag":"doi-thu","quanHe":"Người sở hữu Hạt Châu Thiên Nghịch mà hắn từng muốn cướp, nay phải tránh mặt"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Người hắn truy tìm cùng sợi tơ Thiên Kiếp"},{"ten":"Lăng Thiên Hậu","tag":"dong-minh","quanHe":"Người được cầu nhờ","ghiChu":"Tham Lang tìm tới nhờ xuất thủ chuyện hạt châu, đổi lại bảo vệ mười hai đệ tử của lão trong Đông Hải."},{"ten":"Vương Lâm","tag":"khac","quanHe":"Cảm giác quen thuộc","ghiChu":"Tham Lang cảm thấy trên người Vương Lâm sinh ra cảm giác như cố nhân năm xưa rồi thu hồi ánh mắt."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0487","@c0488","@c0491"]},{"id":"chu-vu-thai","name":"Chu Vũ Thái","tabs":{"kinhLich":[{"bridge":true,"khoang":"@c0489","text":"Đang khoanh chân tĩnh tọa trên Chu Tước Tinh xa xôi, đột nhiên mở hai mắt khi thấy bầu trời đỏ rực bởi hồng quang thủy triều Đông Hải Yêu Linh lan tới."}]},"nguon":["@c0489"]},{"id":"nguoi-xich-loa-tho-san-son-coc","name":"Người xích lõa vẽ nhựa cây (thợ săn)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Cư dân sơn cốc Đông Hải yêu linh","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ (không có linh lực)","trangThai":"song","blurb":"Người nửa thân xích lõa sống trong sơn cốc vùng Đông Hải yêu linh, không có chút linh lực nào nhưng linh tính kinh người, săn dã thú bằng vũ khí u quang.","vaiTro":"Cư dân chủng người lạ trong sơn cốc trận pháp thượng cổ.","tinhCach":[{"text":"Cảnh giác, hoang dã, đề phòng người lạ — giành giữ con thú săn được.","chuong":"@c0492"}],"tabs":{"diem":[{"text":"Không có linh lực nhưng linh tính kinh người, ẩn thân cực giỏi bằng nhựa cây xanh.","chuong":"@c0492"},{"text":"Săn dã thú bằng gậy đen gắn lưỡi dao u quang; máu con thú lộ u quang.","chuong":"@c0492"}],"kinhLich":[{"text":"Nằm ẩn thân trong rừng, bất ngờ bật dậy đâm chết con dã thú lớn không linh lực, nhảy lên lưng thú cắt cổ. Khi Vương Lâm hiện thân, hắn cảnh giác cầm dao thốt giọng khàn “Thú, ta!” để giành con thú; được Vương Lâm nhường, hắn kéo xác thú lui về sơn cốc.","bridge":true,"khoang":"@c0492"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Tu sĩ lạ gặp ở rừng núi, nhường con thú rồi sau giam giữ tra hỏi"}],"tuiDo":{"khac":[{"ten":"Gậy dài màu đen gắn lưỡi dao u quang","loai":"vũ khí","moTa":"Đầu gậy gắn lưỡi dao nhỏ phát u quang; gậy gãy vụn khi đâm thú nhưng lưỡi dao giết được dã thú.","nguon":"@c0492"}]}},"nguon":["@c0492"]},{"id":"au-duong-hoa","name":"Âu Dương Hoa","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Bộ tộc sơn cốc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"","trangThai":"song","blurb":"Lão giả tóc bạc tự xưng trưởng lão sơn cốc, sống ở vùng đất này từ khi có ký ức, thuở nhỏ từng học ở Cổ yêu thành nên có tuổi thọ cao.","vaiTro":"Trưởng lão bộ tộc thân trâu mình người trong sơn cốc, đối đầu Vương Lâm bằng thượng cổ trận pháp.","tinhCach":[{"text":"Vẻ ngoài tang thương, lời lẽ ôn hòa nhưng quyết liệt bảo vệ tộc nhân","chuong":"@c0493"}],"tabs":{"diem":[{"text":"Chỉ hiện thân bằng thế thân hư ảo, bản thể thật ẩn sâu trong cốc","chuong":"@c0493"},{"text":"Thờ yêu linh, định lấy hồn phách người ngoài làm tế phẩm","chuong":"@c0493"}],"kinhLich":[{"text":"Sau ba ngày yên tĩnh, Âu Dương Hoa cầm quải trượng đen cùng mười một sinh vật thân trâu mình người bước ra khỏi cốc, xin thả tộc nhân để đối thoại. Lão tiết lộ về Cổ yêu thành ngoài ba ngàn dặm, khuyên Vương Lâm tới đó tìm vật cần và nói người ngoài cứ bốn trăm năm lại tới một lần.","bridge":true,"khoang":"@c0493"},{"text":"Khi Vương Lâm phá trận, Âu Dương Hoa lộ ra chỉ là thế thân hư ảo; bản thể trong cốc lệnh trận pháp hút kéo vạn vật ngưng thành hư ảnh người màu xanh cao mấy trượng để giết Vương Lâm, lấy hồn phách tế yêu linh.","bridge":true,"khoang":"@c0493"},{"text":"Dựa vào trận pháp thượng cổ trong sơn cốc, Âu Dương Hoa cười lạnh đòi Vương Lâm tự cắt một tay một chân để hắn hấp thu ba phần nguyên thần, dọa biến đối phương thành yêu ảnh thứ hai; khi trận bị tám mươi ba tổ hợp cấm chế đánh tan thì hoảng sợ cầu xin tha mạng.","bridge":true,"khoang":"@c0494"},{"chuong":"@c0495","importance":"normal","tieuDe":"Thần phục Vương Lâm","text":"Dẫn mười tộc nhân ra cốc cung kính xưng Vương Lâm là thượng tiên, xin đừng phá trận pháp kẻo cả tộc thành thức ăn của yêu linh. Cắn ngón tay vẩy giọt máu mở thông đạo mời Vương Lâm vào sơn cốc, kể về Hoàng Long và trận pháp cổ, cảnh báo đêm yêu linh và mời về nhà mình."},{"text":"Kể cho Vương Lâm về nơi yêu linh có chín quận, bộ tộc đang ở thuộc Thiên Yêu quận với yêu đế Tai Hư, bát đại yêu soái, thiên vạn yêu binh, hơn trăm thành trì; nhắc đêm trăng tròn là đêm yêu linh đi săn mồi, và quy luật cứ năm trăm năm có người bên ngoài tiến vào. Sau khi thấy đan dược của Vương Lâm, hạ quyết tâm dẫn hắn tới đáy sơn cốc hình hồ lô xem ngọc yêu linh.","bridge":true,"khoang":"@c0496"},{"text":"Âu Dương Hoa run rẩy nhận hơn mười bình ngọc của Vương Lâm, đem yêu lực kết tinh duy nhất của thung lũng đổi lấy; hé lộ rằng vì trận pháp Hồ Lô Cốc đã suy yếu nặng, không chắc chống được đêm Yêu linh săn mồi, nên cắn răng mời thượng tiên ở lại và tiết lộ bí mật để mong được trợ giúp.","bridge":true,"khoang":"@c0497"},{"bridge":true,"khoang":"@c0497","text":"Đêm xuống, Âu Dương Hoa cùng đàn ông trong cốc cầm vũ khí tập trung ở cửa, niệm chú duy trì trận pháp; khi trận bị sóng yêu khí công phá sắp vỡ, hắn mừng rỡ gọi Vương Lâm là thượng tiên đến cứu mạng."},{"bridge":true,"khoang":"@c0503","text":"Cung kính cung đón Vương Lâm là thượng tiên khi hắn trở về thung lũng, đoán người đi cùng hắn trước đó đã bị giết. Theo lệnh, hắn ra lệnh cấm mọi người vào sâu thung lũng (cấm địa), ai trái lệnh bị đuổi, đồng thời tuyên bố sơn cốc quá nhỏ cần mở rộng địa bàn — tuyên chiến với tộc khác, khiến cư dân phấn khích."},{"chuong":"@c0504","importance":"normal","tieuDe":"Được đả thông kinh mạch, đột phá nhị tinh","text":"Trưởng lão sơn cốc, thuở nhỏ từng học ở thành cổ yêu nhưng bị đuổi vì bị phát hiện có tinh lực. Được Vương Lâm dùng song chỉ điểm từ bụng lên mi tâm cưỡng ép đả thông kinh mạch, đau thấu xương rồi ngất, mấy canh giờ sau tỉnh dậy đạt nhị tinh, tự thấy như được hồi sinh, quỳ tạ thượng tiên."},{"bridge":true,"khoang":"@c0504","text":"Nhận yêu giản, nhìn thấu khẩu quyết luyện hồn, được giao truyền dạy lại cho toàn cốc; ba tháng chuyên tâm tu luyện thuật luyện hồn tiến bộ cực nhanh, cảm kích thề khắc cốt ân điển."},{"chuong":"@c0505","importance":"normal","tieuDe":"Nhường cơ hội, định kế tấn công bộ tộc","text":"Âu Dương Hoa đã tới giai đoạn ba và chế xong hồn phiên trước Thập Tam mấy ngày nhưng cố ý nhường cơ hội cho hắn, nhận ra tương lai sơn cốc thuộc về Thập Tam; lão trình Vương Lâm kế hoạch một tháng sau phát động người trong cốc đánh một bộ tộc vài chục người cách ngàn dặm."},{"chuong":"@c0506","importance":"normal","tieuDe":"Dâng yêu tinh nhận khẩu quyết giai đoạn bốn","text":"Cung kính cầu kiến ‘thượng tiên’, dâng khối đá đen chứa nhị giáp yêu tinh và nhận ngọc giản khẩu quyết Luyện Hồn Thuật giai đoạn thứ tư — hiện là người duy nhất đạt mức này. Vốn phản đối nữ tu, bị Vương Lâm khiển trách liền đổi sang cổ vũ nữ tử tu hành."},{"bridge":true,"khoang":"@c0506–@c0506","text":"Cùng Thập Tam làm chủ công đánh hạ bộ tộc trong động, luyện hóa hồn phách người vừa chết; chỉ huy đồng hóa người ngoại tộc bằng yêu thang và đẩy bộ lạc chuyển sang xâm lược."},{"chuong":"@c0507","importance":"normal","tieuDe":"Lập bộ lạc Luyện Hồn","text":"Dẫn một tổ đi đánh bộ lạc trở về thắng lợi; sau khi Vương Lâm giết lão áo trắng, thu nạp toàn bộ dân Thiên Thủy làm tộc nhân mới và đặt tên bộ lạc là Luyện Hồn."},{"chuong":"@c0508","importance":"normal","tieuDe":"Thủ lĩnh dưới trướng Vương Lâm","text":"Làm thủ lĩnh dưới quyền Vương Lâm trong bộ lạc Luyện Hồn; bắt Hổ Bào về tộc, mang Thập Tam bị thương đến cầu Vương Lâm cứu rồi thầm chúc hắn may mắn. Sau bốn năm tu vi tăng mạnh, quỳ tiễn Vương Lâm lên đường."},{"bridge":true,"khoang":"@c0529","text":"Dẫn đầu bộ lạc Luyện Hồn hóa hắc vụ ra cung nghênh lão tổ Vương Lâm trở về sau trận chiến với Yêu Tướng."},{"chuong":"@c0531","importance":"normal","tieuDe":"Nhận sứ mệnh bành trướng bộ lạc","text":"Được Vương Lâm dặn phái mấy trăm tộc nhân tiềm nhập các bộ lạc lớn nhỏ dùng Hồn Phách Thủ Thần chống Linh Thang Loạn Thần để truyền Luyện Hồn Thuật, mục tiêu hơn trăm vạn tộc nhân; nhận ngọc giản phần hai Luyện Hồn Thuật (thần thông rút phách) chỉ truyền chi chính, bóp nát ghi nhớ rồi quỳ tiễn Vương Lâm, xưng lão tổ."}],"tuViMoc":[{"chuong":"@c0504","canhGioi":"Nhị tinh","text":"Được Vương Lâm cưỡng ép đả thông kinh mạch, đột phá lên trình độ nhị tinh — đường tắt nâng tu vi nhưng để lại di chứng.","importance":"minor"},{"chuong":"@c0505","canhGioi":"Giai đoạn ba (Luyện Hồn Yêu Thuật)","text":"Được Vương Lâm cho phép, Âu Dương Hoa tu luyện Luyện Hồn Yêu Thuật tới giai đoạn ba. Đây là thành tựu thuộc hệ Luyện Hồn Thuật, không phải tu vi chính.","importance":"minor"}],"tuVi":"Tu vi không rõ; thân thể yếu ớt, có tuổi thọ rất cao nhờ từng học ở Cổ yêu thành.","nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Người ngoài xâm nhập sơn cốc, đối đầu qua trận pháp","ghiChu":"Bị Vương Lâm phá trận và nhận ra chỉ là thế thân hư ảo."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối thủ","ghiChu":"Vây Vương Lâm bằng trận pháp nhưng bị hắn phá trận, áp sát buộc phải cầu tha."},{"ten":"Vương Lâm","tag":"khac","quanHe":"Tôn xưng Vương Lâm là thượng tiên, mời vào sơn cốc và tiếp đãi","ghiChu":""},{"ten":"Hoàng Long","tag":"khac","quanHe":"Thượng tiên dẫn tổ tiên tộc Âu Dương Hoa đến định cư, được tôn thờ qua bức tranh","ghiChu":""},{"ten":"Vương Lâm","tag":"khac","quanHe":"Người bên ngoài mà Âu Dương Hoa dẫn đi đổi đan dược lấy ngọc yêu linh","ghiChu":"Lo sợ tộc nhân chết nhưng vẫn dẫn đi vì đan dược là trọng bảo."},{"ten":"Vương Lâm","tag":"an-nhan","quanHe":"Thượng tiên được Âu Dương Hoa mời ở lại và đổi yêu lực kết tinh, cầu cứu khi yêu linh tấn công","ghiChu":"@c0497"},{"ten":"Vương Lâm","tag":"cap-tren","quanHe":"Tôn làm thượng tiên, phụng mệnh thi hành cấm địa và tuyên chiến mở rộng địa bàn","ghiChu":""},{"ten":"Vương Lâm","tag":"an-nhan","quanHe":"Ân nhân / sư tôn","ghiChu":"Đả thông kinh mạch cho đột phá nhị tinh và truyền thụ thuật luyện hồn; Âu Dương Hoa tôn kính xưng vãn bối, hành lễ như đệ tử."},{"ten":"Thập Tam","tag":"khac","quanHe":"Hậu bối được nhường đường","ghiChu":"Âu Dương Hoa nhường cơ hội chế hồn phiên cho Thập Tam và dùng tiểu phiên triệu chim sẻ cứu hắn khi sư tử phản phệ."},{"ten":"Vương Lâm","tag":"su-mon","quanHe":"Cung kính tôn là ‘thượng tiên’, dâng yêu tinh đổi khẩu quyết","ghiChu":""},{"ten":"Thập Tam","tag":"dong-minh","quanHe":"Cùng làm chủ công các trận chinh phạt","ghiChu":""},{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"chủ nhân","ghiChu":"Tộc nhân thân tín, luôn nghe lời Vương Lâm."},{"ten":"Hổ Bào","tag":"doi-thu","quanHe":"Người Âu Dương Hoa bắt về tộc","ghiChu":"Bắt Hổ Bào, cho uống Ly Yêu thang để gia nhập bộ lạc."},{"ten":"Thập Tam","tag":"dong-minh","quanHe":"Cùng bộ lạc","ghiChu":"Mang Thập Tam bị thương đến cầu Vương Lâm cứu, thầm chúc hắn may mắn."},{"ten":"Vương Lâm","tag":"cap-tren","quanHe":"Tôn xưng lão tổ, người ban truyền thừa & sứ mệnh bộ lạc","ghiChu":""}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[{"ten":"Quải trượng màu đen","moTa":"Cây gậy đen Âu Dương Hoa cầm khi bước ra khỏi cốc.","nguon":"@c0493"}]}},"nguon":["@c0493","@c0494","@c0495","@c0496","@c0497","@c0503","@c0504","@c0505","@c0506","@c0507","@c0508","@c0529","@c0531"]},{"id":"hoang-long-thuong-tien","name":"Hoàng Long","cn":"","aliases":["Hoàng Long thượng tiên"],"gioiTinh":"nam","theLuc":[],"trangThai":"khong-ro","blurb":"Nam tử trung niên trong bức tranh cổ ố vàng nhà Âu Dương Hoa, được tộc nhân tôn là Hoàng Long thượng tiên đã dẫn tổ tiên họ đến định cư sơn cốc.","vaiTro":"Nhân vật được nhắc qua truyền miệng và bức tranh; cái tên khiến Vương Lâm chấn động nguyên thần.","tinhCach":[],"tabs":{"diem":[{"text":"Được tộc Âu Dương Hoa tôn là thượng tiên qua lời kể tổ tiên","chuong":"@c0495"}],"kinhLich":[{"chuong":"@c0495","importance":"normal","tieuDe":"Hoàng Long trong bức tranh cổ","text":"Vô số năm trước dẫn tộc nhân tổ tiên Âu Dương Hoa đến định cư sơn cốc, nơi trận pháp cổ đã tồn tại qua vô số năm. Hình ảnh lưu trong bức tranh ố vàng nứt nẻ: nam tử trung niên mặc trang phục kỳ dị, tay phải tạo ấn ký cổ quái trước ngực, nhìn về một hư ảnh ẩn hiện trong màn sương đen. Cái tên khiến Vương Lâm chấn động nguyên thần."}],"tuViMoc":[],"nhanMach":[{"ten":"Âu Dương Hoa","tag":"khac","quanHe":"Trưởng lão tộc nhân lưu giữ bức tranh và tôn thờ Hoàng Long","ghiChu":""},{"ten":"Vương Lâm","tag":"khac","quanHe":"Cái tên Hoàng Long khiến Vương Lâm chấn động nguyên thần","ghiChu":""}],"tuiDo":{}},"nguon":["@c0495"]},{"id":"tai-hu","name":"Tai Hư","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[{"ten":"Thiên Yêu quận","trangThai":"gan-bo"}],"trangThai":"khong-ro","blurb":"Yêu đế của Thiên Yêu quận nơi yêu linh, thống lĩnh bát đại yêu soái, thiên vạn yêu binh và hơn trăm thành trì.","vaiTro":"Yêu đế","tinhCach":[],"tabs":{"diem":[],"kinhLich":[{"chuong":"@c0496","importance":"normal","tieuDe":"Yêu đế Thiên Yêu quận","text":"Được Âu Dương Hoa nhắc tới là yêu đế của Thiên Yêu quận, nắm giữ một phương với bát đại yêu soái, thiên vạn yêu binh và hơn trăm thành trì."}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0496"]},{"id":"hac-y-nam-tu-thien-van-tinh","name":"Hắc y nam tử (Thiên Vận Tinh)","cn":"","aliases":["Hắc y nam tử"],"gioiTinh":"nam","theLuc":[{"ten":"Thiên Yêu Thành","trangThai":"danh-nghia"}],"canhGioiCaoNhat":"Ứng Biến hậu kỳ đại viên mãn","trangThai":"song","blurb":"Tu sĩ áo đen mặt lạnh cầm kiếm mỏng màu đen, săn yêu linh ở Thiên Vận Tinh để lấy yêu tinh đủ tư cách tiến vào Thiên Yêu Thành; coi Vương Lâm là con mồi.","vaiTro":"Đối thủ của Vương Lâm tại Thiên Vận Tinh","tinhCach":[{"text":"Lạnh lùng, khinh miệt và tự tin, thích dồn con mồi vào thế bất ngờ","chuong":"@c0497"}],"tabs":{"diem":[{"text":"Tu vi Ứng Biến hậu kỳ đại viên mãn, hấp thu yêu lực điên cuồng qua thất khiếu","chuong":"@c0497"},{"text":"Săn yêu linh để lấy yêu tinh đủ tư cách tiến vào Thiên Yêu Thành","chuong":"@c0497"}],"kinhLich":[{"chuong":"@c0497","importance":"normal","tieuDe":"Tuyên bố săn Vương Lâm","text":"Thần thức Vương Lâm phát hiện Hắc y nam tử đang múa kiếm thu hút lượng lớn yêu lực; hắn ngẩng đầu cười lạnh, khen tu vi Vương Lâm không tồi nhưng tuyên bố Vương Lâm là con mồi của mình, dù giao nộp yêu linh cũng vô dụng. Hắn lầm tưởng Vương Lâm chỉ Ứng Biến trung kỳ, cho rằng thu được yêu tinh của đối phương thì đủ tư cách tiến vào Thiên Yêu Thành."},{"bridge":true,"khoang":"@c0497","text":"Hắc y nam tử chém một con vật kỳ dị một sừng làm đôi để hút yêu lực, rồi vung kiếm hóa điện quang phi kiếm lao thẳng tới thung lũng, vang thanh âm lạnh như băng: Săn bắn, bắt đầu!"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Coi Vương Lâm là con mồi để lấy yêu tinh tiến vào Thiên Yêu Thành; lầm tưởng đối phương chỉ Ứng Biến trung kỳ","ghiChu":"@c0497"}],"tuiDo":{"phapBao":[{"ten":"Kiếm mỏng màu đen","trangThai":"dang-co","moTa":"Trường kiếm mỏng màu đen dùng thu hút yêu lực và hóa thành điện quang phi kiếm tấn công từ xa.","nguon":"@c0497"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0497"]},{"id":"la-mo-hac-y-nam-tu","name":"La mỗ (Hắc y nam tử)","cn":"","aliases":["Hắc y nam tử","La mỗ"],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Vấn Đỉnh (nguyên thần)","trangThai":"song","blurb":"Tu sĩ hắc y đạp phi kiếm ngông cuồng, chạm trán Vương Lâm giữa sóng yêu linh; sở trường hỏa hệ với Địa diệt chi hỏa và cấm thuật Kiếm toái.","vaiTro":"Đối thủ thoáng qua của Vương Lâm tại Thiên Yêu quận.","tinhCach":[{"text":"Ngông cuồng, lạnh lùng, song thận trọng — sợ giết nhầm người quen nên dò hỏi môn phái trước.","chuong":"@c0498"}],"tabs":{"diem":[{"text":"Nguyên thần cao thâm, sở trường hỏa hệ; tự xưng La mỗ.","chuong":"@c0498"},{"text":"Am hiểu danh tiếng các thế lực, nhận ra ngay thân phận Vương Lâm qua ngọc giản tướng mạo.","chuong":"@c0498"}],"kinhLich":[{"text":"Đạp phi kiếm chặn Vương Lâm, ban đầu tưởng hắn là người Đại La Kiếm Tông. Khi giao đấu, bị loan đao đả thương ngực tuôn huyết quang, phải nuốt đan dược khôi phục. Y tung Kiếm toái cùng Địa diệt chi hỏa hóa sáu rồng lửa nhưng Vương Lâm dùng Sinh Chi Lạc Ấn hóa giải, suýt bị điểm trúng. Cuối cùng y nhận ra đối phương là đệ tử Thiên Vận Tử, Tử hệ lão thất Vương Lâm.","bridge":true,"khoang":"@c0498"},{"text":"Tu sĩ Anh Biến hậu kỳ đại viên mãn tự xưng hành sự thay Tôn sư, giao chiến với Vương Lâm trong Yêu linh khí lãng. Dùng huyết sắc ngũ sát phong ấn Côn Cực Tiên nhưng lần đầu thất bại, bị roi tiên đả thương nguyên thần; sau khi phun độc khí rút lui bất thành, hắn hút khói đen vào ngực chịu đau tột độ, thi triển Ma cấm biến tay trái thành mười Quỷ ảnh thiên quỷ đệ tứ tôn lao vào Vương Lâm.","bridge":true,"khoang":"@c0499"},{"chuong":"@c0501","importance":"normal","tieuDe":"Bị diệt thân, lộ thân phận La Vân","text":"Hồn thú của Vương Lâm thiêu rụi thân thể chỉ còn nguyên thần thoát ra; La Vân dùng Tổn Thần thuật hao tổn tinh hoa nguyên thần để bỏ chạy nhưng bị Côn Cực Tiên quấn bắt. Hắn xưng tên La Vân, người Thiên Quỷ Đạo, có quỷ linh bảo vệ, sư tôn là Quỷ Chân Nhân, dọa sẽ báo thù."},{"chuong":"@c0501","importance":"normal","tieuDe":"Bị Sưu Hồn, giam vào hồn phiên","text":"Vương Lâm lập cấm chế ngăn tự bạo rồi thi triển Sưu Hồn Thuật; La Vân kêu la khoảng một nén nhang rồi bất động, nguyên thần gần như trong suốt. Kết tinh trong đan điền và toàn bộ ký ức bị đoạt, nguyên thần bị giam để luyện thành chủ hồn."}],"tuViMoc":[{"chuong":"@c0501","canhGioi":"Nguyên thần Anh Biến hậu kỳ đại viên mãn","text":"Tu vi sắp bước vào Vấn Đỉnh, nhờ vậy chống được phần nào quỷ phong của hồn thú.","importance":"minor"}],"tuVi":"Nguyên thần cao hơn Vương Lâm nhiều; sở hữu phi kiếm và thủ đoạn hỏa hệ mạnh.","nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối thủ chạm trán","ghiChu":"Nhận ra Vương Lâm là đệ tử Thiên Vận Tử dùng Tịch Diệt Chỉ; lo khó hạ sát vì hắn có pháp bảo bảo mệnh."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối thủ giao chiến","ghiChu":"Bị Côn Cực Tiên của Vương Lâm đả thương nguyên thần; đáp trả bằng Ma cấm."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Bị Vương Lâm diệt thân, bắt sống nguyên thần và Sưu Hồn đoạt ký ức","ghiChu":"@c0501"},{"ten":"Quỷ Chân Nhân","tag":"su-mon","quanHe":"Sư tôn","ghiChu":"La Vân dọa sư tôn sẽ báo thù (@c0501)"}],"tuiDo":{"phapBao":[{"ten":"Phi kiếm (tế kiếm)","trangThai":"hong","moTa":"Phi kiếm y đạp di chuyển, bị kiếm tiên Vương Lâm làm rạn rồi dùng làm Kiếm toái nổ vỡ.","nguon":"@c0498"}],"danDuoc":[{"ten":"Đan dược hồi thương","moTa":"Lấy từ túi trữ vật nuốt nhanh để khôi phục thương thế ngực.","nguon":"@c0498"}],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0498","@c0499","@c0501"]},{"id":"tu-he-lao-luc","name":"Tử hệ lão Lục","cn":"","aliases":["Lão Lục Tử hệ"],"gioiTinh":"nam","theLuc":[{"ten":"Thiên Vận Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Vấn Đỉnh","trangThai":"song","blurb":"Sư huynh đồng môn Tử hệ của Vương Lâm; từng dùng tu vi Vấn Đỉnh đè ép khiến Vương Lâm mất danh hiệu Thiên Vận Thất Tử.","vaiTro":"Nhân vật được nhắc tên — ân oán tiềm tàng trong Tử hệ.","tinhCach":[],"tabs":{"diem":[{"text":"Tu vi Vấn Đỉnh, vị trí lão Lục trong Tử hệ Thiên Vận Tử.","chuong":"@c0498"}],"kinhLich":[{"text":"Được nhắc lại: từng dùng tu vi Vấn Đỉnh đè ép Vương Lâm, khiến danh hiệu Thiên Vận Thất Tử không thuộc về Vương Lâm.","bridge":true,"khoang":"@c0498"}],"tuViMoc":[],"tuVi":"Tu vi Vấn Đỉnh.","nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Sư huynh đồng môn Tử hệ","ghiChu":"Đè ép Vương Lâm, gây ân oán."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0498"]},{"id":"hac-y-nam-tu-mat-seo","name":"Hắc y nhân (mặt sẹo)","tabs":{"diem":[],"kinhLich":[{"chuong":"@c0500","importance":"normal","tieuDe":"Mất Thiên Quỷ, bỏ thân chạy nguyên thần","text":"Trong trận với Vương Lâm, hắn thu Quỷ ảnh (Thiên Quỷ) nhưng bị Vương Lâm áp chế bằng Hóa ma chỉ; Thiên Quỷ tự sinh hắc quang bỏ trốn. Hắn dồn gần 90% quỷ tiên lực vào tiểu cầu hủy diệt, nhưng khi Vương Lâm mở Xạ Thần Xa thả Hồn thú, hắn buộc phải vỗ mi tâm cho nguyên thần rời cơ thể chạy trốn, để lại thân xác không hồn cho tiểu cầu lao tới."}],"tuViMoc":[{"chuong":"@c0500","canhGioi":"Anh Biến hậu kỳ đại viên mãn","text":"Tự xưng Anh Biến hậu kỳ đại viên mãn, hơn Vương Lâm một bậc, dựa vào quỷ tiên lực và Thiên Quỷ hấp thu hồn.","importance":"minor"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối thủ sinh tử","ghiChu":"Bị Vương Lâm áp chế, mất Thiên Quỷ, cuối cùng bỏ thân xác cho nguyên thần chạy trốn."}],"tuiDo":{"phapBao":[{"ten":"Thiên Quỷ (Quỷ ảnh)","loai":"khac","trangThai":"mat","moTa":"Quỷ vật chuyên nuốt hồn thể để tăng quỷ lực; bị ép tới mức tự sinh hắc quang bỏ trốn khỏi chủ nhân.","nguon":"@c0500"}],"congPhap":[{"ten":"Thuật khống chế Quỷ ảnh","moTa":"Dùng tơ mảnh màu đen từ ngực và tay để thu hồi và khống chế Thiên Quỷ; phải đặt tay phải trên ngực giữ thuật khỏi bị phá.","nguon":"@c0500"}],"khac":[]}},"nguon":["@c0500"]},{"id":"quy-chan-nhan","name":"Quỷ Chân Nhân","gioiTinh":"khong-ro","theLuc":[{"ten":"Thiên Quỷ Đạo","trangThai":"gan-bo"}],"trangThai":"khong-ro","blurb":"Sư tôn của La Vân thuộc Thiên Quỷ Đạo, được nói địa vị ngang hàng Thiên Vận Tử.","vaiTro":"Nhân vật được nhắc tên — mầm xung đột tương lai","tinhCach":[],"tabs":{"diem":[],"kinhLich":[{"text":"La Vân dọa Vương Lâm rằng sư tôn Quỷ Chân Nhân sẽ báo thù, người này gặp Thiên Vận Tử cũng phải nói chuyện ngang hàng.","bridge":true,"khoang":"@c0501"}],"tuViMoc":[],"nhanMach":[{"ten":"La Vân","tag":"su-mon","quanHe":"Đệ tử","ghiChu":"@c0501"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0501"]},{"id":"la-van","name":"La Vân","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thiên Quỷ Đạo","trangThai":"gan-bo"}],"canhGioiCaoNhat":"","trangThai":"tu-vong","blurb":"Tu sĩ thân phận tôn quý của Thiên Quỷ Đạo, bị Vương Lâm hấp thu ký ức; bản mạng quỷ linh của hắn phản chủ do tu luyện quá ngắn.","vaiTro":"Phản diện thoáng qua","tinhCach":[{"text":"Toan tính, sẵn sàng giết người ngoài để đoạt yêu lực còn thiếu.","chuong":"@c0502"}],"tabs":{"diem":[{"text":"Thân phận tôn quý ở Thiên Quỷ Đạo, được Sư tôn ban cho một trong chín bản mạng quỷ linh phòng thân.","chuong":"@c0502"}],"kinhLich":[{"text":"La Vân dựa kinh nghiệm tổ tiên Thiên Quỷ Đạo lưu lại, định kế hoạch nhập một quận trong vùng đất yêu linh để đạt chiến công, cần đủ ba giáp yêu lực nên muốn giết Vương Lâm để đoạt nốt một giáp còn thiếu. Kết cục hắn bị Vương Lâm hấp thu trọn ký ức và lấy đi yêu tinh hai giáp; bản mạng Thiên quỷ của hắn cũng phản chủ vì hắn tu luyện quá ngắn.","bridge":true,"khoang":"@c0502"}],"tuViMoc":[],"tuVi":"Yêu tinh trong nguyên thần đan điền tương đương hai giáp yêu lực.","nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Người đoạt ký ức và yêu tinh của hắn","ghiChu":"La Vân định giết Vương Lâm để đoạt giáp yêu lực, ngược lại bị Vương Lâm chế ngự."},{"ten":"Sư tôn của La Vân","tag":"su-mon","quanHe":"Sư tôn ban bản mạng quỷ linh"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0502"]},{"id":"su-ton-cua-la-van","name":"Sư tôn của La Vân","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[{"ten":"Thiên Quỷ Đạo","trangThai":"gan-bo"}],"canhGioiCaoNhat":"","trangThai":"khong-ro","blurb":"Bậc trên ở Thiên Quỷ Đạo, tự tay đưa cho La Vân một trong chín bản mạng quỷ linh yếu nhất để phòng thân.","vaiTro":"Nhân vật nhắc tên","tinhCach":[],"tabs":{"diem":[{"text":"Nắm giữ chín bản mạng quỷ linh của Thiên Quỷ Đạo, ban cho La Vân một con yếu nhất.","chuong":"@c0502"}],"kinhLich":[{"text":"Được nhắc tới khi Vương Lâm giải thích nguồn gốc bản mạng quỷ linh của La Vân.","bridge":true,"khoang":"@c0502"}],"tuViMoc":[],"tuVi":"","nhanMach":[{"ten":"La Vân","tag":"su-mon","quanHe":"Đồ đệ được ban bản mạng quỷ linh"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0502"]},{"id":"thap-tam","name":"Thập Tam","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Tập thể tu luyện sơn cốc (Thiên Vận Tinh)","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Giai đoạn ba (Luyện Hồn Yêu Thuật)","trangThai":"song","blurb":"Thanh niên ở Thiên Vận Tinh có ngộ tính trời sinh với Luyện Hồn Thuật, được Vương Lâm coi trọng và đích thân cứu khi sư tử cánh dài phản phệ.","vaiTro":"Đệ tử triển vọng nhất của nhóm tu luyện Luyện Hồn Yêu Thuật trong sơn cốc của Vương Lâm.","tinhCach":[{"text":"Kính sợ và sùng kính Vương Lâm tới tận đáy lòng, cuồng nhiệt khao khát đạt tới thập/bách/thiên/vạn hồn phiên.","chuong":"@c0505"}],"tabs":{"diem":[{"text":"Ngộ tính trời sinh với Luyện Hồn Thuật, chỉ ba tháng đã tu tới giai đoạn ba, tốc độ khiến cả tiền nhân Độn Thiên cũng phải động dung.","chuong":"@c0505"}],"kinhLich":[{"chuong":"@c0505","importance":"normal","tieuDe":"Được Vương Lâm coi trọng trao ngọc giản","text":"Thập Tam chính là người Vương Lâm âm thầm theo dõi từ trước; sau ba tháng tu luyện tới giai đoạn ba, hắn được Vương Lâm gọi tới trao ngọc giản phương pháp chế hồn phiên mới, run rẩy kích động quỳ lạy ba lạy rồi lui ra toàn lực chế tạo."},{"chuong":"@c0505","importance":"normal","tieuDe":"Chế thành hồn phiên, bị sư tử phản phệ","text":"Sau ba lần thất bại, Thập Tam chế thành cây hồn phiên bảy thước đầu tiên và triệu được hồn phách sư tử cánh dài (luyện từ con sư tử trọng thương trong rừng); khi hắn hô “Thu!”, sư tử quay đầu lao thẳng vào hắn đầy sát khí, Thập Tam bị một lực vô hình giam cầm suýt chết, được Vương Lâm ra tay chấn nhiếp cứu mạng."},{"text":"Khí chất trầm ổn kiên nghị hơn trước, Thập Tam cùng Âu Dương Hoa dẫn mười nam nhân đánh hạ bộ tộc trong động dưới lòng đất sau năm ngày. Hắn gọi chủ hồn sư tử nuốt gọn trưởng lão đối phương rồi luyện hóa hồn phách ngay trước mặt ngoại tộc, có được chủ hồn thứ hai.","bridge":true,"khoang":"@c0506"},{"bridge":true,"khoang":"@c0506–@c0506","text":"Được Vương Lâm ban chủ hồn sư tử cho Hồn Phiên kèm lời cảnh cáo về rủi ro phản phệ; đã luyện hóa bảy cây Hồn Phiên với hai chủ hồn."},{"text":"Dẫn tổ đi đánh bộ lạc thì gặp lão áo trắng (Hóa thần trung kỳ), bị đánh nát kinh mạch toàn thân, mất sạch yêu lực tu luyện luyện hồn thuật (đã đạt tam tinh), hồn phiên bị cướp, bị hạ sợi tơ hồng yêu vật vào ngực để làm chiến thư sống.","bridge":true,"khoang":"@c0507"},{"chuong":"@c0507","importance":"normal","tieuDe":"Tuyệt vọng cố tu, phun máu hôn mê","text":"Sau khi được Vương Lâm cứu nhưng thành người tàn phế không thể tu hành, dập đầu ba cái rời đi; về phòng cố thử thổ nạp thuật Luyện hồn chịu đau thấu tim phổi, kêu “Ta không cam lòng!”, phun một ngụm máu lớn, ngã hôn mê."},{"chuong":"@c0508","importance":"normal","tieuDe":"Phế tu vi, tự phát luyện thể","text":"Bị phế tu vi nên chỉ làm thợ săn, gần như câm điếc và mất sức sống. Không cam lòng, mỗi đêm hắn chịu đau thổ nạp tích yêu lực vào máu thịt suốt hơn một năm, vô tình đạt một loại luyện thể tự nhiên; nhiều lần liều mạng săn thú suýt chết."},{"chuong":"@c0508","importance":"normal","tieuDe":"Được Vương Lâm truyền Luyện Thể thuật","text":"Bị dã thú yêu hóa làm trọng thương, được Âu Dương Hoa mang đến; Vương Lâm cứu chữa và truyền Luyện Thể thuật của Cự Ma Tộc qua ngọc giản. Hai năm sau hắn thành tựu, thân thể cứng như sắt, xông trận đầu tiên rồi theo Vương Lâm đi Cổ Yêu thành."},{"chuong":"@c0509","importance":"normal","tieuDe":"Đả thương thị vệ cửa thành","text":"Bị thị vệ Cổ Yêu thành giơ trường thương quát lui, Thập Tam tức giận dùng thuật Luyện thể Cự Ma Tộc đấm một quyền làm vỡ vụn trường thương, đẩy lui tên thị vệ thổ huyết. Vương Lâm quở vì quyền đó tuy dùng hết sức nhưng chỉ phát huy bốn phần lực, phần còn lại tiết ra ngoài, chưa khống chế tùy tâm."},{"bridge":true,"khoang":"@c0512","text":"Cùng Hổ Bào tìm tới nhà trọ nhờ thần thức Vương Lâm triệu gọi, rồi theo sát hắn dạo Cổ Yêu thành, cảnh giác quan sát xung quanh. Ở Trúc Thanh lâu, hắn đập vò rượu rót cho Vương Lâm nhưng tự mình không uống."},{"chuong":"@c0513","importance":"normal","tieuDe":"Quyết tử bảo vệ lão tổ","text":"Thấy lão tổ Vương Lâm có biến, Thập Tam lo lắng theo dõi rồi giơ tay bắt vò rượu khiêu khích thứ hai, bị chấn thương ứa máu miệng, ghế vỡ vụn. Khi yêu binh xông tới, hắn tung một quyền đánh trọng thương đối phương văng đi mấy trượng dù Luyện Thể thuật còn chưa đầy đủ, cùng Hổ Bào quyết tử chắn trước lão tổ."},{"bridge":true,"khoang":"@c0514–@c0514","text":"Thở phào khi Vương Lâm tỉnh khỏi nhập ma, lạnh lùng nhìn đám yêu binh và để lại chút Hứa Yêu thạch trả tiền rượu trước khi rời tửu lâu."},{"chuong":"@c0514","importance":"normal","tieuDe":"Vào trận thử trước, bị thương rồi được cứu","text":"Với chức trách hộ vệ lão tổ, chủ động bước vào Truyền Tống trận thử trước; sang quân doanh bị sóng âm chấn động phun máu, được Vương Lâm đá nhẹ một luồng tiên lực chữa lành thương thế."},{"bridge":true,"khoang":"@c0515","text":"Theo Vương Lâm vào quân doanh Hắc Giáp quân, Thập Tam điềm tĩnh ngồi thổ nạp ngoài trời, nhắm mắt tu hành thần thông luyện thể tộc Cự Ma; được Vương Lâm giao một ngọc giản để ghi nhớ nội dung quy tắc Cửu quận yêu binh."},{"bridge":true,"khoang":"@c0516–@c0516","text":"Dần bình thản theo Vương Lâm thổ nạp trong quân doanh; thuộc nội dung ngọc giản quân quy, đọc các điều quân quy theo lệnh và đếm ngược nhịp hô hấp khi Vương Lâm ép lui chín thống đội."},{"bridge":true,"khoang":"@c0517","text":"Bám sát Vương Lâm cùng Hổ Bào vào ngôi lầu bùn đất mới dựng trong quân doanh."},{"bridge":true,"khoang":"@c0518","text":"Canh gác ngoài lầu Vương Lâm, Thập Tam quát chặn và xuất một quyền với Diêu Tích Tuyết nhưng bị nàng dùng tia sáng đỏ khống chế đứng im như pho tượng; sau được cơn gió của Vương Lâm giải trừ, nghe thanh âm Vương Lâm liền khoanh chân ngồi xuống, không can dự nữa."},{"chuong":"@c0527","importance":"normal","tieuDe":"Bị phế rồi bị dâng cho Yêu Tướng","text":"Sau khi Vương Lâm rời đi nửa năm, gã kiên quyết ở lại quân doanh chờ chủ. Khi trợ giúp Hổ Bào, gã bị Tư Mã Viêm bóp nát gân cốt ném vào hắc lao. Trước khi chết, gã được Đô thống Tần Lâm mang đi chữa thương rồi dâng cho Yêu Tướng, do thân thể luyện thể kỳ dị với yêu khí gắn kết toàn thân phù hợp yêu cầu của Yêu Tướng."},{"chuong":"@c0529","importance":"normal","tieuDe":"Bị bắt rồi được cứu","text":"Bị Mạc Lệ Hải bắt giữ định dùng thân thể luyện pháp bảo, nhưng chỉ hôn mê chứ không thương thế. Sau khi Vương Lâm hạ Yêu Tướng, Thập Tam được thả và ba ngày sau được Vương Lâm đánh thức; đã hoàn thành xuất sắc khảo nghiệm một năm qua."},{"chuong":"@c0530","importance":"normal","tieuDe":"Nhận truyền thừa, tôn Vương Lâm làm Lão tổ","text":"Được Vương Lâm trao ngọc giản xanh ghi sáu tầng đầu Cự Linh Cửu Tu, Thập Tam kích động quỳ đập đầu, thề cả đời chỉ tuân mệnh lệnh Vương Lâm và gọi hắn là Lão tổ. Hắn được dặn bảo vệ bộ tộc Luyện Hồn cho tốt rồi bị một luồng gió mát cuốn ra ngoài cốc."}],"tuViMoc":[{"chuong":"@c0505","canhGioi":"Giai đoạn ba (Luyện Hồn Yêu Thuật)","text":"Trời sinh ngộ tính, tu luyện Luyện Hồn Yêu Thuật ba tháng đã đạt giai đoạn ba — vượt xa đại bộ phận hai bảy người trong sơn cốc còn ở giai đoạn một. Đây là thành tựu thuộc hệ Luyện Hồn Thuật.","importance":"minor"},{"chuong":"@c0508","canhGioi":"Luyện thể (Cự Ma Tộc)","text":"Từ luyện thể tự phát gần đạt yêu lực nhị tinh, sau khi được truyền Luyện Thể thuật Cự Ma Tộc thì thành tựu, thân thể cứng như sắt. Thuộc hệ luyện thể, không phải tu vi chính thống.","importance":"major"}],"nhanMach":[{"ten":"Vương Lâm","tag":"cap-tren","quanHe":"Thượng tiên hắn sùng kính","ghiChu":"Vương Lâm âm thầm theo dõi, coi trọng, trao phương pháp mới và cứu hắn khỏi sư tử phản phệ."},{"ten":"Âu Dương Hoa","tag":"dong-minh","quanHe":"Tiền bối nhường đường","ghiChu":"Âu Dương Hoa chế xong hồn phiên trước nhưng nhường cơ hội cho Thập Tam và triệu chim sẻ cứu hắn."},{"ten":"Vương Lâm","tag":"su-mon","quanHe":"‘Thượng tiên’ dạy Luyện Hồn Thuật và ban chủ hồn","ghiChu":""},{"ten":"Âu Dương Hoa","tag":"dong-minh","quanHe":"Cùng làm chủ công trong các trận chinh phạt","ghiChu":""},{"ten":"Vương Lâm","tag":"su-mon","quanHe":"sư phụ","ghiChu":"Gọi “Sư phụ”, được cứu mạng nhưng không cứu được tu hành."},{"ten":"Lão già áo trắng","tag":"doi-thu","quanHe":"kẻ đánh phế","ghiChu":"Đánh nát kinh mạch, cướp cờ kỳ quái, hạ yêu vật làm chiến thư sống."},{"ten":"Vương Lâm","tag":"an-nhan","quanHe":"Ân nhân cứu mạng và truyền công","ghiChu":"Cứu sống, truyền Luyện Thể thuật Cự Ma Tộc, hứa truyền khẩu quyết tầng một Cổ Thần nếu thành tựu."},{"ten":"Hổ Bào","tag":"dong-minh","quanHe":"Cùng theo Vương Lâm","ghiChu":"Cùng làm thị vệ tháp tùng Vương Lâm tới Cổ Yêu thành."},{"ten":"Hổ Bào","tag":"dong-minh","quanHe":"Cùng bảo vệ lão tổ","ghiChu":"Sự kiên quyết của Thập Tam khiến Hổ Bào dần đổi thái độ, thấy hắn không phải kẻ đáng ghét."},{"ten":"Thống lĩnh (Nghiêu Lĩnh, Cổ Yêu thành)","tag":"doi-thu","quanHe":"Đối đầu trong tửu lâu","ghiChu":""},{"ten":"Vương Lâm","tag":"cap-tren","quanHe":"Thống lĩnh, người Thập Tam phục tùng","ghiChu":"Đọc quân quy và đếm ngược theo lệnh Vương Lâm."},{"ten":"Diêu Tích Tuyết","tag":"doi-thu","quanHe":"Bị nàng khống chế khi nàng xông vào lầu Vương Lâm"},{"ten":"Tần Lâm","tag":"khac","quanHe":"Người mang Thập Tam đi dâng cho Yêu Tướng"},{"ten":"Hổ Bào","tag":"ban-be","quanHe":"Cùng là tùy tùng man rợ của Vương Lâm, trợ giúp lẫn nhau"},{"ten":"Vương Lâm","tag":"su-mon","quanHe":"Lão tổ tôn kính","ghiChu":"Người truyền cho Thập Tam công pháp luyện thể Cự Linh Cửu Tu."}],"tuiDo":{"phapBao":[{"ten":"Hồn phiên thay thế (Thiên Vận Tinh)","loai":"phap-bao","trangThai":"dang-co","moTa":"Cây hồn phiên bảy thước Thập Tam tự chế thành sau ba lần thất bại, phong ấn hồn phách sư tử cánh dài.","nguon":"@c0505"}],"congPhap":[{"ten":"Luyện Hồn Thuật","loai":"cong-phap","moTa":"Thần thông Luyện Hồn Tông nhất mạch do Vương Lâm truyền, Thập Tam tu tới giai đoạn ba.","nguon":"@c0505"}]}},"nguon":["@c0505","@c0506","@c0507","@c0508","@c0509","@c0512","@c0513","@c0514","@c0515","@c0516","@c0517","@c0518","@c0527","@c0529","@c0530"]},{"id":"lao-gia-ao-trang-thien-thuy","name":"Lão già áo trắng (Thiên Thủy)","gioiTinh":"nam","theLuc":[{"ten":"Cổ Yêu thành / phủ Tả Dực tướng quân","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Hóa thần trung kỳ","trangThai":"tu-vong","blurb":"Chấp sự dưới trướng Tả Dực tướng quân ở Cổ Yêu thành, đánh phế Thập Tam và hạ chiến thư khiêu chiến Vương Lâm; bị Vương Lâm bóp cổ giết, nguyên thần giam vào cờ Tôn Hồn.","vaiTro":"phản diện chương","tinhCach":[{"text":"Hung tàn, đắc ý, khinh người","chuong":"@c0507"}],"tabs":{"diem":[{"text":"Cố ý không giết Thập Tam, dùng yêu vật và lời nhắn làm chiến thư sống dụ người sau lưng xuất hiện để moi khẩu quyết cờ kỳ quái.","chuong":"@c0507"}],"kinhLich":[{"text":"Về bộ lạc Thiên Thủy thăm thân, chặn tổ Thập Tam, đánh nát kinh mạch hắn, cướp mấy cây cờ kỳ quái, hạ sợi tơ hồng yêu vật vào ngực, thả Thập Tam đi truyền tin.","bridge":true,"khoang":"@c0507"},{"chuong":"@c0507","importance":"major","tieuDe":"Bị Vương Lâm bóp cổ giết","text":"Khi Vương Lâm nhổ trận pháp mảnh đất mang về, ra ngoài trận hạ chiến thư đòi đánh tay đôi; bị Vương Lâm chộp cổ bóp “rắc” chết, nguyên thần bị giam vào cờ Tôn Hồn, xác bị chủ hồn đốt thành tro."}],"tuViMoc":[],"nhanMach":[{"ten":"Lão già áo xám (Thiên Thủy)","tag":"dong-hanh","quanHe":"đồng tộc bộ lạc Thiên Thủy","ghiChu":"Được lão áo xám can ngăn nhưng không nghe."},{"ten":"Tả Dực tướng quân","tag":"cap-tren","quanHe":"chủ tướng","ghiChu":"Làm chấp sự/chấp phụ dưới trướng Tả Dực tướng quân tại Cổ Yêu thành."},{"ten":"Thập Tam","tag":"doi-thu","quanHe":"nạn nhân","ghiChu":"Đánh phế và biến thành chiến thư sống."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"kẻ giết mình","ghiChu":"Bị bóp cổ giết, nguyên thần giam vào cờ Tôn Hồn."}],"tuiDo":{"phapBao":[{"ten":"Cây cờ kỳ quái (cướp từ Thập Tam)","trangThai":"da-dung","moTa":"Mấy cây cờ nhỏ cướp từ Thập Tam, muốn moi khẩu quyết sử dụng đầy đủ.","nguon":"@c0507"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0507"]},{"id":"lao-gia-ao-xam-thien-thuy","name":"Lão già áo xám (Thiên Thủy)","gioiTinh":"nam","theLuc":[{"ten":"Bộ lạc Thiên Thủy","trangThai":"da-roi"},{"ten":"Bộ lạc Luyện Hồn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ (am hiểu trận pháp viễn cổ)","trangThai":"song","blurb":"Trưởng lão am hiểu trận pháp của bộ lạc Thiên Thủy; can lão áo trắng không được, sau khi lão áo trắng bị giết thì mở trận pháp đầu hàng, theo Vương Lâm sang bộ lạc Luyện Hồn và sinh hứng thú với thuật Luyện hồn.","vaiTro":"phụ","tinhCach":[{"text":"Cẩn trọng, biết thời thế","chuong":"@c0507"}],"tabs":{"diem":[{"text":"Trách lão áo trắng rước họa, buộc phải tự gánh để cứu bộ lạc; định báo cáo lên phủ Tả Dực nhưng sợ hãi từ bỏ sau khi thấy Vương Lâm giết lão áo trắng.","chuong":"@c0507"}],"kinhLich":[{"chuong":"@c0507","importance":"normal","tieuDe":"Mở trận pháp, quy thuận Luyện Hồn","text":"Sau khi lão áo trắng bị giết, sợ hãi mở trận pháp viễn cổ Thiên Thủy; được thu nạp làm tộc nhân bộ lạc Luyện Hồn mới, sinh hứng thú với thuật Luyện hồn."}],"tuViMoc":[],"nhanMach":[{"ten":"Lão già áo trắng (Thiên Thủy)","tag":"dong-hanh","quanHe":"đồng tộc, đối nghịch ý kiến","ghiChu":"Can ngăn việc rước họa, sau quy trách nhiệm để cứu bộ lạc."},{"ten":"Vương Lâm","tag":"cap-tren","quanHe":"chủ nhân mới","ghiChu":"Quy thuận sau khi chứng kiến uy lực Vương Lâm."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0507"]},{"id":"ta-duc-tuong-quan","name":"Tả Dực tướng quân","gioiTinh":"nam","theLuc":[{"ten":"Cổ Yêu thành","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ","trangThai":"khong-ro","blurb":"Tướng quân thống lĩnh ở Cổ Yêu thành; lão già áo trắng làm chấp sự/chấp phụ dưới trướng, lão áo xám định báo cáo việc Vương Lâm lên phủ Tả Dực.","vaiTro":"nhắc tên","tinhCach":[],"tabs":{"diem":[{"text":"Phủ Tướng quân có hàng Trưởng lão tu vi ngang Vương Lâm — gợi thế lực Cổ Yêu thành sẽ chú ý tới Vương Lâm.","chuong":"@c0507"}],"kinhLich":[{"text":"Lão áo trắng làm chấp sự dưới trướng; lão áo xám định báo lên phủ Tả Dực ở Cổ Yêu thành về việc Vương Lâm.","bridge":true,"khoang":"@c0507"},{"chuong":"@c0509","importance":"normal","tieuDe":"Thử thách Vương Lâm giành chức","text":"Hiện thân trong cung điện khổng lồ có pho tượng đại hán mặc giáp, hỏi tội Vương Lâm đánh yêu binh rồi đánh thử một quyền vô thanh xuyên hư không. Sau khi Vương Lâm hóa giải bằng Tịch Diệt chỉ, hắn đề nghị cho làm Trưởng lão (chức trong) nhưng bị từ chối; bèn ra mười quyền tạo Thập Băng Chiến Ý, hứa nếu tiếp được sẽ ban chức Đô thống có binh quyền."},{"chuong":"@c0510","importance":"normal","tieuDe":"Thi triển Thập Băng Quyền Ý","text":"Tả dực Yêu tương trấn giữ Cổ Yêu thành, dùng thần công Thập Băng Quyền Ý sinh ra từ hư vô, vô hình, phát theo tám lần sụp đổ càng về sau càng mạnh. Hắn khen Vương Lâm là một trong số ít người phản công được dưới quyền ý này và thách hắn phá đủ tám lần sụp đổ mới áp sát được."},{"chuong":"@c0511","importance":"normal","tieuDe":"Chấn Động Trước Vương Lâm","text":"Tả dực Yêu tướng thả các đợt sụp đổ Thập Băng Quyền Ý để thử Vương Lâm, vốn cho rằng đối phương cùng lắm phá đến lần thứ bảy là dừng. Khi Vương Lâm chỉ một lời đã phá tan lần thứ bảy, hắn rốt cục biến sắc, thừa nhận đã xem thường đối phương ngay từ đầu — lần đầu tỏ ra xúc động trong mấy ngàn năm. Quyền ý vốn cực hạn mười lần sụp đổ nhờ hấp thu tâm niệm mà tiến hóa lên lần thứ mười một."},{"chuong":"@c0512","importance":"normal","tieuDe":"Phong Thống lĩnh cho Vương Lâm","text":"Chủ trì khảo nghiệm, thi triển Thập Băng Quyền mười lần ‘sụp đổ’; khi Vương Lâm chủ động lùi trước quyền thứ chín, hắn chộp tay thu lại quyền ý, khen Vương Lâm biết tiến lùi. Hắn xưng danh đầy đủ là Vân Lệ Hải, đánh giá thực lực Vương Lâm đủ làm Thống lĩnh, phong hắn nắm một vạn yêu binh Cổ Yêu thành rồi trao lệnh bài đồng và biến mất."}],"tuViMoc":[{"chuong":"@c0509","canhGioi":"Gần Vấn Đỉnh","text":"Yêu lực nội liễm không dưới mười vạn giáp, kém cảnh giới Vấn Đỉnh không nhi��u.","importance":"major"}],"nhanMach":[{"ten":"Lão già áo trắng (Thiên Thủy)","tag":"cap-tren","quanHe":"thuộc hạ chấp sự","ghiChu":"Chấp sự/chấp phụ dưới trướng."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Người ngoài đến xin chức","ghiChu":"Thử thách Vương Lâm bằng đòn quyền và Thập Băng Chiến Ý để xét ban chức."},{"ten":"Diêu Nghiêu lĩnh","tag":"su-mon","quanHe":"Thuộc hạ Cổ Yêu thành","ghiChu":"Diêu Nghiêu lĩnh dẫn Vương Lâm tới gặp hắn."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối thủ giao chiến","ghiChu":"Khen Vương Lâm phản công được dưới Thập Băng Quyền Ý, thách phá tám lần sụp đổ."},{"ten":"Diêu Tích Tuyết","tag":"khac","quanHe":"Người từng bại dưới Thập Băng Quyền Ý","ghiChu":"Ba năm trước Diêu Tích Tuyết bại ở lần thứ tám của quyền ý này, sau được ban chức Thống lĩnh."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Người hắn thử thách","ghiChu":"Người đầu tiên cảm ngộ được dưới Thập Băng Quyền Ý, khiến hắn lần đầu chấn động."},{"ten":"Yêu đế","tag":"cap-tren","quanHe":"Phụng mệnh","ghiChu":"Phụng mệnh yêu đế đi tìm kiếm một người nhất định."},{"ten":"Vương Lâm","tag":"cap-tren","quanHe":"Phong Vương Lâm làm Thống lĩnh Cổ Yêu thành","ghiChu":"Đánh giá cao thực lực và sự khôn ngoan biết tiến lùi của Vương Lâm."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0507","@c0509","@c0510","@c0511","@c0512"],"aliases":["Tả Dực tướng quân","Tả dực tướng quân","Vân Lệ Hải","Tả Dực Yêu tương"]},{"id":"ho-bao","name":"Hổ Bào","cn":"","aliases":["Hổ Bảo"],"gioiTinh":"nam","theLuc":[{"ten":"Bộ lạc Luyện Hồn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Giai đoạn thứ năm Luyện Hồn (ngang Kết Đan kỳ)","trangThai":"song","blurb":"Thiếu niên thiên tài bộ lạc nhỏ, có yêu lực nhị tinh bẩm sinh, bị bắt nhập bộ lạc Luyện Hồn rồi được Vương Lâm giữ bên người khống chế.","vaiTro":"Đệ tử thiên tài kiêm thị vệ của Vương Lâm","tinhCach":[{"text":"Tư chất thông minh, được đánh giá là thiên tài hiếm có.","chuong":"@c0508"}],"tabs":{"diem":[{"text":"Có yêu lực nhị tinh ngay từ nhỏ, tư chất thông minh xuất chúng.","chuong":"@c0508"},{"text":"Vương Lâm đánh giá nếu trong trăm năm đạt Hóa Thần sẽ gần hoặc vượt Hồng Điệp năm xưa.","chuong":"@c0508"}],"kinhLich":[{"chuong":"@c0508","importance":"normal","tieuDe":"Bị bắt nhập bộ lạc Luyện Hồn","text":"Vốn là cao thủ một bộ lạc nhỏ, Hổ Bào bị Âu Dương Hoa bắt và uống Ly Yêu thang để gia nhập bộ lạc Luyện Hồn. Sau bốn năm hắn tu tới giai đoạn thứ năm với chín mươi ba hồn phiên (ba mươi mốt chủ hồn), thực lực tương đương Kết Đan kỳ."},{"chuong":"@c0508","importance":"normal","tieuDe":"Theo Vương Lâm rời bộ lạc","text":"Được Vương Lâm xem là thiên tài nên giữ bên người để khống chế; cùng Thập Tam theo Vương Lâm rời bộ lạc đi Cổ Yêu thành như thị vệ, cưỡi Văn Thú lên đường."},{"bridge":true,"khoang":"@c0509","text":"Theo Vương Lâm tới Cổ Yêu thành; thoạt thấy thành thì bất giác quỳ lễ, sau xấu hổ đứng dậy nhổ nước bọt về phía thành tỏ vẻ khinh thường, rồi cùng Thập Tam chờ trong thành."},{"bridge":true,"khoang":"@c0512","text":"Đi theo Vương Lâm dạo Cổ Yêu thành, mải mê ngắm hàng quán lầu các náo nhiệt; ở Trúc Thanh lâu, thấy Thập Tam không uống nên hắn cũng không dám uống rượu."},{"chuong":"@c0513","importance":"normal","tieuDe":"Thả Hồn phiên chống yêu binh","text":"Đang len lén uống rượu, Hổ Bào nể lão tổ đang có biến nên nén giận; khi hỗn chiến nổ ra, hắn lấy mười lá cờ nhỏ rồi phất Hồn phiên thả vô số hồn phách rít the thé bay đầy tửu lâu để cản đám yêu binh, cùng Thập Tam quyết tử bảo vệ lão tổ."},{"bridge":true,"khoang":"@c0514–@c0514","text":"Thu hồi hồn phiên đứng cạnh Vương Lâm, cười lạnh với đám yêu binh trong tửu lâu; qua Truyền Tống trận bị sóng âm làm yêu lực tán loạn chạy khắp kinh mạch, được Vương Lâm đặt tay lên vai truyền nguồn lực ôn hòa ổn định lại."},{"bridge":true,"khoang":"@c0515","text":"Theo Vương Lâm vào quân doanh, Hổ Bào tức giận trước sự khinh miệt của yêu binh, gọi Vương Lâm là Lão tổ, nhưng vẫn kìm nén ngồi thổ nạp bên trái hắn suốt ba ngày, càng lúc càng khó giữ bình tĩnh."},{"bridge":true,"khoang":"@c0516–@c0516","text":"Tức giận tích tụ vì thái độ của Vương Lâm nhưng e ngại chưa dám nổi khùng; khi quân doanh bị vây, hắn đứng dậy xuất hồn phiên chuẩn bị chiến đấu."},{"chuong":"@c0517","importance":"normal","tieuDe":"Rung động với nữ thống đội Từ U","text":"Sống thoải mái trong quân doanh, mâu thuẫn cũ tan dần; đặc biệt rung động với một nữ thống đội tên Từ U, tỏ ra vô cùng ân cần và thường ngồi ngoài lầu như thần giữ cửa."},{"chuong":"@c0527","importance":"normal","tieuDe":"Bị phế tu vi rồi mất tích bí ẩn","text":"Muốn rời quân doanh quay về bộ lạc man rợ thì bị Tư Mã Viêm bắt với cớ vi phạm quân quy, phế tu vi ném vào hắc lao. Ba tháng sau, dù hắc lao canh phòng cực nghiêm, Hổ Bào vẫn mất tích bí ẩn mà ngay cả Tư Mã Viêm cũng không hiểu rõ."},{"chuong":"@c0529","importance":"normal","tieuDe":"Mất tích trong hắc lao","text":"Tùy tùng tu Luyện Hồn Thuật do Vương Lâm truyền, quyền khống chế linh hồn nằm ở Vương Lâm. Khi Vương Lâm tìm khắp Cổ Yêu thành và hắc lao, dấu vết linh hồn Hổ Bào hoàn toàn biến mất; Vương Lâm kết luận nếu không chết thì bị giam ở một nơi kỳ dị mà cả thần thức Anh Biến hậu kỳ cũng không quét tới."},{"chuong":"@c0530","importance":"normal","tieuDe":"Tái sinh dưới trướng lão già hắc y, ôm hận Vương Lâm","text":"Sau khi bị Tư Mã Viêm giận cá chém thớt ném vào hắc lao và chờ Vương Lâm tới cứu vô vọng, Hổ Bào được lão già hắc y cứu ra vì sở hữu Luyện Hồn Thuật kỳ dị. Hắn ngồi luyện hóa linh hồn tại chiến trường cổ trong lãnh thổ Yêu Linh, phát thề không bao giờ làm nô bộc cho ai nữa, đang tu Diệt Thế Áp Nguyên Công và quyết báo thù Vương Lâm cùng Tư Mã Viêm khi luyện đủ nghìn vạn hồn phách."}],"tuViMoc":[{"chuong":"@c0508","canhGioi":"Giai đoạn thứ năm Luyện Hồn","text":"Sau bốn năm tu tới giai đoạn thứ năm, sở hữu chín mươi ba hồn phiên trong đó ba mươi mốt chủ hồn, thực lực ngang Kết Đan kỳ. Đây thuộc hệ tu Luyện Hồn của bộ lạc, không phải hệ tu vi chính thống.","importance":"major"}],"nhanMach":[{"ten":"Âu Dương Hoa","tag":"doi-thu","quanHe":"Người bắt Hổ Bào về tộc","ghiChu":"Bắt hắn rồi cho uống Ly Yêu thang gia nhập bộ lạc Luyện Hồn."},{"ten":"Vương Lâm","tag":"su-mon","quanHe":"Lão tổ giữ Hổ Bào bên người","ghiChu":"Đánh giá hắn là thiên tài, giữ bên người để vừa bồi dưỡng vừa khống chế."},{"ten":"Thập Tam","tag":"dong-minh","quanHe":"Cùng theo Vương Lâm","ghiChu":"Cùng làm thị vệ tháp tùng Vương Lâm tới Cổ Yêu thành."},{"ten":"Thập Tam","tag":"dong-minh","quanHe":"Cùng bảo vệ lão tổ","ghiChu":"Cảm phục sự kiên quyết của Thập Tam."},{"ten":"Từ U","tag":"khac","quanHe":"Nữ thống đội khiến Hổ Bào rung động","ghiChu":""},{"ten":"Thập Tam","tag":"ban-be","quanHe":"Cùng tùy tùng man rợ của Vương Lâm"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Chủ tử cũ thành kẻ thù","ghiChu":"Người truyền Luyện Hồn Thuật cho Hổ Bào; bị Hổ Bào căm hận vì không tới cứu khỏi hắc lao."},{"ten":"Tư Mã Viêm","tag":"doi-thu","quanHe":"Kẻ đẩy vào hắc lao","ghiChu":"Giận cá chém thớt ném Hổ Bào vào nhà lao, là mục tiêu báo thù."},{"ten":"Lão già hắc bào (ân công của Hổ Bào)","tag":"an-nhan","quanHe":"Ân nhân cứu mạng","ghiChu":"Cứu Hổ Bào ra khỏi hắc lao, truyền Diệt Thế Áp Nguyên Công, dẫn tới chiến trường cổ luyện hồn."}],"tuiDo":{"phapBao":[{"ten":"Hồn phiên","loai":"phap-bao","trangThai":"dang-co","moTa":"Chín mươi ba hồn phiên cá nhân, trong đó ba mươi mốt là chủ hồn, dùng tu luyện theo thuật Luyện Hồn.","nguon":"@c0508"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0508","@c0509","@c0512","@c0513","@c0514","@c0515","@c0516","@c0517","@c0527","@c0529","@c0530"]},{"id":"dieu-nghieu-linh","name":"Diêu Nghiêu lĩnh","cn":"","aliases":[],"gioiTinh":"nu","theLuc":[{"ten":"Cổ Yêu thành","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Anh Biến hậu kỳ (chưa viên mãn)","trangThai":"song","blurb":"Nữ tử áo trắng mắt phượng tại Cổ Yêu thành, người quen cũ của Vương Lâm; dẫn hắn đi gặp Tả dực Yêu tương.","vaiTro":"Cao thủ ở Cổ Yêu thành, trung gian dẫn Vương Lâm tới gặp Tả dực Yêu tương.","tinhCach":[{"text":"Lý trí, không thích giao chiến vô nghĩa","chuong":"@c0509"}],"tabs":{"diem":[{"text":"Thân ảnh màu hồng, áo trắng, mắt phượng, lông mày sát nhau, tóc đen xõa vai; tu vi Anh biến hậu kỳ chưa viên mãn","chuong":"@c0509"}],"kinhLich":[{"chuong":"@c0509","importance":"normal","tieuDe":"Xuất hiện ở cửa Bắc Cổ Yêu thành","text":"Khi Vương Lâm thị uy đám yêu binh và tạo quả cầu máu, Diêu Nghiêu lĩnh từ trong cửa thành lao ra điểm tay làm tan cầu máu, nhận ra và gọi tên Vương Lâm. Nàng cho rằng cuộc chiến giữa hai người không ý nghĩa, dẫn Vương Lâm tới quảng trường có Truyền tống trận để đi gặp Tả dực Yêu tương."}],"tuViMoc":[{"chuong":"@c0509","canhGioi":"Anh Biến hậu kỳ","text":"Tu vi Anh biến hậu kỳ chưa viên mãn.","importance":"minor"}],"nhanMach":[{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Người quen cũ","ghiChu":"Từng gặp ở ngoài cửa Đông Hải Yêu linh khi nàng độc chiếm một nơi; tại Cổ Yêu thành dẫn Vương Lâm đi gặp Tả dực Yêu tương."},{"ten":"Tả dực Yêu tương","tag":"su-mon","quanHe":"Thuộc phủ Tả dực tướng quân","ghiChu":"Người của Cổ Yêu thành, dẫn Vương Lâm tới gặp chủ thành."}],"tuiDo":{}},"nguon":["@c0509"]},{"id":"yeu-de","name":"Yêu đế","gioiTinh":"khong-ro","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"khong-ro","blurb":"Bậc thống lĩnh Yêu linh chi địa từng ban lời cho phép phong chức cho người ngoài đến nếu đủ tu vi.","vaiTro":"Nhân vật được nhắc tên, đặt lệ ban chức cho người ngoài.","tinhCach":[],"tabs":{"diem":[],"kinhLich":[{"bridge":true,"khoang":"@c0509","text":"Được Tả dực Yêu tương nhắc tới: Yêu đế từng có lời ban chức cho người ngoài đến nếu đủ tu vi."},{"chuong":"@c0543","importance":"normal","tieuDe":"Vắng mặt bất thường tại trận Yêu Tướng","text":"Đế Quân từng đích thân truyền thần thông Yêu Nhiên cho Mạc Lệ Hải khi hắn thành Yêu Tướng. Tại trận chiến Yêu Tướng, ngai Yêu Đế phía đông để trống suốt ba tiếng trống vì Đế Quân không tới, khiến Mạc Lệ Hải lẩm bẩm thắc mắc nguyên do."}],"tuViMoc":[],"nhanMach":[{"ten":"Mạc Lệ Hải","tag":"khac","quanHe":"Đích thân truyền thần thông Yêu Nhiên cho Mạc Lệ Hải","ghiChu":"@c0543"}],"tuiDo":{}},"nguon":["@c0509","@c0543"],"aliases":["Đế Quân"]},{"id":"thong-linh-nghieu-linh-co-yeu-thanh","name":"Thống lĩnh (Nghiêu Lĩnh, Cổ Yêu thành)","cn":"","aliases":["Người nét mặt âm trầm"],"gioiTinh":"nam","theLuc":[{"ten":"Nghiêu Lĩnh","trangThai":"gan-bo"}],"trangThai":"song","blurb":"Yêu nhân khoảng ba mươi tuổi nét mặt âm trầm, cựu Nghiêu Lĩnh chính ở Cổ Yêu thành bị phế chức nên bất mãn người ngoài đến.","vaiTro":"Phản diện thoáng qua khiêu khích nhóm Vương Lâm","tinhCach":[{"text":"Âm trầm, hiếu thắng, sẵn lòng chịu trách phạt để giành lại chức vị.","chuong":"@c0513"}],"tabs":{"diem":[{"text":"Cựu Nghiêu Lĩnh chính bị một người ngoài đến — được Yêu Tương đại nhân phá lệ ban chức — vượt lên thay thế, sinh bất mãn.","chuong":"@c0513"}],"kinhLich":[{"chuong":"@c0513","importance":"normal","tieuDe":"Khiêu khích nhóm Vương Lâm","text":"Dẫn bảy tám yêu binh hắc giáp xông vào tửu lâu, ném hai vò rượu dò xét rồi tấn công bàn Vương Lâm, định dùng Tru Tiên trận giết người ngoài đến. Hắn chú ý Vương Lâm ngay từ đầu, cảm nhận trong cơ thể đối phương có hai luồng lực lượng quỷ dị; khi sáu đạo yêu lực mất khống chế, hắn hô thu hồi không kịp."}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Khiêu khích","ghiChu":""},{"ten":"Yêu Tương đại nhân","tag":"cap-tren","quanHe":"Quyền cao quân yêu","ghiChu":"Phá lệ ban chức thống lĩnh cho người ngoài, khiến hắn bị phế."}],"tuiDo":{}},"nguon":["@c0513"]},{"id":"yeu-tuong-dai-nhan","name":"Yêu Tương đại nhân","cn":"","aliases":["Yêu Tướng","Mạc Lệ Hải","Yêu Tương đại nhân"],"gioiTinh":"khong-ro","theLuc":[{"ten":"Cổ yêu thành","trangThai":"gan-bo"}],"trangThai":"khong-ro","blurb":"Nhân vật quyền cao trong quân yêu Cổ Yêu thành, tự kiểm tra rồi phá lệ ban chức thống lĩnh cho một người ngoài đến.","vaiTro":"Nhân vật được nhắc tên, nắm quyền phong chức quân yêu","tinhCach":[],"tabs":{"diem":[{"text":"Tự kiểm tra rồi phá lệ ban chức Nghiêu Lĩnh chính cho người ngoài đến, làm thống lĩnh cũ bất mãn.","chuong":"@c0513"}],"kinhLich":[{"chuong":"@c0527","importance":"normal","tieuDe":"Bế quan, thu nhận Thập Tam","text":"Chủ nhân cung điện trung tâm Cổ Yêu Thành. Nhiều năm trước hạ lệnh tìm người có cường độ thân thể cao và đã nhận Thập Tam. Nửa năm trước bắt đầu bế quan, mọi truyền tống trận dẫn vào cung đều bị phong kín từ bên trong, trở thành mục tiêu Vương Lâm quyết xông cung."},{"chuong":"@c0529","importance":"normal","tieuDe":"Lộ tên thật & mời phó tướng","text":"Yêu tướng thống lĩnh tung tuyệt chiêu Yêu Hải Bách Lãng giao đấu Vương Lâm nhưng bị chưởng ấn hư ảo uy hiếp, không dám đánh cuộc nên nhận thua. Hắn lộ tên thật Mạc Lệ Hải, khai luyện pháp bảo cần thân thể mười tám người, phong Vương Lâm làm Tả dực đệ nhất phó tướng và thả Thập Tam."},{"bridge":true,"khoang":"@c0529","text":"Sau khi Vương Lâm rời đi, Mạc Lệ Hải thừa nhận với năm lão giả rằng chưởng ấn kia chín phần mười là hư trương thanh thế, song không dám liều mạng; nhắc lại bí ẩn tu vi Vương Lâm tăng vọt và việc mất tích cùng Diêu thống lĩnh năm trước."}],"tuViMoc":[],"nhanMach":[{"ten":"Thống lĩnh (Nghiêu Lĩnh, Cổ Yêu thành)","tag":"khac","quanHe":"Cấp dưới bất mãn","ghiChu":""},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối tượng Vương Lâm xông cung đòi người"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối thủ rồi thu nhận làm phó tướng dưới trướng","ghiChu":"Bị chưởng ấn hư ảo của Vương Lâm uy hiếp, đành mời làm Tả dực đệ nhất phó tướng."},{"ten":"Yêu Đế","tag":"cap-tren","quanHe":"Quân chủ Thiên Yêu quận","ghiChu":"Mạc Lệ Hải định tiến cử Vương Lâm lên Yêu Đế nếu lọt top ba yêu tướng."}],"tuiDo":{}},"nguon":["@c0513","@c0527","@c0529"]},{"id":"quan-su-tham-quan","name":"Quản sự tham quân","cn":"","aliases":["Quản sự tham quân mặt gầy"],"gioiTinh":"nam","theLuc":[{"ten":"Quân doanh (dưới trướng Yêu Tương)","trangThai":"gan-bo"}],"canhGioiCaoNhat":"","trangThai":"song","blurb":"Quản sự tham quân dưới trướng Yêu Tương, được phái tới đưa Vương Lâm tới quân doanh.","vaiTro":"Nhân vật phụ — quản sự tham quân yêu tộc.","tinhCach":[{"text":"Lạnh lùng, cung kính khuôn phép","chuong":"@c0514"}],"tabs":{"diem":[{"text":"Vào phòng khiến không khí lạnh hẳn; mặt gầy gò, chừng bốn mươi tuổi","chuong":"@c0514"}],"kinhLich":[{"chuong":"@c0514","importance":"normal","tieuDe":"Đưa Vương Lâm tới quân doanh","text":"Tuân lệnh Yêu Tương tới cầu kiến Vương thống lĩnh, xin xem lệnh bài đồng rồi cắn ngón tay vẽ Truyền Tống trận bằng máu cực kỳ phức tạp, dẫn ba người tới quân doanh."},{"bridge":true,"khoang":"@c0515","text":"Dẫn Vương Lâm tới quân doanh Hắc Giáp quân nhậm chức, nhấn mạnh chữ phó đầy châm biếm khi giới thiệu Tư Mã Viêm; sau đó ôm quyền cáo từ về phục mệnh Yêu Tương đại nhân, đi vào trận pháp biến mất."},{"chuong":"@c0517","importance":"normal","tieuDe":"Bỏ truy cứu, ngỏ ý kết giao","text":"Theo luồng sáng đỏ như máu hiện thân ở quân doanh, cùng lão già áo vải bố tới phân xử việc th��ng lĩnh giết người. Sau khi truyền yêu lực vào ngọc giản xem lại diễn biến, sự khinh thường biến mất, sinh ý kết giao với Vương Lâm, hứa bẩm báo Yêu Tương đại nhân rồi ôm quyền cáo lui."}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Được phái tới đưa Vương Lâm (Vương thống lĩnh) tới quân doanh"},{"ten":"Yêu Tương","tag":"cap-tren","quanHe":"Quản sự tham quân dưới trướng Yêu Tương"},{"ten":"Lão già áo vải bố","tag":"dong-hanh","quanHe":"Người đi cùng tới quân doanh","ghiChu":"Đứng phía sau quản sự, thân có bốn phong ấn."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0514","@c0515","@c0517"]},{"id":"nam-tu-am-tram-yeu-binh","name":"Nam tử âm trầm","cn":"","aliases":["Đầu lĩnh sáu yêu binh tửu lâu","Nam tử âm trầm","Tư Mã phó thống lĩnh"],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"","trangThai":"song","blurb":"Đầu lĩnh sáu yêu binh trong tửu lâu, vẻ mặt âm trầm, đụng độ thoáng qua với Vương Lâm.","vaiTro":"Nhân vật phụ — yêu binh trong tửu lâu.","tinhCach":[{"text":"Âm trầm, ngạo mạn nhưng dè chừng","chuong":"@c0514"}],"tabs":{"diem":[{"text":"Vẻ mặt âm trầm, là đầu lĩnh của sáu yêu binh bị Vương Lâm nuốt yêu lực","chuong":"@c0514"}],"kinhLich":[{"chuong":"@c0514","importance":"normal","tieuDe":"Tấn công Vương Lâm trong tửu lâu","text":"Đứng lên hỏi danh tính Vương Lâm, vỗ bàn quát đứng lại rồi tán phát yêu lực ngưng thành một thanh trường kiếm bay tới ba người; bị Vương Lâm vung tay tạo gió làm tan, sững lại trầm tư nhìn theo."},{"chuong":"@c0515","importance":"normal","tieuDe":"Ra mắt tân thống lĩnh","text":"Tư Mã Viêm cưỡi một cự thú đen một sừng, mặc hắc giáp phủ kín có đồ họa màu bạc, mũ đen che mặt phóng tới quân doanh. Khi tháo mũ, hắn để lộ khuôn mặt âm trầm chính là người đã gặp Vương Lâm ở tửu lâu, xưng Tư Mã Viêm ra mắt thống lĩnh. Là tâm phúc nắm mười Thống đội của Hắc Giáp quân, hắn lệnh yêu binh tiếp tục thao luyện, ngấm ngầm để vạn yêu binh khinh thường tân thống lĩnh."},{"chuong":"@c0515","importance":"normal","tieuDe":"Khiếp sợ và triệu tập thống đội","text":"Sau ba ngày, Tư Mã Viêm càng lúc càng sợ — không phải sợ Vương Lâm ra tay hay tức giận mà sợ cảm giác nhìn không thấu sự bình thản dị thường của hắn. Tư Mã Viêm triệu bảy tám thống đội về phòng để nghe nhận xét về tân thống lĩnh, được báo hai người Từ U và Chu Khải vắng mặt như thường lệ."}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Bị Vương Lâm nuốt yêu lực và hóa giải đòn trường kiếm; được hẹn sẽ gặp lại"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Tân thống lĩnh Hắc Giáp quân, cấp trên danh nghĩa","ghiChu":"Tư Mã Viêm bề ngoài quy phục nhưng ngầm chống đối, không thể nhìn thấu."},{"ten":"Yêu Tương đại nhân","tag":"cap-tren","quanHe":"Cường giả cấp Yêu Tương cai quản trên Hắc Giáp quân","ghiChu":"Quản sự tham quân về phục mệnh Yêu Tương đại nhân."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0514","@c0515"]},{"id":"tu-u","name":"Từ U","gioiTinh":"nam","theLuc":[{"ten":"Hắc Giáp quân","trangThai":"gan-bo"}],"trangThai":"song","blurb":"Một thống đội của Hắc Giáp quân, ít lui tới Tư Mã Viêm và vắng mặt khi được triệu tập.","vaiTro":"Thống đội Hắc Giáp quân, gợi mở khe hở phe phái trong nội bộ.","tabs":{"kinhLich":[{"bridge":true,"khoang":"@c0515","text":"Là thống đội ít lui tới Tư Mã Viêm, Từ U cùng Chu Khải không đến khi Tư Mã Viêm triệu tập bàn về tân thống lĩnh."},{"bridge":true,"khoang":"@c0517","text":"Là nữ thống đội trong Hắc Giáp quân, khiến Hổ Bào rung động và được hắn ân cần đối đãi."}],"nhanMach":[{"ten":"Tư Mã Viêm","tag":"cap-tren","quanHe":"Phó thống lĩnh Hắc Giáp quân","ghiChu":"Từ U ít lui tới và không nghe triệu tập."},{"ten":"Hổ Bào","tag":"khac","quanHe":"Người rung động và ân cần với nàng","ghiChu":""}],"tuViMoc":[]},"nguon":["@c0515","@c0517"]},{"id":"chu-khai","name":"Chu Khải","gioiTinh":"nam","theLuc":[{"ten":"Hắc Giáp quân","trangThai":"gan-bo"}],"trangThai":"song","blurb":"Một thống đội của Hắc Giáp quân, ít lui tới Tư Mã Viêm và vắng mặt khi được triệu tập.","vaiTro":"Thống đội Hắc Giáp quân, gợi mở khe hở phe phái trong nội bộ.","tabs":{"kinhLich":[{"bridge":true,"khoang":"@c0515","text":"Là thống đội ít lui tới Tư Mã Viêm, Chu Khải cùng Từ U không đến khi Tư Mã Viêm triệu tập bàn về tân thống lĩnh."}],"nhanMach":[{"ten":"Tư Mã Viêm","tag":"cap-tren","quanHe":"Phó thống lĩnh Hắc Giáp quân","ghiChu":"Chu Khải ít lui tới và không nghe triệu tập."}]},"nguon":["@c0515"]},{"id":"dai-han-dau-troc-bo-cap","name":"Đại hán đầu trọc (ký hiệu bọ cạp)","gioiTinh":"nam","theLuc":[{"ten":"Hắc Giáp quân","trangThai":"gan-bo"}],"trangThai":"song","blurb":"Một thống đội dưới quyền Tư Mã Viêm, đầu trọc mặc giáp đen uy nghiêm, trên đầu có ký hiệu con bọ cạp quỷ dị như vật sống.","vaiTro":"Thống đội tâm phúc của Tư Mã Viêm trong Hắc Giáp quân.","tabs":{"kinhLich":[{"bridge":true,"khoang":"@c0515","text":"Trong buổi Tư Mã Viêm triệu tập, đại hán đầu trọc đứng ra báo cáo việc hai người Từ U và Chu Khải ít lui tới và lần này vẫn không đến."}],"nhanMach":[{"ten":"Tư Mã Viêm","tag":"cap-tren","quanHe":"Phó thống lĩnh Hắc Giáp quân","ghiChu":"Là thống đội tâm phúc, báo cáo cho Tư Mã Viêm."}]},"nguon":["@c0515"]},{"id":"tu-ma-viem","name":"Tư Mã Viêm","cn":"","aliases":["Tư Mã thống lĩnh"],"gioiTinh":"nam","theLuc":[{"ten":"Thiên Yêu quận","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Thống lĩnh quân doanh Thiên Yêu quận, âm trầm nhiều mưu kế, đối đầu tranh giành quyền lực với thống lĩnh mới Vương Lâm.","vaiTro":"Thống lĩnh quân doanh yêu binh, đối thủ chính trị của Vương Lâm trong tranh giành quyền lực Thiên Yêu quận.","tinhCach":[{"text":"Âm trầm, nhiều mưu kế","chuong":"@c0516"},{"text":"Thận trọng, biết chờ thời để đối phương lộ sơ hở","chuong":"@c0516"}],"tabs":{"diem":[{"text":"Chủ trương không trêu chọc Vương Lâm, chờ hắn chủ động xuất thủ để có đối sách","chuong":"@c0516"},{"text":"Nhận tin loạn nhưng cố ý chờ Vương Lâm bị vây mới ra mặt, báo trước cho quản sự tham quân","chuong":"@c0516"}],"kinhLich":[{"chuong":"@c0516","importance":"normal","tieuDe":"Bày Kế Ép Vương Lâm Lộ Diện","text":"Tư Mã Viêm cùng các thống đội định sách chờ Vương Lâm chủ động ra tay rồi mới đối phó. Khi Vương Lâm giết Tôn thống đội và trảm yêu binh, hắn dùng bí thuật báo cho quản sự tham quân, cố ý chờ Vương Lâm bị chín ngàn yêu binh vây mới phóng tới chất vấn. Không ngờ bị Vương Lâm viện dẫn quân quy điều mười ba và điều hai ép vào thế bị động, mới hiểu ra Vương Lâm ngồi im cả tháng chính là để chờ cơ hội này."},{"chuong":"@c0517","importance":"normal","tieuDe":"Thất thế buộc nhận lỗi","text":"Hạ lệnh chín ngàn yêu binh tản ra phá thế bao vây, nhưng sau khi quản sự xem ngọc giản thì cục diện đảo ngược; Tư Mã Viêm cung kính nhận “lỗ mãng”, đám thống đội cũng lần lượt nhận lỗi. Sau sự kiện, bốn trong tám thống đội từng thân với hắn dần xa lánh."},{"bridge":true,"khoang":"@c0526","text":"Đứng cung kính bên Đô Thống trong quân doanh Hắc Giáp quân; nhận ra Vương Lâm thì khiếp sợ cực độ, hối hận từng trêu chọc hắn năm xưa, nhớ tới cảnh ngộ của Thập Tam và Hổ Bào, do dự rồi vẫn xông ra."},{"chuong":"@c0527","importance":"normal","tieuDe":"Bị sưu hồn rồi giết","text":"Bị lộ là kẻ đã lấy cớ vi phạm quân quy để phế tu vi Hổ Bào ném vào hắc lao, lại bóp nát gân cốt Thập Tam khi gã trợ giúp Hổ Bào. Bị Vương Lâm chộp tới, dùng Sưu hồn thuật đọc trọn ký ức, rồi bị Sát Lục Tiên quyết khiến thân thể héo rũ tan thành huyết nhục; toàn thân công phu bị luyện hóa thành tia khí xám."}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Thống lĩnh mới của quân doanh, đối thủ tranh quyền","ghiChu":"Bị Vương Lâm dùng quân quy phản chế khi ra mặt chất vấn."},{"ten":"Tôn thống đội","tag":"khac","quanHe":"Thống đội dưới quyền","ghiChu":"Bị Vương Lâm giết khi khiêu khích."},{"ten":"Đô Thống Hắc Giáp quân","tag":"cap-tren","quanHe":"Đứng hầu cận bên Đô Thống trong quân doanh.","ghiChu":"@c0526"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Bị Vương Lâm sưu hồn rồi giết để báo thù cho tùy tùng"}],"tuiDo":{}},"nguon":["@c0516","@c0517","@c0526","@c0527"]},{"id":"ton-thong-doi","name":"Tôn thống đội","cn":"","gioiTinh":"nam","theLuc":[{"ten":"Thiên Yêu quận","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Kết Đan kỳ","trangThai":"tu-vong","blurb":"Thống đội yêu binh dưới quyền Tư Mã Viêm; khinh miệt sỉ nhục Vương Lâm rồi bị hắn bóp nát cổ, phá tu vi và hút yêu khí.","vaiTro":"Thống đội yêu binh, nạn nhân đầu tiên trong màn ra oai của Vương Lâm.","tinhCach":[{"text":"Ngạo mạn, coi thường thống lĩnh mới","chuong":"@c0516"}],"tabs":{"diem":[],"kinhLich":[{"chuong":"@c0516","importance":"normal","tieuDe":"Khiêu Khích Vương Lâm Và Bị Giết","text":"Tôn thống đội dẫn đội ngàn người thao luyện đi ngang chỗ Vương Lâm, nhổ nước bọt và gọi hắn là phế vật. Vương Lâm mở mắt, giơ tay tạo nguồn lực vô hình trói chặt kéo lại bóp cổ, sai Thập Tam đọc điều thứ tám quân quy rồi bóp nát cổ, phá hủy tu vi và hút yêu khí từ thất khiếu của hắn."}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Thống lĩnh mới bị Tôn thống đội sỉ nhục","ghiChu":"Giết Tôn thống đội để ra oai."},{"ten":"Tư Mã Viêm","tag":"khac","quanHe":"Thống lĩnh quân doanh, cấp trên","ghiChu":"Tôn thống đội thuộc quyền Tư Mã Viêm."}],"tuiDo":{}},"nguon":["@c0516"]},{"id":"lao-gia-ao-vai-bo-bon-phong-an","name":"Lão già áo vải bố","aliases":["Lão già tóc bạc bốn phong ấn"],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Lão già mặc áo vải bố, tóc bạc trắng phất phơ, đi cùng quản sự tham quân; trong thân có bốn phong ấn.","vaiTro":"Người đi theo quản sự tham quân tới quân doanh thị uy.","tinhCach":[{"text":"Khiếp sợ rồi bội phục trước thực lực của Vương Lâm.","chuong":"@c0517"}],"tabs":{"diem":[{"text":"Trong cơ thể có tới bốn cái phong ấn, thân phận và sức mạnh thật bị che giấu.","chuong":"@c0517"}],"kinhLich":[{"chuong":"@c0517","importance":"normal","tieuDe":"Phong ấn suýt vỡ vì ánh mắt Vương Lâm","text":"Đi cùng quản sự tham quân hiện thân thị uy ở quân doanh. Khi ánh mắt chạm mắt Vương Lâm, một trong bốn phong ấn của lão suýt bị phá vỡ khiến lão khiếp sợ; cuối cùng lão ôm quyền bội phục tu vi của Vương Lâm."}],"tuViMoc":[],"nhanMach":[{"ten":"Quản sự tham quân","tag":"dong-hanh","quanHe":"Người mà lão đi theo","ghiChu":""},{"ten":"Vương Lâm","tag":"khac","quanHe":"Thống lĩnh khiến phong ấn của lão suýt vỡ","ghiChu":""}],"tuiDo":{}},"nguon":["@c0517"]},{"id":"dong-phu-chi-linh-ton-long","name":"Động Phủ Chi Linh","cn":"","aliases":["Người đàn ông trung niên áo trắng (động phủ)"],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"","trangThai":"khong-ro","blurb":"Một tia linh hồn còn sót lại của động phủ tiên nhân nơi cuối đường Tôn Long, hiện thân thành người trung niên áo trắng tiên phong đạo cốt, canh giữ cửa và khảo nghiệm khách tới bằng ba đạo kiếm khí.","vaiTro":"Người gác động phủ tiên nhân","tinhCach":[{"text":"Lạnh lùng, ra điều kiện sống chết dứt khoát: không vào được động phủ thì cả hai phải chết.","chuong":"@c0523"},{"text":"Trọng nghĩa cố nhân — vì nhận ra công pháp Huyết Quân mà ba lần tha Diêu Tích Tuyết.","chuong":"@c0523"}],"tabs":{"diem":[{"text":"Chỉ là tia linh hồn sót lại nhưng nắm quyền sinh sát qua cửa động phủ.","chuong":"@c0523"}],"kinhLich":[{"chuong":"@c0523","importance":"normal","tieuDe":"Khảo nghiệm khách bằng ba đạo kiếm khí","text":"Hiện ra ở cửa đá hình mặt người nơi đài thứ mười hai, tuyên bố chỉ kẻ có lệnh bài mới được vào động phủ tiên nhân. Vì nhận ra Diêu Tích Tuyết thi triển công pháp của Huyết Quân năm xưa nên đã ba lần tha nàng; lần này phóng ba đạo kiếm khí khảo nghiệm, ai chống được mới đủ tư cách, bằng không phải chết."}],"tuViMoc":[],"nhanMach":[{"ten":"Diêu Tích Tuyết","tag":"an-nhan","quanHe":"Ba lần tha mạng vì nàng mang truyền thừa công pháp Huyết Quân.","ghiChu":""},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Khảo nghiệm bằng ba đạo kiếm khí; Vương Lâm lợi dụng để bày kế.","ghiChu":""}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0523"]},{"id":"dong-phu-chi-linh-tien-cam","name":"Động Phủ Chi Linh (động phủ tiên cấm)","aliases":["Động Phủ Chi Linh","Người đàn ông trung niên dưới cửa đá"],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"khong-ro","blurb":"Linh thể canh giữ động phủ tiên cấm, hiện hình người đàn ông trung niên dưới cửa đá, chỉ trả lời trong khuôn khổ được phép.","vaiTro":"Linh thể bảo vệ động phủ của một vị tiên nhân giấu mặt, dẫn dắt thông tin cho người đủ tư cách tiến vào.","tinhCach":[{"text":"Đáp lời rành mạch nhưng kín đáo, tuyệt không tiết lộ thân phận chủ nhân","chuong":"@c0524"}],"tabs":{"diem":[{"text":"Hiện hình người đàn ông trung niên dưới cửa đá, canh giữ động phủ làm bằng tiên ngọc và tiên cấm","chuong":"@c0524"},{"text":"Khi hỏi chủ nhân là ai chỉ đáp chủ nhân là chủ nhân, chẳng là ai cả","chuong":"@c0524"}],"kinhLich":[{"chuong":"@c0524","importance":"normal","tieuDe":"Vấn Đáp Với Vương Lâm","text":"Xác nhận Vương Lâm và Diêu Tích Tuyết cùng tiếp ba đạo kiếm khí nên có tư cách vào, nhưng mọi thứ bên trong đã bị chủ nhân phong ấn trước khi rời đi. Linh thể giải thích ký hiệu vàng trên mười một đài bên ngoài là Hộ Phủ Thần Thông, rằng mở được một đạo phong ấn sẽ thu quyền hạn nhưng động phủ tự đóng cửa, người vào trước đều đã chết, và muốn rời đi phải mở được một đạo thảo ấn."}],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Người tiến vào động phủ được linh thể giải đáp","ghiChu":"Vương Lâm hỏi về tư cách, chủ nhân và điều kiện mở phong ấn."}]},"nguon":["@c0524"]},{"id":"do-thong-hac-giap-quan","name":"Đô Thống Hắc Giáp quân","cn":"","aliases":["Người đàn ông áo giáp đen","Đô Thống Hắc Giáp quân","Người đàn ông vạm vỡ","Đại hán áo giáp đen"],"gioiTinh":"nam","theLuc":[{"ten":"Hắc Giáp quân","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Anh Biến hậu kỳ (chưa đại viên mãn)","trangThai":"song","blurb":"Người đàn ông vạm vỡ mặc áo giáp đen, Đô Thống chỉ huy quân doanh Hắc Giáp quân ngoài Cổ Yêu Thành, yêu lực ngang Anh Biến hậu kỳ.","vaiTro":"Chỉ huy mười vạn Yêu binh Hắc giác và bốn thống lĩnh; ra lệnh giết Vương Lâm rồi bị hắn áp chế.","tinhCach":[{"text":"Uy nghiêm, ra lệnh dứt khoát nhưng đổ mồ hôi và mất khí thế khi đối diện áp lực vượt cấp.","chuong":"@c0526"}],"tabs":{"diem":[{"text":"Yêu lực ngang Anh Biến hậu kỳ chưa đại viên mãn, có thể hóa thân Huyền Vũ trăm trượng đầy gai nhọn.","chuong":"@c0526"}],"kinhLich":[{"chuong":"@c0526","importance":"normal","tieuDe":"Đối đầu Vương Lâm trở về","text":"Khi Vương Lâm về quân doanh, Đô Thống ra lệnh cho bốn thống lĩnh giết hắn, báo rằng Vương Lâm mất tích hơn một năm nên đã bị Yêu Tướng bãi miễn chức thống lĩnh. Bị áp khí thế, hắn lùi một bước liền mất thế, hóa thân Huyền Vũ trăm trượng chống cự trước Tịch Diệt Chỉ của Vương Lâm."},{"chuong":"@c0527","importance":"normal","tieuDe":"Lộ tên, bại trận và được tha","text":"Lộ tên là Tần Lâm, Đô thống mặc áo giáp đen. Khi giao chiến hắn dung thân vào bóng Huyền Vũ, hai mắt lộ tia sáng yêu dị, điều khiển Huyền Vũ quật đuôi đánh Vương Lâm, nhưng bị Tịch Diệt Chỉ phá tan, áo giáp vỡ vụn, phun tiên huyết quỳ gối. Hắn khai từng theo lệnh Yêu Tướng tìm người có cường độ thân thể cao nên đã chữa thương cho Thập Tam rồi dâng tặng. Được Vương Lâm tha vì có công cứu lẫn có tội, hắn ôm ngực rút về tẩm cung chữa thương sau khi tiết lộ Yêu Tướng bế quan, mọi truyền tống trận đều bị phong kín từ bên trong."},{"chuong":"@c0528","importance":"normal","tieuDe":"Tử chiến Vương Lâm tại cửa thứ ba","text":"Trấn giữ cửa thứ tư cung Yêu Tướng, lão già đầu bạc hóa con mãng xà yêu lực màu xám bạc đánh lén Vương Lâm, kinh ngạc nhận ra đối phương đã mạnh vượt bậc so với hơn một năm trước. Khi Vương Lâm thi triển Hóa Ma Chỉ tạo huyết long phá cửa thứ ba, con mãng xà va chạm huyết long rồi đổ sụp, lão già bỏ mạng tại chỗ."}],"tuViMoc":[{"chuong":"@c0526","canhGioi":"Anh Biến","text":"Yêu lực ngang Anh Biến hậu kỳ, chưa đạt đại viên mãn.","importance":"minor"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Ra lệnh giết Vương Lâm trở về rồi bị hắn áp chế.","ghiChu":"@c0526"},{"ten":"Tư Mã Viêm","tag":"khac","quanHe":"Thuộc hạ cung kính hầu cận bên cạnh.","ghiChu":"@c0526"},{"ten":"Yêu Tương đại nhân","tag":"cap-tren","quanHe":"Cấp trên đã bãi miễn chức thống lĩnh của Vương Lâm.","ghiChu":"@c0526"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Bại dưới tay Vương Lâm nhưng được tha"},{"ten":"Thập Tam","tag":"khac","quanHe":"Mang Thập Tam đi chữa thương rồi dâng cho Yêu Tướng"},{"ten":"Yêu Tương đại nhân","tag":"cap-tren","quanHe":"Tuân lệnh Yêu Tướng tìm người cường độ thân thể cao"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối thủ","ghiChu":"Từng ngang tu vi Vương Lâm và để ý tới hắn ở quân doanh, lần tái ngộ này bị hắn giết."}],"tuiDo":{}},"nguon":["@c0526","@c0527","@c0528"]},{"id":"de-nhat-do-thong","name":"Đệ nhất Đô Thống","cn":"","aliases":["Đô Thống thấp bé"],"gioiTinh":"nam","theLuc":[{"ten":"Thế lực yêu linh","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Anh Biến (suy đoán)","trangThai":"song","blurb":"Đệ nhất Đô Thống dưới trướng Yêu Tướng, dáng thấp bé mắt sáng như điện, trấn giữ cửa thứ hai cung điện.","vaiTro":"Cường giả trấn cửa của cung Yêu Tướng, đối thủ của Vương Lâm trong trận phá cung.","tinhCach":[{"text":"Trầm tĩnh, ra tay dứt khoát, đứng vững vị trí đệ nhất Đô Thống.","chuong":"@c0528"}],"tabs":{"diem":[{"text":"Tự xưng là đệ nhất Đô Thống dưới trướng Yêu Tướng.","chuong":"@c0528"},{"text":"Dáng thấp bé nhưng đôi mắt sáng quắc như điện.","chuong":"@c0528"}],"kinhLich":[{"chuong":"@c0528","importance":"normal","tieuDe":"Chặn Hoàng Tuyền Chỉ bại trận","text":"Khi Vương Lâm tung Hoàng Tuyền Chỉ phá cửa, đệ nhất Đô Thống dùng quả cầu trắng có vô số tia chớp đen ngưng giữa hai tay, chặn được chỉ pháp cách thân ba tấc. Tuy nhiên lực không đủ, hắn bị đẩy lùi xô sập cửa thứ nhất rồi phun tiên huyết bị bắn văng ra xa."}],"tuViMoc":[],"tuVi":"Tu vi cường giả trấn cửa cung Yêu Tướng, đủ sức chặn nhất thời Hoàng Tuyền Chỉ của Vương Lâm.","nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối thủ","ghiChu":"Chặn rồi bại dưới Hoàng Tuyền Chỉ của Vương Lâm."},{"ten":"Yêu Tương đại nhân","tag":"cap-tren","quanHe":"Chủ tướng","ghiChu":"Là đệ nhất Đô Thống dưới trướng Yêu Tướng."}],"tuiDo":{"phapBao":[{"ten":"Quả cầu trắng tia chớp đen","loai":"phap-bao","trangThai":"dang-co","moTa":"Quả cầu nhỏ bằng nắm tay màu trắng, bên trong vô số tia chớp đen ầm ầm, dùng chặn Hoàng Tuyền Chỉ.","nguon":"@c0528"}]}},"nguon":["@c0528"]},{"id":"nguoi-cao-lon-thap-bang-quyen-y","name":"Người cao lớn (Thập Băng Quyền ý)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thế lực yêu linh","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Chưa rõ (cao thâm)","trangThai":"song","blurb":"Cao thủ trấn cửa thứ nhất cung Yêu Tướng, một quyền Thập Băng Quyền ý đủ ngang ngửa Hoàng Tuyền Chỉ của Vương Lâm.","vaiTro":"Đối thủ mạnh nhất Vương Lâm chạm trán khi phá cung Yêu Tướng, thân phận chưa lộ.","tinhCach":[{"text":"Trầm mặc, không nói lời thừa, ra tay là dồn toàn bộ chiến ý.","chuong":"@c0528"}],"tabs":{"diem":[{"text":"Bước ra từ cửa thứ nhất, im lặng không nói nửa lời rồi tung quyền.","chuong":"@c0528"},{"text":"Sở trường Thập Băng Quyền ý, sóng quyền lớp sau mạnh hơn lớp trước.","chuong":"@c0528"}],"kinhLich":[{"chuong":"@c0528","importance":"normal","tieuDe":"Thập Băng Quyền nghênh chiến Hoàng Tuyền Chỉ","text":"Từ cửa thứ nhất, người cao lớn lặng lẽ bước ra tung một quyền Thập Băng Quyền ý đầy chiến ý nghênh đón Hoàng Tuyền Chỉ. Vụ va chạm tạo sóng chấn lan mười dặm, hủy hoại lầu các quanh vùng và hóa tro yêu binh, đẩy Vương Lâm lùi hơn ba trượng."}],"tuViMoc":[],"tuVi":"Tu vi cao thâm, một quyền ngang ngửa sát chiêu Hoàng Tuyền Chỉ của Vương Lâm.","nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối thủ","ghiChu":"Đối đầu Vương Lâm bằng Thập Băng Quyền ý ở cửa thứ nhất."},{"ten":"Yêu Tương đại nhân","tag":"cap-tren","quanHe":"Chủ tướng","ghiChu":"Trấn cửa cuối cùng bảo vệ Yêu Tướng đang bế quan."}],"tuiDo":{"phapBao":[],"congPhap":[]}},"nguon":["@c0528"]},{"id":"lao-gia-hac-bao-an-cong-ho-bao","name":"Lão già hắc bào (ân công của Hổ Bào)","aliases":["Lão già hắc y","Ân công của Hổ Bào"],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"","trangThai":"song","blurb":"Lão già toàn thân hắc y lạnh lùng, thuộc hạ phụng sự chủ nhân trong bộ giáp ở hắc tháp; cứu Hổ Bào vì hắn có Luyện Hồn Thuật kỳ dị và định biến hắn thành Yêu Vệ thí nghiệm.","vaiTro":"Thế lực cổ xưa bí ẩn đứng sau, phụng sự chủ nhân trong hắc tháp.","tinhCach":[{"text":"Lạnh lùng, tính toán, coi trọng người quyết đoán và dứt bỏ.","chuong":"@c0530"}],"tabs":{"diem":[{"text":"Cứu Hổ Bào chỉ vì hắn sở hữu Luyện Hồn Thuật mà lão chưa từng gặp.","chuong":"@c0530"}],"kinhLich":[{"chuong":"@c0530","importance":"normal","tieuDe":"Giám sát Hổ Bào, báo cáo trước bộ giáp chủ nhân","text":"Lão già hắc y giám sát Hổ Bào luyện hóa linh hồn tại chiến trường cổ, tiết lộ chủ tử cũ của Hổ Bào đã xuất hiện ở Cổ Yêu thành. Sau đó lão vào hắc tháp mười tầng, quỳ trên tầng cao nhất trước bộ áo giáp cổ của chủ nhân, báo tin Yêu Đế Thiên Yêu quận ngàn năm trước bị ngừng ở bước đột phá cuối và nh���n tin tức truyền vào mắt khiến lão đổ mồ hôi lạnh."}],"tuViMoc":[],"nhanMach":[{"ten":"Hổ Bào","tag":"khac","quanHe":"Đối tượng được cứu và thí nghiệm","ghiChu":"Cứu khỏi hắc lao, truyền Diệt Thế Áp Nguyên Công, định luyện thành Yêu Vệ."},{"ten":"Chủ nhân (bộ áo giáp trong hắc tháp)","tag":"cap-tren","quanHe":"Chủ nhân phụng sự","ghiChu":"Thực thể cổ xưa trong bộ giáp ở hắc tháp, truyền lệnh và khẩu quyết cho lão."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0530"]},{"id":"chu-nhan-bo-giap-hac-thap","name":"Chủ nhân (bộ áo giáp trong hắc tháp)","aliases":["Chủ nhân","Bộ giáp đen mười tầng"],"gioiTinh":"khong-ro","theLuc":[],"canhGioiCaoNhat":"","trangThai":"song","blurb":"Thực thể cổ xưa ngụ trong bộ áo giáp đen đặt ở tầng cao nhất hắc tháp mười tầng, mũ giáp lóe u quang như ánh mắt, vừa thức tỉnh chưa lâu và truyền lệnh cho lão già hắc y.","vaiTro":"Tuyến đối kháng cổ xưa tiềm tàng, đang theo dõi Yêu Đế Thiên Yêu quận.","tinhCach":[{"text":"Uy nghiêm, bí ẩn, khiến trời đất rung động khi hiển uy.","chuong":"@c0530"}],"tabs":{"diem":[{"text":"Mũ giáp lóe hai đạo u quang như ánh mắt, trời đất rung lên như có tiên linh hàng lâm.","chuong":"@c0530"}],"kinhLich":[{"chuong":"@c0530","importance":"normal","tieuDe":"Thức tỉnh, truyền lệnh từ trong bộ giáp","text":"Ngụ trong bộ áo giáp cổ ở tầng cao nhất hắc tháp, chủ nhân vừa thức tỉnh chưa lâu, dùng u quang trong mũ giáp truyền tin tức và mệnh lệnh cho lão già hắc y. Khẩu quyết do chủ nhân truyền xuống có thể ngưng tụ toàn bộ tuổi thọ và tiềm lực trong một canh giờ rồi bùng nổ biến tu sĩ thành Yêu Vệ."}],"tuViMoc":[],"nhanMach":[{"ten":"Lão già hắc bào (ân công của Hổ Bào)","tag":"khac","quanHe":"Thuộc hạ phụng sự","ghiChu":"Lão già hắc y nhận lệnh và khẩu quyết luyện Yêu Vệ từ chủ nhân."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0530"]},{"id":"mac-luc-hai","name":"Mạc Lực Hải","aliases":["Mạc Lệ Hải"],"tabs":{"diem":[],"kinhLich":[{"chuong":"@c0531","importance":"normal","tieuDe":"Rời Cổ Yêu thành tới kinh đô","text":"Đứng trên tường thành cửa đông Cổ Yêu thành tiếc nuối vì Thập Tam — bộ thứ mười tám hắn cần để hoàn tất Thập Bát Yêu Ma Thân — bị Vương Lâm mang đi; cùng Vương Lâm qua ba truyền tống trận hướng kinh thành Thiên Yêu quận, mưu cầu vào vòng ba cuộc chiến Yêu tướng để giành tư cách vào Cổ Yêu điện và chức phó soái."},{"chuong":"@c0532","importance":"normal","tieuDe":"Hồi Đế Đô dự cuộc chiến Yêu tướng","text":"Yêu tướng trấn thủ Cổ Yêu thành, tu vi đứng đầu trong số Yêu tướng, sau ba mươi năm mới trở về Đế Đô qua truyền tống trận thứ mười bốn, dẫn theo Vương Lâm. Được Yêu binh cung nghênh là “Mạc Yêu tướng”, mời Vương Lâm về phủ ở Hồng thành vì kinh thành đang hỗn tạp thế lực."},{"chuong":"@c0532","importance":"minor","text":"Mười chín kỵ binh giáp đen Hóa Thần dưới trướng quỳ tham kiến Chủ tướng; ông giới thiệu Vương Lâm là “Vương tướng” bạn tốt rồi cùng phóng ngựa về phủ, đoạn trầm sắc tăng tốc khi nghe tiếng vó ngựa lạ phía trước."},{"chuong":"@c0533","importance":"normal","tieuDe":"Đấu Thạch Tiễn trên quân đạo","text":"Hai đoàn người lao thẳng vào nhau; Mạc Lệ Hải tung Thập Băng Quyền Ý đối Lục Chỉ Kiếm Quyết của Thạch Tiễn, cả hai nén lực ở mức thấp nhất. Nhờ Vương Lâm trợ một điểm, chiến mã Mạc Lệ Hải không tổn hại trong khi mã Thạch Tiễn nứt bốn chân — cao thấp đã rõ."},{"bridge":true,"khoang":"@c0533","text":"Vào Đế Đô bái kiến Yêu Đế báo cáo công tác, rồi mấy ngày đi sớm về muộn thăm hỏi các Yêu soái, Phó soái, Yêu tướng thân thiết, cảm nhận Thiên Yêu thành phong vân tụ hội trước cuộc chiến Yêu tướng."},{"chuong":"@c0535","importance":"normal","tieuDe":"Sắp xếp đưa Vương Lâm vào Hồng lao","text":"Yêu tu chủ Mạc phủ; chứng kiến năm đạo sát lục khí của Vương Lâm dung hợp len qua quyền phong chấn động yêu giáp, hắn kinh ngạc nhận ra thứ khí xám sắc bén như yêu kiếm lại có biến hóa khó giải dẫn động sinh cơ trong cơ thể, nếu hình thành tới mấy ngàn đạo thì cực kỳ đáng sợ. Hắn từ chối một tháng nhưng chấp nhận bảy ngày, hẹn ba ngày sau trả lời, và quyết giữ quan hệ tốt không để Vương Lâm thành kẻ địch."}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Đồng hành tới kinh đô, kỳ vọng được trợ giúp hoàn tất Thập Bát Yêu Ma Thân","ghiChu":""},{"ten":"Thập Tam","tag":"khac","quanHe":"Là bộ thứ mười tám còn thiếu của Thập Bát Yêu Ma Thân, bị Vương Lâm mang đi","ghiChu":""},{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Mời làm trợ thủ cuộc chiến Yêu tướng, bảo chứng thân phận “Vương tướng”","ghiChu":""},{"ten":"Thạch Tiễn","tag":"doi-thu","quanHe":"Kình địch trong cuộc chiến Yêu tướng","ghiChu":"Đấu một chiêu ngang ngửa trên quân đạo."},{"ten":"Trần Đào","tag":"doi-thu","quanHe":"Quân sư phe Thạch Tiễn","ghiChu":"Đang trọng thương; nếu khỏe có thể giết được Mạc Lệ Hải theo lời Trần Đào."},{"ten":"Yêu Đế","tag":"cap-tren","quanHe":"Quân chủ Thiên Yêu quận","ghiChu":"Thân truyền thức thứ ba trong Thần Thông Tam Thức cho Mạc Lệ Hải."},{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Đối tác giao dịch — đổi sự giúp đỡ lấy việc sắp xếp Vương Lâm vào Hồng lao tu luyện","ghiChu":"@c0535"},{"ten":"Thập Tam","tag":"khac","quanHe":"Từng lấy mạng Thập Tam để đổi lấy sự giúp đỡ của Vương Lâm","ghiChu":"@c0535"}],"tuiDo":{}},"nguon":["@c0531","@c0532","@c0533","@c0535"]},{"id":"nhi-cau","name":"Nhị Cẩu","gioiTinh":"nam","theLuc":[{"ten":"Thiên Yêu quận","trangThai":"gan-bo"}],"canhGioiCaoNhat":"","trangThai":"song","blurb":"Yêu binh trẻ cơ trí dưới quyền đội trưởng canh truyền tống trận thứ mười bốn của Thiên Yêu thành.","vaiTro":"Yêu binh tân binh","tinhCach":[{"text":"Cơ trí, biết lấy lòng cấp trên","chuong":"@c0532"}],"tabs":{"diem":[],"kinhLich":[{"chuong":"@c0532","importance":"minor","text":"Bóp vai cho đội trưởng Yêu binh rồi hỏi vì sao truyền tống trận thứ mười bốn dạo này mở liên tục, mở đầu cho lời kể về bối cảnh cuộc chiến Yêu tướng."}],"tuViMoc":[],"nhanMach":[{"ten":"Đội trưởng Yêu binh","tag":"cap-tren","quanHe":"Thuộc hạ dưới quyền đội trưởng canh truyền tống trận","ghiChu":""}],"tuiDo":{}},"nguon":["@c0532"]},{"id":"doi-truong-yeu-binh","name":"Đội trưởng Yêu binh (truyền tống trận 14)","gioiTinh":"nam","theLuc":[{"ten":"Thiên Yêu quận","trangThai":"gan-bo"}],"canhGioiCaoNhat":"","trangThai":"song","blurb":"Chỉ huy đội Yêu binh trấn thủ truyền tống trận thứ mười bốn, giáp khắc nhiều hoa văn hơn binh sĩ thường.","vaiTro":"Đội trưởng Yêu binh","tinhCach":[{"text":"Am hiểu nội tình, hay khoe hiểu biết với tân binh","chuong":"@c0532"}],"tabs":{"diem":[],"kinhLich":[{"chuong":"@c0532","importance":"minor","text":"Kể cho đám tân binh nghe lai lịch cuộc chiến Yêu tướng: cứ ba trăm năm một lần do Đế Quân quan sát, lần này chọn hai vị soái mới thay hai phó soái tử trận trong đại chiến với Hỏa Yêu quận hai trăm năm trước. Khi truyền tống tr���n sáng lên, lập tức cảnh giác chỉnh đốn đội ngũ nghênh đón Mạc Lệ Hải và Vương Lâm."}],"tuViMoc":[],"nhanMach":[{"ten":"Nhị Cẩu","tag":"cap-tren","quanHe":"Cấp trên của Nhị Cẩu","ghiChu":""}],"tuiDo":{}},"nguon":["@c0532"]},{"id":"mac-phi-yeu-tuong","name":"Mặc Phi","gioiTinh":"nam","theLuc":[{"ten":"Thiên Yêu quận","trangThai":"gan-bo"}],"canhGioiCaoNhat":"","trangThai":"song","blurb":"Yêu tướng đại nhân trấn thủ biên giới giáp Hỏa Yêu quận, được đánh giá đủ sức vào vòng ba cuộc chiến Yêu tướng.","vaiTro":"Yêu tướng trấn biên","tinhCach":[],"tabs":{"diem":[],"kinhLich":[{"chuong":"@c0532","importance":"minor","text":"Được đội trưởng Yêu binh nhắc tới như một trong những Yêu tướng mạnh nhất, trấn thủ biên giới Hỏa Yêu quận, đủ tư cách lọt vào vòng ba cuộc chiến tuyển soái."},{"chuong":"@c0537","importance":"normal","tieuDe":"Lộ diện ở Vũ Thành","text":"Tại Vũ Thành, Yêu Tương Mặc Phi của Hỏa Yêu Quận ở trong một biệt viện cùng hai đệ tử đeo đại kiếm; gương mặt anh tuấn ẩn cương nghị, tướng mạo giống y hệt thanh niên tóc đen sống sót trong thế giới huyết sắc của Hồng Lao."},{"chuong":"@c0542","importance":"normal","tieuDe":"Đệ nhất nhân Yêu Tướng","text":"Đánh bại Mạc Lệ Hải bằng Chuyển Luân thuật, làm Yêu Hải Bách Lãng quay ngược trở về. Sau khi thành Yêu Tướng đã đến Long Đàm Cổ Yêu Điện tĩnh tu ba năm; suốt ba năm chưa ai bu��c hắn phải dùng thần thông thứ hai ngoài Chuyển Luân thuật."},{"chuong":"@c0543","importance":"normal","tieuDe":"Ứng viên đứng đầu trận Yêu Tướng","text":"Mặc Phi được dân chúng dự đoán chắc chắn giành vị trí thứ nhất trong trận chiến Yêu Tướng. Đã thắng Mạc Lệ Hải ở trận trước. Tại trường đấu, hắn lạnh lùng liếc nhìn Vương Lâm khi Ngao Địch ra khiêu chiến."},{"chuong":"@c0546","importance":"normal","tieuDe":"Gõ tám tiếng Chiến Yêu Cổ","text":"Yêu Tướng đeo mặt nạ dữ tợn, thong dong gõ sáu tiếng liên tục bằng quyền cách không không bị thương, được hoan hô vang dội; rồi ép thêm tiếng bảy (áo giáp nát) và tiếng tám (dùng tinh thể như gương đỡ phản lực, lùi hơn trăm trượng). Mặt nạ vỡ lộ khuôn mặt anh tuấn giống hệt nam tử tóc đen ở chỗ sâu nhất Hồng Lao. Cùng người trợ giúp tổng cộng mười một tiếng, áp đảo các Yêu Tướng."},{"chuong":"@c0548","importance":"normal","tieuDe":"Một mình không cộng hưởng trống niệm","text":"Mặc Phi hỏi thầm có phải Vương Lâm cũng cảm nhận được luồng khí tức trong Yêu Cổ; khi tiếng trống truyền niệm khiến cả trường rơi lệ cộng hưởng, riêng Mặc Phi vẫn bình thản hờ hững, hoàn toàn không bị lay động."}],"tuViMoc":[],"nhanMach":[{"ten":"Thanh niên tóc đen (thế giới huyết sắc)","tag":"khac","quanHe":"Tướng mạo giống y hệt nhau, ngụ ý mối liên hệ phân thân/thế thân chưa giải thích","ghiChu":"@c0537"},{"ten":"Mạc Lệ Hải","tag":"doi-thu","quanHe":"Đã đánh bại trong tỉ thí Yêu Tướng","ghiChu":"@c0542"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Lạnh lùng quan sát Vương Lâm tại trường đấu","ghiChu":"@c0543"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Vương Lâm nhận ra Mặc Phi giống nam tử tóc đen ở Hồng Lao","ghiChu":"@c0546"},{"ten":"Tu sĩ mặc thanh sam","tag":"dong-minh","quanHe":"Người trợ giúp gõ thêm ba tiếng cho Mặc Phi","ghiChu":"@c0546"}],"tuiDo":{}},"nguon":["@c0532","@c0537","@c0542","@c0543","@c0546","@c0548"]},{"id":"thach-tien","name":"Thạch Tiễn","cn":"","aliases":["Người thanh niên tà dị","Áo giáp thanh sắc"],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"","trangThai":"song","blurb":"Kỵ sĩ tóc tím mặc áo giáp thanh sắc, mặt anh tuấn yêu dị với vết sẹo má phải khiến vẻ hung ác; thần thông Lục Chỉ Kiếm Quyết uy lực khó lường, là kình địch của Mạc Lệ Hải trong cuộc chiến Yêu tướng.","vaiTro":"Đối thủ phe Yêu tướng, đồng minh nâng đỡ Trần Đào.","tinhCach":[{"text":"Lạnh lùng, hiếu chiến nhưng biết tính toán — nén lực khi đấu thử, lập tức ngưng trọng khi nghe Trần Đào nể phục Vương Lâm.","chuong":"@c0533"}],"tabs":{"diem":[{"text":"Tóc dài màu tím, vết sẹo má phải khiến gương mặt yêu dị trở nên hung ác.","chuong":"@c0533"},{"text":"Sở trường Lục Chỉ Kiếm Quyết: cong tay điểm năm chỉ cực nhanh rồi khép thành chùy điểm tới.","chuong":"@c0533"}],"kinhLich":[{"chuong":"@c0533","importance":"normal","tieuDe":"Chạm trán Mạc Lệ Hải","text":"Cùng Trần Đào phóng ngựa lao vào đoàn Mạc Lệ Hải, khóa mục tiêu rồi tung Lục Chỉ Kiếm Quyết đối Thập Băng Quyền Ý. Sau trận, hắn bàn với Trần Đào về Thần Thông Tam Thức của Mạc Lệ Hải, hứa phái người thu thập tài liệu để Trần Đào luyện Thiên Nguyên đan khôi phục tu vi."}],"tuViMoc":[],"nhanMach":[{"ten":"Trần Đào","tag":"dong-minh","quanHe":"Đồng hành, nâng đỡ","ghiChu":"Thu thập tài liệu giúp Trần Đào luyện Thiên Nguyên đan."},{"ten":"Mạc Lệ Hải","tag":"doi-thu","quanHe":"Kình địch cuộc chiến Yêu tướng","ghiChu":"Đấu một chiêu trên quân đạo."},{"ten":"Vương Lâm","tag":"khac","quanHe":"Sư đệ đồng hệ của Trần Đào","ghiChu":"Ngưng trọng khi nghe Trần Đào hết lời khen Vương Lâm."}],"tuiDo":{}},"nguon":["@c0533"]},{"id":"co-gai-mu-thuyen-hoa-thien-yeu","name":"Cô gái mù trên thuyền hoa","cn":"","aliases":[],"gioiTinh":"nu","theLuc":[{"ten":"Yêu linh tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"","trangThai":"song","blurb":"Thiếu nữ Yêu linh bị mù, gảy đàn bi thương trên thuyền hoa ở Hồng thành, cô độc giữa đời và cảm nhận được bóng Vương Lâm tan vào đêm.","vaiTro":"Nhân vật phụ","tinhCach":[{"text":"Cô độc, thanh khiết như đóa sen trong bùn không nhiễm bụi","chuong":"@c0534"}],"tabs":{"diem":[{"text":"Bị mù, trước mắt chỉ là một khoảng đen kịt bất kể ngày đêm","chuong":"@c0534"},{"text":"Có linh tính cảm nhận được hình bóng cô độc của Vương Lâm trong bóng tối","chuong":"@c0534"}],"kinhLich":[{"chuong":"@c0534","importance":"normal","tieuDe":"Tiếng đàn trên thuyền hoa","text":"Gảy đàn bi thương trên thuyền hoa giữa đám thanh niên uống rượu; khi thuyền đi xa, nàng như có linh tính khẽ xoay nhìn về con đường ven sông tối đen, mơ hồ thấy một hình bóng cô độc đang tan biến, rồi gảy thêm một tiếng đàn — lộ ra nàng bị mù, tiếng đàn vang nhưng không ai thật sự lắng nghe."}],"tuViMoc":[],"tuVi":"","nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Người dưng gặp thoáng qua","ghiChu":"Vương Lâm đi ngang nghe nàng đánh đàn, chạnh nhớ Uyển Nhi; nàng cảm nhận được bóng hắn tan vào đêm."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0534"]},{"id":"minh-huyen","name":"Minh Huyên","cn":"","aliases":[],"gioiTinh":"nu","theLuc":[],"canhGioiCaoNhat":"khong-ro","trangThai":"song","blurb":"Nữ tử đánh đàn trên hoa thuyền ở Hồng thành; tiếng đàn bi thương của nàng khiến Vương Lâm cảm ngộ về đạo, nhưng nàng lại bị một khách nhân giọng bình thản khống chế.","vaiTro":"Nữ tử đánh đàn hoa thuyền","tinhCach":[{"text":"U buồn, gửi nỗi bi thương vào tiếng đàn","chuong":"@c0535"}],"tabs":{"diem":[{"text":"Tiếng đàn bi thương xuyên cả phong ấn trí nhớ, khiến người nghe cảm động","chuong":"@c0535"},{"text":"Bị một thế lực bí ẩn khống chế, không thể chống cự mệnh lệnh của khách nhân","chuong":"@c0535"}],"kinhLich":[{"chuong":"@c0535","importance":"normal","tieuDe":"Tiếng đàn bên hoa thuyền","text":"Ngày ngày đánh đàn trên hoa thuyền qua lại bờ sông Hồng thành, Minh Huyên không hay có người chăm chú nghe suốt ba ngày; tiếng đàn càng lúc càng bi thương. Khi hoa thuyền xa dần, nàng quay đầu nhìn theo bóng nam tử rời đi, rồi bị một khách nhân giọng bình thản gọi đúng tên và lạnh lùng buộc đổi bài khác vì bài vừa rồi quá buồn; nàng ngọc thủ run rẩy, không thể cự tuyệt cái giọng đại biểu cho trời cao đó."}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Người chăm chú nghe tiếng đàn của nàng ba ngày; nàng quay đầu nhìn theo khi hắn rời đi","ghiChu":"@c0535"},{"ten":"Khách nhân (bên Minh Huyên)","tag":"doi-thu","quanHe":"Kẻ giọng bình thản khống chế nàng, buộc nàng đổi bài đàn; nàng không thể chống cự","ghiChu":"@c0535"}],"tuiDo":{}},"nguon":["@c0535"]},{"id":"khach-nhan-minh-huyen","name":"Khách nhân (bên Minh Huyên)","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[],"canhGioiCaoNhat":"khong-ro","trangThai":"khong-ro","blurb":"Kẻ giọng nói bình thản lạnh lùng bên Minh Huyên, ra lệnh nàng đổi bài đàn mà nàng không thể chống cự; chưa lộ tên lẫn diện mạo.","vaiTro":"Thế lực bí ẩn khống chế Minh Huyên","tinhCach":[{"text":"Lạnh lùng, giọng nói uy áp như đại biểu trời cao","chuong":"@c0535"}],"tabs":{"diem":[{"text":"Giọng nói khiến Minh Huyên không thể cự tuyệt, như đại biểu cho trời cao","chuong":"@c0535"}],"kinhLich":[{"chuong":"@c0535","importance":"minor","tieuDe":"Buộc Minh Huyên đổi bài","text":"Khi Vương Lâm rời đi, một giọng nói bình thản bên cạnh Minh Huyên gọi đúng tên nàng và lạnh lùng bảo đổi bài khác vì b��i vừa rồi quá buồn, khiến tiếng đàn dừng lại."}],"tuViMoc":[],"nhanMach":[{"ten":"Minh Huyên","tag":"khac","quanHe":"Khống chế Minh Huyên, ra lệnh nàng đổi bài đàn","ghiChu":"@c0535"}],"tuiDo":{}},"nguon":["@c0535"]},{"id":"mac-le-hai","name":"Mạc Lệ Hải","tabs":{"kinhLich":[{"chuong":"@c0536","importance":"normal","tieuDe":"Đưa Vương Lâm vào Hồng lao","text":"Đang tu vi Anh Biến hậu kỳ đại viên mãn, dẫn Vương Lâm tới Hồng lao ở Hồng thành, trả giá ba tầng đầu công pháp Thập Băng Quyền Ý cho nam tử họ Hứa để đổi một suất tu luyện, giao Vương Lâm cho Hứa rồi rời đi với lời chúc tu luyện thành công."},{"chuong":"@c0537","importance":"normal","tieuDe":"Che giấu và tiến cử Vương Lâm","text":"Mạc Lệ Hải vận yêu lực che giấu khí tức Vương Lâm khỏi Đế Kiếm, đưa hắn xuống động bế quan dưới giả sơn. Tiết lộ quy chế đại hội Yêu Tướng cho phép người thất bại đề cử người ngoài thay thế, hẹn tiến cử Vương Lâm; rồi dẫn hắn viếng phó soái Huyền Thành."},{"chuong":"@c0538","importance":"normal","tieuDe":"Tranh chức phó soái nhờ Vương Lâm","text":"Dẫn Vương Lâm vào soái phủ bái kiến phó soái Huyền Thành để tranh chức phó soái. Khai nắm chắc bốn phần, thêm Vương Lâm thì lên chín phần. Sau khi chứng kiến uy lực Vương Lâm trấn áp phó soái, lần đầu xem hắn là người vượt đẳng cấp, chân thành ôm quyền nhờ trợ giúp trong đại hội Yêu Tướng và mời rượu quý đã chôn hơn năm trăm năm."},{"chuong":"@c0542","importance":"normal","tieuDe":"Bại trận trước Mặc Phi","text":"Chờ Vương Lâm xuất quan ba ngày với sắc mặt tái nhợt, lo lắng vì ngày Yêu Tướng tranh đoạt cận kề. Báo tin mình đã bại trận trước Mặc Phi: dùng Thập Băng Quyền Ý bị đỡ hết, Yêu Hải Bách Lãng bị Chuyển Luân thuật làm quay ngược về."},{"chuong":"@c0543","importance":"normal","tieuDe":"Giao phó toàn cục cho Vương Lâm","text":"Đêm trước trận chiến Yêu Tướng, Mạc Lệ Hải tiết lộ với Vương Lâm rằng ngoài Thập Băng Quyền Ý và Yêu Hải Bách Lãng, hắn còn tuyệt chiêu Yêu Nhiên do Đế Quân đích thân truyền. Vì đã thua Mặc Phi nên theo giao ước hắn không được tham chiến hôm sau, việc đoạt ngôi Phó Soái hoàn toàn trông cậy vào Vương Lâm. Hắn vái sâu từ biệt, bóng dáng hiu quạnh rời đi."},{"chuong":"@c0545","importance":"normal","tieuDe":"Đặt hy vọng vào Vương Lâm","text":"Mỗi ngày đến Đế Đô quan sát các trận tranh đoạt Yêu Tướng, dùng thần thông ghi lại những đối thủ có thể uy hiếp Vương Lâm rồi đưa về cho hắn xem, đặt toàn bộ hy vọng lên Vương Lâm."},{"chuong":"@c0546","importance":"normal","tieuDe":"Khuyên Vương Lâm chịu thua vòng gõ trống","text":"Khi nghe luật gõ Chiến Yêu Cổ, Mạc Lệ Hải rúng động, sắc mặt tái nhợt; sau khuyên Vương Lâm chịu thua vòng này vì cho rằng khó vượt nổi thành tích Mặc Phi."},{"chuong":"@c0548","importance":"normal","tieuDe":"Hồi ức dậy sóng trước trống niệm","text":"Khi tiếng trống truyền niệm của Vương Lâm lan khắp Thiên Yêu thành, Mạc Lệ Hải lộ hồi ức, chìm vào cộng hưởng tâm linh cùng cả khán đài."}],"nhanMach":[{"ten":"Nam tử họ Hứa","tag":"dong-minh","quanHe":"Người phụ trách Hồng lao mà Mạc Lệ Hải trả ba tầng Thập Băng Quyền Ý để gửi Vương Lâm vào tu luyện.","ghiChu":"@c0536."},{"ten":"Phó soái Huyền Thành","tag":"dong-minh","quanHe":"Đưa Vương Lâm tới phủ phó soái Huyền Thành, được cho mời vào đình viện","ghiChu":"@c0537"},{"ten":"Phó soái Huyền Thành","tag":"doi-thu","quanHe":"Đối thủ tranh chức phó soái","ghiChu":"Mạc Lệ Hải dẫn Vương Lâm tới bái kiến để tranh chức phó soái Thiên Yêu Thành."},{"ten":"Mặc Phi","tag":"doi-thu","quanHe":"Đối thủ Yêu Tướng đã đánh bại Mạc Lệ Hải bằng Chuyển Luân thuật","ghiChu":"@c0542"},{"ten":"Mặc Phi","tag":"doi-thu","quanHe":"Thua trận trước Mặc Phi nên mất tư cách tham chiến tranh Phó Soái","ghiChu":"@c0543"},{"ten":"Thạch Tiêu","tag":"doi-thu","quanHe":"Ba trăm năm trước từng để lại vết sẹo trên mặt Thạch Tiêu","ghiChu":"@c0543"},{"ten":"Yêu Đế","tag":"khac","quanHe":"Được Đế Quân đích thân truyền thần thông Yêu Nhiên khi thành Yêu Tướng","ghiChu":"@c0543"}],"tuiDo":{},"tuViMoc":[]},"nguon":["@c0536","@c0537","@c0538","@c0542","@c0543","@c0545","@c0546","@c0548"]},{"id":"nam-tu-ho-hua-hong-lao","name":"Nam tử họ Hứa","aliases":["Nam tử áo xám (Hồng lao)","Hứa (Hồng lao)","Họ Hứa (Hồng Lao)"],"gioiTinh":"nam","theLuc":[{"ten":"Hồng lao","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Anh Biến hậu kỳ đại viên mãn","trangThai":"song","blurb":"Một trong mười người phụ trách Hồng lao, dáng to béo sắc mặt âm trầm, tu luyện sát lục yêu đạo dùng tâm hóa yêu.","vaiTro":"Người tiếp nhận và chỉ điểm sát tâm cho Vương Lâm trong Hồng lao","tinhCach":[{"text":"Âm trầm, ẩn nhẫn; sát tâm sâu kín như kiếm chưa rời vỏ — không tỏa sát khí mà khiến đối phương rúng động nguyên thần.","chuong":"@c0536"}],"tabs":{"diem":[{"text":"Sống ở Hồng lao mấy trăm năm, là người duy nhất trong mười người nơi đây tu sát lục yêu đạo dùng tâm hóa yêu.","chuong":"@c0536"},{"text":"Bị hạn chế không rời được Hồng lao, ôm mối thù muốn giết yêu tướng Thạch Tiễn.","chuong":"@c0536"}],"kinhLich":[{"chuong":"@c0536","importance":"normal","tieuDe":"Tiếp nhận Vương Lâm vào Hồng lao","text":"Ra đón Mạc Lệ Hải và Vương Lâm với tu vi Anh Biến hậu kỳ đại viên mãn, nhận ba tầng đầu Thập Băng Quyền Ý làm giá, dẫn Vương Lâm xuống lồng giam dưới lòng đất và cho một tháng tu luyện."},{"chuong":"@c0536","importance":"normal","tieuDe":"Chỉ điểm sát tâm, giao ước Thạch Tiễn","text":"Phô bày sát tâm khiến Vương Lâm lông tóc dựng ngược, ra điều kiện đưa Vương Lâm tới nơi cảm nh���n sát lục chân chính để đổi việc Vương Lâm âm thầm giết yêu tướng Thạch Tiễn; tiết lộ bí mật thế giới máu tầng đáy nuôi yêu kiếm của yêu đế và dặn không được tiết lộ kể cả với Mạc Lệ Hải."},{"chuong":"@c0537","importance":"normal","tieuDe":"Dẫn Vương Lâm trốn khỏi Hồng Lao","text":"Đợi Vương Lâm tại bậc thang cao nhất Hồng Lao, than “lớn chuyện rồi”, dẫn hắn theo đường khác trốn qua một khe nứt tường nhà dân Hồng Thành, dặn đừng quên giao hẹn; hối tiếc đã đưa người dẫn Đế Kiếm tới."}],"tuViMoc":[{"chuong":"@c0536","canhGioi":"Anh Biến hậu kỳ đại viên mãn","text":"Tu vi ngang Mạc Lệ Hải khi ra mặt tại Hồng lao.","importance":"minor"}],"nhanMach":[{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Người hắn tiếp nhận và chỉ điểm sát tâm, ra điều kiện nhờ giết Thạch Tiễn.","ghiChu":"@c0536."},{"ten":"Mạc Lệ Hải","tag":"dong-minh","quanHe":"Người gửi Vương Lâm vào Hồng lao, trả ba tầng Thập Băng Quyền Ý.","ghiChu":"@c0536."},{"ten":"Thạch Tiễn","tag":"doi-thu","quanHe":"Yêu tướng hắn thù hận, muốn nhờ Vương Lâm âm thầm giết.","ghiChu":"@c0536."},{"ten":"Vương Lâm","tag":"khac","quanHe":"Giúp Vương Lâm trốn khỏi Hồng Lao; có giao hẹn chưa tiết lộ","ghiChu":"@c0537"}],"tuiDo":{}},"nguon":["@c0536","@c0537"]},{"id":"thanh-suong","name":"Thanh Sương","gioiTinh":"khong-ro","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"khong-ro","blurb":"Danh tính thần bí tự xưng trong thanh âm mà Vương Lâm nghe được khi đắc kim phù ấn tại Yêu Linh chi địa.","vaiTro":"Nhân vật bí ẩn","tinhCach":[],"tabs":{"diem":[{"text":"Thanh âm thần bí vọng ra giữa cảnh huyễn, chỉ tự xưng “Ta là Thanh Sương” mà chưa lộ thân phận.","chuong":"@c0521"}],"kinhLich":[{"chuong":"@c0521","importance":"normal","tieuDe":"Thanh âm Thanh Sương","text":"Khi Vương Lâm rơi vào trạng thái huyễn hoặc lúc đắc kim phù ấn, hắn nghe được tiếng nam nữ thì thào, trong đó vọng ra câu tự xưng “Ta là Thanh Sương”. Danh tính này gắn với lực lượng thần bí ban kim phù ấn ở Yêu Linh chi địa, có thể liên quan tới động phủ Tiên đế."}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Người nghe được thanh âm tự xưng của Thanh Sương khi đắc kim phù ấn","ghiChu":""}],"tuiDo":{}},"nguon":["@c0521"]},{"id":"thanh-nien-toc-den-the-gioi-huyet-sac","name":"Thanh niên tóc đen (thế giới huyết sắc)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"không-ro","trangThai":"song","blurb":"Tu sĩ duy nhất trong thế giới máu của Hồng Lao chống được sát lục khí của Vương Lâm, thân không tan; tướng mạo giống hệt Yêu Tương Mặc Phi.","vaiTro":"Người sống sót bí ẩn trong thế giới huyết sắc","tinhCach":[{"text":"Kiên cường nhưng cũng có lúc yếu ớt kêu cứu","chuong":"@c0537"}],"tabs":{"diem":[{"text":"Là tu sĩ duy nhất trong thế giới huyết sắc không bị sát lục khí của Vương Lâm xé tan, ngoài thân có một tầng huyết sát vụ","chuong":"@c0537"},{"text":"Tướng mạo giống y hệt Yêu Tương Mặc Phi của Hỏa Yêu Quận — ngụ ý mối liên hệ phân thân chưa rõ","chuong":"@c0537"}],"kinhLich":[{"chuong":"@c0537","importance":"normal","tieuDe":"Sống sót trong thế giới huyết sắc","text":"Khi sát lục khí của Vương Lâm bạo phát xé tan mọi tu sĩ trong các hồ máu, chỉ mình hắn chống được, thân không tan. Khi Đế Kiếm phá hư không đuổi theo Vương Lâm, hắn yếu ớt kêu “Cứu ta với” nhưng bị bỏ mặc."}],"tuViMoc":[],"tuVi":"Chưa rõ cảnh giới.","nhanMach":[{"ten":"Mặc Phi","tag":"khac","quanHe":"Tướng mạo giống y hệt nhau, ngụ ý mối liên hệ phân thân/thế thân chưa giải thích","ghiChu":"@c0537"}],"tuiDo":{}},"nguon":["@c0537"]},{"id":"thach-tieu-yeu-tuong","name":"Thạch Tiêu","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thiên Yêu Quận","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không-ro","trangThai":"song","blurb":"Yêu Tướng ở trong phủ Yêu Soái, kinh hãi khi Đế Kiếm tự bay ra trận nhãn.","vaiTro":"Yêu Tướng Thiên Yêu Quận","tinhCach":[],"tabs":{"diem":[{"text":"Kinh hãi khi Đế Kiếm tự rời trận nhãn, gọi việc này có quỷ dị","chuong":"@c0537"}],"kinhLich":[{"chuong":"@c0537","importance":"normal","tieuDe":"Kinh động trước Đế Kiếm rời trận","text":"Ở trong phủ Yêu Soái, kinh hãi khi Đế Kiếm tự bay ra khỏi trận nhãn, cho rằng việc này có quỷ dị."},{"chuong":"@c0543","importance":"normal","tieuDe":"Hạ Mộ Vân, giết trợ giúp","text":"Đến nhịp thở thứ năm sau khi Mộ Vân được chỉ định, Thạch Tiêu ra khiêu chiến. Hắn dùng quang đồ hình thoi cắn nát năm đạo khí xanh lục của Mộ Vân rồi ấn nổ. Khi Thiên Khôi Công Nhân — trợ giúp của Mộ Vân — xông lên, Thạch Tiêu dùng hình nón dung yêu lực đâm vỡ thân y thành máu thịt, năm đường chỉ đen từ máu thịt nhập vào người hắn."},{"chuong":"@c0543","importance":"normal","tieuDe":"Khiêu chiến rồi hăm dọa Vương Lâm","text":"Thạch Tiêu thách Mạc Lệ Hải nhưng bị từ chối, liền chuyển sang khiêu chiến Vương Lâm. Vương Lâm cự tuyệt; giáp vàng buộc Thạch Tiêu lui vì đã thắng không được khiêu chiến tiếp. Lúc đi ngang, hắn hạ giọng dọa sẽ giết Vương Lâm cho hả giận."},{"chuong":"@c0546","importance":"normal","tieuDe":"Nhẩm tính cùng Trần Đào","text":"Đứng trong đám Yêu Tướng, hỏi Trần Đào gõ được mấy tiếng; lộ sát khí khi nhìn Mặc Phi."},{"chuong":"@c0548","importance":"normal","tieuDe":"Sát khí dao động trước trống Vương Lâm","text":"Khi Vương Lâm tẩy tủy bằng tiếng trống, Thạch Tiêu nhìn hắn với sát khí ngày càng đậm, nhiều lần giơ tay nhưng do dự rồi thả xuống; tới tiếng trống truyền niệm thì cũng lộ một tia bi thương."}],"tuViMoc":[],"tuVi":"Chưa rõ cảnh giới.","nhanMach":[{"ten":"Tôn Đào","tag":"dong-minh","quanHe":"Ở cạnh nhau khi chứng kiến Đế Kiếm rời trận nhãn","ghiChu":"@c0537"},{"ten":"Mạc Lệ Hải","tag":"doi-thu","quanHe":"Bị Mạc Lệ Hải để lại vết sẹo trên mặt ba trăm năm trước","ghiChu":"@c0543"},{"ten":"Mộ Vân","tag":"doi-thu","quanHe":"Hạ gục Mộ Vân ở trận đầu","ghiChu":"@c0543"},{"ten":"Thiên Khôi Công Nhân","tag":"doi-thu","quanHe":"Giết chết, đâm vỡ thân thành máu thịt","ghiChu":"@c0543"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Khiêu chiến rồi hăm dọa sẽ giết Vương Lâm","ghiChu":"@c0543"},{"ten":"Trần Đào","tag":"dong-minh","quanHe":"Hỏi Trần Đào ước lượng có thể gõ được mấy tiếng","ghiChu":"@c0546"}],"tuiDo":{}},"nguon":["@c0537","@c0543","@c0546","@c0548"]},{"id":"ton-dao-yeu-tuong","name":"Tôn Đào","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thiên Yêu Quận","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không-ro","trangThai":"song","blurb":"Người đứng cạnh Thạch Tiêu, sắc mặt ngưng trọng khi nhìn ngân quang Đế Kiếm.","vaiTro":"Nhân vật phe Thiên Yêu Quận","tinhCach":[],"tabs":{"diem":[{"text":"Sắc mặt ngưng trọng, kinh hãi nhìn ngân quang Đế Kiếm bay ra","chuong":"@c0537"}],"kinhLich":[{"chuong":"@c0537","importance":"normal","tieuDe":"Chứng kiến Đế Kiếm rời trận","text":"Đứng cạnh Thạch Tiêu, sắc mặt ngưng trọng kinh hãi nhìn ngân quang Đế Kiếm tự rời trận nhãn."}],"tuViMoc":[],"tuVi":"Chưa rõ cảnh giới.","nhanMach":[{"ten":"Thạch Tiêu","tag":"dong-minh","quanHe":"Ở cạnh nhau khi chứng kiến Đế Kiếm rời trận nhãn","ghiChu":"@c0537"}],"tuiDo":{}},"nguon":["@c0537"]},{"id":"thanh-nien-ao-xanh-hoa-thuyen","name":"Thanh niên áo xanh (trên họa thuyền)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"không-ro","trangThai":"song","blurb":"Thanh niên khoảng 27-28 tuổi mang yêu lực mơ hồ, yêu cầu nữ tử đàn “tiếng đàn chân chính” và nâng rượu chào Vương Lâm.","vaiTro":"Nhân vật bí ẩn bên họa thuyền","tinhCach":[{"text":"Tao nhã, thích thưởng nhạc, tinh tế nhận ra người trên bờ","chuong":"@c0537"}],"tabs":{"diem":[{"text":"Mang yêu lực mơ hồ, gọi Vương Lâm là “một tiểu tử rất thú vị”","chuong":"@c0537"}],"kinhLich":[{"chuong":"@c0537","importance":"normal","tieuDe":"Đối ẩm với Vương Lâm bên sông","text":"Trên họa thuyền, yêu cầu nữ tử mắt đen đàn “tiếng đàn chân chính”; cảm nhận có người trên bờ, nâng rượu đối ẩm từ xa với Vương Lâm, nhận xét hắn là “tiểu tử rất thú vị”."}],"tuViMoc":[],"tuVi":"Mang yêu lực, cảnh giới chưa rõ.","nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Đối ẩm từ xa bên sông, nâng rượu chào nhau","ghiChu":"@c0537"},{"ten":"Nữ tử đánh đàn (mắt đen)","tag":"khac","quanHe":"Yêu cầu nàng đàn tiếng đàn chân chính trên họa thuyền","ghiChu":"@c0537"}],"tuiDo":{}},"nguon":["@c0537"]},{"id":"nguoi-hoang-bao-quy-phi-lau","name":"Người mặc hoàng bào (Quý Phi Lâu)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"không-ro","trangThai":"song","blurb":"Người mặc hoàng bào trong Quý Phi Lâu, thái độ thân mật bỡn cợt với Đế Kiếm khi nó nổi giận bay ra.","vaiTro":"Nhân vật bí ẩn trong hoàng cung","tinhCach":[],"tabs":{"diem":[{"text":"Cười hỏi “Đế Kiếm có chuyện gì vui vậy” khi thấy ngân quang bay qua — thái độ thân mật khác thường","chuong":"@c0537"}],"kinhLich":[{"chuong":"@c0537","importance":"normal","tieuDe":"Quan sát Đế Kiếm tại Quý Phi Lâu","text":"Trong Quý Phi Lâu, nhìn ngân quang Đế Kiếm bay qua, cười hỏi Đế Kiếm có chuyện gì vui; phía sau có nữ tử xinh đẹp đứng hạ giọng nói."}],"tuViMoc":[],"tuVi":"Chưa rõ cảnh giới.","nhanMach":[{"ten":"Nữ tử xinh đẹp (Quý Phi Lâu)","tag":"khac","quanHe":"Nữ tử đứng sau lưng, hạ giọng nói chuyện","ghiChu":"@c0537"}],"tuiDo":{}},"nguon":["@c0537"]},{"id":"nu-tu-xinh-dep-quy-phi-lau","name":"Nữ tử xinh đẹp (Quý Phi Lâu)","cn":"","aliases":[],"gioiTinh":"nu","theLuc":[],"canhGioiCaoNhat":"không-ro","trangThai":"song","blurb":"Nữ tử xinh đẹp đứng sau người mặc hoàng bào trong Quý Phi Lâu, hạ giọng nói khi Đế Kiếm bay qua.","vaiTro":"Nhân vật phụ trong hoàng cung","tinhCach":[],"tabs":{"diem":[{"text":"Đứng sau người hoàng bào, hạ giọng nói khi thấy ngân quang Đế Kiếm","chuong":"@c0537"}],"kinhLich":[{"chuong":"@c0537","importance":"normal","tieuDe":"Quan sát Đế Kiếm tại Quý Phi Lâu","text":"Đứng sau người mặc hoàng bào trong Quý Phi Lâu, hạ giọng nói khi ngân quang Đế Kiếm bay qua."}],"tuViMoc":[],"tuVi":"Chưa rõ cảnh giới.","nhanMach":[{"ten":"Người mặc hoàng bào (Quý Phi Lâu)","tag":"khac","quanHe":"Đứng sau lưng, hạ giọng nói chuyện","ghiChu":"@c0537"}],"tuiDo":{}},"nguon":["@c0537"]},{"id":"trung-nien-ao-bao-trang-phu-yeu-soai","name":"Trung niên áo bào trắng (phủ Yêu Soái)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thiên Yêu Quận","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không-ro","trangThai":"song","blurb":"Trung niên áo bào trắng trong phủ Yêu Soái, kinh ngạc trước việc Đế Kiếm phẫn nộ rời trận nhãn.","vaiTro":"Nhân vật cấp cao phủ Yêu Soái","tinhCach":[],"tabs":{"diem":[{"text":"Chắp tay sau lưng, kinh ngạc tự hỏi ai khiến Đế Kiếm phẫn nộ ra khỏi trận nhãn","chuong":"@c0537"}],"kinhLich":[{"chuong":"@c0537","importance":"normal","tieuDe":"Kinh ngạc trước Đế Kiếm rời trận","text":"Trong phủ Yêu Soái, chắp tay sau lưng kinh ngạc, tự hỏi là ai khiến Đế Kiếm phẫn nộ ra khỏi trận nhãn."}],"tuViMoc":[],"tuVi":"Chưa rõ cảnh giới.","nhanMach":[],"tuiDo":{}},"nguon":["@c0537"]},{"id":"pho-soai-huyen-thanh","name":"Phó soái Huyền Thành","cn":"","aliases":["Nam tử áo tím"],"gioiTinh":"nam","theLuc":[{"ten":"Thiên Yêu Quận","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không-ro","trangThai":"song","blurb":"Chủ Huyền Thành soái phủ, giao tình tốt với Yêu Đế; cho mời Mạc Lệ Hải và Vương Lâm vào đình viện.","vaiTro":"Phó soái Huyền Thành, Thiên Yêu Quận","tinhCach":[],"tabs":{"diem":[{"text":"Giao tình tốt với Yêu Đế, chủ phủ phó soái Huyền Thành","chuong":"@c0537"}],"kinhLich":[{"chuong":"@c0537","importance":"normal","tieuDe":"Tiếp Mạc Lệ Hải và Vương Lâm","text":"Cho mời Mạc Lệ Hải và Vương Lâm vào đình viện trong phủ phó soái Huyền Thành."},{"chuong":"@c0538","importance":"normal","tieuDe":"Bị Vương Lâm trấn áp nội thương","text":"Tiếp Mạc Lệ Hải và Vương Lâm tại soái phủ, coi thường Vương Lâm chỉ là tùy tùng Anh Biến Hậu Kỳ. Thách Vương Lâm thi triển thần thông mạnh nhất, nếu làm hắn động dung thì công nhận tư cách. Bị hai nghìn đạo sát lục chi khí phá vỡ mãnh hổ yêu khí và màn yêu giáp bảy tấc, liên tục lui giẫm nát hoa quý, đành công nhận Vương Lâm có tư cách. Sau khi hai người đi, phun một ngụm máu tươi, hạ lệnh ba tháng không tiếp ai rồi bế quan."}],"tuViMoc":[{"chuong":"@c0538","canhGioi":"Tương đương Vấn Đỉnh Sơ Kỳ đỉnh phong","text":"Bản lãnh đạt đỉnh Sơ Kỳ và sắp đột phá, nhưng còn cách Vấn Đỉnh Trung Kỳ rất xa.","importance":"minor"}],"tuVi":"Chưa rõ cảnh giới.","nhanMach":[{"ten":"Mạc Lệ Hải","tag":"dong-minh","quanHe":"Tiếp Mạc Lệ Hải và Vương Lâm vào đình viện phủ phó soái","ghiChu":"@c0537"},{"ten":"Mạc Lệ Hải","tag":"doi-thu","quanHe":"Đối thủ tranh chức phó soái","ghiChu":"Mạc Lệ Hải tới bái kiến để tranh chức phó soái."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Bị Vương Lâm trấn áp","ghiChu":"Coi thường rồi bị một chiêu sát lục chi khí ép lui, công nhận tư cách và phải bế quan."},{"ten":"Yêu đế","tag":"dong-minh","quanHe":"Quan hệ tốt với Yêu Đế","ghiChu":"Quan hệ tốt với Yêu Đế là lý do chịu tiếp Mạc Lệ Hải."}],"tuiDo":{}},"nguon":["@c0537","@c0538"]},{"id":"nguoi-hoang-bao-de-do-kiem-cac","name":"Người mặc hoàng bào (Đế Đô Kiếm Các)","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[{"ten":"Yêu tộc Thiên Yêu Thành","trangThai":"gan-bo"}],"canhGioiCaoNhat":"khong-ro","trangThai":"song","blurb":"Nhân vật bí ẩn chỉ thấy lưng tại Đế Đô Kiếm Các, trấn áp Đế Kiếm trong trận pháp, cấm nó tới Hồng Lao phá hoại.","vaiTro":"Người trấn giữ Đế Kiếm tại Đế Đô Kiếm Các.","tinhCach":[],"tabs":{"diem":[],"kinhLich":[{"chuong":"@c0538","importance":"normal","tieuDe":"Trấn áp Đế Kiếm","text":"Tại Đế Đô Kiếm Các ở trung tâm Thiên Yêu Thành, trấn áp Đế Kiếm trong trận pháp, cấm nó tới Hồng Lao phá hoại nữa, dọa đưa tới Long Đàm. Sau khi Đế Kiếm rút, thế giới huyết sắc tầng thấp nhất của Hồng Lao dần khôi phục."}],"tuViMoc":[],"nhanMach":[],"tuiDo":{}},"nguon":["@c0538"]},{"id":"nam-tu-toc-den-huyet-dam","name":"Nam tử tóc đen (trong huyết đàm)","gioiTinh":"nam","aliases":[],"theLuc":[],"canhGioiCaoNhat":"không-ro","trangThai":"khong-ro","blurb":"Kẻ tu sát trong huyết đàm vô tận, quyết thoát ra như người từng thoát trước đó.","vaiTro":"Nhân vật phụ thoáng qua trong huyết đàm","tinhCach":[{"text":"Kiên định, lấy “hắn” (kẻ từng thoát huyết đàm) làm hình mẫu để noi theo","chuong":"@c0539"}],"tabs":{"diem":[{"text":"Để sát niệm từ huyết đàm nhập thân, sát khí ngày càng đậm, mắt đỏ như máu","chuong":"@c0539"}],"kinhLich":[{"chuong":"@c0539","importance":"normal","tieuDe":"Tự bạo thân làm thương ngân long","text":"Trong huyết đàm vô tận, nam tử tóc đen khoanh chân để sát niệm nhập thân, ra tay cực ác như huyết long; sau một ngày chỉ còn mình hắn đứng vững. Hắn lao về phía lối ra; khi Ngân long Đế Kiếm chụp móng vuốt tới, hắn mỉm cười hô “Bạo!”, toàn thân nổ tung tạo màn sương máu trăm trượng đánh thương tay ngân long. Sau đó hắn sống lại trong huyết đàm và bị ngân long phun kiếm khí giết đi sống lại nhiều lần."}],"tuViMoc":[],"nhanMach":[],"tuiDo":{}},"nguon":["@c0539"]},{"id":"nguoi-ao-den-sat-thu-tham-thinh","name":"Người áo đen (sát thủ thám thính)","gioiTinh":"nam","aliases":[],"theLuc":[{"ten":"Yêu Linh","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Hóa Thần hậu kỳ","trangThai":"tu-vong","blurb":"Người của Yêu Linh, bản lãnh Hóa Thần hậu kỳ, theo lệnh một Yêu Tướng tới thử Vương Lâm rồi bị giết.","vaiTro":"Sát thủ thám thính thoáng qua","tinhCach":[{"text":"Khinh miệt, ngạo mạn — vừa tới đã đòi ra tay","chuong":"@c0539"}],"tabs":{"diem":[],"kinhLich":[{"chuong":"@c0539","importance":"normal","tieuDe":"Bị Tịch Diệt Chỉ giết","text":"Đứng cách trăm trượng với phi kiếm mảnh như rắn nước quấn thân, hắn khinh miệt hỏi Vương Lâm có phải phó tướng Mạc Lệ Hải rồi đòi ra tay. Vương Lâm không thèm nhìn, điểm Tịch Diệt Chỉ phóng đạo hắc khí làm phi kiếm vỡ tan như chẻ tre, đâm trúng ngực khiến hắn phun sương máu mà chết, hối hận trong mắt; khí xám từ thất khiếu hắn bị Vương Lâm thu vào tay phải."}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Tới thám thính thử Vương Lâm rồi bị giết","ghiChu":""}],"tuiDo":{}},"nguon":["@c0539"]},{"id":"nam-tu-lon-tuoi-ao-den-dau-linh-sat-thu","name":"Nam tử lớn tuổi áo đen (đầu lĩnh sát thủ)","gioiTinh":"nam","aliases":[],"theLuc":[{"ten":"Nhóm sát thủ của lão tổ","trangThai":"gan-bo"}],"trangThai":"song","blurb":"Đầu lĩnh nhóm sát thủ trên tửu lầu, điềm tĩnh đánh giá tu vi Vương Lâm và nhận lệnh lão tổ bắt người.","vaiTro":"Chỉ huy nhóm sát thủ truy bắt Vương Lâm; cuối chương kinh hãi nhận ra ánh mắt Sát Lục Đạo.","tinhCach":[{"text":"Điềm tĩnh, lạnh lùng đánh giá đối thủ","chuong":"@c0540"},{"text":"Biến sắc dữ dội khi nhận ra Sát Lục Đạo","chuong":"@c0540"}],"tabs":{"diem":[],"kinhLich":[{"chuong":"@c0540","importance":"normal","tieuDe":"Điều phối truy bắt Vương Lâm","text":"Cùng số hai quan sát Vương Lâm trên tầng hai tửu lầu, đánh giá tu vi đối thủ đạt Anh Biến Kỳ và lần lượt phái sát thủ. Khi thấy ánh mắt Sát Lục Đạo phóng sát khí, hắn đứng bật dậy làm vỡ bàn, kinh hãi kêu lên đây là Sát Lục Đạo."}],"tuViMoc":[],"tuVi":"Tu vi cao, khí tức tiên yêu dung hợp; chưa rõ cảnh giới cụ thể.","nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Mục tiêu truy bắt theo lệnh lão tổ","gap":"@c0540"},{"ten":"Sát thủ số hai (thanh niên áo đen)","tag":"dong-minh","quanHe":"Thuộc hạ cùng nhóm sát thủ","gap":"@c0540"}],"tuiDo":{}},"nguon":["@c0540"]},{"id":"sat-thu-so-hai-thanh-nien-ao-den","name":"Sát thủ số hai (thanh niên áo đen)","gioiTinh":"nam","aliases":["Số hai"],"theLuc":[{"ten":"Nhóm sát thủ của lão tổ","trangThai":"gan-bo"}],"trangThai":"song","blurb":"Sát thủ bản lãnh tương đương Anh Biến Hậu Kỳ gần viên mãn, thân tỏa khí tức tiên yêu dung hợp.","vaiTro":"Đích thân ra trận đối đầu Vương Lâm, giải được Tịch Diệt Nhất Chỉ nhưng bị Sát Lục Đạo áp chế suýt sụp đổ tâm thần.","tinhCach":[{"text":"Tự tin, hiếu chiến, ung dung khi bước vào trận","chuong":"@c0540"}],"tabs":{"diem":[],"kinhLich":[{"chuong":"@c0540","importance":"normal","tieuDe":"Giải Tịch Diệt Chỉ rồi bị Sát Lục Đạo áp chế","text":"Tự xưng là số hai, đích thân ung dung bước nghìn trượng tới đối đầu Vương Lâm. Hắn tạo hơn trăm quang cầu yêu lực liên tiếp chống đỡ, hao tổn lớn mới tiêu tan được Tịch Diệt Nhất Chỉ, còn lại tám quang cầu. Khi Vương Lâm quay đầu phóng Sát Lục Đạo, hắn như bị sét đánh, thân cứng đờ run rẩy, tâm thần suýt sụp đổ như đối mặt cái chết."}],"tuViMoc":[{"chuong":"@c0540","canhGioi":"Anh Biến Hậu Kỳ (tương đương)","text":"Bản lãnh tương đương Anh Biến Hậu Kỳ, gần viên mãn; thân tỏa yêu lực kèm một tia tiên lực dung hợp kỳ dị.","importance":"minor"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối thủ trực tiếp, bị Sát Lục Đạo áp chế","gap":"@c0540"},{"ten":"Nam tử lớn tuổi áo đen (đầu lĩnh sát thủ)","tag":"dong-minh","quanHe":"Đầu lĩnh cùng nhóm sát thủ","gap":"@c0540"}],"tuiDo":{}},"nguon":["@c0540"]},{"id":"sat-thu-so-bon-trung-nien-ao-den","name":"Sát thủ số bốn (trung niên mắt sáng)","gioiTinh":"nam","aliases":["Số bốn"],"theLuc":[{"ten":"Nhóm sát thủ của lão tổ","trangThai":"gan-bo"}],"trangThai":"tu-vong","blurb":"Sát thủ bản lãnh tương đương Anh Biến Sơ Kỳ, hóa đạo cầu vồng tập kích Vương Lâm.","vaiTro":"Sát thủ đầu tiên ra trận, bị Tịch Diệt Nhất Chỉ giết chết.","tinhCach":[{"text":"Quyết liệt, lao thẳng vào tập kích","chuong":"@c0540"}],"tabs":{"diem":[],"kinhLich":[{"chuong":"@c0540","importance":"normal","tieuDe":"Bị Tịch Diệt Nhất Chỉ giết","text":"Nhận hiệu lệnh, hóa thành đạo cầu vồng mang sát khí bay tới tập kích Vương Lâm. Bị Tịch Diệt Nhất Chỉ phá vỡ cầu vồng, phun máu, dù dùng yêu lực vẫn bị hắc khí đuổi đâm vào ngực ngã chết, để lại một đạo khí xám bay về phía Vương Lâm."}],"tuViMoc":[{"chuong":"@c0540","canhGioi":"Anh Biến Sơ Kỳ (tương đương)","text":"Bản lãnh tương đương Anh Biến Sơ Kỳ.","importance":"minor"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Bị Vương Lâm giết bằng Tịch Diệt Nhất Chỉ","gap":"@c0540"}],"tuiDo":{}},"nguon":["@c0540"]},{"id":"mo-van-yeu-tuong","name":"Mộ Vân","gioiTinh":"nam","tabs":{"diem":[{"text":"Yêu Tướng gầy yếu sắc mặt vàng vọt, xếp top 30, tu Cửu Tử Cửu Sinh chi khí","chuong":"@c0543"}],"kinhLich":[{"chuong":"@c0543","importance":"normal","tieuDe":"Bại trận đầu trước Thạch Tiêu","text":"Mộ Vân được giáp vàng chỉ định ra trước, từng đạt Ngũ Tử Ngũ Sinh ba trăm năm trước, nay đột phá tầng bảy hóa năm đạo sinh tử yêu khí (khí xanh lục như linh xà). Bị Thạch Tiêu dùng quang đồ hình thoi cắn nát năm đạo khí rồi ấn nổ, thua trận."}],"tuViMoc":[],"nhanMach":[{"ten":"Thạch Tiêu","tag":"doi-thu","quanHe":"Bị Thạch Tiêu hạ gục ở trận đầu","ghiChu":"@c0543"},{"ten":"Thiên Khôi Công Nhân","tag":"dong-minh","quanHe":"Người trợ giúp của Mộ Vân trong trận","ghiChu":"@c0543"}],"tuiDo":{}},"nguon":["@c0543"]},{"id":"thien-khoi-cong-nhan","name":"Thiên Khôi Công Nhân","gioiTinh":"nam","theLuc":[{"ten":"Cự Linh Môn","trangThai":"gan-bo"}],"tabs":{"diem":[{"text":"Người trợ giúp của Mộ Vân, xuất thân Cự Linh Môn trên Thiên Vận Tinh, thân thể to lớn thiên về sức lực","chuong":"@c0543"}],"kinhLich":[{"chuong":"@c0543","importance":"normal","tieuDe":"Tử trận dưới tay Thạch Tiêu","text":"Khi Mộ Vân thua, Thiên Khôi Công Nhân xông lên trợ chiến, dùng tiên lực từ lỗ chân lông tạo sương bao thân kèm chú ngữ dựng cấm chế phạm vi trăm trượng. Bị Thạch Tiêu dùng hình nón dung yêu lực đâm vỡ thân, hóa thành đám máu thịt."}],"tuViMoc":[],"nhanMach":[{"ten":"Mộ Vân","tag":"dong-minh","quanHe":"Là người trợ giúp của Mộ Vân","ghiChu":"@c0543"},{"ten":"Thạch Tiêu","tag":"doi-thu","quanHe":"Bị Thạch Tiêu giết chết","ghiChu":"@c0543"}],"tuiDo":{}},"nguon":["@c0543"]},{"id":"ngao-dich-yeu-tuong","name":"Ngao Địch","gioiTinh":"nam","tabs":{"diem":[{"text":"Yêu Tướng bản lãnh trung bình, tính xảo trá trơ trẽn","chuong":"@c0543"}],"kinhLich":[{"chuong":"@c0543","importance":"normal","tieuDe":"Khiêu chiến Vương Lâm","text":"Ngao Địch chớp cơ hội ra khiêu chiến Vương Lâm vì thắng Vương Lâm tương đương thắng Mạc Lệ Hải. Hắn dọa rằng nếu ngang sức thì còn người trợ giúp. Vương Lâm bình thản đáp rằng hắn không phải là đối thủ."},{"chuong":"@c0546","importance":"normal","tieuDe":"Yêu Tướng duy nhất bị trọng thương vòng một","text":"Được nhắc là Yêu Tướng duy nhất bị Vương Lâm đánh trọng thương ở vòng một; ngoài hắn không Yêu Tướng nào bị thương nặng."}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Ra khiêu chiến Vương Lâm, bị coi thường","ghiChu":"@c0543"}],"tuiDo":{}},"nguon":["@c0543","@c0546"]},{"id":"huyen-pho-soai","name":"Huyền Phó Soái","gioiTinh":"nam","theLuc":[{"ten":"Thiên Yêu Quận","trangThai":"gan-bo"}],"tabs":{"diem":[{"text":"Một trong sáu Phó Soái Thiên Yêu Quận, sắc mặt tái nhợt như có thương; có thù cũ với Vương Lâm","chuong":"@c0543"}],"kinhLich":[{"chuong":"@c0543","importance":"normal","tieuDe":"Đánh cược về Vương Lâm","text":"Huyền Phó Soái căm giận nhìn Vương Lâm vì có thù cũ, song quả quyết với Hoàng Phó Soái rằng người này chắc chắn vào tam giáp, thậm chí đứng đầu. Hai bên cược: Huyền đưa Phó Thiên Triệu Kỳ nếu Vương Lâm không dẫn đầu. Hắn thầm mong Vương Lâm đánh trọng thương Hoàng Phó Soái."},{"chuong":"@c0546","importance":"normal","tieuDe":"Đánh cược về Vương Lâm","text":"Một trong sáu Phó Soái; chăm chú vào Vương Lâm, đánh cược với Hoàng Phó Soái rằng tu sĩ mình chọn (Vương Lâm) không thua. Trong lòng cảm thấy Mặc Phi chỉ mạnh, còn Vương Lâm mới thật sự đáng sợ; giọng nói khi nhắc Vương Lâm có vẻ sợ hãi."}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Căm ghét vì thù cũ nhưng tin Vương Lâm sẽ dẫn đầu","ghiChu":"@c0543"},{"ten":"Hoàng Phó Soái","tag":"khac","quanHe":"Đánh cược về thành tích Vương Lâm","ghiChu":"@c0543"},{"ten":"Hoàng Phó Soái","tag":"doi-thu","quanHe":"Đối thủ đánh cược về việc Vương Lâm có thua hay không","ghiChu":"@c0546"},{"ten":"Vương Lâm","tag":"khac","quanHe":"Chọn Vương Lâm để đánh cược, âm thầm cho rằng hắn đáng sợ","ghiChu":"@c0546"}],"tuiDo":{}},"nguon":["@c0543","@c0546"]},{"id":"hoang-pho-soai","name":"Hoàng Phó Soái","gioiTinh":"nam","theLuc":[{"ten":"Thiên Yêu Quận","trangThai":"gan-bo"}],"tabs":{"diem":[{"text":"Phó Soái mặc giáp lam, tướng mạo tầm thường mà uy nghiêm","chuong":"@c0543"}],"kinhLich":[{"chuong":"@c0543","importance":"normal","tieuDe":"Nghi ngờ thực lực Vương Lâm","text":"Hoàng Phó Soái thấy Vương Lâm chỉ là Anh Biến hậu kỳ viên mãn nên nghi ngờ lời Huyền Phó Soái. Hắn nhận cược, hứa đưa Huyền Huyền Đan nếu Vương Lâm đứng đầu."},{"chuong":"@c0546","importance":"normal","tieuDe":"Đánh cược với Huyền Phó Soái","text":"Phó Soái, đối thủ đánh cược của Huyền Phó Soái; cho rằng tu sĩ phải tự ra tay nên Huyền tất bại, nhưng cảm nhận giọng Huyền có vẻ sợ hãi khi nói về Vương Lâm."}],"tuViMoc":[],"nhanMach":[{"ten":"Huyền Phó Soái","tag":"khac","quanHe":"Đánh cược về thành tích Vương Lâm","ghiChu":"@c0543"},{"ten":"Vương Lâm","tag":"khac","quanHe":"Nghi ngờ thực lực, coi thường vì chỉ Anh Biến hậu kỳ","ghiChu":"@c0543"},{"ten":"Huyền Phó Soái","tag":"doi-thu","quanHe":"Đối thủ đánh cược về Vương Lâm","ghiChu":"@c0546"}],"tuiDo":{}},"nguon":["@c0543","@c0546"]},{"id":"nam-tu-giap-vang-chu-tri-yeu-tuong","name":"Nam tử mặc giáp vàng","gioiTinh":"nam","theLuc":[{"ten":"Thiên Yêu Quận","trangThai":"gan-bo"}],"tabs":{"diem":[{"text":"Quan chủ trì trận chiến Yêu Tướng, phụng mệnh Đế Quân; chưa lộ tên","chuong":"@c0543"}],"kinhLich":[{"chuong":"@c0543","importance":"normal","tieuDe":"Chủ trì trận chiến Yêu Tướng","text":"Nam tử mặc giáp vàng từ cung điện bước ra, hô gọi các Yêu Tướng bước ra khỏi hàng, công bố quy tắc khiêu chiến tàn khốc: một thắng một bại thì cả hai mất tư cách, Yêu Tướng không được chết, chỉ trợ giúp được phép tử vong. Hắn lần lượt chỉ định người tham chiến và buộc Thạch Tiêu lui sau khi thắng."},{"chuong":"@c0546","importance":"normal","tieuDe":"Chủ trì vòng hai, thách Vương Lâm đánh cược","text":"Phụng mệnh Đế Quân chủ trì vòng hai cuộc tranh đoạt Yêu Tướng, tuyên luật gõ Chiến Yêu Cổ. Lạnh lùng, coi tu sĩ tới đây là đám cường đạo nhắm truyền thừa Cổ Yêu, ôm ý giết kẻ đánh trọng thương Yêu Tướng. Cuối chương gọi Vương Lâm, tỏa sát khí và hỏi hắn có dám đánh cược không."},{"chuong":"@c0548","importance":"normal","tieuDe":"Chế giễu rồi kinh hoàng vì trống niệm","text":"Người mặc kim giáp cười lạnh chế giễu việc đánh Yêu Cổ là giả thần giả quỷ; lão từng theo Yêu Đế nhiều năm, nghĩ tu vi Vương Lâm không đủ thì tẩy tủy ắt trọng thương. Nhưng tới tiếng trống thứ mười một lão lần đầu đại biến sắc mặt, vô thức lùi vài bước, trắng xanh mặt ngơ ngẩn không nói nên lời trước cảnh giới trống truyền niệm."}],"tuViMoc":[],"nhanMach":[{"ten":"Yêu Đế","tag":"cap-tren","quanHe":"Phụng mệnh Đế Quân chủ trì trận chiến","ghiChu":"@c0543"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Tỏa sát khí với Vương Lâm vì đánh trọng thương Yêu Tướng, thách đánh cược","ghiChu":"@c0546"},{"ten":"Yêu đế","tag":"cap-tren","quanHe":"Đã theo Yêu Đế nhiều năm, nghe Yêu Đế nói về việc dùng tiếng trống tẩy tủy","ghiChu":"@c0548"}],"tuiDo":{}},"nguon":["@c0543","@c0546","@c0548"]},{"id":"vu-sam-yeu-tuong","name":"Vu Sâm","gioiTinh":"nam","theLuc":[{"ten":"Thiên Yêu Quận","trangThai":"gan-bo"}],"tabs":{"diem":[{"text":"Yêu Tướng duy nhất không có thành trì, hằng năm lấy sát lục tu luyện tới đỉnh ở Hỏa Yêu Quận","chuong":"@c0543"}],"kinhLich":[{"chuong":"@c0543","importance":"minor","tieuDe":"Ứng viên trận Yêu Tướng","text":"Vu Sâm được dân chúng nhắc đến như Yêu Tướng duy nhất không có thành trì, chuyên tu sát lục đạo."},{"chuong":"@c0546","importance":"normal","tieuDe":"Gõ bốn tiếng Chiến Yêu Cổ","text":"Yêu Tướng tu Sát Lục đạo, điều tức rồi bùng nổ dùng song chỉ và thần thông Phệ Hồn Sát Lục đệ nhất thức gõ trống. Gõ liên tiếp bốn tiếng, sau đó tay phải mất cảm giác, yêu lực hao tám phần, lùi hơn trăm trượng, nuốt máu dừng lại. Tuyên bố không có người trợ giúp."}],"tuViMoc":[],"nhanMach":[],"tuiDo":{}},"nguon":["@c0543","@c0546"]},{"id":"ma-van-yeu-tuong","name":"Ma Văn","gioiTinh":"nam","theLuc":[{"ten":"Thiên Yêu Quận","trangThai":"gan-bo"}],"tabs":{"diem":[{"text":"Yêu Tướng công pháp đặc biệt, kế thừa Long Đàm Cổ Yêu Điện, khiêm tốn ẩn giấu thực lực","chuong":"@c0543"}],"kinhLich":[{"chuong":"@c0543","importance":"minor","tieuDe":"Ứng viên trận Yêu Tướng","text":"Ma Văn được nhắc đến như Yêu Tướng kế thừa Long Đàm Cổ Yêu Điện, công pháp đặc biệt, khiêm tốn giấu thực lực."}],"tuViMoc":[],"nhanMach":[],"tuiDo":{}},"nguon":["@c0543"]},{"id":"ta-lien-yeu-tuong","name":"Tà Liên","gioiTinh":"nu","theLuc":[{"ten":"Thiên Yêu Quận","trangThai":"gan-bo"}],"tabs":{"diem":[{"text":"Nữ Yêu Tướng duy nhất, ba trăm năm trước bị thương vẫn đạt vị trí thứ tư","chuong":"@c0543"}],"kinhLich":[{"chuong":"@c0543","importance":"minor","tieuDe":"Ứng viên trận Yêu Tướng","text":"Tà Liên được nhắc đến như nữ Yêu Tướng duy nhất, từng bị thương ba trăm năm trước mà vẫn đạt vị trí thứ tư."},{"chuong":"@c0547","importance":"normal","tieuDe":"Chú ý Vương Lâm gõ Yêu Cổ","text":"Tà Liên xuất hiện trong hàng ngũ yêu tướng quan sát Vương Lâm gõ trống Yêu Cổ; mắt đẹp lóe tinh quang dõi theo khi hắn lập thành tích chín tiếng."}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Chú ý quan sát Vương Lâm khi hắn gõ Yêu Cổ","ghiChu":""}],"tuiDo":{}},"nguon":["@c0543","@c0547"]},{"id":"thanh-nien-thuyen-tranh","name":"Thanh niên trên thuyền tranh","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"không rõ","trangThai":"song","blurb":"Thanh niên tướng mạo tầm thường nhưng cởi mở, quan sát Vương Lâm nhiều ngày rồi mời lên thuyền tranh nghe đàn uống rượu; tự nhận tục nhân, danh tính bất phàm chưa rõ.","vaiTro":"Nhân vật bí ẩn","tinhCach":[{"text":"Cởi mở, ung dung, thích kết giao theo tâm thái khách qua đường","chuong":"@c0545"}],"tabs":{"diem":[{"text":"Nhận Vương Lâm là tục nhân đồng điệu, mời uống rượu nghe đàn tới bình minh","chuong":"@c0545"},{"text":"Hé lộ có gia đình với “vài vị khách thô lỗ tranh cãi ầm ĩ” và bảy đứa cháu gái bướng bỉnh bị một vị khách đáng ghét quấn lấy","chuong":"@c0545"}],"kinhLich":[{"chuong":"@c0545","importance":"normal","tieuDe":"Mời Vương Lâm lên thuyền tranh","text":"Buổi trưa thuyền tranh đến, thanh niên nâng chén mời Vương Lâm lên mũi thuyền cùng nghe đàn của Minh Phí cô nương. Cuối buổi hỏi Vương Lâm nghe đàn có cảm xúc gì, hai người nhận nhau là tục nhân và hẹn uống tới bình minh; qua đối thoại lộ hắn có gia đình bất phàm."}],"tuViMoc":[],"tuVi":"Chưa rõ tu vi.","nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Mời lên thuyền tranh nghe đàn uống rượu, cùng nhận nhau là tục nhân","ghiChu":"@c0545"},{"ten":"Minh Phí (cô nương)","tag":"khac","quanHe":"Nữ tử đánh đàn trên thuyền của hắn","ghiChu":"@c0545"}],"tuiDo":{}},"nguon":["@c0545"]},{"id":"minh-phi-co-nuong","name":"Minh Phí (cô nương)","cn":"","aliases":["Minh Phí"],"gioiTinh":"nu","theLuc":[],"canhGioiCaoNhat":"không rõ","trangThai":"song","blurb":"Nữ tử đánh đàn trên thuyền tranh; tiếng đàn vô tình nhưng hàm chứa bi thương, khiến tâm vướng bận của người nghe rung động.","vaiTro":"Nhân vật phụ","tinhCach":[{"text":"Lặng lẽ, tiếng đàn vô tình mà ẩn chứa bi thương","chuong":"@c0545"}],"tabs":{"diem":[{"text":"Tiếng đàn của nàng khơi gợi cảm ngộ chữ “nghịch” và nỗi nhớ cố nhân nơi Vương Lâm","chuong":"@c0545"}],"kinhLich":[{"chuong":"@c0545","importance":"normal","tieuDe":"Đánh đàn trên thuyền tranh","text":"Trên thuyền tranh ở Hồng Thành, Minh Phí đánh đàn cho Vương Lâm và thanh niên bí ẩn nghe; tiếng đàn vô tình mà hàm chứa nghịch ý và bi thương khiến người nghe rung động."}],"tuViMoc":[],"tuVi":"Chưa rõ tu vi.","nhanMach":[{"ten":"Thanh niên trên thuyền tranh","tag":"khac","quanHe":"Đánh đàn trên thuyền của thanh niên","ghiChu":"@c0545"},{"ten":"Vương Lâm","tag":"khac","quanHe":"Tiếng đàn khơi cảm ngộ của Vương Lâm","ghiChu":"@c0545"}],"tuiDo":{}},"nguon":["@c0545"]},{"id":"thieu-mon-chu-ngoc-kiem-mon","name":"Thiếu môn chủ Ngọc Kiếm Môn (nam tử áo trắng)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Ngọc Kiếm Môn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Anh Biến kỳ trở lên","trangThai":"song","blurb":"Nam tử áo trắng tướng mạo sáng sủa, thiếu môn chủ Ngọc Kiếm Môn; bị cuốn vào tranh đoạt Yêu Tướng, thức tỉnh dẫn đoàn tu sĩ rời khỏi Thiên Yêu Thành.","vaiTro":"Nhân vật phụ","tinhCach":[{"text":"Khí khái, không cam làm con hát mua vui cho Yêu Linh","chuong":"@c0545"}],"tabs":{"diem":[{"text":"Cảm phục Vương Lâm; nhắc danh tiếng Vương Lâm vang như sấm ở Thiên Vận Tinh","chuong":"@c0545"}],"kinhLich":[{"chuong":"@c0545","importance":"normal","tieuDe":"Dẫn đoàn rời Thiên Yêu Thành","text":"Trên đường tới Mạc phủ, thiếu môn chủ Ngọc Kiếm Môn cùng người trợ giúp của Yêu Tướng Ngao Địch bày tỏ thức tỉnh: ở Yêu Linh tu sĩ chỉ là con hát mua vui, sinh mạng thấp hơn kiến. Họ cáo từ Vương Lâm, hóa cầu vồng bay đi."}],"tuViMoc":[],"tuVi":"Anh Biến kỳ trở lên.","nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Cảm phục Vương Lâm, cáo từ trước khi rời đi","ghiChu":"@c0545"},{"ten":"Người trợ giúp của Yêu Tướng Ngao Địch (đạo bào trung niên)","tag":"dong-hanh","quanHe":"Cùng thức tỉnh rời khỏi Thiên Yêu Thành","ghiChu":"@c0545"}],"tuiDo":{}},"nguon":["@c0545"]},{"id":"nguoi-tro-giup-yeu-tuong-ngao-dich","name":"Người trợ giúp của Yêu Tướng Ngao Địch (đạo bào trung niên)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"không rõ","trangThai":"song","blurb":"Trung niên đạo bào từng trợ giúp Yêu Tướng Ngao Địch; sau cái chết của Ngao Địch thì thức tỉnh, theo đoàn rời khỏi Thiên Yêu Thành.","vaiTro":"Nhân vật phụ","tinhCach":[{"text":"Tỉnh ngộ chiến công vô nghĩa nếu không còn sống để hưởng","chuong":"@c0545"}],"tabs":{"diem":[{"text":"Cái chết của Ngao Địch khiến hắn buông bỏ, theo đoàn Ngọc Kiếm Môn rời đi","chuong":"@c0545"}],"kinhLich":[{"chuong":"@c0545","importance":"normal","tieuDe":"Thức tỉnh rời Thiên Yêu Thành","text":"Sau cái chết của Yêu Tướng Ngao Địch, hắn nói chiến công vô nghĩa nếu không còn sống để hưởng, cùng thiếu môn chủ Ngọc Kiếm Môn cáo từ Vương Lâm rồi hóa cầu vồng bay đi."}],"tuViMoc":[],"tuVi":"Chưa rõ tu vi.","nhanMach":[{"ten":"Ngao Địch","tag":"cap-tren","quanHe":"Từng trợ giúp Yêu Tướng Ngao Địch; cái chết của Ngao Địch khiến hắn thức tỉnh","ghiChu":"@c0545"},{"ten":"Thiếu môn chủ Ngọc Kiếm Môn (nam tử áo trắng)","tag":"dong-hanh","quanHe":"Cùng thức tỉnh rời khỏi Thiên Yêu Thành","ghiChu":"@c0545"}],"tuiDo":{}},"nguon":["@c0545"]},{"id":"mat-duong","name":"Mạt Dương","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Đại La Kiếm Tông","trangThai":"gan-bo"},{"ten":"Kiếm Tiếu Thập Nhị Tử","trangThai":"gan-bo"}],"canhGioiCaoNhat":"","trangThai":"tu-vong","blurb":"Một trong Kiếm Tiếu Thập Nhị Tử của Đại La Kiếm Tông, địa vị tương đương Thiên Vận Thất Tử; đưa chiến thư của Mặc Phi rồi khiêu chiến Vương Lâm và bị giết.","vaiTro":"Phản diện thoáng qua — sứ giả đưa chiến thư kiêm kẻ khiêu chiến Vương Lâm.","tinhCach":[{"text":"Kiêu ngạo, hiếu chiến, coi thường đối thủ nhưng nhanh chóng thất vọng khi bị áp chế.","chuong":"@c0541"}],"tabs":{"diem":[{"text":"Nam tử áo xanh đeo đại kiếm, tỏa tiên lực bao phủ, ai tới gần trong mười trượng đều tan thành sương máu.","chuong":"@c0541"},{"text":"Bảo kiếm bản mệnh là cự kiếm tím dung hợp Tà Dương Chi Hồn (hư ảnh con dê tím).","chuong":"@c0541"}],"kinhLich":[{"chuong":"@c0541","importance":"major","tieuDe":"Khiêu chiến Vương Lâm và tử vong","text":"Mạt Dương đột nhập Mạc phủ giết hai quân sĩ, vượt qua người thấp bé và ba lão già để trao chiến thư “Chiến!” của Mặc Phi cho Mạc Lệ Hải, hẹn ba ngày sau ở sảnh đường Cổ Đạo. Khi quay đi, hắn chặn Vương Lâm khiêu chiến, phóng sáu mươi tư đạo kiếm khí và thi triển Mạt Dương kiếm trảm với cự kiếm tím dung hợp Tà Dương Chi Hồn, nhưng đều bị hóa giải; bị Vương Lâm đoạt kiếm, hộc máu, định dùng kiếm khí bảo mệnh của Lăng Thiên Hậu thì được tha. Rời Mạc phủ nghìn trượng thầm thề báo thù, hắn bị khí xám ẩn trong cự kiếm xâm nhập, cắt nguyên thần khỏi thân thể, hóa thây khô và bị Vương Lâm đoạt xác."}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Kẻ địch giết mình","ghiChu":"Khiêu chiến tại Mạc phủ, bị hóa giải kiếm khí, đoạt kiếm bản mệnh rồi âm thầm hạ sát."},{"ten":"Mặc Phi","tag":"su-mon","quanHe":"Người sai phái","ghiChu":"Yêu Tướng Mặc Phi sai Mạt Dương đưa chiến thư cho Mạc Lệ Hải."},{"ten":"Mạc Lệ Hải","tag":"doi-thu","quanHe":"Người nhận chiến thư","ghiChu":"Mạt Dương thay mặt Mặc Phi đưa chiến thư khiêu chiến tới Mạc Lệ Hải."},{"ten":"Lăng Thiên Hậu","tag":"su-mon","quanHe":"Sư tôn","ghiChu":"Sư tôn của Kiếm Tiếu Thập Nhị Tử, ban cho Mạt Dương một đạo kiếm khí bảo mệnh."},{"ten":"Tham Lang","tag":"dong-minh","quanHe":"Tiền bối cùng phe","ghiChu":"Cường giả Mạt Dương trông cậy để báo thù; đang ở Hỏa Yêu Quận."}],"tuViMoc":[],"tuVi":"Cường giả Kiếm Tiếu Thập Nhị Tử của Đại La Kiếm Tông, địa vị tương đương Thiên Vận Thất Tử nhưng không phải đối thủ của Vương Lâm.","tuiDo":{"phapBao":[{"ten":"Cự kiếm tím (bảo kiếm bản mệnh)","loai":"phap-bao","trangThai":"mat","moTa":"Cự kiếm màu tím dung hợp Tà Dương Chi Hồn, bị Vương Lâm bắt sống và diệt Dương Hồn rồi trả lại; chủ nhân hóa thây khô sau đó.","nguon":"@c0541"}]}},"nguon":["@c0541"]},{"id":"tu-si-thanh-sam-tro-giup-mac-phi","name":"Tu sĩ mặc thanh sam","gioiTinh":"nam","aliases":["Người trợ giúp Mặc Phi"],"tabs":{"diem":[],"kinhLich":[{"chuong":"@c0546","importance":"normal","tieuDe":"Trợ giúp Mặc Phi gõ ba tiếng","text":"Tu sĩ lưng mang đại kiếm ra trợ giúp Mặc Phi, dùng chỉ/chưởng/kiếm khí gõ ba tiếng rồi cười khổ lui (có thể gõ năm nhưng sẽ trọng thương, không đáng vì Mặc Phi đã tất thắng)."}],"tuViMoc":[],"nhanMach":[{"ten":"Mặc Phi","tag":"dong-minh","quanHe":"Trợ giúp Mặc Phi gõ thêm ba tiếng Chiến Yêu Cổ","ghiChu":"@c0546"}],"tuiDo":{}},"nguon":["@c0546"]},{"id":"dia-soai","name":"Địa Soái","gioiTinh":"nam","tabs":{"diem":[],"kinhLich":[{"chuong":"@c0546","importance":"normal","tieuDe":"Ái tài Mặc Phi","text":"Một trong tám Yêu Soái; ái tài Mặc Phi, hứa dù không thành Phó Soái cũng đề cử nếu gõ được sáu tiếng. Bị nam tử trung niên mặc tử bào ngồi cạnh trêu là động lòng ái tài."}],"tuViMoc":[],"nhanMach":[{"ten":"Mặc Phi","tag":"khac","quanHe":"Ái tài, hứa đề cử nếu Mặc Phi gõ sáu tiếng","ghiChu":"@c0546"}],"tuiDo":{}},"nguon":["@c0546"]},{"id":"thien-soai-thien-yeu-quan","name":"Thiên Soái","gioiTinh":"nam","aliases":["Thiên Soái đại nhân"],"tabs":{"diem":[],"kinhLich":[{"chuong":"@c0546","importance":"normal","tieuDe":"Kỷ lục mười lăm tiếng Chiến Yêu Cổ","text":"Đứng đầu các Yêu Soái; được nhắc là người duy nhất từng gõ Chiến Yêu Cổ đến mười lăm tiếng (kỷ lục). Trong chương ánh mắt luôn bình thản không đổi sắc."},{"chuong":"@c0548","importance":"normal","tieuDe":"Thiên soái động dung nhận ra Vương Lâm","text":"Ban đầu nhắm hờ mắt lộ vẻ thất vọng với Vương Lâm rồi thở dài không muốn nhìn nữa, nhưng khi tiếng trống thứ mười một vang lên Thiên soái lần đầu mở to mắt, đứng thẳng người, ánh mắt sáng như điện kinh ngạc nhận ra danh tính “Là Vương Lâm sao?”."},{"chuong":"@c0549","importance":"normal","tieuDe":"Nhận ra tẩy tủy thật","text":"Là một trong tám Yêu soái, Thiên soái lần đầu mở miệng tuyên bố sẽ nhớ kỹ tên Vương Lâm. Hắn nhận ra tiếng trống của Vương Lâm là tẩy tủy thật, tán thưởng; nhìn thấu sự do dự của Vương Lâm, nhớ năm xưa mình cũng phải lựa chọn khi Vấn Đỉnh, lẩm bẩm Vấn Đỉnh là sự cô độc mà người chưa đạt không thể hiểu."}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Người khiến Thiên soái động dung và nhận ra danh tính sau tiếng trống truyền niệm","ghiChu":"@c0548"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Yêu soái chứng kiến Vương Lâm gõ trống","ghiChu":"Tuyên bố nhớ kỹ tên Vương Lâm, tán thưởng tẩy tủy thật (@c0549)."}],"tuiDo":{}},"nguon":["@c0546","@c0548","@c0549"]},{"id":"vu-soai","name":"Vũ soái","cn":"","aliases":[],"gioiTinh":"nu","theLuc":[{"ten":"Yêu tộc Thiên Yêu Thành (hệ Yêu Tướng - Yêu Soái)","trangThai":"gan-bo"}],"canhGioiCaoNhat":"","trangThai":"song","blurb":"Nữ Yêu soái duy nhất; đính chính rằng Vương Lâm đang cảm ngộ chứ không phải cảm nhận khí tức trong Yêu Cổ.","vaiTro":"Yêu soái nữ duy nhất trên khán đài Thiên Yêu thành.","tinhCach":[{"text":"Điềm tĩnh, am hiểu cốt lõi của Yêu Cổ.","chuong":"@c0548"}],"tabs":{"diem":[{"text":"Là Yêu soái nữ duy nhất, từng đích thân đánh Yêu Cổ và cảm được khí tức bên trong.","chuong":"@c0548"}],"kinhLich":[{"chuong":"@c0548","importance":"normal","tieuDe":"Đính chính cảm ngộ Yêu Cổ","text":"Khi người mặc kim giáp chế giễu Vương Lâm là giả thần giả quỷ, Vũ soái lên tiếng khẳng định hắn đang “cảm ngộ” chứ không phải “cảm nhận”, kể năm xưa bà đánh Yêu Cổ cũng cảm được một khí tức bên trong, khiến toàn bộ Yêu soái ngưng trọng."}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Người mà bà đính chính bênh vực về việc cảm ngộ Yêu Cổ","ghiChu":"@c0548"}],"tuiDo":{}},"nguon":["@c0548"]},{"id":"huyen-soai-thien-yeu","name":"Huyền soái","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Yêu tộc Thiên Yêu Thành (hệ Yêu Tướng - Yêu Soái)","trangThai":"gan-bo"}],"canhGioiCaoNhat":"","trangThai":"song","blurb":"Yêu soái ngồi khán đài; thắc mắc liệu tu sĩ đánh Yêu Cổ có cảm nhận được khí tức bên trong.","vaiTro":"Một trong hàng Yêu soái quan sát màn đánh Yêu Cổ.","tinhCach":[{"text":"Thận trọng, hay đặt nghi vấn.","chuong":"@c0548"}],"tabs":{"diem":[{"text":"Thắc mắc liệu tu sĩ đánh Yêu Cổ có thật sự cảm nhận được khí tức trong trống.","chuong":"@c0548"}],"kinhLich":[{"chuong":"@c0548","importance":"normal","tieuDe":"Nghi vấn cảm nhận Yêu Cổ","text":"Khi Vương Lâm đánh Yêu Cổ tới mức kỳ lạ, Huyền soái nêu thắc mắc liệu tu sĩ này có cảm nhận được Yêu Cổ, mở đường cho Vũ soái đính chính."}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Tu sĩ mà Huyền soái nghi vấn về việc cảm nhận Yêu Cổ","ghiChu":"@c0548"}],"tuiDo":{}},"nguon":["@c0548"]},{"id":"huyen-hon-soai-thien-yeu","name":"Huyền Hôn soái","cn":"","aliases":["Huyền Hôn soái"],"gioiTinh":"nam","theLuc":[{"ten":"Yêu tộc Thiên Yêu Thành (hệ Yêu Tướng - Yêu Soái)","trangThai":"gan-bo"}],"canhGioiCaoNhat":"","trangThai":"song","blurb":"Yêu soái kính phục Vương Lâm sau tiếng trống truyền niệm; ngờ hắn là người Yêu Đế đã chờ đợi nhiều năm.","vaiTro":"Yêu soái trên khán đài Thiên Yêu thành.","tinhCach":[{"text":"Biết kính phục, nhạy bén với cảnh giới tu hành.","chuong":"@c0548"}],"tabs":{"diem":[{"text":"Tu vi đã dừng lại từ lâu nhưng tiếng trống truyền niệm khiến lão lại rung động.","chuong":"@c0548"}],"kinhLich":[{"chuong":"@c0548","importance":"normal","tieuDe":"Ngờ Vương Lâm là người Yêu Đế chờ","text":"Sau tiếng trống truyền niệm, Huyền Hôn soái kính phục thốt rằng đó là một loại cảnh giới và có lẽ Vương Lâm chính là người mà Yêu Đế bệ hạ đã chờ đợi rất nhiều năm; tu vi lão vốn đình trệ từ lâu nay lại bị rung động."}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Người Huyền Hôn soái kính phục và ngờ là kẻ Yêu Đế chờ đợi","ghiChu":"@c0548"},{"ten":"Yêu đế","tag":"khac","quanHe":"Đế vương Yêu tộc mà Huyền Hôn soái cho là đang chờ đợi Vương Lâm","ghiChu":"@c0548"}],"tuiDo":{}},"nguon":["@c0548"]}]};
